function normalizeQaMetricRoute(route) {
  const token = String(route || '').trim();
  return token || 'unknown';
}

function escapePrometheusLabel(value) {
  return String(value || '')
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n');
}

function trimQaEventValue(value, max = 240) {
  const text = String(value || '').trim();
  if (!text) return '';
  return text.length > max ? `${text.slice(0, max - 1)}…` : text;
}

function getQaRouteMetricBucket(route) {
  const key = normalizeQaMetricRoute(route);
  if (!qaRouteObservability.totals_by_route[key]) {
    qaRouteObservability.totals_by_route[key] = {
      total: 0,
      by_reason: Object.create(null),
      timeout_stage_by_stage: Object.create(null),
      latency_total_ms: 0,
      gate_wait_total_ms: 0,
      upstream_total_ms: 0,
      last_model: '',
      last_prompt_bytes: 0,
      last_schema_bytes: 0,
      last_max_output_tokens: 0,
    };
  }
  return qaRouteObservability.totals_by_route[key];
}

function recordQaRouteObservability(meta = {}) {
  const route = normalizeQaMetricRoute(meta.route);
  const bucket = getQaRouteMetricBucket(route);
  const reason = trimQaEventValue(meta.result_reason || 'unknown', 120) || 'unknown';
  const timeoutStage = trimQaEventValue(meta.timeout_stage || 'none', 32) || 'none';
  bucket.total += 1;
  bucket.by_reason[reason] = Number(bucket.by_reason[reason] || 0) + 1;
  bucket.timeout_stage_by_stage[timeoutStage] = Number(bucket.timeout_stage_by_stage[timeoutStage] || 0) + 1;
  bucket.latency_total_ms += Number.isFinite(Number(meta.total_ms)) ? Math.max(0, Number(meta.total_ms)) : 0;
  bucket.gate_wait_total_ms += Number.isFinite(Number(meta.gate_wait_ms)) ? Math.max(0, Number(meta.gate_wait_ms)) : 0;
  bucket.upstream_total_ms += Number.isFinite(Number(meta.upstream_ms)) ? Math.max(0, Number(meta.upstream_ms)) : 0;
  bucket.last_model = trimQaEventValue(meta.model || '', 120);
  bucket.last_prompt_bytes = Number.isFinite(Number(meta.prompt_bytes)) ? Math.max(0, Math.trunc(Number(meta.prompt_bytes))) : 0;
  bucket.last_schema_bytes = Number.isFinite(Number(meta.schema_bytes)) ? Math.max(0, Math.trunc(Number(meta.schema_bytes))) : 0;
  bucket.last_max_output_tokens = Number.isFinite(Number(meta.max_output_tokens))
    ? Math.max(0, Math.trunc(Number(meta.max_output_tokens)))
    : 0;

  qaRouteObservability.recent_events.push({
    ts: new Date().toISOString(),
    route,
    model: bucket.last_model || null,
    prompt_bytes: bucket.last_prompt_bytes,
    schema_bytes: bucket.last_schema_bytes,
    max_output_tokens: bucket.last_max_output_tokens,
    gate_wait_ms: Number.isFinite(Number(meta.gate_wait_ms)) ? Math.max(0, Math.trunc(Number(meta.gate_wait_ms))) : 0,
    upstream_ms: Number.isFinite(Number(meta.upstream_ms)) ? Math.max(0, Math.trunc(Number(meta.upstream_ms))) : 0,
    total_ms: Number.isFinite(Number(meta.total_ms)) ? Math.max(0, Math.trunc(Number(meta.total_ms))) : 0,
    timeout_stage: timeoutStage === 'none' ? null : timeoutStage,
    result_reason: reason,
    detail: trimQaEventValue(meta.detail || '', 320) || null,
  });
  if (qaRouteObservability.recent_events.length > 100) {
    qaRouteObservability.recent_events.splice(0, qaRouteObservability.recent_events.length - 100);
  }
}

function getQaRouteObservabilitySnapshot() {
  return {
    totals_by_route: JSON.parse(JSON.stringify(qaRouteObservability.totals_by_route || {})),
    recent_events: Array.isArray(qaRouteObservability.recent_events)
      ? qaRouteObservability.recent_events.slice(-50)
      : [],
  };
}

function renderGeminiQaMetricsPrometheus() {
  const gate = getGeminiGlobalGate();
  const snapshot = gate && typeof gate.snapshot === 'function' ? gate.snapshot() : null;
  const routeMetrics =
    snapshot && snapshot.metrics && snapshot.metrics.by_route && typeof snapshot.metrics.by_route === 'object'
      ? snapshot.metrics.by_route
      : {};
  const lines = [
    '# HELP aurora_gemini_gate_route_window_total Rolling 60s Gemini gate counts by route and status.',
    '# TYPE aurora_gemini_gate_route_window_total gauge',
  ];
  const routes = Object.keys(routeMetrics).sort();
  if (!routes.length) {
    lines.push('aurora_gemini_gate_route_window_total{route="none",status="success"} 0');
  } else {
    for (const route of routes) {
      const row = routeMetrics[route] || {};
      for (const status of ['success', 'timeout', 'rate_limited']) {
        lines.push(
          `aurora_gemini_gate_route_window_total{route="${escapePrometheusLabel(route)}",status="${status}"} ${Number(row[status] || 0)}`,
        );
      }
    }
  }

  lines.push('# HELP aurora_gemini_qa_timeout_stage_total Total QA timeout classifications by route and stage.');
  lines.push('# TYPE aurora_gemini_qa_timeout_stage_total counter');
  const totalsByRoute = qaRouteObservability.totals_by_route || {};
  const qaRoutes = Object.keys(totalsByRoute).sort();
  if (!qaRoutes.length) {
    lines.push('aurora_gemini_qa_timeout_stage_total{route="none",stage="none"} 0');
  } else {
    for (const route of qaRoutes) {
      const row = totalsByRoute[route] || {};
      const stages = row.timeout_stage_by_stage || {};
      const stageKeys = Object.keys(stages).sort();
      if (!stageKeys.length) {
        lines.push(`aurora_gemini_qa_timeout_stage_total{route="${escapePrometheusLabel(route)}",stage="none"} 0`);
        continue;
      }
      for (const stage of stageKeys) {
        lines.push(
          `aurora_gemini_qa_timeout_stage_total{route="${escapePrometheusLabel(route)}",stage="${escapePrometheusLabel(stage)}"} ${Number(stages[stage] || 0)}`,
        );
      }
    }
  }

  lines.push('# HELP aurora_gemini_qa_avg_latency_ms Average QA latency by route and segment.');
  lines.push('# TYPE aurora_gemini_qa_avg_latency_ms gauge');
  if (!qaRoutes.length) {
    lines.push('aurora_gemini_qa_avg_latency_ms{route="none",segment="total"} 0');
  } else {
    for (const route of qaRoutes) {
      const row = totalsByRoute[route] || {};
      const denom = Number(row.total || 0);
      const totalAvg = denom > 0 ? Math.round(Number(row.latency_total_ms || 0) / denom) : 0;
      const gateAvg = denom > 0 ? Math.round(Number(row.gate_wait_total_ms || 0) / denom) : 0;
      const upstreamAvg = denom > 0 ? Math.round(Number(row.upstream_total_ms || 0) / denom) : 0;
      lines.push(`aurora_gemini_qa_avg_latency_ms{route="${escapePrometheusLabel(route)}",segment="total"} ${totalAvg}`);
      lines.push(`aurora_gemini_qa_avg_latency_ms{route="${escapePrometheusLabel(route)}",segment="gate_wait"} ${gateAvg}`);
      lines.push(`aurora_gemini_qa_avg_latency_ms{route="${escapePrometheusLabel(route)}",segment="upstream"} ${upstreamAvg}`);
    }
  }
  return `${lines.join('\n')}\n`;
}

function escapeRegExp(text) {
  return String(text || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function buildLooseAsciiAliasRegex(alias) {
  const tokens = String(alias || '')
    .trim()
    .toLowerCase()
    .split(/\s+/)
    .map((t) => t.trim())
    .filter(Boolean)
    .slice(0, 6);
  if (!tokens.length) return null;
  const sep = '(?:[\\s\\p{P}_-])*';
  const body = tokens.map((t) => escapeRegExp(t)).join(sep);
  return new RegExp(`(?<![a-z0-9])${body}(?![a-z0-9])`, 'iu');
}

function messageHasAvailabilityHint(text) {
  const raw = String(text || '').trim();
  if (!raw) return false;
  return (
    /(有没有|有无|有吗|有没|有木有|有货|现货|库存|哪里买|怎么买|能买|购买|下单|链接|渠道|旗舰|自营|店|请问)/.test(raw) ||
    /\b(in stock|available|availability|where (can i|to) buy|do you have|have any|buy|purchase|link)\b/i.test(raw) ||
    /^有[^\n]{1,80}(产品|单品|品牌|[a-z0-9%+\-/]{2,})[^\n]{0,12}(吗|么|嗎|？|\?)$/iu.test(raw)
  );
}

function hasExplicitCatalogPurchaseIntent(text) {
  const raw = String(text || '').trim();
  if (!raw) return false;
  return /(哪里买|怎么买|购买|下单|有货|现货|库存|链接|旗舰|自营|店铺|有没有|有吗|有无|where (can i|to) buy|in stock|available|availability|purchase|buy|shop|do you have|have any)/i.test(
    raw,
  );
}

function hasLikelyProductEntityMention(text) {
  const raw = String(text || '').trim();
  if (!raw) return false;
  if (/https?:\/\//i.test(raw)) return true;
  if (/(serum|cleanser|moisturizer|cream|toner|sunscreen|spf|retinol|niacinamide|mask|精华|洁面|面霜|乳液|爽肤水|防晒|面膜)/i.test(raw)) {
    return true;
  }
  const lowered = raw.toLowerCase();
  for (const brand of Object.values(CATALOG_BRANDS || {})) {
    const aliases = Array.isArray(brand && brand.aliases) ? brand.aliases : [];
    for (const alias of aliases) {
      const token = String(alias || '').trim();
      if (!token) continue;
      if (/[\u4e00-\u9fff]/.test(token)) {
        if (raw.includes(token)) return true;
        continue;
      }
      const re = buildLooseAsciiAliasRegex(token);
      if (re && re.test(lowered)) return true;
    }
  }
  const tokens = raw
    .replace(/[，。！？!?]/g, ' ')
    .split(/\s+/)
    .map((token) => token.trim())
    .filter(Boolean);
  const informative = tokens.filter(
    (token) => token.length >= 3 && !/^(i|me|you|he|she|it|we|they|the|a|an|to|for|and|or|my|your|this|that)$/i.test(token),
  );
  return informative.length >= 2;
}

function detectCatalogAvailabilityShortCircuitBlockReason(text) {
  const hasAvailabilityHint = messageHasAvailabilityHint(text);
  if (!hasAvailabilityHint) return 'availability_hint_missing';
  const hasEntityMention = hasLikelyProductEntityMention(text);
  if (!hasEntityMention) return 'product_entity_missing';
  return '';
}

function shouldAllowCatalogAvailabilityShortCircuit(text) {
  return !detectCatalogAvailabilityShortCircuitBlockReason(text);
}

function stripGenericAvailabilityTokens(value) {
  return String(value || '')
    .replace(
      /(有没有|有无|有吗|有没|有木有|请问|产品|商品|有货|现货|库存|哪里买|怎么买|购买|下单|链接|渠道|官方|旗舰|自营|店|给我看下|查一下)/gi,
      ' ',
    )
    .replace(/\b(do you have|have any|where can i buy|where to buy|in stock|available|availability|buy|purchase|link|products?|items?|catalog|store|shop)\b/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function detectBrandAvailabilityIntent(message, lang) {
  const raw = String(message || '').trim();
  if (!raw) return null;

  // Exclude obvious non-commerce asks.
  if (looksLikeDiagnosisStart(raw)) return null;
  if (looksLikeSuitabilityRequest(raw)) return null;
  if (looksLikeRecommendationRequest(raw)) return null;
  if (looksLikeRoutineRequest(raw, null)) return null;
  if (looksLikeCompatibilityOrConflictQuestion(raw)) return null;
  if (looksLikeWeatherOrEnvironmentQuestion(raw)) return null;

  const text = raw.normalize('NFKC');
  const lowered = text.toLowerCase();

  const availabilityHint = messageHasAvailabilityHint(text);

  for (const brand of Object.values(CATALOG_BRANDS)) {
    const aliases = Array.isArray(brand.aliases) ? brand.aliases : [];
    let matchedAlias = '';
    for (const alias of aliases) {
      const a = String(alias || '').trim();
      if (!a) continue;
      if (/[\u4e00-\u9fff]/.test(a)) {
        if (text.includes(a)) {
          matchedAlias = a;
          break;
        }
        continue;
      }

      const re = buildLooseAsciiAliasRegex(a);
      if (re && re.test(lowered)) {
        matchedAlias = a;
        break;
      }
    }

    if (!matchedAlias) continue;

    const compact = (value) =>
      String(value || '')
        .toLowerCase()
        .replace(/[\s\p{P}_-]+/gu, '');
    const compactAlias = compact(matchedAlias);
    const compactText = compact(text);
    const bareBrandQuery =
      compactText === compactAlias ||
      compactText === `${compactAlias}品牌` ||
      compactText === `${compactAlias}brand` ||
      compactText === `${compactAlias}${compactAlias}`;
    if (!availabilityHint && !bareBrandQuery) continue;

    const brandName = lang === 'CN' ? brand?.name?.CN || '' : brand?.name?.EN || '';
    return {
      intent: 'availability',
      brand_id: brand.brand_id,
      brand_name: brandName || String(matchedAlias || '').trim(),
      matched_alias: matchedAlias,
      reason: availabilityHint ? 'availability_hint' : 'bare_brand_query',
    };
  }

  return null;
}

function detectCatalogAvailabilityIntent(message, lang) {
  const knownBrandIntent = detectBrandAvailabilityIntent(message, lang);
  if (knownBrandIntent) return knownBrandIntent;

  const raw = String(message || '').trim();
  if (!raw) return null;

  if (looksLikeDiagnosisStart(raw)) return null;
  if (looksLikeSuitabilityRequest(raw)) return null;
  if (looksLikeRecommendationRequest(raw)) return null;
  if (looksLikeRoutineRequest(raw, null)) return null;
  if (looksLikeCompatibilityOrConflictQuestion(raw)) return null;
  if (looksLikeWeatherOrEnvironmentQuestion(raw)) return null;

  if (!messageHasAvailabilityHint(raw)) return null;

  const availabilityQuery = buildAvailabilityCatalogQuery(raw, null);
  const genericTarget = stripGenericAvailabilityTokens(availabilityQuery);
  const compactTarget = genericTarget.toLowerCase().replace(/[\s\p{P}_-]+/gu, '');
  if (!compactTarget || compactTarget.length < 3) return null;

  const isLangCn = String(lang || '').toUpperCase() === 'CN';
  const displayName = genericTarget || availabilityQuery || (isLangCn ? '目标商品' : 'Target product');
  return {
    intent: 'availability',
    brand_id: 'brand_generic',
    brand_name: displayName.slice(0, 120),
    matched_alias: '',
    reason: 'availability_hint_generic',
    query_hint: availabilityQuery || displayName,
  };
}

function buildAvailabilityCatalogQuery(message, availabilityIntent) {
  const raw = String(message || '')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/[。！？!?]+$/g, '');
  const brand = String(
    availabilityIntent?.brand_name || availabilityIntent?.matched_alias || availabilityIntent?.brand_id || '',
  ).trim();
  if (!raw) return brand;

  let cleaned = raw
    .replace(/^(请问|请帮我|请|我想问下|我想问|could you|can you|do you|i want to know)\s*/i, '')
    .replace(/\b(in stock|available|availability|where can i buy|where to buy|do you have|have any|buy|purchase|link|have|has)\b/gi, ' ')
    .replace(/(有没有|有无|有吗|有没|有木有|有货|现货|库存|哪里买|怎么买|购买|下单|链接|渠道|官方旗舰|旗舰店|自营|请问)/g, ' ')
    .replace(/[（(]\s*(品牌|brand|official)\s*[）)]/gi, ' ')
    .replace(/\bbrand\b/gi, ' ')
    .replace(/品牌/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/[。！？!?]+$/g, '');

  if (!cleaned) cleaned = raw;
  cleaned = cleaned
    .split(/\s+/)
    .filter((token, idx, arr) => idx === 0 || token.toLowerCase() !== arr[idx - 1].toLowerCase())
    .join(' ')
    .trim();
  cleaned = cleaned.replace(/[吗嘛呢呀]+$/g, '').trim();

  if (brand) {
    const compact = (value) =>
      String(value || '')
        .toLowerCase()
        .replace(/[\s\p{P}_-]+/gu, '');
    const compactBrand = compact(brand);
    const compactCleaned = compact(cleaned);
    if (compactBrand && compactCleaned && compactCleaned === compactBrand.repeat(2)) cleaned = brand;
  }

  if (cleaned.length > 120) cleaned = cleaned.slice(0, 120).trim();

  if (!cleaned) return brand;
  if (brand && cleaned.toLowerCase() === brand.toLowerCase()) return brand;
  return cleaned;
}

function isSpecificAvailabilityQuery(queryText, availabilityIntent) {
  const q = String(queryText || '').trim().toLowerCase();
  if (!q) return false;
  const brandId = String(availabilityIntent?.brand_id || '').trim().toLowerCase();
  const brand = String(
    availabilityIntent?.brand_name || availabilityIntent?.matched_alias || availabilityIntent?.brand_id || '',
  )
    .trim()
    .toLowerCase();
  const compact = (value) =>
    String(value || '')
      .toLowerCase()
      .replace(/[\s\p{P}_-]+/gu, '');

  if (brandId === 'brand_generic') {
    const genericOnly = compact(
      q
        .replace(
          /(有没有|有无|有吗|有没|有木有|请问|产品|商品|有货|现货|库存|哪里买|怎么买|购买|下单|链接|渠道|官方|旗舰|自营|店|products?|items?|catalog|store|shop|buy|available|availability|in\s*stock)/gi,
          ' ',
        )
        .replace(/\b(do you have|have any|where can i buy|where to buy)\b/gi, ' '),
    );
    if (!genericOnly) return false;
    const tokenCount = String(q)
      .split(/\s+/)
      .map((t) => t.trim())
      .filter(Boolean).length;
    // For generic-intent routing, keep multi-token/product-pattern queries on the specific path.
    if (/[0-9%+]/.test(q) && genericOnly.length >= 5) return true;
    if (tokenCount >= 3 && genericOnly.length >= 8) return true;
    return genericOnly.length >= 12;
  }

  if (!brand) return compact(q).length >= 8;
  const qCompact = compact(q);
  const brandCompact = compact(brand);
  if (!qCompact || !brandCompact) return false;
  if (qCompact === brandCompact) return false;

  const genericOnly = compact(
    q
      .replace(
        /(有没有|有无|有吗|有没|有木有|请问|产品|商品|有货|现货|库存|哪里买|怎么买|购买|下单|链接|渠道|官方|旗舰|自营|店|products?|items?|catalog|store|shop|buy|available|availability|in\s*stock)/gi,
        ' ',
      )
      .replace(/\b(do you have|have any|where can i buy|where to buy)\b/gi, ' '),
  );
  if (!genericOnly) return false;
  if (genericOnly === brandCompact) return false;
  return genericOnly.length > brandCompact.length + 2;
}

function isSkincareCatalogProduct(product) {
  const p = product && typeof product === 'object' ? product : {};
  const joined = [
    p.category,
    p.category_name,
    p.category_path,
    p.name,
    p.display_name,
    p.title,
    p.product_type,
    p.type,
    p.tags,
  ]
    .flatMap((value) => (Array.isArray(value) ? value : [value]))
    .map((value) => String(value || '').toLowerCase())
    .join(' ');
  if (!joined.trim()) return true;
  const skincareHit = /(skincare|cleanser|serum|essence|moistur|cream|toner|mask|sunscreen|spf|lotion|barrier|niacinamide|retinol|retinoid|vitamin c|azelaic|ceramide|hyaluronic|acne|护肤|洁面|精华|面霜|乳液|爽肤水|面膜|防晒|修护|烟酰胺|视黄醇|壬二酸|神经酰胺|玻尿酸|祛痘)/.test(
    joined,
  );
  const poisonHit = /(brush|blush|foundation brush|makeup brush|eyeshadow|lipstick|mascara|化妆刷|腮红刷|彩妆刷)/.test(joined);
  if (poisonHit) return false;
  return skincareHit;
}

function isSkincareCatalogCard(card) {
  if (!card || typeof card !== 'object' || Array.isArray(card)) return true;
  const type = String(card.type || '').trim().toLowerCase();
  if (type === 'product_parse') {
    const payload = card.payload && typeof card.payload === 'object' && !Array.isArray(card.payload)
      ? card.payload
      : {};
    const product = payload.product && typeof payload.product === 'object' ? payload.product : null;
    return isSkincareCatalogProduct(product);
  }
  if (type === 'offers_resolved') {
    const payload = card.payload && typeof card.payload === 'object' && !Array.isArray(card.payload)
      ? card.payload
      : {};
    const items = Array.isArray(payload.items) ? payload.items : [];
    if (!items.length) return true;
    return items.every((item) => {
      const product = item && typeof item === 'object' && item.product && typeof item.product === 'object'
        ? item.product
        : null;
      return isSkincareCatalogProduct(product);
    });
  }
  return true;
}

function buildAvailabilityResolvedProduct({
  resolvedRef,
  resolveBody,
  fallbackQuery = '',
  fallbackBrand = '',
} = {}) {
  const normalizedRef = normalizeCanonicalProductRef(resolvedRef, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (!normalizedRef) return null;

  const firstCandidate =
    Array.isArray(resolveBody?.candidates) &&
    resolveBody.candidates.length &&
    resolveBody.candidates[0] &&
    typeof resolveBody.candidates[0] === 'object'
      ? resolveBody.candidates[0]
      : null;
  const normalizedCandidate = normalizeRecoCatalogProduct(firstCandidate);
  const queryFallbackName = String(fallbackQuery || '').trim();
  const safeQueryFallbackName = (() => {
    const token = normalizeProductCatalogQuery(queryFallbackName);
    if (!token) return '';
    if (/^https?:\/\//i.test(queryFallbackName)) return '';
    if (token.split(/\s+/).length > 8) return '';
    return queryFallbackName;
  })();
  const displayName = pickFirstTrimmed(
    normalizedCandidate?.display_name,
    normalizedCandidate?.name,
    firstCandidate?.title,
    firstCandidate?.name,
    safeQueryFallbackName,
  );
  const name = pickFirstTrimmed(normalizedCandidate?.name, firstCandidate?.title, safeQueryFallbackName, displayName);
  const brand = pickFirstTrimmed(
    normalizedCandidate?.brand,
    firstCandidate?.vendor,
    firstCandidate?.brand,
    fallbackBrand,
  );
  const imageUrl = pickFirstTrimmed(
    normalizedCandidate?.image_url,
    firstCandidate?.image_url,
    firstCandidate?.thumbnail_url,
  );
  return {
    ...(normalizedCandidate && typeof normalizedCandidate === 'object' ? normalizedCandidate : {}),
    product_id: normalizedRef.product_id,
    merchant_id: normalizedRef.merchant_id,
    canonical_product_ref: normalizedRef,
    ...(brand ? { brand } : {}),
    ...(name ? { name } : {}),
    ...(displayName ? { display_name: displayName } : {}),
    ...(imageUrl ? { image_url: imageUrl } : {}),
  };
}

async function resolveAvailabilityProductByQuery({
  query,
  lang = 'en',
  hints = null,
  logger,
  timeoutMs = CATALOG_AVAIL_RESOLVE_TIMEOUT_MS,
} = {}) {
  const q = String(query || '').trim();
  if (!q) return { ok: false, reason: 'query_missing', product: null, resolve_reason_code: 'no_candidates', latency_ms: 0 };
  if (!PIVOTA_BACKEND_BASE_URL) {
    return { ok: false, reason: 'pivota_backend_not_configured', product: null, resolve_reason_code: 'db_error', latency_ms: 0 };
  }

  const startedAt = Date.now();
  const resolveTimeoutMs = Math.max(
    250,
    Math.min(
      CATALOG_AVAIL_RESOLVE_TIMEOUT_MS,
      Number.isFinite(Number(timeoutMs)) ? Math.trunc(Number(timeoutMs)) : CATALOG_AVAIL_RESOLVE_TIMEOUT_MS,
    ),
  );
  const url = `${PIVOTA_BACKEND_BASE_URL}/agent/v1/products/resolve`;
  const payload = {
    query: q,
    lang: String(lang || 'en').toLowerCase() === 'cn' ? 'zh' : 'en',
    options: {
      search_all_merchants: true,
      timeout_ms: resolveTimeoutMs,
      upstream_retries: 0,
      stable_alias_short_circuit: true,
      allow_stable_alias_for_uuid: true,
    },
    ...(hints && typeof hints === 'object' && !Array.isArray(hints) ? { hints } : {}),
    caller: 'aurora_chatbox',
  };

  let resp = null;
  let err = null;
  try {
    resp = await axios.post(url, payload, {
      headers: buildPivotaBackendAgentHeaders(),
      timeout: resolveTimeoutMs,
      validateStatus: () => true,
    });
  } catch (e) {
    err = e;
  }

  const body = resp && typeof resp.data === 'object' ? resp.data : null;
  const statusCode = Number.isFinite(Number(resp?.status)) ? Math.trunc(Number(resp.status)) : 0;
  const resolvedRef = normalizeCanonicalProductRef(body?.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (statusCode === 200 && body?.resolved === true && resolvedRef) {
    const product = buildAvailabilityResolvedProduct({
      resolvedRef,
      resolveBody: body,
      fallbackQuery: q,
      fallbackBrand: hints && typeof hints === 'object' ? hints.brand : '',
    });
    return {
      ok: true,
      reason: null,
      product,
      resolve_reason_code: null,
      status_code: statusCode,
      latency_ms: Date.now() - startedAt,
    };
  }

  const reasonCode = mapResolveFailureCode({
    resolveBody: body,
    statusCode,
    error: err,
  });
  const localResolveUrl = `${String(RECO_PDP_LOCAL_INVOKE_BASE_URL || '').replace(/\/+$/, '')}/agent/v1/products/resolve`;
  const shouldAttemptLocalResolveFallback =
    RECO_PDP_LOCAL_INVOKE_FALLBACK_CHAT_ENABLED &&
    RECO_PDP_LOCAL_INVOKE_FALLBACK_ENABLED &&
    localResolveUrl &&
    localResolveUrl !== url &&
    shouldAttemptLocalRecoFallback(reasonCode, err);
  let finalReasonCode = reasonCode;
  if (shouldAttemptLocalResolveFallback) {
    let localResp = null;
    let localErr = null;
    try {
      localResp = await axios.post(localResolveUrl, payload, {
        headers: { 'Content-Type': 'application/json' },
        timeout: Math.max(250, Math.min(RECO_PDP_LOCAL_INVOKE_TIMEOUT_MS, resolveTimeoutMs)),
        validateStatus: () => true,
      });
    } catch (e) {
      localErr = e;
    }

    const localBody = localResp && typeof localResp.data === 'object' ? localResp.data : null;
    const localStatusCode = Number.isFinite(Number(localResp?.status)) ? Math.trunc(Number(localResp.status)) : 0;
    const localResolvedRef = normalizeCanonicalProductRef(localBody?.product_ref, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    });
    if (localStatusCode === 200 && localBody?.resolved === true && localResolvedRef) {
      return {
        ok: true,
        reason: null,
        product: buildAvailabilityResolvedProduct({
          resolvedRef: localResolvedRef,
          resolveBody: localBody,
          fallbackQuery: q,
          fallbackBrand: hints && typeof hints === 'object' ? hints.brand : '',
        }),
        resolve_reason_code: null,
        status_code: localStatusCode,
        latency_ms: Date.now() - startedAt,
      };
    }
    const localReasonCode = mapResolveFailureCode({
      resolveBody: localBody,
      statusCode: localStatusCode,
      error: localErr,
    });
    if (
      (finalReasonCode === 'no_candidates' || finalReasonCode === 'upstream_timeout') &&
      localReasonCode &&
      localReasonCode !== 'no_candidates'
    ) {
      finalReasonCode = localReasonCode;
    }
    if (localErr || localReasonCode !== 'no_candidates') {
      logger?.warn(
        {
          query: q.slice(0, 120),
          primary_status_code: statusCode || null,
          primary_resolve_reason_code: reasonCode,
          local_status_code: localStatusCode || null,
          local_resolve_reason_code: localReasonCode,
          local_err: localErr ? localErr.message || String(localErr) : null,
        },
        'aurora bff: availability local resolve fallback unresolved',
      );
    }
  }
  if (err || reasonCode !== 'no_candidates') {
    logger?.warn(
      {
        query: q.slice(0, 120),
        status_code: statusCode || null,
        resolve_reason_code: finalReasonCode,
        err: err ? err.message || String(err) : null,
      },
      'aurora bff: availability resolve fallback failed',
    );
  }
  return {
    ok: false,
    reason: 'unresolved',
    product: null,
    resolve_reason_code: finalReasonCode,
    status_code: statusCode || null,
    latency_ms: Date.now() - startedAt,
  };
}

async function resolveAvailabilityProductByLocalResolver({
  query,
  lang = 'en',
  hints = null,
  logger,
  timeoutMs = CATALOG_AVAIL_RESOLVE_TIMEOUT_MS,
} = {}) {
  const q = String(query || '').trim();
  if (!q) return { ok: false, reason: 'query_missing', product: null, resolve_reason_code: 'no_candidates', latency_ms: 0 };
  if (typeof resolveProductRefDirectImpl !== 'function') {
    return { ok: false, reason: 'local_resolver_unavailable', product: null, resolve_reason_code: 'db_error', latency_ms: 0 };
  }

  const startedAt = Date.now();
  const resolveTimeoutMs = Math.max(
    250,
    Math.min(
      CATALOG_AVAIL_RESOLVE_TIMEOUT_MS,
      Number.isFinite(Number(timeoutMs)) ? Math.trunc(Number(timeoutMs)) : CATALOG_AVAIL_RESOLVE_TIMEOUT_MS,
    ),
  );

  let responseBody = null;
  let responseError = null;
  try {
    responseBody = await resolveProductRefDirectImpl({
      query: q,
      lang: String(lang || 'en').toLowerCase() === 'cn' ? 'cn' : 'en',
      ...(hints && typeof hints === 'object' && !Array.isArray(hints) ? { hints } : {}),
      options: {
        search_all_merchants: true,
        timeout_ms: resolveTimeoutMs,
        upstream_retries: 0,
        stable_alias_short_circuit: true,
        allow_stable_alias_for_uuid: true,
      },
      caller: 'aurora_chatbox',
    });
  } catch (err) {
    responseError = err;
  }

  const resolvedRef = normalizeCanonicalProductRef(responseBody?.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (responseBody?.resolved === true && resolvedRef) {
    return {
      ok: true,
      reason: null,
      product: buildAvailabilityResolvedProduct({
        resolvedRef,
        resolveBody: responseBody,
        fallbackQuery: q,
        fallbackBrand: hints && typeof hints === 'object' ? hints.brand : '',
      }),
      resolve_reason_code: null,
      status_code: null,
      latency_ms: Date.now() - startedAt,
    };
  }

  const reasonCode = mapResolveFailureCode({
    resolveBody: responseBody,
    statusCode: null,
    error: responseError,
  });
  if (responseError || reasonCode !== 'no_candidates') {
    logger?.warn(
      {
        query: q.slice(0, 120),
        resolve_reason_code: reasonCode,
        err: responseError ? responseError.message || String(responseError) : null,
      },
      'aurora bff: availability local resolver failed',
    );
  }
  return {
    ok: false,
    reason: 'unresolved',
    product: null,
    resolve_reason_code: reasonCode,
    status_code: null,
    latency_ms: Date.now() - startedAt,
  };
}

function buildBrandPlaceholderProduct({ brandId, brandName, lang } = {}) {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const brand = String(brandName || '').trim() || (isCn ? '未知品牌' : 'Unknown brand');
  const skuId = String(brandId || '').trim() || `brand_${stableHashBase36(brand).slice(0, 10)}`;
  const name = isCn ? `${brand}（品牌）` : `${brand} (brand)`;
  return {
    product_id: `brand:${skuId}`,
    sku_id: skuId,
    brand,
    name,
    display_name: name,
    image_url: '',
    category: isCn ? '品牌' : 'Brand',
  };
}

function normalizeProductCatalogQuery(raw) {
  let s = String(raw || '').trim();
  if (!s) return '';
  try {
    s = decodeURIComponent(s);
  } catch {
    // ignore malformed URI fragments
  }
  s = s
    .replace(/\+/g, ' ')
    .replace(/[_]+/g, ' ')
    .replace(/[|]+/g, ' ')
    .replace(/\.(html?|php|aspx?)$/i, ' ')
    .replace(/\b(en|cn|zh|us|uk|jp|kr|fr|de|es|pt|it|ca|au)\b/gi, ' ')
    .replace(/\b(product|products|item|items)\b/gi, ' ')
    .replace(/[-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (s.length > 160) s = s.slice(0, 160).trim();
  return s;
}

function extractProductCatalogQueryFromUrl(rawUrl) {
  const urlText = String(rawUrl || '').trim();
  if (!urlText) return null;
  let parsed = null;
  try {
    parsed = new URL(urlText);
  } catch {
    return null;
  }

  const hostLabels = String(parsed.hostname || '')
    .trim()
    .toLowerCase()
    .replace(/^www\./, '')
    .split('.')
    .map((x) => x.trim())
    .filter(Boolean);
  const hostStop = new Set(['com', 'net', 'org', 'co', 'io', 'ai', 'shop', 'store', 'www', 'cn', 'cc', 'us', 'uk']);
  const hostToken = normalizeProductCatalogQuery(hostLabels.filter((x) => !hostStop.has(x)).join(' '));

  const pathTokens = String(parsed.pathname || '')
    .split('/')
    .map((x) => normalizeProductCatalogQuery(x))
    .filter(Boolean);
  const tailToken = normalizeProductCatalogQuery(pathTokens.slice(-2).join(' '));

  const queryToken = normalizeProductCatalogQuery(
    parsed.searchParams.get('product') ||
      parsed.searchParams.get('name') ||
      parsed.searchParams.get('title') ||
      parsed.searchParams.get('sku') ||
      '',
  );

  return {
    raw_url: urlText,
    host_token: hostToken,
    tail_token: tailToken,
    query_token: queryToken,
  };
}

function buildProductCatalogQueryCandidates({ inputText, inputUrl, parsedProduct } = {}) {
  const out = [];
  const seen = new Set();
  const add = (value, { normalize = true } = {}) => {
    let s = String(value || '').trim();
    if (!s) return;
    if (normalize) s = normalizeProductCatalogQuery(s);
    if (!s) return;
    const key = s.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    out.push(s);
  };

  const productObj = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  if (productObj) {
    add(joinBrandAndName(productObj.brand, productObj.name || productObj.display_name || productObj.displayName || ''));
    add(productObj.display_name || productObj.displayName || productObj.name || '');
    add(productObj.sku_id || productObj.product_id || '');
  }

  const urlCandidate =
    String(inputUrl || '').trim() ||
    (/^https?:\/\//i.test(String(inputText || '').trim()) ? String(inputText || '').trim() : '');
  const fromUrl = extractProductCatalogQueryFromUrl(urlCandidate);
  if (fromUrl) {
    add(fromUrl.raw_url, { normalize: false });
    if (fromUrl.host_token && fromUrl.tail_token) add(`${fromUrl.host_token} ${fromUrl.tail_token}`);
    add(fromUrl.tail_token);
    add(fromUrl.query_token);
    add(fromUrl.host_token);
  }

  add(inputText);

  return out.slice(0, Math.max(1, PRODUCT_INTEL_CATALOG_FALLBACK_MAX_QUERIES));
}

function buildActiveIntentRecallQuery({ keyIngredients = [], parsedProduct = null, categoryToken = '' } = {}) {
  const normalizedCategory = normalizeProductCatalogQuery(categoryToken);
  const productObj = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  const ingredientText = Array.isArray(keyIngredients) ? keyIngredients.join(' | ') : '';
  const text = `${ingredientText} ${String(productObj?.name || '')} ${String(productObj?.display_name || '')}`.toLowerCase();
  if (!text.trim()) return '';

  let keyword = '';
  if (/\bcopper\b/.test(text) && /\b(peptide|tripeptide|tetrapeptide|hexapeptide|pentapeptide)\b/.test(text)) keyword = 'copper peptide';
  else if (/\b(peptide|tripeptide|tetrapeptide|hexapeptide|pentapeptide)\b/.test(text)) keyword = 'peptide';
  else if (/\bretinol|retinal|retinoid|retinoate\b/.test(text)) keyword = 'retinol';
  else if (/\bniacinamide\b/.test(text)) keyword = 'niacinamide';
  else if (/\bsalicylic\b/.test(text)) keyword = 'salicylic acid';
  else if (/\bglycolic\b/.test(text)) keyword = 'glycolic acid';
  else if (/\blactic\b/.test(text)) keyword = 'lactic acid';
  else if (/\bhyaluron|hyaluronic|hyaluronate\b/.test(text)) keyword = 'hyaluronic acid';
  else if (/\bceramide\b/.test(text)) keyword = 'ceramide';

  if (!keyword) return '';
  return normalizeProductCatalogQuery(`${keyword} ${normalizedCategory}`.trim());
}

function buildRealtimeCompetitorQueryPlan({
  fromCatalogQueries = [],
  keyIngredients = [],
  parsedProduct = null,
  categoryToken = '',
  maxQueries = 2,
} = {}) {
  const limit = Math.max(1, Math.min(6, Number.isFinite(Number(maxQueries)) ? Math.trunc(Number(maxQueries)) : 2));
  const productObj = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  const anchorBrand = String(productObj?.brand || '').trim();
  const anchorName = String(productObj?.name || productObj?.display_name || '').trim();
  const nameWithoutBrand = (() => {
    if (!anchorName) return '';
    if (!anchorBrand) return anchorName;
    const escaped = escapeRegExp(anchorBrand);
    const removed = anchorName.replace(new RegExp(`^${escaped}\\s+`, 'i'), '').trim();
    return removed || anchorName;
  })();
  const activeIntentQuery = buildActiveIntentRecallQuery({
    keyIngredients,
    parsedProduct: productObj,
    categoryToken,
  });
  const ingredientQuery = normalizeProductCatalogQuery(
    `${(Array.isArray(keyIngredients) ? keyIngredients : []).slice(0, 2).join(' ')} ${categoryToken}`.trim(),
  );
  const categoryOnlyQuery = normalizeProductCatalogQuery(categoryToken);
  const genericNameQuery = normalizeProductCatalogQuery(nameWithoutBrand);

  const specific = [];
  const diversified = [];
  const pushUnique = (list, value) => {
    const q = normalizeProductCatalogQuery(value);
    if (!q || /^https?:\/\//i.test(q)) return;
    if (list.includes(q)) return;
    list.push(q);
  };

  for (const query of Array.isArray(fromCatalogQueries) ? fromCatalogQueries : []) {
    pushUnique(specific, query);
  }
  pushUnique(diversified, activeIntentQuery);
  pushUnique(diversified, ingredientQuery);
  pushUnique(diversified, categoryOnlyQuery);
  pushUnique(diversified, genericNameQuery);

  const out = [];
  const seen = new Set();
  const add = (value) => {
    const q = normalizeProductCatalogQuery(value);
    if (!q || /^https?:\/\//i.test(q)) return;
    const key = q.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    out.push(q);
  };

  if (specific.length) add(specific[0]);
  if (diversified.length) add(diversified[0]);
  for (const q of diversified.slice(1)) {
    if (out.length >= limit) break;
    add(q);
  }
  for (const q of specific.slice(1)) {
    if (out.length >= limit) break;
    add(q);
  }

  return out.slice(0, limit);
}

function hasAnchorCategorySignals(candidate) {
  const row = candidate && typeof candidate === 'object' && !Array.isArray(candidate) ? candidate : {};
  return [
    row.category,
    row.category_name,
    row.category_path,
    row.product_type,
    row.type,
    row.tags,
  ]
    .flatMap((value) => (Array.isArray(value) ? value : [value]))
    .map((value) => String(value || '').trim())
    .some(Boolean);
}

function evaluateAnchorProductSkincareGuard(candidate, { strictFilter = AURORA_PRODUCT_STRICT_SKINCARE_FILTER } = {}) {
  const normalized =
    normalizeRecoCatalogProduct(candidate) ||
    (candidate && typeof candidate === 'object' && !Array.isArray(candidate) ? candidate : null);
  if (!normalized || typeof normalized !== 'object') {
    return { ok: false, reason: 'invalid_candidate', candidate: null };
  }
  const blacklistHit = isBlacklistedCategoryOrTitle(normalized);
  const categorySignals = hasAnchorCategorySignals(normalized);
  const categoryMismatch = categorySignals && !isSkincareCategory(normalized) && !isSkincareCatalogProduct(normalized);
  if (blacklistHit || categoryMismatch) {
    const reason = blacklistHit ? 'non_skincare_blacklist' : 'non_skincare_category';
    if (strictFilter) return { ok: false, reason, candidate: normalized, low_relevance: false };
    return { ok: true, reason: 'non_skincare_soft', candidate: normalized, low_relevance: true };
  }
  return { ok: true, reason: null, candidate: normalized, low_relevance: false };
}

function sanitizeAnchorProductForProductIntel(candidate, { strictFilter = AURORA_PRODUCT_STRICT_SKINCARE_FILTER } = {}) {
  const row = candidate && typeof candidate === 'object' && !Array.isArray(candidate) ? candidate : null;
  if (!row) return { product: null, filtered: false, reason: null };
  const guard = evaluateAnchorProductSkincareGuard(row, { strictFilter });
  if (guard.ok) return { product: row, filtered: false, reason: null };
  if (guard.reason === 'non_skincare_blacklist' || guard.reason === 'non_skincare_category') {
    return { product: null, filtered: true, reason: guard.reason };
  }
  return { product: row, filtered: false, reason: null };
}

function normalizeAnchorCompareText(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9\u4e00-\u9fff]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenizeAnchorCompareText(value) {
  const normalized = normalizeAnchorCompareText(value);
  if (!normalized) return [];
  return uniqCaseInsensitiveStrings(
    normalized
      .split(/\s+/)
      .map((item) => String(item || '').trim())
      .filter((item) => item.length >= 2),
    32,
  );
}

function computeAnchorNameSimilarity({ inputText = '', candidate = null } = {}) {
  const inputTokens = tokenizeAnchorCompareText(inputText);
  if (!inputTokens.length) return { score: 0, overlap: 0, total: 0 };
  const row =
    normalizeRecoCatalogProduct(candidate) ||
    (candidate && typeof candidate === 'object' && !Array.isArray(candidate) ? candidate : null);
  const candidateTokens = new Set(
    tokenizeAnchorCompareText(
      [
        pickFirstTrimmed(row?.brand, row?.brand_name, row?.brandName),
        pickFirstTrimmed(row?.name, row?.display_name, row?.displayName, row?.title),
        pickFirstTrimmed(row?.display_name, row?.displayName),
      ]
        .filter(Boolean)
        .join(' '),
    ),
  );
  const overlap = inputTokens.filter((token) => candidateTokens.has(token)).length;
  const score = inputTokens.length ? Number((overlap / inputTokens.length).toFixed(3)) : 0;
  return { score, overlap, total: inputTokens.length };
}

function extractUrlAnchorSignals(inputUrl) {
  const urlText = String(inputUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) return null;
  try {
    const parsed = new URL(urlText);
    const hostBrand = inferBrandFromHostname(parsed.hostname || '');
    const pathSegments = String(parsed.pathname || '')
      .split('/')
      .map((segment) => decodeUrlTokenSafe(segment).replace(/\.[a-z0-9]{1,5}$/i, '').trim())
      .filter(Boolean);
    let pathToken = '';
    for (let idx = pathSegments.length - 1; idx >= 0; idx -= 1) {
      const segment = String(pathSegments[idx] || '').trim();
      if (!segment) continue;
      if (/^[a-z]{2}(?:-[a-z]{2})?$/i.test(segment)) continue;
      if (/^(products?|collections?|shop|store|sku|item|p)$/i.test(segment.toLowerCase())) continue;
      pathToken = segment;
      break;
    }
    const slugName = pathToken
      ? String(pathToken)
        .replace(/[-_]+/g, ' ')
        .replace(/\s+/g, ' ')
        .trim()
      : '';
    return {
      url: parsed.toString(),
      host_brand: hostBrand,
      slug_name: slugName,
    };
  } catch {
    return null;
  }
}

function normalizeAnchorCandidateForTrust(candidate) {
  return (
    coerceRecoCandidateForGuardrail(candidate) ||
    normalizeRecoCatalogProduct(candidate) ||
    (candidate && typeof candidate === 'object' && !Array.isArray(candidate) ? candidate : null)
  );
}

function buildAnchorDisplayFromCandidate(candidate, { fallbackName = '', fallbackUrl = '' } = {}) {
  const row = normalizeAnchorCandidateForTrust(candidate);
  if (!row || typeof row !== 'object') return null;
  const brand = pickFirstTrimmed(row.brand, row.brand_name, row.brandName);
  const name = pickFirstTrimmed(row.name, row.display_name, row.displayName, row.title, fallbackName);
  const displayName = pickFirstTrimmed(row.display_name, row.displayName, joinBrandAndName(brand, name), name);
  const directUrl = pickFirstTrimmed(
    row.url,
    row.pdp_url,
    row.pdpUrl,
    row.product_url,
    row.productUrl,
    fallbackUrl,
  );
  if (!brand && !name && !displayName && !directUrl) return null;
  return {
    ...(pickFirstTrimmed(row.product_id, row.productId) ? { product_id: pickFirstTrimmed(row.product_id, row.productId) } : {}),
    ...(pickFirstTrimmed(row.sku_id, row.skuId) ? { sku_id: pickFirstTrimmed(row.sku_id, row.skuId) } : {}),
    ...(brand ? { brand } : {}),
    ...(name ? { name } : {}),
    ...(displayName ? { display_name: displayName } : {}),
    ...(directUrl ? { url: directUrl } : {}),
    ...(pickFirstTrimmed(row.image_url, row.imageUrl) ? { image_url: pickFirstTrimmed(row.image_url, row.imageUrl) } : {}),
    ...(pickFirstTrimmed(row.product_group_id, row.productGroupId) ? { product_group_id: pickFirstTrimmed(row.product_group_id, row.productGroupId) } : {}),
    ...(pickFirstTrimmed(row.merchant_id, row.merchantId) ? { merchant_id: pickFirstTrimmed(row.merchant_id, row.merchantId) } : {}),
    ...(row.canonical_product_ref ? { canonical_product_ref: row.canonical_product_ref } : {}),
    category: 'product',
  };
}

function evaluateAnchorTrustForProductIntel({
  candidate = null,
  inputText = '',
  inputUrl = '',
  source = 'unknown',
  strictFilter = AURORA_PRODUCT_STRICT_SKINCARE_FILTER,
  policy = PRODUCT_INTEL_URL_ANCHOR_TRUST_POLICY,
} = {}) {
  const row = normalizeAnchorCandidateForTrust(candidate);
  if (!row || typeof row !== 'object') {
    return {
      trusted_anchor: null,
      display_anchor: null,
      usable_for_anchor_id: false,
      trust_level: 'none',
      reason_codes: ['anchor_soft_blocked_ambiguous'],
      source: String(source || 'unknown'),
      candidate_quality: 'none',
      url_consistency: null,
    };
  }

  const displayAnchor = buildAnchorDisplayFromCandidate(row, {
    fallbackName: String(inputText || '').trim(),
    fallbackUrl: String(inputUrl || '').trim(),
  });
  const guard = evaluateAnchorProductSkincareGuard(row, { strictFilter });
  const hasId = Boolean(pickFirstTrimmed(row.product_id, row.productId, row.sku_id, row.skuId));
  const hasBrand = Boolean(pickFirstTrimmed(row.brand, row.brand_name, row.brandName));
  const hasName = Boolean(pickFirstTrimmed(row.name, row.display_name, row.displayName, row.title));
  const hasCategory = hasAnchorCategorySignals(row);
  const qualityScore = (hasId ? 0.4 : 0) + (hasBrand ? 0.2 : 0) + (hasName ? 0.2 : 0) + (hasCategory ? 0.2 : 0);
  const candidateQuality = qualityScore >= 0.75 ? 'strong' : qualityScore >= 0.45 ? 'medium' : 'weak';

  const urlSignals = extractUrlAnchorSignals(inputUrl);
  let urlConsistency = null;
  if (urlSignals) {
    const hostBrandToken = normalizeAnchorCompareText(urlSignals.host_brand);
    const anchorBrandToken = normalizeAnchorCompareText(pickFirstTrimmed(row.brand, row.brand_name, row.brandName));
    const anchorNameTokens = new Set(
      tokenizeAnchorCompareText(
        pickFirstTrimmed(row.name, row.display_name, row.displayName, row.title, String(inputText || '').trim()),
      ),
    );
    const slugTokens = tokenizeAnchorCompareText(urlSignals.slug_name);
    const slugOverlap = slugTokens.filter((token) => anchorNameTokens.has(token)).length;
    let score = 0.5;
    if (hostBrandToken && anchorBrandToken) {
      score += hostBrandToken === anchorBrandToken ? 0.25 : -0.35;
    }
    if (slugTokens.length) {
      score += slugOverlap > 0 ? 0.25 : -0.25;
    }
    urlConsistency = Number(Math.max(0, Math.min(1, score)).toFixed(3));
  }

  const reasonCodes = [];
  if (
    guard.low_relevance === true ||
    guard.reason === 'non_skincare_soft' ||
    (!guard.ok && (guard.reason === 'non_skincare_blacklist' || guard.reason === 'non_skincare_category'))
  ) {
    reasonCodes.push('anchor_soft_blocked_non_skincare');
  }
  if (urlConsistency != null && urlConsistency < 0.35) {
    reasonCodes.push('anchor_soft_blocked_url_mismatch');
  }
  if (!hasId || candidateQuality === 'weak') {
    reasonCodes.push('anchor_soft_blocked_ambiguous');
  }

  let usableForAnchorId = guard.ok && hasId && reasonCodes.length === 0;
  if (!PRODUCT_INTEL_URL_ANCHOR_TRUST_GUARD_ENABLED) {
    usableForAnchorId = Boolean(hasId);
  }
  if (
    String(policy || '').trim().toLowerCase() === 'hard' &&
    reasonCodes.length &&
    !AURORA_RULE_RELAX_AGGRESSIVE &&
    !AURORA_PRODUCT_GUARDRAIL_TELEMETRY_ONLY
  ) {
    return {
      trusted_anchor: null,
      display_anchor: null,
      usable_for_anchor_id: false,
      trust_level: 'none',
      reason_codes: uniqCaseInsensitiveStrings(reasonCodes, 6),
      source: String(source || 'unknown'),
      candidate_quality: candidateQuality,
      ...(urlConsistency != null ? { url_consistency: urlConsistency } : {}),
    };
  }

  return {
    trusted_anchor: usableForAnchorId ? displayAnchor : null,
    display_anchor: displayAnchor || null,
    usable_for_anchor_id: Boolean(usableForAnchorId),
    trust_level: usableForAnchorId ? 'trusted' : 'soft_blocked',
    reason_codes: uniqCaseInsensitiveStrings(reasonCodes, 6),
    source: String(source || 'unknown'),
    candidate_quality: candidateQuality,
    ...(urlConsistency != null ? { url_consistency: urlConsistency } : {}),
  };
}

function mapCatalogProductToAnchorProduct(rawProduct, { fallbackName = '' } = {}) {
  const normalized = normalizeAnchorCandidateForTrust(rawProduct);
  if (!normalized || typeof normalized !== 'object') return null;
  const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
  if (!productId) return null;
  const brand = pickFirstTrimmed(normalized.brand);
  const name = pickFirstTrimmed(normalized.name, normalized.display_name, fallbackName);
  const displayName = pickFirstTrimmed(normalized.display_name, joinBrandAndName(brand, name), name);
  return {
    product_id: productId,
    ...(normalized.sku_id ? { sku_id: normalized.sku_id } : {}),
    ...(brand ? { brand } : {}),
    ...(name ? { name } : {}),
    ...(displayName ? { display_name: displayName } : {}),
    ...(normalized.image_url ? { image_url: normalized.image_url } : {}),
    ...(normalized.product_group_id ? { product_group_id: normalized.product_group_id } : {}),
    ...(normalized.merchant_id ? { merchant_id: normalized.merchant_id } : {}),
    ...(normalized.canonical_product_ref ? { canonical_product_ref: normalized.canonical_product_ref } : {}),
    category: 'product',
  };
}

async function resolveCatalogProductForProductInput({ inputText, inputUrl, parsedProduct, lang = 'EN', logger } = {}) {
  if (!PRODUCT_INTEL_CATALOG_FALLBACK_ENABLED) {
    return {
      ok: false,
      reason: 'catalog_fallback_disabled',
      source: null,
      query_used: null,
      product: null,
      attempts: [],
    };
  }

  if (!PIVOTA_BACKEND_BASE_URL) {
    return {
      ok: false,
      reason: 'pivota_backend_not_configured',
      source: null,
      query_used: null,
      product: null,
      attempts: [],
    };
  }

  const queries = buildProductCatalogQueryCandidates({ inputText, inputUrl, parsedProduct });
  if (!queries.length) {
    return {
      ok: false,
      reason: 'query_missing',
      source: null,
      query_used: null,
      product: null,
      attempts: [],
    };
  }

  const attempts = [];
  let filteredNonSkincareCount = 0;

  for (const query of queries) {
    const resolved = await resolveAvailabilityProductByQuery({ query, lang, logger });
    const resolvedHasProduct = Boolean(resolved && resolved.ok && resolved.product);
    const guard = resolvedHasProduct
      ? evaluateAnchorProductSkincareGuard(resolved.product, {
        strictFilter: AURORA_PRODUCT_STRICT_SKINCARE_FILTER,
      })
      : null;
    const accepted = Boolean(resolvedHasProduct && guard && guard.ok);
    if (resolvedHasProduct && guard && !guard.ok) filteredNonSkincareCount += 1;
    attempts.push({
      mode: 'resolve',
      query,
      ok: accepted,
      reason:
        accepted
          ? null
          : resolvedHasProduct && guard && guard.reason
            ? `catalog_${String(guard.reason).trim().toLowerCase()}`
            : resolved && resolved.resolve_reason_code
              ? resolved.resolve_reason_code
              : resolved && resolved.reason
                ? resolved.reason
                : null,
      latency_ms: Number.isFinite(Number(resolved?.latency_ms)) ? Math.trunc(Number(resolved?.latency_ms)) : null,
    });
    if (accepted) {
      return {
        ok: true,
        reason: null,
        source: 'resolve',
        query_used: query,
        product: resolved.product,
        attempts,
      };
    }
  }

  for (const query of queries) {
    const searched = await searchPivotaBackendProducts({
      query,
      limit: 3,
      logger,
      timeoutMs: CATALOG_AVAIL_SEARCH_TIMEOUT_MS,
    });
    let first = null;
    if (Array.isArray(searched && searched.products)) {
      for (const candidate of searched.products) {
        if (!candidate || typeof candidate !== 'object') continue;
        if (!String(candidate.product_id || '').trim()) continue;
        const guard = evaluateAnchorProductSkincareGuard(candidate, {
          strictFilter: AURORA_PRODUCT_STRICT_SKINCARE_FILTER,
        });
        if (guard.ok) {
          first = candidate;
          break;
        }
        if (guard.reason === 'non_skincare_blacklist' || guard.reason === 'non_skincare_category') {
          filteredNonSkincareCount += 1;
        }
      }
    }
    attempts.push({
      mode: 'search',
      query,
      ok: Boolean(first),
      reason: first
        ? null
        : filteredNonSkincareCount > 0
          ? 'catalog_non_skincare_match'
          : searched && searched.reason
            ? String(searched.reason)
            : null,
      latency_ms: Number.isFinite(Number(searched?.latency_ms)) ? Math.trunc(Number(searched?.latency_ms)) : null,
    });
    if (first) {
      return {
        ok: true,
        reason: null,
        source: 'search',
        query_used: query,
        product: first,
        attempts,
      };
    }
  }

  return {
    ok: false,
    reason: filteredNonSkincareCount > 0 ? 'catalog_non_skincare_match' : 'catalog_no_match',
    source: null,
    query_used: queries[0] || null,
    product: null,
    attempts,
  };
}

async function resolvePrimaryAnalyzeAnchorForProductInput({ inputText, inputUrl, parsedProduct, lang = 'EN', logger } = {}) {
  const queries = buildProductCatalogQueryCandidates({ inputText, inputUrl, parsedProduct }).slice(0, 2);
  if (!queries.length) {
    return {
      ok: false,
      reason: 'query_missing',
      source: null,
      query_used: null,
      product: null,
      attempts: [],
    };
  }

  const attempts = [];
  let filteredNonSkincareCount = 0;
  for (const query of queries) {
    const resolved = await resolveAvailabilityProductByQuery({ query, lang, logger });
    const resolvedHasProduct = Boolean(resolved && resolved.ok && resolved.product);
    const guard = resolvedHasProduct
      ? evaluateAnchorProductSkincareGuard(resolved.product, {
        strictFilter: AURORA_PRODUCT_STRICT_SKINCARE_FILTER,
      })
      : null;
    const accepted = Boolean(resolvedHasProduct && guard && guard.ok);
    if (resolvedHasProduct && guard && !guard.ok) filteredNonSkincareCount += 1;
    const reasonCode =
      accepted
        ? null
        : resolvedHasProduct && guard && guard.reason
          ? `catalog_${String(guard.reason).trim().toLowerCase()}`
          : resolved && resolved.resolve_reason_code
            ? String(resolved.resolve_reason_code)
            : resolved && resolved.reason
              ? String(resolved.reason)
              : null;
    attempts.push({
      mode: 'resolve',
      query,
      ok: accepted,
      reason: reasonCode,
      latency_ms: Number.isFinite(Number(resolved?.latency_ms)) ? Math.trunc(Number(resolved?.latency_ms)) : null,
    });
    if (accepted) {
      return {
        ok: true,
        reason: null,
        source: 'resolve',
        query_used: query,
        product: resolved.product,
        attempts,
      };
    }
  }

  return {
    ok: false,
    reason:
      filteredNonSkincareCount > 0
        ? 'catalog_non_skincare_match'
        : attempts.length
          ? String(attempts[attempts.length - 1].reason || 'catalog_no_match')
          : 'catalog_no_match',
    source: null,
    query_used: queries[0] || null,
    product: null,
    attempts,
  };
}

function decodeHtmlEntitiesBasic(value) {
  const text = String(value || '');
  if (!text) return '';
  const base = text
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
  return base.replace(/&#(\d+);/g, (_, code) => {
    const n = Number(code);
    if (!Number.isFinite(n) || n <= 0) return _;
    try {
      return String.fromCodePoint(n);
    } catch {
      return _;
    }
  });
}

function stripHtmlToText(value) {
  return decodeHtmlEntitiesBasic(String(value || ''))
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function uniqCaseInsensitiveStrings(items, max = 80) {
  const out = [];
  const seen = new Set();
  for (const raw of Array.isArray(items) ? items : []) {
    const s = String(raw || '').trim();
    if (!s) continue;
    const key = s.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(s);
    if (out.length >= max) break;
  }
  return out;
}

function splitInciList(raw) {
  const text = stripHtmlToText(raw)
    .replace(/\b(ingredients?|inci)\s*[:：]\s*/gi, '')
    .replace(/\s*\|\s*/g, ', ')
    .trim();
  if (!text) return [];
  const rows = text
    .split(/[,;•·]\s*/)
    .map((item) =>
      String(item || '')
        .replace(/\.\s*(overview|discover|build|shop|how to use|can i use|faq)\b[\s\S]*$/i, '')
        .replace(/\s+/g, ' ')
        .trim(),
    )
    .filter((item) => item.length >= 2 && item.length <= 120)
    .filter((item) => !/[?!:]/.test(item))
    .filter((item) => !/\b(overview|discover|regimen|build my regimen|shop now|add to cart|how to use|faq)\b/i.test(item))
    .filter((item) => item.split(/\s+/).length <= 8);
  return canonicalizeIngredientCandidates(rows, { max: 120 });
}

function extractInciListFromHtml(html) {
  const text = String(html || '');
  if (!text) return [];

  const patterns = [
    /data-original-ingredients\s*=\s*"([^"]{40,8000})"/i,
    /data-original-ingredients\s*=\s*'([^']{40,8000})'/i,
    /class="[^"]*ingredients[^"]*"[^>]*>\s*([\s\S]{40,6000}?)\s*<\/p>/i,
    />\s*Ingredients\s*<\/[^>]+>\s*<[^>]*>\s*([\s\S]{40,6000}?)\s*<\/(?:p|div)>/i,
    /"ingredients"\s*:\s*"([^"]{40,8000})"/i,
  ];
  for (const re of patterns) {
    const m = text.match(re);
    const list = splitInciList(m && m[1] ? m[1] : '');
    if (list.length >= 5) return list;
  }
  return [];
}

function extractKeyIngredientsFromHtml(html) {
  const text = String(html || '');
  if (!text) return [];
  const patterns = [
    />\s*Key ingredients\s*<\/[^>]+>\s*<[^>]*class="[^"]*list[^"]*"[^>]*>([\s\S]{10,3000})<\/div>/i,
    /"key_ingredients"\s*:\s*"([^"]{10,3000})"/i,
    /"hero_actives"\s*:\s*\[([^\]]{10,3000})\]/i,
  ];
  for (const re of patterns) {
    const m = text.match(re);
    const list = splitInciList(m && m[1] ? m[1] : '');
    if (list.length) return list.slice(0, 20);
  }
  return [];
}

function extractPageTitleFromHtml(html) {
  const text = String(html || '');
  if (!text) return '';
  const m = text.match(/<title[^>]*>([^<]{3,300})<\/title>/i);
  if (!m || !m[1]) return '';
  return stripHtmlToText(m[1]);
}

function buildProductDescriptorFromInput({
  parsedProduct = null,
  productUrl = '',
} = {}) {
  const parsed = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  const urlText = String(productUrl || '').trim();
  let parsedUrl = null;
  try {
    parsedUrl = urlText ? new URL(urlText) : null;
  } catch {
    parsedUrl = null;
  }
  const pathSegments = parsedUrl
    ? String(parsedUrl.pathname || '')
      .split('/')
      .map((item) => String(item || '').trim())
      .filter(Boolean)
    : [];
  const pathNameCandidate = pathSegments.length ? slugToCandidateProductName(pathSegments[pathSegments.length - 1]) : '';
  const inferredBrand = parsedUrl ? inferBrandFromHostname(parsedUrl.hostname || '') : '';
  const brand = pickFirstTrimmed(parsed?.brand, parsed?.brand_name, parsed?.brandName, inferredBrand);
  const name = pickFirstTrimmed(
    parsed?.name,
    parsed?.display_name,
    parsed?.displayName,
    parsed?.title,
    parsed?.product_name,
    parsed?.productName,
    pathNameCandidate,
  );
  return {
    brand,
    name,
    query: pickFirstTrimmed([brand, name].filter(Boolean).join(' '), name, brand),
  };
}

function extractDailyMedDrugInfoUrl(searchHtml = '', searchUrl = '') {
  const source = String(searchHtml || '');
  if (!source) return '';
  const base = String(searchUrl || '').trim() || 'https://dailymed.nlm.nih.gov/dailymed/search.cfm';
  const re = /href=["']([^"']*\/dailymed\/drugInfo\.cfm\?setid=[^"']+)["']/gi;
  let m = re.exec(source);
  while (m) {
    const href = decodeHtmlEntitiesBasic(m[1] || '').trim();
    if (!href) {
      m = re.exec(source);
      continue;
    }
    try {
      const abs = new URL(href, base);
      if (String(abs.hostname || '').trim().toLowerCase().includes('dailymed.nlm.nih.gov')) {
        return abs.toString();
      }
    } catch {
      // ignore invalid links
    }
    m = re.exec(source);
  }
  return '';
}

function extractDailyMedActiveIngredientsFromHtml(html = '') {
  const source = String(html || '');
  if (!source) return [];
  const text = stripHtmlToText(source);
  if (!text) return [];
  const scope =
    text.match(/active ingredients?([\s\S]{0,2400})(?:inactive ingredients|purpose|uses|warnings|do not use|stop use)/i)?.[1] ||
    text.slice(0, 4200);
  const out = [];
  const re = /([A-Za-z][A-Za-z0-9()\-\/,\s]{1,80}?)\s+(\d{1,2}(?:\.\d+)?)\s*%/gi;
  let m = re.exec(scope);
  while (m) {
    const ingredientName = normalizeInciIngredientName(String(m[1] || '').trim());
    const pct = String(m[2] || '').trim();
    if (!ingredientName || !pct) {
      m = re.exec(scope);
      continue;
    }
    out.push(`${ingredientName} ${pct}%`);
    if (out.length >= 12) break;
    m = re.exec(scope);
  }
  return uniqCaseInsensitiveStrings(out, 12);
}

function buildDailyMedRiskNotes({
  html = '',
  activeIngredients = [],
  lang = 'EN',
} = {}) {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const text = `${stripHtmlToText(html)} | ${Array.isArray(activeIngredients) ? activeIngredients.join(' | ') : ''}`.toLowerCase();
  const out = [];
  if (/\boxybenzone\b/.test(text)) {
    out.push(
      isCn
        ? '监管源显示含 Oxybenzone（氧苯酮），敏感肌或眼周更建议先做耐受测试。'
        : 'Regulatory source indicates Oxybenzone; sensitive users should patch test and avoid close eye area.',
    );
  }
  if (/\boctocrylene\b/.test(text)) {
    out.push(
      isCn
        ? '监管源显示含 Octocrylene，易熏眼人群建议先在眼眶外试用。'
        : 'Regulatory source indicates Octocrylene; users prone to eye stinging should test away from eye contour.',
    );
  }
  out.push(
    isCn
      ? '提醒：不同地区/批次配方可能存在差异，建议再核对你手里实物包装的 INCI。'
      : 'Reminder: formula can vary by market/batch; verify INCI on your actual package before final decisions.',
  );
  return uniqCaseInsensitiveStrings(out, 4);
}

async function fetchDailyMedRegulatorySupplement({
  parsedProduct = null,
  productUrl = '',
  timeoutMs = 3600,
  lang = 'EN',
  logger,
} = {}) {
  const descriptor = buildProductDescriptorFromInput({
    parsedProduct,
    productUrl,
  });
  if (!descriptor.query) return null;

  const searchUrl = `https://dailymed.nlm.nih.gov/dailymed/search.cfm?query=${encodeURIComponent(descriptor.query)}`;
  const searchFetch = await fetchProductHtmlWithFallback({
    productUrl: searchUrl,
    timeoutMs: Math.max(1200, Math.min(5000, Number(timeoutMs) || 3600)),
    allowHostVariant: false,
    logger,
  });
  if (!searchFetch.ok || !searchFetch.html) {
    return {
      ok: false,
      query: descriptor.query,
      search_url: searchUrl,
      reason: String(searchFetch?.failure_code || 'regulatory_search_failed'),
    };
  }
  const drugInfoUrl = extractDailyMedDrugInfoUrl(searchFetch.html, searchUrl);
  if (!drugInfoUrl) {
    return {
      ok: false,
      query: descriptor.query,
      search_url: searchUrl,
      reason: 'regulatory_no_match',
    };
  }

  const detailFetch = await fetchProductHtmlWithFallback({
    productUrl: drugInfoUrl,
    timeoutMs: Math.max(1200, Math.min(5000, Number(timeoutMs) || 3600)),
    allowHostVariant: false,
    logger,
  });
  if (!detailFetch.ok || !detailFetch.html) {
    return {
      ok: false,
      query: descriptor.query,
      search_url: searchUrl,
      source_url: drugInfoUrl,
      reason: String(detailFetch?.failure_code || 'regulatory_detail_failed'),
    };
  }
  const activeIngredients = extractDailyMedActiveIngredientsFromHtml(detailFetch.html);
  if (!activeIngredients.length) {
    return {
      ok: false,
      query: descriptor.query,
      search_url: searchUrl,
      source_url: drugInfoUrl,
      reason: 'regulatory_active_not_found',
    };
  }
  return {
    ok: true,
    query: descriptor.query,
    search_url: searchUrl,
    source_url: drugInfoUrl,
    active_ingredients: activeIngredients,
    risk_notes: buildDailyMedRiskNotes({
      html: detailFetch.html,
      activeIngredients,
      lang,
    }),
    source: {
      type: 'regulatory',
      url: drugInfoUrl,
      label: 'DailyMed',
      confidence: 0.72,
    },
  };
}

function toIncidecoderSlug(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/['’"]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 160);
}

function extractIncidecoderProductUrls(searchHtml = '', baseUrl = 'https://incidecoder.com') {
  const source = String(searchHtml || '');
  if (!source) return [];
  const out = [];
  const seen = new Set();
  const re = /href=["']([^"']*\/products\/[^"']+)["']/gi;
  let m = re.exec(source);
  while (m) {
    const rawHref = decodeHtmlEntitiesBasic(m[1] || '').trim();
    if (!rawHref) {
      m = re.exec(source);
      continue;
    }
    try {
      const abs = new URL(rawHref, baseUrl);
      const host = String(abs.hostname || '').trim().toLowerCase();
      const path = String(abs.pathname || '').trim();
      if (!host.endsWith('incidecoder.com')) {
        m = re.exec(source);
        continue;
      }
      if (!/^\/products\/[a-z0-9-]+$/i.test(path)) {
        m = re.exec(source);
        continue;
      }
      const normalizedUrl = `${abs.origin}${path}`;
      const key = normalizedUrl.toLowerCase();
      if (seen.has(key)) {
        m = re.exec(source);
        continue;
      }
      seen.add(key);
      out.push(normalizedUrl);
      if (out.length >= PRODUCT_INTEL_INCIDECODER_MAX_CANDIDATES) break;
    } catch {
      // ignore malformed links
    }
    m = re.exec(source);
  }
  return out;
}

async function fetchIncidecoderSearchCandidates({ query, timeoutMs = PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS, logger } = {}) {
  const queryText = String(query || '').trim();
  if (!queryText) {
    return {
      ok: false,
      query: '',
      search_url: '',
      product_urls: [],
      reason: 'incidecoder_query_missing',
      fetch_meta: null,
    };
  }
  const searchUrl = `https://incidecoder.com/search?query=${encodeURIComponent(queryText)}`;
  const fetchOut = await fetchProductHtmlWithFallback({
    productUrl: searchUrl,
    timeoutMs: Math.max(1200, Math.min(6000, Number(timeoutMs) || PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS)),
    allowHostVariant: false,
    logger,
  });
  if (!fetchOut.ok || !fetchOut.html) {
    return {
      ok: false,
      query: queryText,
      search_url: searchUrl,
      product_urls: [],
      reason: String(fetchOut?.failure_code || 'incidecoder_search_fetch_failed'),
      fetch_meta: fetchOut,
    };
  }
  const productUrls = extractIncidecoderProductUrls(fetchOut.html, searchUrl);
  return {
    ok: productUrls.length > 0,
    query: queryText,
    search_url: searchUrl,
    product_urls: productUrls,
    reason: productUrls.length ? null : 'incidecoder_no_match',
    fetch_meta: fetchOut,
  };
}

async function fetchIncidecoderProductPage({ productUrl, timeoutMs = PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS, logger } = {}) {
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\/(?:www\.)?incidecoder\.com\/products\/[a-z0-9-]+$/i.test(urlText)) {
    return {
      ok: false,
      url: urlText,
      reason: 'incidecoder_url_invalid',
      fetch_meta: null,
      html: '',
    };
  }
  const fetchOut = await fetchProductHtmlWithFallback({
    productUrl: urlText,
    timeoutMs: Math.max(1200, Math.min(6000, Number(timeoutMs) || PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS)),
    allowHostVariant: false,
    logger,
  });
  return {
    ok: Boolean(fetchOut.ok && fetchOut.html),
    url: urlText,
    reason: fetchOut.ok ? null : String(fetchOut.failure_code || 'incidecoder_detail_fetch_failed'),
    fetch_meta: fetchOut,
    html: fetchOut.ok ? String(fetchOut.html || '') : '',
  };
}

function extractIncidecoderIngredientsFromHtml(html = '') {
  const source = String(html || '');
  if (!source) return [];

  const linkedIngredients = [];
  const linkRe = /\/ingredients\/[a-z0-9-]+["'][^>]*>([^<]{2,120})</gi;
  let linkMatch = linkRe.exec(source);
  while (linkMatch) {
    const token = normalizeInciIngredientName(stripHtmlToText(linkMatch[1] || ''));
    if (token) linkedIngredients.push(token);
    if (linkedIngredients.length >= 160) break;
    linkMatch = linkRe.exec(source);
  }

  const blockCandidates = [];
  const blockPatterns = [
    /Ingredient\s+list[\s\S]{0,1000}?<p[^>]*>([\s\S]{40,12000})<\/p>/i,
    /Ingredients?[\s\S]{0,1000}?<div[^>]*class=["'][^"']*(?:content|ingredients)[^"']*["'][^>]*>([\s\S]{40,12000})<\/div>/i,
    /"ingredient_list"\s*:\s*"([^"]{40,12000})"/i,
    /"ingredients"\s*:\s*\[([^\]]{40,12000})\]/i,
  ];
  for (const re of blockPatterns) {
    const match = source.match(re);
    if (!match || !match[1]) continue;
    const rows = splitInciList(match[1]).map((item) => normalizeInciIngredientName(item)).filter(Boolean);
    blockCandidates.push(...rows);
    if (blockCandidates.length >= 160) break;
  }

  const merged = uniqCaseInsensitiveStrings([...linkedIngredients, ...blockCandidates], 180);
  return merged.slice(0, 140);
}

function tokenizeIncidecoderComparable(text) {
  return uniqCaseInsensitiveStrings(
    String(text || '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, ' ')
      .split(/\s+/)
      .map((token) => token.trim())
      .filter((token) => token.length >= 3),
    80,
  );
}

function scoreIncidecoderMatch({ descriptor = null, pageTitle = '', productUrl = '' } = {}) {
  const d = isPlainObject(descriptor) ? descriptor : {};
  const queryTokens = tokenizeIncidecoderComparable(
    `${pickFirstTrimmed(d.brand)} ${pickFirstTrimmed(d.name)} ${pickFirstTrimmed(d.query)}`,
  );
  const titleTokens = tokenizeIncidecoderComparable(`${pageTitle} ${productUrl}`);
  if (!queryTokens.length || !titleTokens.length) return 0.35;
  const titleSet = new Set(titleTokens);
  const overlap = queryTokens.filter((token) => titleSet.has(token)).length;
  const overlapScore = overlap / Math.max(1, queryTokens.length);
  const brandToken = pickFirstTrimmed(d.brand).toLowerCase();
  const hasBrand = brandToken && String(pageTitle || '').toLowerCase().includes(brandToken);
  const nameToken = pickFirstTrimmed(d.name).toLowerCase();
  const hasName = nameToken && String(pageTitle || '').toLowerCase().includes(nameToken);
  return Math.max(0, Math.min(1, Number((overlapScore + (hasBrand ? 0.2 : 0) + (hasName ? 0.15 : 0)).toFixed(3))));
}

async function fetchIncidecoderIngredientSupplement({
  parsedProduct = null,
  productUrl = '',
  timeoutMs = PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS,
  logger,
} = {}) {
  const descriptor = buildProductDescriptorFromInput({ parsedProduct, productUrl });
  if (!descriptor.query) {
    return {
      ok: false,
      reason: 'incidecoder_query_missing',
      query: '',
      attempts: [],
    };
  }
  const maxBudgetMs = Math.max(1200, Math.min(9000, Number(timeoutMs) || PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS));
  const deadline = Date.now() + maxBudgetMs;
  const remainingBudget = () => Math.max(800, deadline - Date.now());
  const queryCandidates = uniqCaseInsensitiveStrings(
    [
      descriptor.query,
      pickFirstTrimmed(`${descriptor.brand || ''} ${descriptor.name || ''}`),
      descriptor.name,
    ].filter(Boolean),
    3,
  );
  const attempts = [];
  const candidateUrls = [];
  for (const queryText of queryCandidates) {
    if (Date.now() >= deadline) break;
    // eslint-disable-next-line no-await-in-loop
    const searchOut = await fetchIncidecoderSearchCandidates({
      query: queryText,
      timeoutMs: remainingBudget(),
      logger,
    });
    attempts.push({
      stage: 'search',
      query: queryText,
      ok: Boolean(searchOut.ok),
      reason: searchOut.reason || null,
      status: Number.isFinite(Number(searchOut?.fetch_meta?.status)) ? Number(searchOut.fetch_meta.status) : null,
    });
    for (const url of Array.isArray(searchOut.product_urls) ? searchOut.product_urls : []) {
      if (!candidateUrls.includes(url)) candidateUrls.push(url);
      if (candidateUrls.length >= PRODUCT_INTEL_INCIDECODER_MAX_CANDIDATES) break;
    }
    if (candidateUrls.length >= PRODUCT_INTEL_INCIDECODER_MAX_CANDIDATES) break;
  }

  const directSlug = toIncidecoderSlug(descriptor.name || descriptor.query);
  if (directSlug) {
    const directUrl = `https://incidecoder.com/products/${directSlug}`;
    if (!candidateUrls.includes(directUrl)) candidateUrls.unshift(directUrl);
  }

  let best = null;
  for (const url of candidateUrls.slice(0, PRODUCT_INTEL_INCIDECODER_MAX_CANDIDATES)) {
    if (Date.now() >= deadline) break;
    // eslint-disable-next-line no-await-in-loop
    const pageOut = await fetchIncidecoderProductPage({
      productUrl: url,
      timeoutMs: remainingBudget(),
      logger,
    });
    const pageTitle = pageOut.ok ? extractPageTitleFromHtml(pageOut.html) : '';
    const ingredients = pageOut.ok ? extractIncidecoderIngredientsFromHtml(pageOut.html) : [];
    const matchScore = pageOut.ok ? scoreIncidecoderMatch({ descriptor, pageTitle, productUrl: url }) : 0;
    attempts.push({
      stage: 'detail',
      url,
      ok: Boolean(pageOut.ok),
      reason: pageOut.reason || null,
      ingredient_count: ingredients.length,
      match_score: matchScore,
      status: Number.isFinite(Number(pageOut?.fetch_meta?.status)) ? Number(pageOut.fetch_meta.status) : null,
    });
    if (!pageOut.ok || !ingredients.length) continue;
    if (!best || matchScore > best.match_score || (matchScore === best.match_score && ingredients.length > best.ingredients.length)) {
      best = {
        source_url: url,
        ingredients,
        match_score: matchScore,
        page_title: pageTitle,
      };
    }
  }

  if (!best || best.ingredients.length < 4 || best.match_score < PRODUCT_INTEL_INCIDECODER_MIN_MATCH_SCORE) {
    const hadFetchFailure = attempts.some((item) => String(item?.reason || '').includes('fetch_failed'));
    return {
      ok: false,
      query: descriptor.query,
      reason: hadFetchFailure ? 'incidecoder_fetch_failed' : 'incidecoder_no_match',
      attempts: attempts.slice(0, 12),
    };
  }

  return {
    ok: true,
    query: descriptor.query,
    source_url: best.source_url,
    page_title: best.page_title,
    ingredients: best.ingredients,
    match_score: best.match_score,
    attempts: attempts.slice(0, 12),
    source: {
      type: 'inci_decoder',
      url: best.source_url,
      label: 'INCIDecoder',
      confidence: Number(Math.max(0.35, Math.min(0.82, best.match_score + 0.18)).toFixed(2)),
    },
  };
}

const RETAIL_SOURCE_CONFIG = [
  {
    host: 'sephora.com',
    label: 'Sephora',
    searchUrlBuilder: (query) => `https://www.sephora.com/search?keyword=${encodeURIComponent(query)}`,
    productPathRe: /^\/product\/[a-z0-9-]+/i,
  },
  {
    host: 'ulta.com',
    label: 'Ulta',
    searchUrlBuilder: (query) => `https://www.ulta.com/discover/search?Ntt=${encodeURIComponent(query)}`,
    productPathRe: /^\/p\/[a-z0-9-]+/i,
  },
  {
    host: 'target.com',
    label: 'Target',
    searchUrlBuilder: (query) => `https://www.target.com/s?searchTerm=${encodeURIComponent(query)}`,
    productPathRe: /^\/p\/[a-z0-9-]+/i,
  },
  {
    host: 'walmart.com',
    label: 'Walmart',
    searchUrlBuilder: (query) => `https://www.walmart.com/search?q=${encodeURIComponent(query)}`,
    productPathRe: /^\/ip\/[a-z0-9-]+/i,
  },
];

function extractRetailProductUrls(searchHtml = '', baseUrl = '', sourceConfig = null) {
  const source = String(searchHtml || '');
  if (!source || !sourceConfig || typeof sourceConfig !== 'object') return [];
  const out = [];
  const seen = new Set();
  const expectedHost = String(sourceConfig.host || '').toLowerCase();
  const productPathRe = sourceConfig.productPathRe instanceof RegExp ? sourceConfig.productPathRe : null;
  const re = /href=["']([^"']{4,600})["']/gi;
  let m = re.exec(source);
  while (m) {
    const rawHref = decodeHtmlEntitiesBasic(m[1] || '').trim();
    if (!rawHref || rawHref.startsWith('javascript:') || rawHref.startsWith('#')) {
      m = re.exec(source);
      continue;
    }
    try {
      const abs = new URL(rawHref, baseUrl || `https://www.${expectedHost}`);
      const host = String(abs.hostname || '').trim().toLowerCase().replace(/^www\./, '');
      if (!host || host !== expectedHost.replace(/^www\./, '')) {
        m = re.exec(source);
        continue;
      }
      const path = String(abs.pathname || '').trim();
      if (!path || !productPathRe || !productPathRe.test(path)) {
        m = re.exec(source);
        continue;
      }
      const normalized = `${abs.origin}${path}`;
      const key = normalized.toLowerCase();
      if (seen.has(key)) {
        m = re.exec(source);
        continue;
      }
      seen.add(key);
      out.push(normalized);
      if (out.length >= PRODUCT_INTEL_RETAIL_MAX_CANDIDATES) break;
    } catch {
      // ignore malformed retail href
    }
    m = re.exec(source);
  }
  return out;
}

function extractRetailIngredientsFromHtml(html = '') {
  const source = String(html || '');
  if (!source) return [];
  const patterns = [
    /(?:ingredients?|ingredient list|full ingredients?)\s*[:：]\s*([^<]{40,12000})/i,
    /"ingredients"\s*:\s*"([^"]{40,12000})"/i,
    /"activeIngredients"\s*:\s*"([^"]{20,12000})"/i,
    /class=["'][^"']*ingredient[^"']*["'][^>]*>([\s\S]{40,12000}?)<\/(?:div|p|section)>/i,
  ];
  for (const re of patterns) {
    const m = source.match(re);
    const list = splitInciList(m && m[1] ? m[1] : '');
    if (list.length >= 4) return list;
  }
  return [];
}

function scoreRetailMatch({ descriptor = null, pageTitle = '', productUrl = '' } = {}) {
  const d = isPlainObject(descriptor) ? descriptor : {};
  const queryTokens = tokenizeIncidecoderComparable(
    `${pickFirstTrimmed(d.brand)} ${pickFirstTrimmed(d.name)} ${pickFirstTrimmed(d.query)}`,
  );
  const titleTokens = tokenizeIncidecoderComparable(`${pageTitle} ${productUrl}`);
  if (!queryTokens.length || !titleTokens.length) return 0.26;
  const titleSet = new Set(titleTokens);
  const overlap = queryTokens.filter((token) => titleSet.has(token)).length;
  const overlapScore = overlap / Math.max(1, queryTokens.length);
  const brandToken = pickFirstTrimmed(d.brand).toLowerCase();
  const hasBrand = brandToken && String(pageTitle || '').toLowerCase().includes(brandToken);
  const nameToken = pickFirstTrimmed(d.name).toLowerCase();
  const hasName = nameToken && String(pageTitle || '').toLowerCase().includes(nameToken);
  return Math.max(0, Math.min(1, Number((overlapScore + (hasBrand ? 0.18 : 0) + (hasName ? 0.12 : 0)).toFixed(3))));
}

async function fetchRetailSearchCandidates({
  sourceConfig = null,
  query = '',
  timeoutMs = 3600,
  logger,
} = {}) {
  const cfg = sourceConfig && typeof sourceConfig === 'object' ? sourceConfig : null;
  const queryText = String(query || '').trim();
  if (!cfg || !queryText) {
    return {
      ok: false,
      reason: 'retail_source_no_match',
      product_urls: [],
      fetch_meta: null,
    };
  }
  const searchUrl = typeof cfg.searchUrlBuilder === 'function' ? cfg.searchUrlBuilder(queryText) : '';
  if (!searchUrl) {
    return {
      ok: false,
      reason: 'retail_source_no_match',
      product_urls: [],
      fetch_meta: null,
    };
  }
  const fetchOut = await fetchProductHtmlWithUnblockChain({
    productUrl: searchUrl,
    timeoutMs: Math.max(1200, Math.min(6000, Number(timeoutMs) || 3600)),
    allowHostVariant: false,
    logger,
  });
  if (!fetchOut.ok || !fetchOut.html) {
    return {
      ok: false,
      reason: String(fetchOut.failure_code || 'retail_source_no_match'),
      search_url: searchUrl,
      product_urls: [],
      fetch_meta: fetchOut,
    };
  }
  const productUrls = extractRetailProductUrls(fetchOut.html, searchUrl, cfg);
  return {
    ok: productUrls.length > 0,
    reason: productUrls.length ? null : 'retail_source_no_match',
    search_url: searchUrl,
    product_urls: productUrls,
    fetch_meta: fetchOut,
  };
}

async function fetchRetailProductPage({
  productUrl = '',
  timeoutMs = 3600,
  logger,
} = {}) {
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) {
    return {
      ok: false,
      reason: 'retail_source_no_match',
      html: '',
      fetch_meta: null,
      url: urlText,
    };
  }
  const fetchOut = await fetchProductHtmlWithUnblockChain({
    productUrl: urlText,
    timeoutMs: Math.max(1200, Math.min(7000, Number(timeoutMs) || 3600)),
    allowHostVariant: false,
    logger,
  });
  return {
    ok: Boolean(fetchOut.ok && fetchOut.html),
    reason: fetchOut.ok ? null : String(fetchOut.failure_code || 'retail_source_no_match'),
    html: fetchOut.ok ? String(fetchOut.html || '') : '',
    fetch_meta: fetchOut,
    url: urlText,
  };
}

async function fetchRetailIngredientSupplement({
  parsedProduct = null,
  productUrl = '',
  timeoutMs = 5200,
  logger,
} = {}) {
  const descriptor = buildProductDescriptorFromInput({ parsedProduct, productUrl });
  if (!descriptor.query) {
    return {
      ok: false,
      reason: 'retail_source_no_match',
      attempts: [],
      query: '',
    };
  }

  const maxBudgetMs = Math.max(1600, Math.min(12000, Number(timeoutMs) || 5200));
  const deadline = Date.now() + maxBudgetMs;
  const remainingBudget = () => Math.max(900, deadline - Date.now());
  const queryCandidates = uniqCaseInsensitiveStrings(
    [descriptor.query, pickFirstTrimmed(`${descriptor.brand || ''} ${descriptor.name || ''}`), descriptor.name].filter(Boolean),
    3,
  );
  const attempts = [];
  let best = null;
  let hadFetchFailure = false;

  for (const cfg of RETAIL_SOURCE_CONFIG) {
    if (Date.now() >= deadline) break;
    for (const queryText of queryCandidates) {
      if (Date.now() >= deadline) break;
      // eslint-disable-next-line no-await-in-loop
      const searchOut = await fetchRetailSearchCandidates({
        sourceConfig: cfg,
        query: queryText,
        timeoutMs: remainingBudget(),
        logger,
      });
      attempts.push({
        stage: 'search',
        host: cfg.host,
        query: queryText,
        ok: Boolean(searchOut.ok),
        reason: searchOut.reason || null,
      });
      if (!searchOut.ok) {
        if (String(searchOut.reason || '').includes('fetch') || String(searchOut.reason || '').startsWith('url_fetch_')) {
          hadFetchFailure = true;
        }
        continue;
      }
      for (const candidateUrl of (Array.isArray(searchOut.product_urls) ? searchOut.product_urls : []).slice(0, PRODUCT_INTEL_RETAIL_MAX_CANDIDATES)) {
        if (Date.now() >= deadline) break;
        // eslint-disable-next-line no-await-in-loop
        const pageOut = await fetchRetailProductPage({
          productUrl: candidateUrl,
          timeoutMs: remainingBudget(),
          logger,
        });
        const pageTitle = pageOut.ok ? extractPageTitleFromHtml(pageOut.html) : '';
        const ingredients = pageOut.ok ? extractRetailIngredientsFromHtml(pageOut.html) : [];
        const matchScore = pageOut.ok ? scoreRetailMatch({ descriptor, pageTitle, productUrl: candidateUrl }) : 0;
        attempts.push({
          stage: 'detail',
          host: cfg.host,
          url: candidateUrl,
          ok: Boolean(pageOut.ok),
          reason: pageOut.reason || null,
          ingredient_count: ingredients.length,
          match_score: matchScore,
        });
        if (!pageOut.ok || !ingredients.length) {
          if (String(pageOut.reason || '').includes('fetch') || String(pageOut.reason || '').startsWith('url_fetch_')) {
            hadFetchFailure = true;
          }
          continue;
        }
        if (!best || matchScore > best.match_score || (matchScore === best.match_score && ingredients.length > best.ingredients.length)) {
          best = {
            source_url: candidateUrl,
            ingredients,
            match_score: matchScore,
            page_title: pageTitle,
            source_host: cfg.host,
            source_label: cfg.label,
          };
        }
      }
    }
  }

  if (!best || best.ingredients.length < 4 || best.match_score < 0.24) {
    return {
      ok: false,
      query: descriptor.query,
      reason: hadFetchFailure ? 'retail_source_no_match' : 'retail_source_no_match',
      attempts: attempts.slice(0, 20),
    };
  }

  return {
    ok: true,
    query: descriptor.query,
    source_url: best.source_url,
    page_title: best.page_title,
    ingredients: best.ingredients,
    match_score: best.match_score,
    attempts: attempts.slice(0, 20),
    source: {
      type: 'retail_page',
      url: best.source_url,
      label: best.source_label || best.source_host || 'Retail PDP',
      confidence: Number(Math.max(0.28, Math.min(0.74, best.match_score + 0.16)).toFixed(2)),
    },
  };
}

async function fetchLlmIngredientVerification({
  brand = '',
  productName = '',
  extractedInci = [],
  timeoutMs = 6000,
  logger,
} = {}) {
  const brandText = String(brand || '').trim();
  const nameText = String(productName || '').trim();
  const productLabel = [brandText, nameText].filter(Boolean).join(' ');
  if (!productLabel) {
    return { ok: false, reason: 'no_product_identifier', ingredients: [], confidence: 0 };
  }
  const extractedList = Array.isArray(extractedInci) ? extractedInci.filter(Boolean) : [];
  const hasExtracted = extractedList.length >= 4;

  const systemPrompt = [
    'You are a cosmetics INCI expert. Output STRICT JSON only.',
    'Your task: recall the full INCI ingredient list for a specific skincare product from your training knowledge.',
    'If you are not confident about this product, set confidence to 0 and return an empty ingredients array.',
    'Do NOT fabricate ingredients. Only return ingredients you are reasonably sure are in this product.',
  ].join('\n');

  const userPrompt = hasExtracted
    ? [
        `Product: ${productLabel}`,
        '',
        `We extracted these ingredients from the product page: ${extractedList.slice(0, 40).join(', ')}`,
        '',
        'Please:',
        '1. Recall the full INCI list for this product from your knowledge.',
        '2. Cross-check against the extracted list and flag any discrepancies (missing or extra ingredients).',
        '3. Provide a confidence score (0-1) for how sure you are about this product\'s INCI.',
        '',
        'Return JSON: {"ingredients": string[], "confidence": number, "discrepancies": {"missing_from_extracted": string[], "extra_in_extracted": string[]}}',
      ].join('\n')
    : [
        `Product: ${productLabel}`,
        '',
        'We could not extract ingredients from any source for this product.',
        'Please recall the full INCI ingredient list from your knowledge.',
        'If you are unsure, return empty ingredients with confidence 0.',
        '',
        'Return JSON: {"ingredients": string[], "confidence": number, "discrepancies": {"missing_from_extracted": string[], "extra_in_extracted": string[]}}',
      ].join('\n');

  try {
    const resp = await callGeminiJsonObjectImpl({
      model: ANALYSIS_STORY_MODEL_GEMINI,
      systemPrompt,
      userPrompt,
      timeoutMs: Math.max(2000, Math.min(8000, Number(timeoutMs) || 6000)),
      temperature: 0,
      maxOutputTokens: 2048,
      route: 'aurora_llm_inci_verification',
    });

    if (!resp.ok || !resp.json || typeof resp.json !== 'object') {
      logger?.warn?.({ reason: resp.reason }, 'aurora bff: LLM ingredient verification call failed');
      return { ok: false, reason: String(resp.reason || 'llm_verification_failed'), ingredients: [], confidence: 0 };
    }

    const json = resp.json;
    const llmIngredients = Array.isArray(json.ingredients)
      ? json.ingredients.map((item) => String(item || '').trim()).filter(Boolean)
      : [];
    const rawConfidence = Number(json.confidence);
    const confidence = Number.isFinite(rawConfidence) ? Math.max(0, Math.min(1, rawConfidence)) : 0;

    if (confidence < 0.3 || llmIngredients.length < 3) {
      return {
        ok: false,
        reason: 'llm_low_confidence',
        ingredients: llmIngredients,
        confidence,
      };
    }

    const discrepancies = json.discrepancies && typeof json.discrepancies === 'object' ? json.discrepancies : {};
    const matchScore = hasExtracted ? computeLlmInciMatchScore(extractedList, llmIngredients) : confidence * 0.7;

    return {
      ok: true,
      ingredients: llmIngredients,
      confidence,
      match_score: Number(matchScore.toFixed(3)),
      discrepancies: {
        missing_from_extracted: Array.isArray(discrepancies.missing_from_extracted)
          ? discrepancies.missing_from_extracted.map((s) => String(s || '').trim()).filter(Boolean).slice(0, 10)
          : [],
        extra_in_extracted: Array.isArray(discrepancies.extra_in_extracted)
          ? discrepancies.extra_in_extracted.map((s) => String(s || '').trim()).filter(Boolean).slice(0, 10)
          : [],
      },
      source: {
        type: 'llm_verification',
        confidence: Number(Math.min(0.68, confidence * 0.72).toFixed(2)),
        ingredient_count: llmIngredients.length,
      },
    };
  } catch (err) {
    logger?.warn?.({ err: err?.message || String(err) }, 'aurora bff: LLM ingredient verification threw');
    return { ok: false, reason: 'llm_verification_error', ingredients: [], confidence: 0 };
  }
}

function computeLlmInciMatchScore(extractedList, llmList) {
  const extractedNorm = new Set(
    (Array.isArray(extractedList) ? extractedList : []).map((s) => String(s || '').trim().toLowerCase()).filter(Boolean),
  );
  const llmNorm = (Array.isArray(llmList) ? llmList : []).map((s) => String(s || '').trim().toLowerCase()).filter(Boolean);
  if (!extractedNorm.size || !llmNorm.length) return 0;
  const overlap = llmNorm.filter((item) => extractedNorm.has(item)).length;
  return overlap / Math.max(extractedNorm.size, llmNorm.length);
}

const CONCENTRATION_PERCENT_RE = /\b(\d{1,2}(?:\.\d{1,2})?)\s*%/gi;
const CONCENTRATION_CONTEXT_RE = /\b(acid|retinol|retinal|retinoid|niacinamide|vitamin\s*c|ascorb|peptide|copper|zinc|benzoyl|salicylic|glycolic|lactic|mandelic|serum|solution)\b/i;

function extractConcentrationSignalsFromText(rawText, max = 4) {
  const text = stripHtmlToText(rawText);
  if (!text) return [];
  const out = [];
  const seen = new Set();
  let m;
  CONCENTRATION_PERCENT_RE.lastIndex = 0;
  while ((m = CONCENTRATION_PERCENT_RE.exec(text))) {
    const valueToken = `${String(m[1] || '').trim()}%`;
    if (!valueToken || seen.has(valueToken.toLowerCase())) continue;
    const start = Math.max(0, m.index - 42);
    const end = Math.min(text.length, m.index + String(m[0] || '').length + 42);
    const windowText = text.slice(start, end);
    if (!CONCENTRATION_CONTEXT_RE.test(windowText)) continue;
    seen.add(valueToken.toLowerCase());
    out.push(valueToken);
    if (out.length >= max) break;
  }
  return out;
}

function extractConcentrationSignals({
  pageTitle = '',
  anchorName = '',
  anchorDisplayName = '',
  keyIngredients = [],
} = {}) {
  return uniqCaseInsensitiveStrings(
    [
      ...extractConcentrationSignalsFromText(pageTitle, 2),
      ...extractConcentrationSignalsFromText(anchorName, 2),
      ...extractConcentrationSignalsFromText(anchorDisplayName, 2),
      ...((Array.isArray(keyIngredients) ? keyIngredients : []).flatMap((item) =>
        extractConcentrationSignalsFromText(String(item || ''), 1)
      )),
    ],
    6,
  );
}

function normalizeCurrencyCode(value, fallback = '') {
  const token = String(value || '').trim().toUpperCase().replace(/[^A-Z]/g, '');
  if (token.length === 3) return token;
  const fb = String(fallback || '').trim().toUpperCase().replace(/[^A-Z]/g, '');
  return fb.length === 3 ? fb : '';
}

function inferCurrencyFromPriceText(value, fallback = '') {
  const text = String(value || '').trim();
  if (!text) return normalizeCurrencyCode(fallback, '');
  if (/[$]|usd|us\$/i.test(text)) return 'USD';
  if (/[€]|eur/i.test(text)) return 'EUR';
  if (/[£]|gbp/i.test(text)) return 'GBP';
  if (/[¥]|cny|rmb/i.test(text)) return 'CNY';
  if (/jpy|円/i.test(text)) return 'JPY';
  return normalizeCurrencyCode(fallback, '');
}

function toPositiveNumberOrNull(value) {
  if (value == null) return null;
  if (typeof value === 'string') {
    const text = String(value).trim();
    if (!text) return null;
    const compact = text.replace(/\s+/g, '');
    const direct = Number(compact.replace(/,/g, ''));
    if (Number.isFinite(direct) && direct > 0) return Number(direct.toFixed(2));
    const numeric = compact.replace(/[^0-9.,-]/g, '');
    if (!numeric) return null;
    let normalized = numeric;
    const commaCount = (numeric.match(/,/g) || []).length;
    const dotCount = (numeric.match(/\./g) || []).length;
    if (commaCount && !dotCount) normalized = numeric.replace(',', '.');
    normalized = normalized.replace(/,(?=\d{3}\b)/g, '');
    const parsed = Number(normalized);
    if (!Number.isFinite(parsed) || parsed <= 0) return null;
    return Number(parsed.toFixed(2));
  }
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return null;
  return Number(n.toFixed(2));
}

function normalizePriceObject(rawPrice, { fallbackCurrency = 'USD' } = {}) {
  if (rawPrice == null) return null;
  if (typeof rawPrice === 'number' || typeof rawPrice === 'string') {
    const amount = toPositiveNumberOrNull(rawPrice);
    if (amount == null) return null;
    const inferredCurrency = inferCurrencyFromPriceText(rawPrice, fallbackCurrency);
    return { amount, currency: inferredCurrency || normalizeCurrencyCode(fallbackCurrency, 'USD') || 'USD', unknown: false };
  }
  if (typeof rawPrice !== 'object' || Array.isArray(rawPrice)) return null;

  if (rawPrice.unknown === true) return null;

  const nestedPrice = rawPrice.price && typeof rawPrice.price === 'object' && !Array.isArray(rawPrice.price)
    ? rawPrice.price
    : null;

  const directAmount = toPositiveNumberOrNull(
    rawPrice.amount ??
      rawPrice.price_amount ??
      rawPrice.priceAmount ??
      rawPrice.value ??
      rawPrice.price_value ??
      rawPrice.priceValue ??
      rawPrice.price ??
      nestedPrice?.amount ??
      nestedPrice?.value ??
      nestedPrice?.price ??
      rawPrice.min ??
      rawPrice.min_price ??
      rawPrice.minPrice ??
      rawPrice.offer_price ??
      rawPrice.offerPrice,
  );
  if (directAmount != null) {
    const directCurrency = normalizeCurrencyCode(
      rawPrice.currency ??
        rawPrice.currency_code ??
        rawPrice.currencyCode ??
        rawPrice.priceCurrency ??
        nestedPrice?.currency ??
        nestedPrice?.currencyCode ??
        nestedPrice?.priceCurrency,
      fallbackCurrency,
    );
    return { amount: directAmount, currency: directCurrency || 'USD', unknown: false };
  }

  const usd = toPositiveNumberOrNull(rawPrice.usd ?? rawPrice.price_usd ?? rawPrice.priceUsd);
  if (usd != null) return { amount: usd, currency: 'USD', unknown: false };
  const cny = toPositiveNumberOrNull(rawPrice.cny ?? rawPrice.price_cny ?? rawPrice.priceCny);
  if (cny != null) return { amount: cny, currency: 'CNY', unknown: false };
  return null;
}

function extractCatalogCandidatePrice(rawProduct) {
  const base = rawProduct && typeof rawProduct === 'object' && !Array.isArray(rawProduct) ? rawProduct : null;
  if (!base) return null;

  const seeds = [
    base.price,
    base.price_amount,
    base.priceAmount,
    base.price_value,
    base.priceValue,
    base.offer_price,
    base.offerPrice,
    base.sale_price,
    base.salePrice,
    base.list_price,
    base.listPrice,
    base.min_price,
    base.minPrice,
    base.max_price,
    base.maxPrice,
    base.pricing,
    base.price_info,
    base.priceInfo,
    base.offer,
    base.offers,
    base.subject && typeof base.subject === 'object' && !Array.isArray(base.subject) ? base.subject.price : null,
    base.subject && typeof base.subject === 'object' && !Array.isArray(base.subject) ? base.subject.offers : null,
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku) ? base.sku.price : null,
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku) ? base.sku.offers : null,
    base.product && typeof base.product === 'object' && !Array.isArray(base.product) ? base.product.price : null,
    base.product && typeof base.product === 'object' && !Array.isArray(base.product) ? base.product.offers : null,
  ];

  for (const seed of seeds) {
    if (seed == null) continue;
    if (Array.isArray(seed)) {
      for (const item of seed) {
        const parsed = normalizePriceObject(item, { fallbackCurrency: 'USD' });
        if (parsed) return parsed;
      }
      continue;
    }
    const parsed = normalizePriceObject(seed, { fallbackCurrency: 'USD' });
    if (parsed) return parsed;
  }

  const usd = toPositiveNumberOrNull(base.price_usd ?? base.priceUsd ?? base.usd);
  if (usd != null) return { amount: usd, currency: 'USD', unknown: false };
  const cny = toPositiveNumberOrNull(base.price_cny ?? base.priceCny ?? base.cny);
  if (cny != null) return { amount: cny, currency: 'CNY', unknown: false };
  return null;
}

function extractProductPriceFromHtml(html) {
  const text = String(html || '');
  if (!text) return null;

  const metaCurrencyMatch = text.match(
    /<meta[^>]+(?:property|name)=["'](?:product:price:currency|og:price:currency)["'][^>]+content=["']([^"']{2,12})["']/i,
  );
  const metaCurrency = normalizeCurrencyCode(metaCurrencyMatch?.[1] || '', '');

  const scriptRe = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
  let m;
  while ((m = scriptRe.exec(text))) {
    const raw = decodeHtmlEntitiesBasic(String(m[1] || '')).trim();
    if (!raw) continue;
    let parsed = null;
    try {
      parsed = JSON.parse(raw);
    } catch {
      continue;
    }
    const stack = Array.isArray(parsed) ? [...parsed] : [parsed];
    while (stack.length) {
      const node = stack.shift();
      if (!node || typeof node !== 'object') continue;
      if (Array.isArray(node)) {
        stack.push(...node);
        continue;
      }

      const currency = normalizeCurrencyCode(
        node.priceCurrency ?? node.price_currency ?? node.currency ?? node.currencyCode,
        metaCurrency,
      );
      const offerAmount =
        toPositiveNumberOrNull(node.price) ??
        toPositiveNumberOrNull(node.lowPrice) ??
        toPositiveNumberOrNull(node.highPrice);
      if (offerAmount != null) {
        return {
          amount: offerAmount,
          currency: currency || 'USD',
          unknown: false,
          source: 'json_ld_offer',
        };
      }

      const offers = node.offers ?? node.offer ?? node.aggregateOffer ?? node.aggregate_offer;
      if (offers) {
        if (Array.isArray(offers)) stack.push(...offers);
        else stack.push(offers);
      }
      if (node['@graph']) {
        if (Array.isArray(node['@graph'])) stack.push(...node['@graph']);
        else stack.push(node['@graph']);
      }
      const nested = node.mainEntity ?? node.main_entity ?? node.itemOffered;
      if (nested) stack.push(nested);
    }
  }

  const metaAmountMatch = text.match(
    /<meta[^>]+(?:property|name)=["'](?:product:price:amount|og:price:amount|twitter:data1|price)["'][^>]+content=["']([^"']{1,32})["']/i,
  );
  const metaAmount = toPositiveNumberOrNull(metaAmountMatch?.[1]);
  if (metaAmount != null) {
    return {
      amount: metaAmount,
      currency: metaCurrency || 'USD',
      unknown: false,
      source: 'meta_price',
    };
  }

  const inlineCurrency = normalizeCurrencyCode(
    text.match(/"priceCurrency"\s*:\s*"([A-Za-z]{3})"/i)?.[1] || '',
    metaCurrency,
  );
  const inlineAmount = toPositiveNumberOrNull(text.match(/"price"\s*:\s*"?([0-9]+(?:\.[0-9]{1,2})?)"?/i)?.[1]);
  if (inlineAmount != null) {
    return {
      amount: inlineAmount,
      currency: inlineCurrency || 'USD',
      unknown: false,
      source: 'inline_price',
    };
  }

  const plainText = stripHtmlToText(text).replace(/\s+/g, ' ').trim();
  if (plainText) {
    const prefixed = /(?:\b(USD|EUR|GBP|CNY|JPY)\b|([$€£¥]))\s*([0-9]{1,4}(?:[.,][0-9]{1,2})?)/gi;
    let mPrefixed;
    while ((mPrefixed = prefixed.exec(plainText))) {
      const rawCurrency = mPrefixed[1] || mPrefixed[2] || '';
      const amount = toPositiveNumberOrNull(mPrefixed[3]);
      if (amount == null) continue;
      const currency = inferCurrencyFromPriceText(rawCurrency, metaCurrency || 'USD');
      return {
        amount,
        currency: currency || 'USD',
        unknown: false,
        source: 'on_page_structured_text',
      };
    }

    const suffixed = /([0-9]{1,4}(?:[.,][0-9]{1,2})?)\s*(USD|EUR|GBP|CNY|JPY)\b/gi;
    let mSuffixed;
    while ((mSuffixed = suffixed.exec(plainText))) {
      const amount = toPositiveNumberOrNull(mSuffixed[1]);
      if (amount == null) continue;
      const currency = inferCurrencyFromPriceText(mSuffixed[2], metaCurrency || 'USD');
      return {
        amount,
        currency: currency || 'USD',
        unknown: false,
        source: 'on_page_structured_text',
      };
    }
  }
  return null;
}

function slugToCandidateProductName(raw) {
  const text = String(raw || '')
    .replace(/\.[a-z0-9]{2,8}$/i, '')
    .replace(/[_-]+/g, ' ')
    .replace(/\b\d{5,}\b/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!text) return '';
  return text
    .split(' ')
    .map((token) => {
      const t = String(token || '').trim();
      if (!t) return '';
      if (/^[A-Z0-9%+]+$/.test(t)) return t;
      return `${t.slice(0, 1).toUpperCase()}${t.slice(1).toLowerCase()}`;
    })
    .join(' ')
    .trim();
}

function extractOnPageRelatedProducts(html, { baseUrl, anchorName = '', max = 4 } = {}) {
  const source = String(html || '');
  const base = String(baseUrl || '').trim();
  if (!source || !base) return [];

  let parsedBase = null;
  try {
    parsedBase = new URL(base);
  } catch {
    parsedBase = null;
  }
  if (!parsedBase) return [];

  const generic = new Set([
    'shop now',
    'add to cart',
    'learn more',
    'read more',
    'details',
    'discover',
    'ingredients',
    'reviews',
    'view',
    'buy',
    'product',
    'skip to main content',
    'skip to footer content',
    'contact us',
    'search',
    'my account',
    'sign in',
    'menu',
    'home',
  ]);
  const productPathLike = /(product|serum|cream|moistur|cleanser|toner|mask|spf|sunscreen|retinol|niacinamide|peptide)/i;
  const genericProductTokens = new Set([
    'moisturizer',
    'moisturize',
    'skincare',
    'spf',
    'sunscreen',
    'serum',
    'cleanser',
    'toner',
    'mask',
    'lotion',
    'cream',
  ]);
  const explicitGenericProductNames = new Set([
    'moisturizer',
    'moisturizer spf',
    'moisturizer/spf',
    'skincare moisturizer',
    'skincare moisturize',
    'spf',
    'sunscreen',
    'serum',
    'cleanser',
    'toner',
    'mask',
  ]);
  const tokenizeName = (value) => String(value || '').trim().toLowerCase().split(/[^a-z0-9]+/).filter(Boolean);
  const isGenericProductName = (value) => {
    const normalized = String(value || '').trim().toLowerCase().replace(/\s+/g, ' ');
    if (!normalized) return true;
    if (explicitGenericProductNames.has(normalized)) return true;
    const tokens = tokenizeName(normalized);
    if (!tokens.length) return true;
    return tokens.length <= 3 && tokens.every((token) => genericProductTokens.has(token));
  };
  const anchorKey = String(anchorName || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
  const anchorTokens = tokenizeName(anchorKey);

  const seen = new Set();
  const out = [];
  const re = /<a[^>]+href\s*=\s*["']([^"']{2,600})["'][^>]*>([\s\S]{1,400}?)<\/a>/gi;
  let m = re.exec(source);
  while (m) {
    const hrefRaw = decodeHtmlEntitiesBasic(m[1] || '');
    const hrefTrimmed = String(hrefRaw || '').trim();
    if (!hrefTrimmed || hrefTrimmed.startsWith('#') || /^javascript:/i.test(hrefTrimmed) || /^mailto:/i.test(hrefTrimmed) || /^tel:/i.test(hrefTrimmed)) {
      m = re.exec(source);
      continue;
    }
    const textRaw = stripHtmlToText(m[2] || '');
    let absUrl = '';
    try {
      const u = new URL(hrefTrimmed, parsedBase);
      if (!/^https?:$/i.test(u.protocol)) {
        m = re.exec(source);
        continue;
      }
      if (u.hostname.replace(/^www\./i, '') !== parsedBase.hostname.replace(/^www\./i, '')) {
        m = re.exec(source);
        continue;
      }
      const samePath = String(u.pathname || '') === String(parsedBase.pathname || '');
      const sameSearch = String(u.search || '') === String(parsedBase.search || '');
      if (samePath && sameSearch) {
        m = re.exec(source);
        continue;
      }
      absUrl = u.toString();
      const pathLower = String(u.pathname || '').toLowerCase();
      if (!productPathLike.test(pathLower) && !/\.html$/i.test(pathLower)) {
        m = re.exec(source);
        continue;
      }
    } catch {
      m = re.exec(source);
      continue;
    }

    const textNorm = String(textRaw || '').replace(/\s+/g, ' ').trim();
    const lowerTextNorm = textNorm.toLowerCase();
    const slugName = (() => {
      try {
        const u = new URL(absUrl);
        const parts = String(u.pathname || '')
          .split('/')
          .map((x) => x.trim())
          .filter(Boolean);
        return parts.length ? slugToCandidateProductName(parts[parts.length - 1]) : '';
      } catch {
        return '';
      }
    })();

    let name = textNorm;
    if (!name || name.length < 4 || generic.has(lowerTextNorm) || /^skip to /i.test(name) || /\b(contact us|search|my account|sign in)\b/i.test(name)) {
      name = slugName;
    }
    if (!name || name.length < 4 || name.length > 120) {
      m = re.exec(source);
      continue;
    }
    const nameKey = name.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
    if (!nameKey) {
      m = re.exec(source);
      continue;
    }
    if (isGenericProductName(nameKey)) {
      m = re.exec(source);
      continue;
    }
    if (generic.has(nameKey) || /^skip to /i.test(name) || /^contact us$/i.test(name)) {
      m = re.exec(source);
      continue;
    }
    if (anchorKey && nameKey === anchorKey) {
      m = re.exec(source);
      continue;
    }
    if (seen.has(nameKey)) {
      m = re.exec(source);
      continue;
    }
    const nameTokens = tokenizeName(nameKey);
    if (anchorTokens.length && nameTokens.length) {
      const overlap = nameTokens.filter((token) => anchorTokens.includes(token)).length;
      const similarity = overlap / Math.max(anchorTokens.length, nameTokens.length);
      if (similarity >= 0.8) {
        m = re.exec(source);
        continue;
      }
    }
    seen.add(nameKey);
    out.push({ name, url: absUrl });
    if (out.length >= Math.max(1, Math.min(8, Number(max) || 4))) break;

    m = re.exec(source);
  }

  return out;
}

function buildOnPageCompetitorCandidates({
  html,
  productUrl,
  anchorProduct = null,
  profileSummary = null,
  lang = 'EN',
  maxCandidates = 4,
} = {}) {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const anchorObj = anchorProduct && typeof anchorProduct === 'object' && !Array.isArray(anchorProduct) ? anchorProduct : null;
  const anchorBrand = pickFirstTrimmed(anchorObj?.brand);
  const anchorName = pickFirstTrimmed(anchorObj?.name, anchorObj?.display_name);
  const anchorText = `${anchorBrand || ''} ${anchorName || ''}`.trim();
  const anchorTokens = tokenizeProductTextForSimilarity(anchorText);
  const anchorCategory = inferProductCategoryToken(anchorText);
  const profileSkinTags = buildProfileSkinTags(profileSummary);
  const rows = extractOnPageRelatedProducts(html, {
    baseUrl: productUrl,
    anchorName,
    max: Math.max(1, Math.min(8, Number(maxCandidates) || 4)),
  });
  const totalQueries = Math.max(1, rows.length);
  return rows.map((row, idx) => {
    const rowTokens = tokenizeProductTextForSimilarity(`${anchorBrand || ''} ${String(row.name || '')}`);
    const queryOverlap = rowTokens.filter((token) => anchorTokens.includes(token)).length;
    const rowCategory = inferProductCategoryToken(row.name || '');
    const sameCategory = Boolean(anchorCategory && rowCategory && anchorCategory === rowCategory);
    const scored = scoreRealtimeCompetitorCandidate({
      queryOverlap,
      ingredientNameOverlap: 0,
      sameCategory,
      sameBrand: Boolean(anchorBrand),
      anchorIngredientTokens: [],
      candidateIngredientTokens: [],
      profileSkinTags,
      candidateSkinTags: [],
      candidateSocialScore: null,
      candidateSocialSupportCount: null,
      recallHitCount: Math.max(1, totalQueries - idx),
      totalQueries,
    });
    const fallbackSimilarity = Number(Math.max(0.35, Math.min(0.72, 0.66 - idx * 0.07)).toFixed(3));
    const similarityScore = Number(Math.max(scored.similarity_score, fallbackSimilarity).toFixed(3));
    return {
      ...(anchorBrand ? { brand: anchorBrand } : {}),
      name: row.name,
      source: { type: 'on_page_related' },
      source_type: 'on_page_related',
      similarity_score: similarityScore,
      score_breakdown: scored.score_breakdown,
      why_candidate: uniqCaseInsensitiveStrings(
        [
          isCn ? '来自同站产品页的相关产品链接' : 'related product link found on the same product page',
          sameCategory
            ? isCn
              ? '同品类同场景'
              : 'same category/use-case'
            : '',
          scored.score_breakdown.query_overlap_score >= 0.45
            ? isCn
              ? '与锚点产品命名关键词相近'
              : 'name tokens overlap with anchor product'
            : '',
          scored.score_breakdown.skin_fit_similarity >= 0.6
            ? isCn
              ? '与当前肤质画像匹配度较高'
              : 'better aligned with current skin profile'
            : '',
        ],
        4,
      ),
      compare_highlights: [
        isCn
          ? '同品牌同场景候选，建议再对比成分与浓度。'
          : 'Same-brand/context candidate; compare INCI and concentration before final pick.',
        row.url,
      ],
    };
  });
}

function deriveIngredientMechanisms(ingredients, lang = 'EN') {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const pool = Array.isArray(ingredients) ? ingredients.map((v) => String(v || '').toLowerCase()) : [];
  const joined = pool.join(' | ');
  const out = [];
  if (/\b(peptide|tripeptide|tetrapeptide|hexapeptide|pentapeptide)\b/.test(joined)) {
    out.push(
      isCn
        ? '多肽类通常用于支持皮肤紧致与细纹观感改善（具体效果与浓度/配方相关）。'
        : 'Peptide complexes are commonly used to support firmness and the look of fine lines (effect depends on formula and concentration).',
    );
  }
  if (/\b(sodium hyaluronate|hyaluronate|hyaluronic|glycerin|glycerol|trehalose|urea|sodium pca|\bpca\b)\b/.test(joined)) {
    out.push(
      isCn
        ? '保湿剂/吸湿剂组合较完整，通常更偏向补水与维持角质层含水。'
        : 'Humectant blend suggests hydration support and moisture retention.',
    );
  }
  if (/\b(allantoin|panthenol|betaine|bisabolol|centella|madecassoside|cica)\b/.test(joined)) {
    out.push(
      isCn ? '含舒缓相关成分，通常更利于降低刺激感。' : 'Includes soothing-support ingredients that can improve tolerance.',
    );
  }
  if (/\b(ceramide|cholesterol|fatty acid|linoleic|sphingosine|phytosphingosine)\b/.test(joined)) {
    out.push(
      isCn ? '含有屏障修复成分，有助于支持皮肤屏障功能。' : 'Contains barrier-repair ingredients to support skin barrier function.',
    );
  }
  if (/\b(niacinamide|ascorbic|vitamin c|retinol|retinal|azelaic|tranexamic|kojic)\b/.test(joined)) {
    out.push(
      isCn ? '含亮肤/淡斑活性成分，需注意使用频率与叠加方式。' : 'Contains brightening or tone-correcting actives; note frequency and layering needs.',
    );
  }
  return uniqCaseInsensitiveStrings(out, 5);
}

function deriveIngredientRiskNotes(ingredients, profileSummary, lang = 'EN', inciStatus = null) {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const list = Array.isArray(ingredients) ? ingredients.map((v) => String(v || '').trim()) : [];
  const joined = list.join(' | ').toLowerCase();
  const risks = [];

  const hasRetinoid = /\b(retinol|retinal|retinoate|adapalene|tretinoin)\b/.test(joined);
  const hasAcid = /\b(aha|bha|pha|glycolic|lactic|mandelic|salicylic|citric acid)\b/.test(joined);
  const hasFragrance = /\b(fragrance|parfum|linalool|limonene|citral|geraniol|eugenol|benzyl alcohol|benzyl benzoate)\b/.test(joined);
  const hasAlcoholDenat = /\balcohol denat\b/.test(joined);
  const hasEssentialOil = /\b(essential oil|lavender oil|citrus peel oil|eucalyptus oil|menthol|tea tree)\b/.test(joined);

  const sensitivity = String(profileSummary?.sensitivity || '').trim().toLowerCase();
  const barrier = String(profileSummary?.barrierStatus || '').trim().toLowerCase();
  const sensitiveProfile = sensitivity === 'high' || sensitivity === 'medium' || barrier === 'impaired';
  const inciVerified = !inciStatus?.verification_required;

  if (hasRetinoid) risks.push(isCn ? '含维A类成分，初期更可能出现刺激/干燥。' : 'Contains retinoid-like ingredients with higher irritation/dryness risk early on.');
  if (hasAcid) risks.push(isCn ? '含酸类成分，频率与叠加需更谨慎。' : 'Contains exfoliating acids; frequency and layering need caution.');
  if (hasFragrance || hasEssentialOil) {
    if (inciVerified) {
      risks.push(
        isCn
          ? '成分表已确认含香精/香料相关成分，敏感肌更建议先做局部测试。'
          : 'Fragrance/fragrance-related ingredients confirmed in INCI; patch testing recommended for sensitive skin.',
      );
    } else {
      risks.push(
        isCn
          ? '成分来源未完全验证，可能含香精/香料相关成分，建议核实后再判断。'
          : 'INCI not fully verified — fragrance/fragrance-related ingredients possible; verify before relying on this assessment.',
      );
    }
  }
  if (hasAlcoholDenat && sensitiveProfile) {
    risks.push(
      isCn
        ? '敏感或屏障不稳时，酒精变性配方可能增加刺痛概率。'
        : 'With sensitive or impaired barrier, denatured alcohol can increase stinging risk.',
    );
  }
  return uniqCaseInsensitiveStrings(risks, 4);
}

function deriveKeyIngredientsForAnalysis(inciList, keyHints) {
  const hints = uniqCaseInsensitiveStrings(Array.isArray(keyHints) ? keyHints : [], 12);
  const inci = uniqCaseInsensitiveStrings(Array.isArray(inciList) ? inciList : [], 120);
  const picked = [];
  const seen = new Set();

  const add = (v) => {
    const s = normalizeInciIngredientName(v);
    if (!s) return;
    if (isLikelyInvalidInciToken(s)) return;
    const key = s.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    picked.push(s);
  };

  for (const item of hints) add(item);

  const activePatterns = [
    /\b(peptide|tripeptide|tetrapeptide|hexapeptide|pentapeptide|niacinamide|salicylic|glycolic|lactic|mandelic|retinol|retinal|adapalene|tretinoin|azelaic|tranexamic|ascorbic|vitamin c|ceramide|panthenol|hyaluronate|hyaluronic|allantoin)\b/i,
  ];
  for (const item of inci) {
    if (activePatterns.some((re) => re.test(item))) add(item);
    if (picked.length >= 10) break;
  }
  if (!picked.length) {
    for (const item of inci) {
      if (/^aqua|^water$/i.test(item)) continue;
      add(item);
      if (picked.length >= 8) break;
    }
  }
  return picked.slice(0, 10);
}

const INCI_INVALID_PHRASE_PATTERNS = [
  /as we wrote in our lengthy retinol description/i,
  /read more|learn more|discover|shop now|add to cart|buy now/i,
  /\b(how to use|frequently asked|faq|full routine|overview)\b/i,
  /\b(copyright|all rights reserved|privacy policy|terms of use)\b/i,
  /\b(choose size|selected because|strong category\/use-case)\b/i,
  /^key ingredients?[:\s]/i,
  /^active ingredients?[:\s]/i,
  /^other ingredients?[:\s]/i,
  /^ingredients?[:\s]/i,
  /^full ingredients?[:\s]/i,
  /^inactive ingredients?[:\s]/i,
  /^(directions|usage|warning|caution|disclaimer|note|notes)[:\s]/i,
  /^(contains|formula|composition)[:\s]/i,
  /^成分[：:]/,
  /^主要成分/,
  /^全成分/,
];

function isLikelyInvalidInciToken(raw) {
  const text = String(raw || '').trim();
  if (!text) return true;
  if (text.length < 2 || text.length > 120) return true;
  if (INCI_INVALID_PHRASE_PATTERNS.some((re) => re.test(text))) return true;
  if (/[?!]/.test(text)) return true;
  if (/https?:\/\//i.test(text)) return true;
  if (/\b(this|that|your|our|we|you|they|recommended|selected)\b/i.test(text) && text.split(/\s+/).length > 5) return true;
  if (/[\u4e00-\u9fff]/.test(text) && /说明|描述|介绍|推荐|适合/.test(text)) return true;
  if (/[:\uff1a]$/.test(text)) return true;
  if (/^(key|active|other|full|inactive|main)\s+ingredient/i.test(text)) return true;
  if (/^\*+\s*(key|active|main)/i.test(text)) return true;
  const words = text.split(/\s+/).filter(Boolean);
  if (words.length > 8) return true;
  const alphaNumRatio = (text.match(/[a-z0-9]/gi) || []).length / Math.max(1, text.length);
  if (alphaNumRatio < 0.25) return true;
  return false;
}

function canonicalizeIngredientCandidates(candidates, { max = 120 } = {}) {
  const out = [];
  const seen = new Set();
  for (const raw of Array.isArray(candidates) ? candidates : []) {
    const normalized = normalizeInciIngredientName(raw);
    if (!normalized) continue;
    if (isLikelyInvalidInciToken(normalized)) continue;
    const key = normalized.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(normalized);
    if (out.length >= Math.max(1, Math.min(300, Number(max) || 120))) break;
  }
  return out;
}

function buildIngredientConsensus({
  official = [],
  regulatory = [],
  retail = [],
  inciDecoder = [],
  llmVerified = [],
  llmMatchScore = 0,
} = {}) {
  const officialNorm = canonicalizeIngredientCandidates([...(Array.isArray(official) ? official : []), ...(Array.isArray(regulatory) ? regulatory : [])], { max: 220 });
  const retailNorm = canonicalizeIngredientCandidates(retail, { max: 180 });
  const inciNorm = canonicalizeIngredientCandidates(inciDecoder, { max: 180 });
  const llmNorm = canonicalizeIngredientCandidates(llmVerified, { max: 180 });
  const union = canonicalizeIngredientCandidates([...officialNorm, ...retailNorm, ...inciNorm, ...llmNorm], { max: 260 });
  const officialSet = new Set(officialNorm.map((item) => item.toLowerCase()));
  const retailSet = new Set(retailNorm.map((item) => item.toLowerCase()));
  const inciSet = new Set(inciNorm.map((item) => item.toLowerCase()));
  const llmSet = new Set(llmNorm.map((item) => item.toLowerCase()));
  const overlapRetailOfficial = retailNorm.filter((item) => officialSet.has(item.toLowerCase())).length;
  const overlapInciOfficial = inciNorm.filter((item) => officialSet.has(item.toLowerCase())).length;
  const overlapLlmOfficial = llmNorm.filter((item) => officialSet.has(item.toLowerCase())).length;
  const crossSourceCovered = union.filter((item) => {
    const key = item.toLowerCase();
    let sourceHits = 0;
    if (officialSet.has(key)) sourceHits += 1;
    if (retailSet.has(key)) sourceHits += 1;
    if (inciSet.has(key)) sourceHits += 1;
    if (llmSet.has(key)) sourceHits += 1;
    return sourceHits >= 2;
  }).length;
  const hasOfficial = officialNorm.length > 0;
  const hasLlm = llmNorm.length > 0;
  const effectiveLlmMatchScore = Number(llmMatchScore) || 0;
  const highConflict = hasOfficial
    ? (
      (retailNorm.length > 0 && overlapRetailOfficial / Math.max(1, retailNorm.length) < 0.25) ||
      (inciNorm.length > 0 && overlapInciOfficial / Math.max(1, inciNorm.length) < 0.2)
    )
    : false;
  const llmCorroboratesOfficial = hasOfficial && hasLlm && effectiveLlmMatchScore > 0.7;
  const llmAloneReasonable = !hasOfficial && hasLlm && effectiveLlmMatchScore > 0.5;
  const confidenceTier =
    (hasOfficial && crossSourceCovered >= 3) || llmCorroboratesOfficial
      ? 'high'
      : hasOfficial || crossSourceCovered >= 2 || llmAloneReasonable
        ? 'med'
        : union.length
          ? 'low'
          : 'none';

  return {
    merged: union,
    has_conflict: Boolean(highConflict),
    confidence_tier: confidenceTier,
    stats: {
      official_count: officialNorm.length,
      retail_count: retailNorm.length,
      inci_decoder_count: inciNorm.length,
      llm_verified_count: llmNorm.length,
      overlap_retail_official: overlapRetailOfficial,
      overlap_inci_official: overlapInciOfficial,
      overlap_llm_official: overlapLlmOfficial,
      cross_source_covered: crossSourceCovered,
      llm_match_score: effectiveLlmMatchScore,
    },
  };
}

const UV_FILTER_ACTIVES = [
  'homosalate',
  'avobenzone',
  'octinoxate',
  'octocrylene',
  'octisalate',
  'oxybenzone',
  'zinc oxide',
  'titanium dioxide',
  'tinosorb',
  'uvinul',
  'bis-ethylhexyloxyphenol methoxyphenyl triazine',
  'methylene bis-benzotriazolyl',
  'diethylamino hydroxybenzoyl hexyl benzoate',
  'ethylhexyl triazone',
  'iscotrizinol',
  'drometrizole trisiloxane',
];

const AHA_BHA_RETINOID_ACTIVES = [
  'retinol',
  'retinal',
  'retinoate',
  'retinaldehyde',
  'adapalene',
  'tretinoin',
  'glycolic acid',
  'lactic acid',
  'mandelic acid',
  'malic acid',
  'tartaric acid',
  'citric acid',
  'salicylic acid',
  'beta-hydroxy',
  'benzoyl peroxide',
  'azelaic acid',
  'polyhydroxy acid',
  'gluconolactone',
  'lactobionic acid',
];

function classifyProductType({ name = '', url = '', inciList = [] } = {}) {
  const nameLower = String(name || '').toLowerCase();
  const urlLower = String(url || '').toLowerCase();
  const inciJoined = Array.isArray(inciList)
    ? inciList.map((i) => String(i || '').toLowerCase()).join(' | ')
    : '';

  const hasSpfText = /\bspf\b|\bsunscreen\b|\bsun protect|\bsun block|\b防晒\b/.test(nameLower + ' ' + urlLower);
  const hasUvFilter = UV_FILTER_ACTIVES.some((f) => inciJoined.includes(f));
  const hasAhaBhaRetinoid = AHA_BHA_RETINOID_ACTIVES.some((a) => inciJoined.includes(a));

  const hasCleanserText = /\bcleanse|\bcleanser|\bface wash|\bfoaming|\bmicellar|\bexfoliat|\b洁面\b|\b洗面\b/.test(nameLower);
  const hasMoisturizerText = /\bmoisturiz|\bcream\b|\blotion\b|\bemulsion\b|\bbalm\b|\b乳液\b|\b面霜\b|\b保湿\b/.test(nameLower);
  const hasSerumText = /\bserum\b|\bessence\b|\bampoule\b|\bbooster\b|\b精华\b/.test(nameLower);
  const hasTonerText = /\btoner\b|\btoning\b|\bsoftener\b|\b水\b|\b化妆水\b/.test(nameLower);
  const hasMaskText = /\bmask\b|\bsheet mask\b|\bclay mask\b|\b面膜\b/.test(nameLower);

  let product_type;
  if (hasSpfText || hasUvFilter) {
    product_type = hasMoisturizerText ? 'spf_moisturizer' : 'spf';
  } else if (hasAhaBhaRetinoid) {
    product_type = 'active_treatment';
  } else if (hasCleanserText) {
    product_type = 'cleanser';
  } else if (hasSerumText) {
    product_type = 'serum';
  } else if (hasTonerText) {
    product_type = 'toner';
  } else if (hasMaskText) {
    product_type = 'mask';
  } else if (hasMoisturizerText) {
    product_type = 'moisturizer';
  } else {
    product_type = 'other';
  }

  const usage_overrides = {};
  if (product_type === 'spf' || product_type === 'spf_moisturizer') {
    usage_overrides.when = 'AM_only';
    usage_overrides.frequency = 'daily';
    usage_overrides.reapply_guidance = true;
    usage_overrides.suppress_pm_first = true;
    usage_overrides.suppress_2_3x_week = true;
  } else if (product_type === 'active_treatment') {
    usage_overrides.allow_intro_schedule = true;
  } else if (product_type === 'cleanser') {
    usage_overrides.when = 'Both';
    usage_overrides.frequency = 'daily';
  } else if (product_type === 'moisturizer' || product_type === 'spf_moisturizer') {
    usage_overrides.when = 'Both';
    usage_overrides.frequency = 'daily';
  }

  return { product_type, usage_overrides };
}

function buildInciStatus({ gapCodes = [], consensusResult = null, sources = [] } = {}) {
  const codes = Array.isArray(gapCodes) ? gapCodes.map((c) => String(c || '').toLowerCase()) : [];

  const extraction = codes.includes('on_page_fetch_blocked')
    ? 'blocked'
    : (consensusResult?.merged?.length > 0 || codes.includes('incidecoder_source_used') || codes.includes('regulatory_source_used') || codes.includes('llm_verification_used'))
      ? 'success'
      : 'missing';

  const consensusTier = (() => {
    const tier = String(consensusResult?.confidence_tier || '').toLowerCase();
    if (tier === 'high') return 'high';
    if (tier === 'med' || tier === 'medium') return 'medium';
    return 'low';
  })();

  const verification_required = consensusTier === 'low' || extraction === 'blocked' || extraction === 'missing';
  const total_ingredients = Array.isArray(consensusResult?.merged) ? consensusResult.merged.length : 0;

  const normalizedSources = Array.isArray(sources)
    ? sources
      .map((s) => ({
        type: String(s?.type || '').trim(),
        url: String(s?.url || '').trim(),
        confidence: s?.confidence != null ? Number(s.confidence) : null,
        ingredient_count: s?.ingredient_count != null ? Number(s.ingredient_count) : null,
      }))
      .filter((s) => s.type || s.url)
    : [];

  return {
    extraction,
    consensus_tier: consensusTier,
    sources: normalizedSources,
    verification_required,
    total_ingredients,
  };
}

function normalizeInciIngredientName(raw) {
  const source = String(raw || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\[\s*more\s*\]\s*/gi, ' ')
    .replace(/\(\s*more\s*\)\s*/gi, ' ')
    .replace(/^(?:show|read|view|see)\s+more\s*[:\-]?\s*/i, '')
    .replace(/\b(?:show|read|view|see)\s+more\b/gi, ' ')
    .replace(/^(?:full|inactive|active|key|main|other)\s+ingredients?\s*[:：\-]?\s*/i, '')
    .replace(/^ingredients?\s*[:：\-]?\s*/i, '')
    .replace(/^[-•·\s]+/, '')
    .replace(/\s*[•·]\s*/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!source) return '';
  if (/^(?:full|inactive|active|key|main|other)\s+ingredients?$/i.test(source)) return '';
  if (/^ingredients?$/i.test(source)) return '';
  return source
    .split(/\s+/)
    .map((token) => {
      const t = String(token || '').trim();
      if (!t) return '';
      if (/^[A-Z0-9+%(),./-]+$/.test(t)) return t;
      return t
        .split('-')
        .map((part) => {
          const s = String(part || '').trim();
          if (!s) return '';
          if (/^[A-Z0-9]+$/.test(s)) return s;
          return `${s.slice(0, 1).toUpperCase()}${s.slice(1).toLowerCase()}`;
        })
        .join('-');
    })
    .join(' ')
    .trim();
}

function countRegexMatches(text, regex) {
  if (!(regex instanceof RegExp)) return 0;
  const rawFlags = String(regex.flags || '');
  const flags = rawFlags.includes('g') ? rawFlags : `${rawFlags}g`;
  const re = new RegExp(regex.source, flags);
  let count = 0;
  while (re.exec(text)) {
    count += 1;
    if (count >= 2000) break;
  }
  return count;
}

function collectThemeCountsFromText(text, definitions) {
  const out = [];
  for (const def of Array.isArray(definitions) ? definitions : []) {
    const label = String(def?.label || '').trim();
    if (!label) continue;
    const patterns = Array.isArray(def?.patterns) ? def.patterns : [];
    let count = 0;
    for (const re of patterns) count += countRegexMatches(text, re);
    if (count > 0) out.push({ label, count });
  }
  out.sort((a, b) => {
    if (b.count !== a.count) return b.count - a.count;
    return String(a.label || '').localeCompare(String(b.label || ''));
  });
  return out;
}

function extractAggregateRatingFromHtml(html) {
  const source = String(html || '');
  if (!source) return { rating_value: null, review_count: null };

  const ratingRaw =
    source.match(/"ratingValue"\s*:\s*"?([0-9]+(?:\.[0-9]+)?)"?/i)?.[1] ||
    source.match(/itemprop\s*=\s*"ratingValue"[^>]*content\s*=\s*"([0-9]+(?:\.[0-9]+)?)"/i)?.[1] ||
    null;
  const reviewRaw =
    source.match(/"reviewCount"\s*:\s*"?([0-9]{1,8})"?/i)?.[1] ||
    source.match(/itemprop\s*=\s*"reviewCount"[^>]*content\s*=\s*"([0-9]{1,8})"/i)?.[1] ||
    null;

  let ratingValue = ratingRaw != null ? Number(ratingRaw) : null;
  if (!Number.isFinite(ratingValue)) ratingValue = null;
  if (ratingValue != null && ratingValue > 5 && ratingValue <= 10) ratingValue = ratingValue / 2;
  if (ratingValue != null && (ratingValue < 0 || ratingValue > 5)) ratingValue = null;

  let reviewCount = reviewRaw != null ? Number(reviewRaw) : null;
  if (!Number.isFinite(reviewCount) || reviewCount < 0) reviewCount = null;
  if (reviewCount != null) reviewCount = Math.trunc(reviewCount);

  return { rating_value: ratingValue, review_count: reviewCount };
}

function extractRealtimeSocialSignalsFromHtml(html, { lang = 'EN', riskNotes = [] } = {}) {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const sourceText = stripHtmlToText(html).toLowerCase();
  const text = sourceText.length > 240000 ? sourceText.slice(0, 240000) : sourceText;

  const positiveThemes = collectThemeCountsFromText(text, [
    { label: isCn ? '补水保湿' : 'hydration', patterns: [/\bhydrat(?:e|ing|ion)\b/gi, /\bmoisturi(?:z|s)(?:e|ing|er)\b/gi, /补水|保湿/gi] },
    { label: isCn ? '舒缓温和' : 'soothing', patterns: [/\bsoothing?\b/gi, /\bcalm(?:ing)?\b/gi, /舒缓|温和/gi] },
    { label: isCn ? '肤感轻薄' : 'lightweight texture', patterns: [/\blightweight\b/gi, /\bnon[-\s]?greasy\b/gi, /清爽|轻薄/gi] },
    { label: isCn ? '紧致细纹' : 'firming', patterns: [/\bfirm(?:ing|ness)?\b/gi, /\bfine lines?\b/gi, /紧致|细纹/gi] },
    { label: isCn ? '提亮均匀' : 'brightening', patterns: [/\bbrighten(?:ing)?\b/gi, /\beven tone\b/gi, /提亮|均匀肤色/gi] },
  ]);
  const negativeThemes = collectThemeCountsFromText(text, [
    { label: isCn ? '搓泥/黏腻' : 'sticky or pilling', patterns: [/\bsticky\b/gi, /\bpill(?:ing)?\b/gi, /搓泥|黏腻|粘腻/gi] },
    { label: isCn ? '刺痛泛红' : 'stinging or redness', patterns: [/\bsting(?:ing)?\b/gi, /\bred(?:ness)?\b/gi, /\birritat(?:e|ion)\b/gi, /刺痛|泛红|刺激/gi] },
    { label: isCn ? '爆痘/闷痘' : 'breakout concerns', patterns: [/\bbreak ?out(?:s)?\b/gi, /\bclog(?:ged)? pores?\b/gi, /爆痘|闷痘/gi] },
    { label: isCn ? '偏干/拔干' : 'drying feel', patterns: [/\bdry(?:ing|ness)?\b/gi, /\btight(?:ness)?\b/gi, /拔干|干燥|紧绷/gi] },
  ]);

  const rating = extractAggregateRatingFromHtml(html);
  const positiveLabels = positiveThemes.slice(0, 5).map((row) => row.label);
  const negativeLabels = negativeThemes.slice(0, 5).map((row) => row.label);
  const totalPos = positiveThemes.reduce((sum, row) => sum + Number(row.count || 0), 0);
  const totalNeg = negativeThemes.reduce((sum, row) => sum + Number(row.count || 0), 0);

  const combinedRiskText = `${String(riskNotes.join(' | ') || '').toLowerCase()} | ${negativeLabels.join(' | ').toLowerCase()} | ${text}`;
  const riskForGroups = uniqCaseInsensitiveStrings(
    [
      /\bsting|red|irritat|sensitive|刺痛|泛红|刺激/.test(combinedRiskText)
        ? isCn
          ? '敏感肌：先低频试用并观察刺痛/泛红。'
          : 'Sensitive skin: start low and monitor for stinging/redness.'
        : '',
      /\bbreakout|clog|acne|闷痘|爆痘/.test(combinedRiskText)
        ? isCn
          ? '易痘肌：关注是否闷痘，避免厚重叠加。'
          : 'Acne-prone skin: watch for clogging/breakout feedback.'
        : '',
      /\bdry|tight|barrier|干燥|紧绷|屏障/.test(combinedRiskText)
        ? isCn
          ? '屏障不稳：加强保湿封层，降低活性叠加。'
          : 'Impaired barrier: prioritize moisturizer and reduce active layering.'
        : '',
    ],
    4,
  );

  const platformScores = {};
  if (rating.rating_value != null) {
    platformScores.BrandSite = Number(Math.max(0, Math.min(1, rating.rating_value / 5)).toFixed(3));
  } else if (totalPos > 0 || totalNeg > 0) {
    const base = 0.52 + (totalPos - totalNeg) / Math.max(6, totalPos + totalNeg);
    platformScores.BrandSite = Number(Math.max(0.35, Math.min(0.8, base)).toFixed(3));
  }

  const notes = uniqCaseInsensitiveStrings(
    [
      rating.rating_value != null
        ? isCn
          ? `页面可见评分约 ${rating.rating_value.toFixed(1)}/5${rating.review_count != null ? `（样本 ${rating.review_count}）` : ''}。`
          : `Visible page rating is about ${rating.rating_value.toFixed(1)}/5${rating.review_count != null ? ` (n=${rating.review_count})` : ''}.`
        : '',
      totalPos || totalNeg
        ? isCn
          ? `页面文本信号汇总：正向主题 ${totalPos}，负向主题 ${totalNeg}。`
          : `On-page text signals: positive themes ${totalPos}, negative themes ${totalNeg}.`
        : '',
      isCn
        ? '说明：该社媒信号来自产品页公开文本，非全平台实时抓取。'
        : 'Note: these social signals are aggregated from public product-page text, not full cross-platform crawl.',
    ],
    3,
  );

  return {
    platform_scores: platformScores,
    typical_positive: positiveLabels,
    typical_negative: negativeLabels,
    risk_for_groups: riskForGroups,
    notes,
    has_signal: Boolean(Object.keys(platformScores).length || positiveLabels.length || negativeLabels.length || riskForGroups.length),
    review_count: rating.review_count,
  };
}

function tokenizeProductTextForSimilarity(raw) {
  const stopWords = new Set([
    'the', 'and', 'for', 'with', 'from', 'this', 'that', 'serum', 'cream', 'mask', 'toner', 'lotion', 'face', 'skin',
    'product', 'multi', 'plus', 'care', 'daily', 'night', 'day',
  ]);
  return Array.from(
    new Set(
      String(raw || '')
        .toLowerCase()
        .split(/[^a-z0-9]+/)
        .map((token) => token.trim())
        .filter((token) => token.length >= 3 && !stopWords.has(token)),
    ),
  );
}

function inferProductCategoryToken(raw) {
  const text = String(raw || '').toLowerCase();
  if (!text) return '';
  const categories = ['serum', 'essence', 'cream', 'moisturizer', 'cleanser', 'toner', 'sunscreen', 'spf', 'mask', 'oil'];
  return categories.find((token) => new RegExp(`\\b${token}\\b`, 'i').test(text)) || '';
}

function scoreCategoryUseCaseMatch({
  anchorCategoryToken = '',
  candidateNameText = '',
  candidateCategoryText = '',
} = {}) {
  const anchorToken = String(anchorCategoryToken || '').trim().toLowerCase();
  if (!anchorToken) return 0.7;

  const candidateToken = inferProductCategoryToken(`${candidateNameText || ''} ${candidateCategoryText || ''}`);
  if (candidateToken && candidateToken === anchorToken) return 1;
  if (candidateToken && candidateToken !== anchorToken) return 0.32;
  if (String(candidateCategoryText || '').trim()) return 0.48;
  return 0.58;
}

function computeTokenJaccardScore(a, b) {
  const left = Array.from(new Set(Array.isArray(a) ? a.map((x) => String(x || '').trim().toLowerCase()).filter(Boolean) : []));
  const right = Array.from(new Set(Array.isArray(b) ? b.map((x) => String(x || '').trim().toLowerCase()).filter(Boolean) : []));
  if (!left.length || !right.length) return null;
  const rightSet = new Set(right);
  let inter = 0;
  for (const token of left) {
    if (rightSet.has(token)) inter += 1;
  }
  const union = left.length + right.length - inter;
  if (!union) return null;
  return clamp01Score(inter / union);
}

function buildProfileSkinTags(profileSummary) {
  const profile = profileSummary && typeof profileSummary === 'object' && !Array.isArray(profileSummary) ? profileSummary : null;
  if (!profile) return [];
  const out = [];
  const add = (value) => {
    const tag = normalizeSkinTypeTag(value);
    if (!tag) return;
    if (!out.includes(tag)) out.push(tag);
  };
  add(profile.skinType);
  const sensitivity = String(profile.sensitivity || '').trim().toLowerCase();
  if (sensitivity === 'high' || sensitivity === 'medium' || sensitivity === 'sensitive' || sensitivity === 'reactive') {
    add('sensitive');
  } else {
    add(sensitivity);
  }
  const barrier = String(profile.barrierStatus || '').trim().toLowerCase();
  if (barrier === 'impaired' || barrier === 'damaged' || barrier === 'reactive') add('impaired_barrier');
  else add(barrier);
  for (const goal of Array.isArray(profile.goals) ? profile.goals : []) add(goal);
  return out.slice(0, 8);
}

function computeSkinFitSimilarity(profileTags, candidateTags) {
  const profile = Array.isArray(profileTags) ? profileTags.filter(Boolean) : [];
  const candidate = Array.isArray(candidateTags) ? candidateTags.filter(Boolean) : [];
  if (!profile.length) return 0.5;
  if (!candidate.length) return 0.42;
  const pSet = new Set(profile);
  let matched = 0;
  for (const tag of candidate) {
    if (pSet.has(tag)) matched += 1;
  }
  const base = matched / Math.max(1, Math.min(profile.length, 3));
  return clamp01Score(base);
}

function computeSocialReferenceScore({ baseScore, supportCount, hitCount, totalQueries }) {
  const ratingScore = baseScore == null ? 0.5 : clamp01Score(baseScore);
  const queryCap = Math.max(1, Math.min(4, Number(totalQueries) || 1));
  const freq = Math.max(0, (Number(hitCount) || 0) - 1);
  const coMention = queryCap <= 1 ? 0 : clamp01Score(freq / (queryCap - 1));
  const supportBoost =
    Number.isFinite(Number(supportCount)) && Number(supportCount) > 0
      ? Math.min(0.06, Math.log10(1 + Number(supportCount)) * 0.016)
      : 0;
  return clamp01Score(ratingScore * 0.78 + coMention * 0.22 + supportBoost);
}

function scoreRealtimeCompetitorCandidate({
  queryOverlap = 0,
  ingredientNameOverlap = 0,
  sameCategory = false,
  sameBrand = false,
  anchorIngredientTokens = [],
  candidateIngredientTokens = [],
  profileSkinTags = [],
  candidateSkinTags = [],
  candidateSocialScore = null,
  candidateSocialSupportCount = null,
  recallHitCount = 1,
  totalQueries = 1,
} = {}) {
  const queryScore = clamp01Score(queryOverlap > 0 ? Math.min(1, queryOverlap / 3) : 0.25);
  const ingredientNameScore = clamp01Score(ingredientNameOverlap > 0 ? Math.min(1, ingredientNameOverlap / 2) : 0);
  const ingredientJaccard = computeTokenJaccardScore(anchorIngredientTokens, candidateIngredientTokens);
  const ingredientSimilarity =
    ingredientJaccard == null
      ? clamp01Score(ingredientNameScore > 0 ? 0.4 + ingredientNameScore * 0.45 : 0.45)
      : clamp01Score(ingredientJaccard * 0.65 + ingredientNameScore * 0.35);

  const skinFitSimilarity = computeSkinFitSimilarity(profileSkinTags, candidateSkinTags);
  const socialReferenceScore = computeSocialReferenceScore({
    baseScore: candidateSocialScore,
    supportCount: candidateSocialSupportCount,
    hitCount: recallHitCount,
    totalQueries,
  });

  const breakdown = {
    category_score: sameCategory ? 1 : 0,
    ingredient_similarity: Number(ingredientSimilarity.toFixed(3)),
    skin_fit_similarity: Number(skinFitSimilarity.toFixed(3)),
    social_reference_score: Number(socialReferenceScore.toFixed(3)),
    query_overlap_score: Number(queryScore.toFixed(3)),
    brand_score: sameBrand ? 1 : 0,
  };

  const weighted =
    breakdown.category_score * 0.2 +
    breakdown.ingredient_similarity * 0.24 +
    breakdown.skin_fit_similarity * 0.17 +
    breakdown.social_reference_score * 0.17 +
    breakdown.query_overlap_score * 0.17 +
    breakdown.brand_score * 0.05;

  return {
    similarity_score: Number(Math.max(0.22, Math.min(0.95, weighted)).toFixed(3)),
    score_breakdown: breakdown,
  };
}

async function buildRealtimeCompetitorCandidates({
  productUrl,
  parsedProduct = null,
  keyIngredients = [],
  anchorProduct = null,
  profileSummary = null,
  lang = 'EN',
  mode = 'main_path',
  deadlineMs = 0,
  timeoutMs = PRODUCT_URL_REALTIME_COMPETITOR_TIMEOUT_MS,
  maxQueries = PRODUCT_URL_REALTIME_COMPETITOR_MAX_QUERIES,
  maxCandidates = PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  searchFn = null,
  logger,
} = {}) {
  const isCn = String(lang || '').toUpperCase() === 'CN';
  const catalogSearchBaseUrls = buildRecoCatalogSearchBaseUrlCandidates({
    includeLocalFallback:
      RECO_PDP_LOCAL_INVOKE_FALLBACK_CHAT_ENABLED &&
      RECO_PDP_LOCAL_INVOKE_FALLBACK_ENABLED,
  });
  if (!catalogSearchBaseUrls.length) {
    return { candidates: [], queries: [], reason: 'pivota_backend_not_configured' };
  }
  const startedAt = Date.now();
  const effectiveTimeoutMs = Math.max(
    260,
    Math.min(12000, Number.isFinite(Number(timeoutMs)) ? Math.trunc(Number(timeoutMs)) : PRODUCT_URL_REALTIME_COMPETITOR_TIMEOUT_MS),
  );
  const normalizedDeadlineMs = Number.isFinite(Number(deadlineMs)) ? Math.trunc(Number(deadlineMs)) : 0;
  const absoluteDeadlineMs = normalizedDeadlineMs > 0
    ? Math.min(normalizedDeadlineMs, startedAt + effectiveTimeoutMs)
    : startedAt + effectiveTimeoutMs;
  // Return before outer DAG source timeout to avoid dropping the whole block on wrapper timeout.
  const softDeadlineMs = Math.max(
    startedAt + 120,
    absoluteDeadlineMs - PRODUCT_URL_REALTIME_COMPETITOR_RETURN_SLACK_MS,
  );
  const normalizedMode = String(mode || '').trim().toLowerCase();
  const runMode =
    normalizedMode === 'sync_repair' || normalizedMode === 'async_backfill'
      ? normalizedMode
      : 'main_path';
  const syncResolveFallbackEnabled = (() => {
    const raw = String(process.env.AURORA_BFF_RECO_COMPETITOR_SYNC_RESOLVE_FALLBACK || 'false')
      .trim()
      .toLowerCase();
    return raw === 'true' || raw === '1' || raw === 'yes' || raw === 'y' || raw === 'on';
  })();
  const asyncResolveFallbackEnabled = (() => {
    const raw = String(process.env.AURORA_BFF_RECO_COMPETITOR_ASYNC_RESOLVE_FALLBACK || 'false')
      .trim()
      .toLowerCase();
    return raw === 'true' || raw === '1' || raw === 'yes' || raw === 'y' || raw === 'on';
  })();
  const allowResolveFallback =
    (runMode === 'async_backfill' && asyncResolveFallbackEnabled) ||
    (runMode === 'sync_repair' && syncResolveFallbackEnabled) ||
    (runMode === 'main_path' && PRODUCT_URL_REALTIME_COMPETITOR_MAIN_RESOLVE_FALLBACK);
  const searchAllMerchants =
    runMode !== 'main_path'
      ? true
      : PRODUCT_URL_REALTIME_COMPETITOR_MAIN_SEARCH_ALL_MERCHANTS;
  const allowExternalSeed =
    runMode === 'async_backfill'
      ? PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_ALLOW_EXTERNAL_SEED
      : runMode === 'sync_repair'
        ? PRODUCT_URL_REALTIME_COMPETITOR_SYNC_ALLOW_EXTERNAL_SEED
        : PRODUCT_URL_REALTIME_COMPETITOR_MAIN_ALLOW_EXTERNAL_SEED;
  const externalSeedStrategy = allowExternalSeed
    ? PRODUCT_URL_REALTIME_COMPETITOR_EXTERNAL_SEED_STRATEGY
    : 'legacy';
  const runSearch = typeof searchFn === 'function' ? searchFn : searchPivotaBackendProducts;
  const transientReasons = new Set(['upstream_timeout', 'upstream_error', 'rate_limited']);
  const getRemainingMs = () => Math.max(0, softDeadlineMs - Date.now());
  const reserveAfterSearchMs =
    runMode === 'async_backfill'
      ? 180
      : runMode === 'sync_repair'
        ? 280
        : 120;
  const effectiveSearchTimeoutMs = Math.max(
    260,
    Math.min(
      effectiveTimeoutMs,
      Math.max(260, effectiveTimeoutMs - reserveAfterSearchMs),
    ),
  );

  const parsedProductObj = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  const anchorObj = anchorProduct && typeof anchorProduct === 'object' && !Array.isArray(anchorProduct) ? anchorProduct : parsedProductObj;
  const anchorId = pickFirstTrimmed(anchorObj?.product_id, anchorObj?.sku_id);
  const anchorBrand = pickFirstTrimmed(anchorObj?.brand);
  const anchorText = buildProductInputText(anchorObj, null) || '';

  const baseInput = buildProductInputText(parsedProductObj, null) || String(productUrl || '').trim();
  const fromCatalogQueries = buildProductCatalogQueryCandidates({
    inputText: baseInput,
    inputUrl: productUrl,
    parsedProduct: parsedProductObj,
  });
  const categoryToken = inferProductCategoryToken(`${anchorText} ${baseInput}`);
  const queries = buildRealtimeCompetitorQueryPlan({
    fromCatalogQueries,
    keyIngredients,
    parsedProduct: parsedProductObj,
    categoryToken,
    maxQueries,
  });
  if (!queries.length) return { candidates: [], queries: [], reason: 'query_missing' };

  const rankAsyncQuery = (queryText) => {
    const text = String(queryText || '').trim().toLowerCase();
    if (!text) return -999;
    const tokens = text.split(/\s+/).filter(Boolean);
    const tokenCount = tokens.length;
    let score = 0;
    if (categoryToken && text.includes(String(categoryToken).toLowerCase())) score += 2;
    if (/\b(peptide|retinol|niacinamide|salicylic|glycolic|lactic|hyaluronic|ceramide)\b/.test(text)) score += 3;
    if (tokenCount >= 2 && tokenCount <= 6) score += 1;
    if (tokenCount >= 7) score -= 1;
    if (anchorBrand && text.includes(String(anchorBrand).toLowerCase()) && tokenCount >= 4) score -= 2;
    return score;
  };
  const orderedQueries =
    runMode === 'async_backfill'
      ? queries
        .slice()
        .sort((left, right) => {
          const scoreDiff = rankAsyncQuery(right) - rankAsyncQuery(left);
          if (scoreDiff !== 0) return scoreDiff;
          return String(left || '').length - String(right || '').length;
        })
      : queries;

  const minimumPerQueryBudgetMs = runMode === 'main_path' ? 420 : 320;
  const maxQueriesByBudget = Math.max(
    1,
    Math.min(
      orderedQueries.length,
      Math.floor(Math.max(minimumPerQueryBudgetMs, getRemainingMs()) / minimumPerQueryBudgetMs),
    ),
  );
  const mainPathFanoutCap =
    runMode === 'main_path' && allowResolveFallback
      ? PRODUCT_URL_REALTIME_COMPETITOR_MAIN_QUERY_FANOUT_CAP
      : orderedQueries.length;
  const plannedQueries = orderedQueries.slice(
    0,
    Math.max(1, Math.min(orderedQueries.length, Math.min(maxQueriesByBudget, mainPathFanoutCap))),
  );
  const searchResults = [];
  const reasonCounts = Object.create(null);
  const attemptedSourceSet = new Set();
  const attemptedSourceEndpointSet = new Set();
  let resolverFirstApplied = false;
  let resolverFirstSkippedForAurora = false;
  let sourceTemporarilyDeprioritized = false;
  const bumpReason = (rawReason) => {
    const token = String(rawReason || '').trim().toLowerCase();
    if (!token) return;
    reasonCounts[token] = Number(reasonCounts[token] || 0) + 1;
  };
  const observedRecallHits = new Set();
  const earlyStopTarget =
    runMode === 'main_path'
      ? Math.max(1, Math.min(maxCandidates, PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT))
      : runMode === 'async_backfill'
        ? Math.max(1, Math.min(maxCandidates, Math.max(PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT, 2)))
      : Math.max(1, Math.min(maxCandidates, 6));

  for (let queryIdx = 0; queryIdx < plannedQueries.length; queryIdx += 1) {
    const queryText = plannedQueries[queryIdx];
    const remainingMs = getRemainingMs();
    const isMainFirstQuery = runMode === 'main_path' && queryIdx === 0;
    const firstQueryGraceMs = isMainFirstQuery ? PRODUCT_URL_REALTIME_COMPETITOR_MAIN_LAST_QUERY_GRACE_MS : 0;
    const gatedRemainingMs = remainingMs + firstQueryGraceMs;
    const allowFirstQueryWithTightBudget =
      isMainFirstQuery &&
      gatedRemainingMs >= PRODUCT_URL_REALTIME_COMPETITOR_MAIN_QUERY_MIN_BUDGET_MS;
    if (gatedRemainingMs < 260 && !allowFirstQueryWithTightBudget) {
      searchResults.push({
        query: queryText,
        searched: {
          ok: false,
          products: [],
          reason: 'budget_exhausted',
          latency_ms: 0,
        },
      });
      bumpReason('budget_exhausted');
      break;
    }
    const queriesRemaining = plannedQueries.length - queryIdx;
    const fairShareMs =
      runMode === 'async_backfill'
        ? (() => {
          const reserveForFollowupMs =
            plannedQueries.length > 1 && queryIdx === 0
              ? Math.min(1800, Math.max(1200, Math.trunc(remainingMs * 0.2)))
              : 0;
          return Math.max(260, remainingMs - reserveAfterSearchMs - reserveForFollowupMs);
        })()
        : Math.max(
          220,
          Math.trunc(Math.max(220, remainingMs - reserveAfterSearchMs) / Math.max(1, queriesRemaining)),
        );
    const perQueryMinMs =
      runMode === 'async_backfill'
        ? 260
        : runMode === 'main_path'
          ? PRODUCT_URL_REALTIME_COMPETITOR_MAIN_TIMEOUT_FLOOR_MS
          : 220;
    const perQueryTimeoutMs = Math.max(perQueryMinMs, Math.min(effectiveSearchTimeoutMs, fairShareMs));
    const searchSourceOverride =
      runMode === 'main_path' ? RECO_CATALOG_MAIN_PATH_SEARCH_SOURCE : '';
    // eslint-disable-next-line no-await-in-loop
    const searched = await runSearch({
      query: queryText,
      limit: 6,
      logger,
      timeoutMs: perQueryTimeoutMs,
      minTimeoutMs: perQueryMinMs,
      searchAllMerchants,
      deadlineMs: isMainFirstQuery ? softDeadlineMs + firstQueryGraceMs : softDeadlineMs,
      mode: runMode,
      allowExternalSeed,
      externalSeedStrategy,
      fastMode: true,
      searchSourceOverride,
    });
    searchResults.push({ query: queryText, searched });
    for (const sourceBaseUrl of Array.isArray(searched?.attempted_sources) ? searched.attempted_sources : []) {
      const token = String(sourceBaseUrl || '').trim();
      if (token) attemptedSourceSet.add(token);
    }
    for (const endpoint of Array.isArray(searched?.attempted_endpoints) ? searched.attempted_endpoints : []) {
      const token = String(endpoint || '').trim();
      if (token) attemptedSourceEndpointSet.add(token);
    }
    resolverFirstApplied = resolverFirstApplied || searched?.resolver_first_applied === true;
    resolverFirstSkippedForAurora =
      resolverFirstSkippedForAurora || searched?.resolver_first_skipped_for_aurora === true;
    sourceTemporarilyDeprioritized =
      sourceTemporarilyDeprioritized || searched?.source_temporarily_deprioritized === true;
    if (searched && typeof searched === 'object') {
      if (searched.ok === false) bumpReason(searched.reason || 'upstream_error');
      else if (Array.isArray(searched.products) && searched.products.length === 0) bumpReason('empty');
    }

    const list = Array.isArray(searched?.products) ? searched.products : [];
    for (const product of list) {
      const normalized = normalizeRecoCatalogProduct(product);
      if (!normalized) continue;
      const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
      if (!productId) continue;
      observedRecallHits.add(String(productId).toLowerCase());
    }
    if (observedRecallHits.size >= earlyStopTarget) break;
    if (observedRecallHits.size >= maxCandidates) break;
  }

  const diagnosticQueries = searchResults.map((row) => String(row?.query || '').trim()).filter(Boolean);
  const transientFailureCount =
    Number(reasonCounts.upstream_timeout || 0) +
    Number(reasonCounts.upstream_error || 0) +
    Number(reasonCounts.rate_limited || 0);
  const retrievalBudgetProfile = {
    mode: runMode,
    timeout_ms: effectiveTimeoutMs,
    soft_deadline_ms: Math.max(0, softDeadlineMs - startedAt),
    search_timeout_ms: effectiveSearchTimeoutMs,
    per_query_min_ms: runMode === 'main_path' ? PRODUCT_URL_REALTIME_COMPETITOR_MAIN_TIMEOUT_FLOOR_MS : 220,
  };
  const retrievalMeta = {
    reason_counts: reasonCounts,
    query_attempted: searchResults.length,
    transient_failure_count: transientFailureCount,
    attempted_sources: Array.from(attemptedSourceSet).slice(0, 8),
    attempted_endpoints: Array.from(attemptedSourceEndpointSet).slice(0, 12),
    resolver_first_applied: resolverFirstApplied,
    resolver_first_skipped_for_aurora: resolverFirstSkippedForAurora,
    source_temporarily_deprioritized: sourceTemporarilyDeprioritized,
    budget_profile: retrievalBudgetProfile,
  };
  const queryTokens = tokenizeProductTextForSimilarity(
    (diagnosticQueries.length ? diagnosticQueries : plannedQueries).join(' | '),
  );
  const ingredientTokens = tokenizeProductTextForSimilarity(keyIngredients.slice(0, 6).join(' | '));
  const anchorIngredientTokens = ingredientTokens;
  const profileSkinTags = buildProfileSkinTags(profileSummary);
  const totalQueriesForRecall = Math.max(1, diagnosticQueries.length || plannedQueries.length || queries.length);

  const recallHitCountByProduct = new Map();
  for (const row of searchResults) {
    const list = Array.isArray(row?.searched?.products) ? row.searched.products : [];
    for (const product of list) {
      const normalized = normalizeRecoCatalogProduct(product);
      if (!normalized) continue;
      const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
      if (!productId) continue;
      const key = String(productId).toLowerCase();
      recallHitCountByProduct.set(key, (recallHitCountByProduct.get(key) || 0) + 1);
    }
  }

  const seenProduct = new Set();
  const candidates = [];
  for (const row of searchResults) {
    const list = Array.isArray(row?.searched?.products) ? row.searched.products : [];
    for (const product of list) {
      const normalized = normalizeRecoCatalogProduct(product);
      if (!normalized) continue;
      const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
      if (!productId) continue;
      if (anchorId && productId === anchorId) continue;
      const lowerKey = `${productId}`.toLowerCase();
      if (seenProduct.has(lowerKey)) continue;
      seenProduct.add(lowerKey);

      const brand = pickFirstTrimmed(normalized.brand);
      const name = pickFirstTrimmed(normalized.display_name, normalized.name);
      const candidateText = `${brand} ${name}`.trim().toLowerCase();
      const nameTokens = tokenizeProductTextForSimilarity(candidateText);
      const categoryUseCaseMatch = scoreCategoryUseCaseMatch({
        anchorCategoryToken: categoryToken,
        candidateNameText: candidateText,
        candidateCategoryText: normalized.category || '',
      });

      const queryOverlap = queryTokens.filter((token) => nameTokens.includes(token)).length;
      const ingredientOverlap = ingredientTokens.filter((token) => nameTokens.includes(token)).length;
      const sameBrand = anchorBrand && brand && anchorBrand.toLowerCase() === brand.toLowerCase();
      const sameCategory = categoryUseCaseMatch >= 0.78;
      const scored = scoreRealtimeCompetitorCandidate({
        queryOverlap,
        ingredientNameOverlap: ingredientOverlap,
        sameCategory,
        sameBrand,
        anchorIngredientTokens,
        candidateIngredientTokens: Array.isArray(normalized.ingredient_tokens) ? normalized.ingredient_tokens : [],
        profileSkinTags,
        candidateSkinTags: Array.isArray(normalized.skin_type_tags) ? normalized.skin_type_tags : [],
        candidateSocialScore: normalized.social_ref_score,
        candidateSocialSupportCount: normalized.social_ref_support_count,
        recallHitCount: recallHitCountByProduct.get(lowerKey) || 1,
        totalQueries: totalQueriesForRecall,
      });
      const similarityScore = scored.similarity_score;

      const whyCandidate = uniqCaseInsensitiveStrings(
        [
          sameCategory
            ? isCn
              ? `同品类（${categoryToken}）`
              : `same category (${categoryToken})`
            : '',
          ingredientOverlap
            ? isCn
              ? '与关键活性关键词重合'
              : 'overlap with key-active tokens'
            : '',
          scored.score_breakdown.ingredient_similarity >= 0.62
            ? isCn
              ? '关键成分相似度较高'
              : 'high key-ingredient similarity'
            : '',
          scored.score_breakdown.skin_fit_similarity >= 0.6
            ? isCn
              ? '对当前肤质/敏感度适配度较高'
              : 'better match for current skin profile'
            : '',
          scored.score_breakdown.social_reference_score >= 0.65
            ? isCn
              ? '社媒评分/被对比频次信号较强'
              : 'strong social rating/comparison-reference signal'
            : '',
          (recallHitCountByProduct.get(lowerKey) || 0) > 1
            ? isCn
              ? '多查询重复召回（对比参考热度更高）'
              : 'appears across multiple comparison queries'
            : '',
          sameBrand
            ? isCn
              ? '同品牌相近线产品'
              : 'same-brand nearby option'
            : '',
          queryOverlap
            ? isCn
              ? '产品名/诉求关键词相近'
              : 'similar name/claim keywords'
            : '',
          !sameCategory && !ingredientOverlap && !sameBrand && !queryOverlap
            ? isCn
              ? 'catalog 文本召回候选'
              : 'catalog text-match candidate'
            : '',
        ],
        4,
      );

      const compareHighlights = uniqCaseInsensitiveStrings(
        [
          sameCategory
            ? isCn
              ? '同剂型/场景，可作为平替起点。'
              : 'Same format/use-case, suitable as a dupe baseline.'
            : '',
          scored.score_breakdown.ingredient_similarity >= 0.55
            ? isCn
              ? '关键成分相似度较高，仍需比较浓度与配方结构。'
              : 'Ingredient similarity is high; still compare concentration and formula structure.'
            : '',
          scored.score_breakdown.skin_fit_similarity >= 0.6
            ? isCn
              ? '与用户画像（肤质/敏感度/屏障）匹配度较高。'
              : 'Closer alignment with user skin profile (type/sensitivity/barrier).'
            : '',
          scored.score_breakdown.social_reference_score >= 0.65
            ? isCn
              ? '社媒评分/参考对比信号较强，可优先进入 dupe 比较。'
              : 'Strong social reference signal; prioritize for dupe comparison.'
            : '',
        ],
        3,
      );

      candidates.push({
        product_id: productId,
        name: name || (isCn ? '未知产品' : 'Unknown product'),
        ...(brand ? { brand } : {}),
        ...(normalized.category ? { category: normalized.category } : {}),
        ...(normalized.price ? { price: normalized.price } : {}),
        source: { type: 'catalog_search' },
        source_type: 'catalog_search',
        category_use_case_match: Number(categoryUseCaseMatch.toFixed(3)),
        ...(normalized.social_raw ? { social_raw: normalized.social_raw } : {}),
        why_candidate: whyCandidate,
        similarity_score: similarityScore,
        score_breakdown: scored.score_breakdown,
        ...(compareHighlights.length ? { compare_highlights: compareHighlights } : {}),
      });
    }
  }

  candidates.sort((a, b) => {
    const scoreA = Number.isFinite(Number(a?.similarity_score)) ? Number(a.similarity_score) : 0;
    const scoreB = Number.isFinite(Number(b?.similarity_score)) ? Number(b.similarity_score) : 0;
    if (scoreB !== scoreA) return scoreB - scoreA;
    return String(a?.name || '').localeCompare(String(b?.name || ''));
  });

  let finalCandidates = candidates.slice(0, maxCandidates);
  if (finalCandidates.length) {
    return {
      candidates: finalCandidates,
      queries: diagnosticQueries.length ? diagnosticQueries : plannedQueries,
      reason: null,
      meta: retrievalMeta,
    };
  }
  const allSearchTransientFailure =
    searchResults.length > 0 &&
    searchResults.every((row) => {
      const searched = row && typeof row === 'object' ? row.searched : null;
      const reason = String(searched?.reason || '').trim().toLowerCase();
      return !searched?.ok && transientReasons.has(reason);
    });
  if (!allowResolveFallback) {
    return {
      candidates: [],
      queries: diagnosticQueries.length ? diagnosticQueries : plannedQueries,
      reason: allSearchTransientFailure ? 'catalog_search_transient_failed' : 'catalog_search_no_candidates',
      meta: retrievalMeta,
    };
  }
  if (runMode === 'main_path' && !allSearchTransientFailure) {
    return {
      candidates: [],
      queries: diagnosticQueries.length ? diagnosticQueries : plannedQueries,
      reason: 'catalog_search_no_candidates',
      meta: retrievalMeta,
    };
  }
  if (runMode === 'main_path' && getRemainingMs() < 420) {
    return {
      candidates: [],
      queries: diagnosticQueries.length ? diagnosticQueries : plannedQueries,
      reason: allSearchTransientFailure ? 'catalog_search_transient_failed' : 'catalog_search_budget_exhausted',
      meta: retrievalMeta,
    };
  }

  const resolveLimit = runMode === 'main_path'
    ? PRODUCT_URL_REALTIME_COMPETITOR_MAIN_RESOLVE_MAX_QUERIES
    : Math.max(1, Math.min(6, queries.length));
  const resolveQueryList = [...queries].sort((a, b) => {
    const lenA = String(a || '').trim().length || 999;
    const lenB = String(b || '').trim().length || 999;
    if (lenA !== lenB) return lenA - lenB;
    return String(a || '').localeCompare(String(b || ''));
  }).slice(0, resolveLimit);
  const resolveResults = [];
  for (const queryText of resolveQueryList) {
    const remainingMs = getRemainingMs();
    if (remainingMs < 320) break;
    // Keep resolve fallback bounded so source can return within DAG budget.
    const resolveTimeoutMs = Math.max(260, Math.min(remainingMs - 80, CATALOG_AVAIL_RESOLVE_TIMEOUT_MS));
    // eslint-disable-next-line no-await-in-loop
    const resolved = await resolveAvailabilityProductByQuery({
      query: queryText,
      lang,
      logger,
      timeoutMs: resolveTimeoutMs,
    });
    resolveResults.push({ query: queryText, resolved });
    if (resolved && typeof resolved === 'object') {
      if (resolved.ok === false) bumpReason(`resolve_${resolved.reason || 'failed'}`);
      else if (!resolved.product) bumpReason('resolve_empty');
    }
  }
  for (const row of resolveResults) {
    const normalized = normalizeRecoCatalogProduct(row?.resolved?.product);
    if (!normalized) continue;
    const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
    if (!productId) continue;
    if (anchorId && productId === anchorId) continue;
    const lowerKey = `${productId}`.toLowerCase();
    if (seenProduct.has(lowerKey)) continue;
    seenProduct.add(lowerKey);

    const brand = pickFirstTrimmed(normalized.brand);
    const name = pickFirstTrimmed(normalized.display_name, normalized.name);
    const candidateText = `${brand} ${name}`.trim().toLowerCase();
    const nameTokens = tokenizeProductTextForSimilarity(candidateText);
    const categoryUseCaseMatch = scoreCategoryUseCaseMatch({
      anchorCategoryToken: categoryToken,
      candidateNameText: candidateText,
      candidateCategoryText: normalized.category || '',
    });

    const queryTokensForRow = tokenizeProductTextForSimilarity(String(row.query || ''));
    const queryOverlap = queryTokensForRow.filter((token) => nameTokens.includes(token)).length;
    const ingredientOverlap = ingredientTokens.filter((token) => nameTokens.includes(token)).length;
    const sameBrand = anchorBrand && brand && anchorBrand.toLowerCase() === brand.toLowerCase();
    const sameCategory = categoryUseCaseMatch >= 0.78;
    const scored = scoreRealtimeCompetitorCandidate({
      queryOverlap,
      ingredientNameOverlap: ingredientOverlap,
      sameCategory,
      sameBrand,
      anchorIngredientTokens,
      candidateIngredientTokens: Array.isArray(normalized.ingredient_tokens) ? normalized.ingredient_tokens : [],
      profileSkinTags,
      candidateSkinTags: Array.isArray(normalized.skin_type_tags) ? normalized.skin_type_tags : [],
      candidateSocialScore: normalized.social_ref_score,
      candidateSocialSupportCount: normalized.social_ref_support_count,
      recallHitCount: recallHitCountByProduct.get(lowerKey) || 1,
      totalQueries: totalQueriesForRecall,
    });
    const similarityScore = scored.similarity_score;

    candidates.push({
      product_id: productId,
      name: name || (isCn ? '未知产品' : 'Unknown product'),
      ...(brand ? { brand } : {}),
      ...(normalized.category ? { category: normalized.category } : {}),
      ...(normalized.price ? { price: normalized.price } : {}),
      source: { type: 'catalog_resolve_fallback' },
      source_type: 'catalog_resolve_fallback',
      category_use_case_match: Number(categoryUseCaseMatch.toFixed(3)),
      ...(normalized.social_raw ? { social_raw: normalized.social_raw } : {}),
      why_candidate: uniqCaseInsensitiveStrings(
        [
          isCn ? 'catalog resolve 回退命中' : 'catalog resolve fallback hit',
          sameCategory
            ? isCn
              ? `同品类（${categoryToken}）`
              : `same category (${categoryToken})`
            : '',
          queryOverlap
            ? isCn
              ? '查询关键词相近'
              : 'similar query keywords'
            : '',
          scored.score_breakdown.ingredient_similarity >= 0.6
            ? isCn
              ? '关键成分相似度较高'
              : 'high key-ingredient similarity'
            : '',
          scored.score_breakdown.skin_fit_similarity >= 0.6
            ? isCn
              ? '与用户画像匹配度较高'
              : 'better match for user skin profile'
            : '',
          scored.score_breakdown.social_reference_score >= 0.65
            ? isCn
              ? '社媒评分/参考对比信号较强'
              : 'strong social rating/comparison-reference signal'
            : '',
          sameBrand
            ? isCn
              ? '同品牌相近线产品'
              : 'same-brand nearby option'
            : '',
        ],
        4,
      ),
      similarity_score: similarityScore,
      score_breakdown: scored.score_breakdown,
      compare_highlights: uniqCaseInsensitiveStrings(
        [
          isCn
            ? '来自 resolve 回退结果，建议进一步比较配方细节。'
            : 'Derived from resolve fallback; compare formula details before final pick.',
          sameCategory
            ? isCn
              ? '同剂型/场景，可作为平替起点。'
              : 'Same format/use-case, suitable as a dupe baseline.'
            : '',
          scored.score_breakdown.ingredient_similarity >= 0.55
            ? isCn
              ? '关键成分相似度较高，建议进入 dupe 对比。'
              : 'Ingredient similarity is high; candidate is suitable for dupe compare.'
            : '',
        ],
        3,
      ),
    });
  }

  candidates.sort((a, b) => {
    const scoreA = Number.isFinite(Number(a?.similarity_score)) ? Number(a.similarity_score) : 0;
    const scoreB = Number.isFinite(Number(b?.similarity_score)) ? Number(b.similarity_score) : 0;
    if (scoreB !== scoreA) return scoreB - scoreA;
    return String(a?.name || '').localeCompare(String(b?.name || ''));
  });
  finalCandidates = candidates.slice(0, maxCandidates);
  if (finalCandidates.length) {
    return {
      candidates: finalCandidates,
      queries: diagnosticQueries.length ? diagnosticQueries : plannedQueries,
      reason: null,
      meta: retrievalMeta,
    };
  }

  const allFailed = searchResults.every((row) => !(row?.searched?.ok));
  const resolveAllFailed = resolveResults.every((row) => !(row?.resolved?.ok));
  return {
    candidates: [],
    queries: diagnosticQueries.length ? diagnosticQueries : plannedQueries,
    reason: allFailed && resolveAllFailed ? 'catalog_search_failed' : 'catalog_search_empty',
    meta: retrievalMeta,
  };
}

function canonicalizeProductUrlForIntelKb(rawUrl) {
  const text = String(rawUrl || '').trim();
  if (!text) return '';
  try {
    const parsed = new URL(text);
    parsed.hash = '';
    const trackingParams = ['fbclid', 'gclid', 'igshid', 'mc_cid', 'mc_eid', 'ref', 'ref_src'];
    for (const key of Array.from(parsed.searchParams.keys())) {
      const lower = String(key || '').toLowerCase();
      if (lower.startsWith('utm_') || trackingParams.includes(lower)) parsed.searchParams.delete(key);
    }
    if (typeof parsed.searchParams.sort === 'function') parsed.searchParams.sort();
    return parsed.toString();
  } catch {
    return text;
  }
}

function normalizeProductIntelFingerprintToken(raw, { maxLen = 220 } = {}) {
  const text = String(raw || '')
    .trim()
    .toLowerCase()
    .replace(/https?:\/\/\S+/gi, ' ')
    .replace(/[^a-z0-9\u4e00-\u9fff%+]+/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!text) return '';
  return text.length > maxLen ? text.slice(0, maxLen).trim() : text;
}

function extractProductIntelInciFingerprint(parsedProductObj) {
  const base = parsedProductObj && typeof parsedProductObj === 'object' && !Array.isArray(parsedProductObj) ? parsedProductObj : null;
  if (!base) return '';
  const direct = pickFirstTrimmed(base.inci, base.ingredients, base.ingredient_list, base.ingredientList);
  if (direct) return direct;
  const ingredientsArray = Array.isArray(base.ingredients)
    ? base.ingredients
    : Array.isArray(base.inci_list)
      ? base.inci_list
      : Array.isArray(base.inciList)
        ? base.inciList
        : [];
  if (!ingredientsArray.length) return '';
  return ingredientsArray
    .map((item) => (typeof item === 'string' ? item : item == null ? '' : String(item)).trim())
    .filter(Boolean)
    .slice(0, 80)
    .join('|');
}

function buildProductIntelFingerprintSeed({ parsedProductObj, productHint = '', langCode = 'EN' } = {}) {
  void langCode;
  const parsed = parsedProductObj && typeof parsedProductObj === 'object' && !Array.isArray(parsedProductObj) ? parsedProductObj : null;
  const brandRaw = pickFirstTrimmed(parsed?.brand, parsed?.brand_name, parsed?.brandName);
  const nameRaw = pickFirstTrimmed(
    parsed?.name,
    parsed?.display_name,
    parsed?.displayName,
    parsed?.title,
    parsed?.product_name,
    parsed?.productName,
  );
  const inciRaw = extractProductIntelInciFingerprint(parsed);
  const hintRaw = String(productHint || '').trim();

  const brand = normalizeProductIntelFingerprintToken(brandRaw, { maxLen: 120 });
  const name = normalizeProductIntelFingerprintToken(nameRaw || hintRaw, { maxLen: 200 });
  const inci = normalizeProductIntelFingerprintToken(inciRaw, { maxLen: 700 });
  const hint = normalizeProductIntelFingerprintToken(hintRaw, { maxLen: 220 });

  if (!brand && !name && !inci && !hint) return '';
  return [brand, name, inci, hint].join('|');
}

function buildProductIntelKbKeyParts({ productUrl, parsedProduct, productHint = '', lang = 'EN' } = {}) {
  const parsedProductObj = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  const anchorId = pickFirstTrimmed(parsedProductObj?.product_id, parsedProductObj?.sku_id);
  const langCode = String(lang || 'EN').toUpperCase() === 'CN' ? 'CN' : 'EN';
  const urlRaw = String(productUrl || '').trim();
  const normalizedUrl = /^https?:\/\/\S+/i.test(urlRaw) ? canonicalizeProductUrlForIntelKb(urlRaw) : '';
  const fingerprintSeed = buildProductIntelFingerprintSeed({ parsedProductObj, productHint, langCode });
  return {
    anchorId,
    normalizedUrl,
    fingerprintSeed,
    langCode,
  };
}

function resolveProductIntelKbKeyQuality({ productUrl, parsedProduct, productHint = '', lang = 'EN' } = {}) {
  const parts = buildProductIntelKbKeyParts({ productUrl, parsedProduct, productHint, lang });
  if (parts.normalizedUrl) return 'url';
  if (parts.anchorId) return 'anchor';
  if (parts.fingerprintSeed) return 'fingerprint';
  return 'none';
}

function buildProductIntelKbKey({ productUrl, parsedProduct, lang = 'EN', productHint = '' } = {}) {
  const parts = buildProductIntelKbKeyParts({ productUrl, parsedProduct, productHint, lang });
  const fingerprintHash = parts.fingerprintSeed
    ? crypto.createHash('sha256').update(parts.fingerprintSeed).digest('hex')
    : '';
  const keyRaw = parts.normalizedUrl
    ? `url:${parts.normalizedUrl}`
    : parts.anchorId
      ? `product:${parts.anchorId}`
      : fingerprintHash
        ? `fp:${fingerprintHash}`
        : '';
  return normalizeProductIntelKbKey(keyRaw);
}

function buildLegacyProductIntelKbKey({ productUrl, parsedProduct, lang = 'EN', productHint = '' } = {}) {
  const parts = buildProductIntelKbKeyParts({ productUrl, parsedProduct, productHint, lang });
  const fingerprintHash = parts.fingerprintSeed
    ? crypto.createHash('sha256').update(parts.fingerprintSeed).digest('hex')
    : '';
  const keyRaw = parts.normalizedUrl
    ? `url:${parts.normalizedUrl}|lang:${parts.langCode}`
    : parts.anchorId
      ? `product:${parts.anchorId}|lang:${parts.langCode}`
      : fingerprintHash
        ? `fp:${fingerprintHash}|lang:${parts.langCode}`
        : '';
  return normalizeProductIntelKbKey(keyRaw);
}

function buildProductIntelKbReadCandidates({ productUrl, parsedProduct, lang = 'EN', productHint = '' } = {}) {
  const out = [];
  const push = (rawKey) => {
    const key = String(rawKey || '').trim();
    if (!key) return;
    if (out.includes(key)) return;
    out.push(key);
  };

  push(buildProductIntelKbKey({ productUrl, parsedProduct, lang, productHint }));
  push(buildLegacyProductIntelKbKey({ productUrl, parsedProduct, lang, productHint }));
  push(buildLegacyProductIntelKbKey({ productUrl, parsedProduct, lang: 'EN', productHint }));
  push(buildLegacyProductIntelKbKey({ productUrl, parsedProduct, lang: 'CN', productHint }));

  return out;
}

function parseTimestampMs(raw) {
  const text = String(raw || '').trim();
  if (!text) return 0;
  const ms = Date.parse(text);
  return Number.isFinite(ms) ? ms : 0;
}

function getProductAnalysisSocialSummaryCount(payload) {
  let count = 0;
  for (const block of ['competitors', 'related_products', 'dupes']) {
    const blockObj = isPlainObject(payload?.[block]) ? payload[block] : {};
    const candidates = Array.isArray(blockObj.candidates) ? blockObj.candidates : [];
    for (const candidate of candidates) {
      const summary = isPlainObject(candidate?.social_summary_user_visible)
        ? candidate.social_summary_user_visible
        : null;
      const themes = Array.isArray(summary?.themes) ? summary.themes.filter(Boolean) : [];
      if (themes.length) count += 1;
    }
  }
  return count;
}

function getProductAnalysisSocialChannels(payload) {
  const provenance = isPlainObject(payload?.provenance) ? payload.provenance : {};
  const evidence = isPlainObject(payload?.evidence) ? payload.evidence : {};
  const socialSignals = isPlainObject(evidence.social_signals) ? evidence.social_signals : {};
  const platformScores = isPlainObject(socialSignals.platform_scores) ? socialSignals.platform_scores : {};
  return extractWhitelistedSocialChannels({
    channels: [
      ...(Array.isArray(provenance.social_channels_used) ? provenance.social_channels_used : []),
      ...Object.keys(platformScores),
    ],
  });
}

function resolveProductAnalysisSocialState(payload) {
  const provenance = isPlainObject(payload?.provenance) ? payload.provenance : {};
  const nowMs = Date.now();
  const ttlMs = Number(RECO_DOGFOOD_CONFIG?.social?.ttl_ms) > 0
    ? Number(RECO_DOGFOOD_CONFIG.social.ttl_ms)
    : 72 * 60 * 60 * 1000;
  const freshUntilMs = parseTimestampMs(provenance.social_fresh_until);
  const generatedAtMs = parseTimestampMs(provenance.generated_at);
  const isFreshByWindow = freshUntilMs > nowMs;
  const isFreshByGeneratedAt = generatedAtMs > 0 && generatedAtMs + ttlMs > nowMs;
  const socialSummaryCount = getProductAnalysisSocialSummaryCount(payload);
  const socialChannels = getProductAnalysisSocialChannels(payload);
  const hasCoverage = socialSummaryCount > 0 && socialChannels.length >= 2;
  const fresh = (isFreshByWindow || isFreshByGeneratedAt) && hasCoverage;
  return {
    shouldRefresh: !fresh,
    fetchMode: fresh ? 'kb_hit' : 'stale_kb',
    socialChannels,
    socialSummaryCount,
    socialFreshUntil: freshUntilMs > 0 ? new Date(freshUntilMs).toISOString() : null,
  };
}

function applyProductAnalysisSocialProvenance(payload, patch = {}) {
  const p = isPlainObject(payload) ? payload : {};
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  const next = {
    ...provenance,
    ...(isPlainObject(patch) ? patch : {}),
  };
  const socialChannels = extractWhitelistedSocialChannels({
    channels: Array.isArray(next.social_channels_used) ? next.social_channels_used : [],
  });
  if (socialChannels.length) next.social_channels_used = socialChannels;
  else delete next.social_channels_used;
  return {
    ...p,
    provenance: next,
  };
}

function shouldRefreshCompetitorSnapshot(payload, sourceMeta = null) {
  const p = isPlainObject(payload) ? payload : {};
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  const competitorMeta = isPlainObject(provenance.competitor_meta) ? provenance.competitor_meta : {};
  const sourceMetaObj = isPlainObject(sourceMeta) ? sourceMeta : {};
  const sourceToken = String(
    competitorMeta.source ||
    sourceMetaObj.competitor_source ||
    sourceMetaObj.competitor_snapshot_meta?.source ||
    '',
  ).trim().toLowerCase();
  if (sourceToken !== 'snapshot') return false;
  if (competitorMeta.very_stale === true || competitorMeta.stale === true || competitorMeta.degraded === true) {
    return true;
  }
  const ageSec = Number(competitorMeta.snapshot_age_sec);
  if (Number.isFinite(ageSec) && ageSec > 0) {
    return ageSec >= Math.trunc((Number(process.env.AURORA_COMP_SNAPSHOT_SOFT_TTL_MS || 259200000) || 259200000) / 1000);
  }
  return true;
}

function collectProductIntelEvidenceSourceTypes(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const evidence = isPlainObject(p.evidence) ? p.evidence : {};
  const sources = Array.isArray(evidence.sources) ? evidence.sources : [];
  return uniqCaseInsensitiveStrings(
    sources
      .map((item) => (isPlainObject(item) ? String(item.type || '').trim().toLowerCase() : ''))
      .filter(Boolean),
    8,
  );
}

function collectProductIntelInciTokens(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const evidence = isPlainObject(p.evidence) ? p.evidence : {};
  const science = isPlainObject(evidence.science) ? evidence.science : {};
  const ingredientIntel = isPlainObject(p.ingredient_intel) ? p.ingredient_intel : {};
  const inciNormalized = Array.isArray(ingredientIntel.inci_normalized) ? ingredientIntel.inci_normalized : [];
  return uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(science.key_ingredients || science.keyIngredients) ? (science.key_ingredients || science.keyIngredients) : []),
      ...inciNormalized.map((item) => {
        if (typeof item === 'string') return item;
        if (isPlainObject(item)) return pickFirstTrimmed(item.name, item.inci, item.value);
        return '';
      }),
    ]
      .map((item) => normalizeInciIngredientName(item))
      .filter(Boolean),
    120,
  );
}

function resolveProductAnalysisConfidenceBand(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const confidenceObj = isPlainObject(p.confidence) ? p.confidence : {};
  const confidenceRaw = Number(
    confidenceObj.score != null
      ? confidenceObj.score
      : confidenceObj.value != null
        ? confidenceObj.value
        : p.confidence_score != null
          ? p.confidence_score
          : p.confidence,
  );
  const score = Number.isFinite(confidenceRaw) ? Math.max(0, Math.min(1, confidenceRaw)) : null;
  if (score == null) return 'unknown';
  if (score >= 0.75) return 'high';
  if (score >= 0.45) return 'medium';
  return 'low';
}

function resolveProductAnalysisQualityBand(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const assessment = isPlainObject(p.assessment) ? p.assessment : {};
  const verdict = String(assessment.verdict || '').trim().toLowerCase();
  if (verdict === 'unknown' || verdict === '未知' || !verdict) return 'low';
  const coverage = getProductAnalysisEvidenceCoverageScore(p);
  if (coverage >= 0.68) return 'high';
  if (coverage >= 0.34) return 'medium';
  return 'low';
}

function collectProductGuardrailFlags(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  const violations = Array.isArray(provenance.guardrail_violations) ? provenance.guardrail_violations : [];
  const internal = getProductAnalysisInternalMissingCodes(p).filter((token) => /^guardrail_/i.test(String(token || '').trim()));
  return uniqCaseInsensitiveStrings([...violations, ...internal], 16);
}

function annotateProductIntelRelaxedProvenance(payload, { quarantineReasons = [] } = {}) {
  const p = isPlainObject(payload) ? payload : null;
  if (!p) return payload;
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  const existingSourceChain = Array.isArray(provenance.source_chain) ? provenance.source_chain : [];
  const existingFlags = Array.isArray(provenance.guardrail_flags) ? provenance.guardrail_flags : [];
  const nextQuarantineReasons = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(provenance.kb_quarantine_reasons) ? provenance.kb_quarantine_reasons : []),
      ...(Array.isArray(quarantineReasons) ? quarantineReasons : []),
    ],
    12,
  );
  p.provenance = {
    ...provenance,
    source_chain: uniqCaseInsensitiveStrings(
      [
        ...existingSourceChain,
        'llm_extraction',
      ],
      12,
    ),
    confidence_band: resolveProductAnalysisConfidenceBand(p),
    quality_band: resolveProductAnalysisQualityBand(p),
    guardrail_flags: uniqCaseInsensitiveStrings(
      [
        ...existingFlags,
        ...collectProductGuardrailFlags(p),
      ],
      20,
    ),
    gate_relax_mode: AURORA_RULE_RELAX_MODE,
    kb_write_policy: AURORA_KB_WRITE_POLICY,
    kb_serve_policy: AURORA_KB_SERVE_POLICY,
    ...(nextQuarantineReasons.length ? { kb_quarantine_reasons: nextQuarantineReasons } : {}),
  };
  return p;
}

function shouldPersistProductIntelKb(payload, sourceMeta = null) {
  const p = isPlainObject(payload) ? payload : null;
  if (!p) {
    return { attempted: false, persisted: false, blocked_reason: 'payload_missing' };
  }
  const sourceTypes = collectProductIntelEvidenceSourceTypes(p);
  const hasInciDecoder = sourceTypes.includes('inci_decoder');
  const hasAuthoritativeEvidence = sourceTypes.includes('official_page') || sourceTypes.includes('regulatory');
  let blockedReason = null;
  if (!hasAuthoritativeEvidence) {
    blockedReason = hasInciDecoder ? 'incidecoder_unverified_not_persisted' : 'authoritative_source_missing';
  }
  if (!blockedReason && hasInciDecoder) {
    const sourceMetaObj = isPlainObject(sourceMeta) ? sourceMeta : {};
    const overlapFromMeta = Number(sourceMetaObj?.inci_decoder_overlap_count);
    const overlapCount = Number.isFinite(overlapFromMeta) ? Math.max(0, Math.trunc(overlapFromMeta)) : 0;
    if (overlapCount <= 0) {
      const inciTokens = collectProductIntelInciTokens(p);
      const hasSufficientInci = inciTokens.length >= 4;
      if (!hasSufficientInci) {
        blockedReason = 'incidecoder_unverified_not_persisted';
      }
    }
  }
  if (AURORA_KB_WRITE_POLICY === 'allow_all') {
    return {
      attempted: true,
      persisted: true,
      blocked_reason: blockedReason,
      audit_blocked_reason: blockedReason,
      policy: AURORA_KB_WRITE_POLICY,
    };
  }
  return {
    attempted: true,
    persisted: !blockedReason,
    blocked_reason: blockedReason,
    audit_blocked_reason: blockedReason,
    policy: AURORA_KB_WRITE_POLICY,
  };
}

function annotateProductIntelKbWriteDecision(payload, decision) {
  const p = isPlainObject(payload) ? payload : null;
  if (!p) return payload;
  const d = isPlainObject(decision) ? decision : {};
  const blockedReason =
    d.persisted === false && d.blocked_reason
      ? String(d.blocked_reason)
      : null;
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  const missingInfo = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(p.missing_info) ? p.missing_info : []),
      ...(Array.isArray(p.user_facing_gaps) ? p.user_facing_gaps : []),
      ...(blockedReason === 'incidecoder_unverified_not_persisted' ? ['incidecoder_unverified_not_persisted'] : []),
    ],
    16,
  );
  const internalCodes = uniqCaseInsensitiveStrings(
    [
      ...getProductAnalysisInternalMissingCodes(p),
      ...(blockedReason === 'incidecoder_unverified_not_persisted' ? ['incidecoder_unverified_not_persisted'] : []),
    ],
    24,
  );
  p.provenance = {
    ...provenance,
    gate_relax_mode: AURORA_RULE_RELAX_MODE,
    kb_write_policy: AURORA_KB_WRITE_POLICY,
    kb_serve_policy: AURORA_KB_SERVE_POLICY,
    confidence_band: resolveProductAnalysisConfidenceBand(p),
    quality_band: resolveProductAnalysisQualityBand(p),
    guardrail_flags: uniqCaseInsensitiveStrings(
      [
        ...(Array.isArray(provenance.guardrail_flags) ? provenance.guardrail_flags : []),
        ...collectProductGuardrailFlags(p),
      ],
      20,
    ),
    kb_write: {
      attempted: d.attempted === true,
      persisted: d.persisted === true,
      blocked_reason: d.blocked_reason ? String(d.blocked_reason) : null,
      audit_blocked_reason: d.audit_blocked_reason ? String(d.audit_blocked_reason) : null,
      policy: d.policy ? String(d.policy) : AURORA_KB_WRITE_POLICY,
    },
  };
  if (missingInfo.length) p.missing_info = missingInfo;
  if (internalCodes.length) {
    p.internal_debug_codes = internalCodes;
    p.missing_info_internal = internalCodes;
  }
  return p;
}

function scheduleProductIntelKbBackfill({
  productUrl,
  parsedProduct = null,
  productHint = '',
  payload = null,
  lang = 'EN',
  source = 'url_realtime_product_intel',
  sourceMeta = null,
  logger,
} = {}) {
  if (!PRODUCT_INTEL_KB_ASYNC_BACKFILL_ENABLED) {
    annotateProductIntelKbWriteDecision(payload, {
      attempted: false,
      persisted: false,
      blocked_reason: 'kb_backfill_disabled',
    });
    return { attempted: false, persisted: false, blocked_reason: 'kb_backfill_disabled' };
  }
  const kbKey = buildProductIntelKbKey({ productUrl, parsedProduct, lang, productHint });
  if (!kbKey) {
    annotateProductIntelKbWriteDecision(payload, {
      attempted: false,
      persisted: false,
      blocked_reason: 'kb_key_missing',
    });
    return { attempted: false, persisted: false, blocked_reason: 'kb_key_missing' };
  }
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
    return { attempted: false, persisted: false, blocked_reason: 'payload_missing' };
  }
  annotateProductIntelRelaxedProvenance(payload);

  let analysisSnapshot = null;
  try {
    analysisSnapshot = JSON.parse(JSON.stringify(payload));
  } catch {
    analysisSnapshot = null;
  }
  if (!analysisSnapshot || typeof analysisSnapshot !== 'object' || Array.isArray(analysisSnapshot)) {
    annotateProductIntelKbWriteDecision(payload, {
      attempted: false,
      persisted: false,
      blocked_reason: 'payload_snapshot_failed',
    });
    return { attempted: false, persisted: false, blocked_reason: 'payload_snapshot_failed' };
  }

  const sourceMetaObj = sourceMeta && typeof sourceMeta === 'object' && !Array.isArray(sourceMeta) ? sourceMeta : null;
  const persistDecision = shouldPersistProductIntelKb(payload, sourceMetaObj);
  annotateProductIntelKbWriteDecision(payload, persistDecision);
  if (!persistDecision.persisted) {
    logger?.debug?.(
      {
        kb_key: kbKey,
        blocked_reason: persistDecision.blocked_reason || 'kb_write_blocked',
      },
      'aurora bff: skipped product-intel kb backfill by strict gate',
    );
    return persistDecision;
  }
  try {
    analysisSnapshot = JSON.parse(JSON.stringify(payload));
  } catch {
    analysisSnapshot = null;
  }
  if (!analysisSnapshot || typeof analysisSnapshot !== 'object' || Array.isArray(analysisSnapshot)) {
    return { attempted: false, persisted: false, blocked_reason: 'payload_snapshot_failed' };
  }
  annotateProductIntelRelaxedProvenance(analysisSnapshot);
  const keyQuality = resolveProductIntelKbKeyQuality({ productUrl, parsedProduct, productHint, lang });
  const guardrailFlags = collectProductGuardrailFlags(analysisSnapshot);
  const confidenceBand = resolveProductAnalysisConfidenceBand(analysisSnapshot);
  const qualityBand = resolveProductAnalysisQualityBand(analysisSnapshot);
  const mergedSourceMeta = {
    ...(sourceMetaObj || {}),
    key_quality:
      sourceMetaObj && typeof sourceMetaObj.key_quality === 'string' && sourceMetaObj.key_quality.trim()
        ? sourceMetaObj.key_quality.trim()
        : keyQuality,
    kb_write: {
      attempted: persistDecision.attempted === true,
      persisted: persistDecision.persisted === true,
      blocked_reason: persistDecision.blocked_reason ? String(persistDecision.blocked_reason) : null,
      audit_blocked_reason: persistDecision.audit_blocked_reason ? String(persistDecision.audit_blocked_reason) : null,
      policy: persistDecision.policy ? String(persistDecision.policy) : AURORA_KB_WRITE_POLICY,
    },
    kb_write_policy: AURORA_KB_WRITE_POLICY,
    kb_serve_policy: AURORA_KB_SERVE_POLICY,
    gate_relax_mode: AURORA_RULE_RELAX_MODE,
    confidence_band: confidenceBand,
    quality_grade: qualityBand,
    guardrail_flags: guardrailFlags,
  };
  setImmediate(() => {
    upsertProductIntelKbEntry({
      kb_key: kbKey,
      analysis: analysisSnapshot,
      source,
      source_meta: mergedSourceMeta,
      last_success_at: new Date().toISOString(),
      last_error: null,
    }).catch((err) => {
      logger?.warn(
        { err: err?.message || String(err), kb_key: kbKey },
        'aurora bff: async product-intel kb backfill failed',
      );
    });
  });
  return persistDecision;
}

function isLikelyNoiseCompetitorName(name) {
  const text = String(name || '').trim().toLowerCase();
  if (!text) return true;
  if (text.length < 4) return true;
  if (/\{\{+|\}\}+/i.test(text)) return true;
  if (/\bsku_[a-z0-9_]+\b/i.test(text)) return true;
  if (/\b(prod|product)_rgn_[a-z0-9_]+\b/i.test(text)) return true;
  if (/^skip to\b/i.test(text)) return true;
  if (/^(contact us|home|menu|search|my account|sign in|footer|header|bestsellers?|new arrivals?)$/i.test(text)) return true;
  if (/\b(skip to main content|skip to footer content|contact us)\b/i.test(text)) return true;
  if (/^(moisturizer(?:\s*\/\s*spf)?|skincare moisturize|skincare moisturizer|spf|sunscreen|serum|cleanser|toner|mask)$/i.test(text)) return true;
  const genericTokens = text.split(/[^a-z0-9]+/).filter(Boolean);
  const genericLexicon = new Set(['moisturizer', 'moisturize', 'skincare', 'spf', 'sunscreen', 'serum', 'cleanser', 'toner', 'mask', 'lotion', 'cream']);
  if (genericTokens.length > 0 && genericTokens.length <= 3 && genericTokens.every((token) => genericLexicon.has(token))) return true;
  const symbolChars = (text.match(/[^a-z0-9\u4e00-\u9fff\s]/g) || []).length;
  if (symbolChars / Math.max(1, text.length) > 0.35) return true;
  return false;
}

const GENERIC_RELATED_NAME_TOKENS = new Set([
  'moisturizer',
  'moisturizing',
  'cream',
  'lotion',
  'cleanser',
  'serum',
  'toner',
  'sunscreen',
  'sunblock',
  'spf',
  'uv',
  'protection',
  'shield',
  'hydrating',
  'hydration',
  'gel',
  'balm',
  'face',
  'day',
  'night',
]);

function isLikelyGenericRelatedCandidateName(name, candidate = null) {
  const text = String(name || '').trim().toLowerCase();
  if (!text) return true;
  void candidate;

  const compact = text
    .replace(/[^a-z0-9+% ]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!compact) return true;

  if (/^(?:moisturizer|moisturizing cream|cleanser|serum|toner|sunscreen|sunblock|spf(?:\s*\d{1,2}\+?)?)$/.test(compact)) {
    return true;
  }

  const tokens = compact.split(' ').filter(Boolean);
  if (!tokens.length || tokens.length > 3) return false;
  const onlyGenericTokens = tokens.every((token) => {
    if (GENERIC_RELATED_NAME_TOKENS.has(token)) return true;
    if (/^spf\d{0,2}\+?$/.test(token)) return true;
    if (/^\d{1,2}\+?$/.test(token)) return true;
    return false;
  });
  return onlyGenericTokens;
}

function initCandidateFilterStats(seed = null) {
  const base = seed && typeof seed === 'object' && !Array.isArray(seed) ? seed : {};
  return {
    competitors_dropped_non_skincare: Number.isFinite(Number(base.competitors_dropped_non_skincare))
      ? Number(base.competitors_dropped_non_skincare)
      : 0,
    related_dropped_non_skincare: Number.isFinite(Number(base.related_dropped_non_skincare))
      ? Number(base.related_dropped_non_skincare)
      : 0,
    dupes_dropped_non_skincare: Number.isFinite(Number(base.dupes_dropped_non_skincare))
      ? Number(base.dupes_dropped_non_skincare)
      : 0,
  };
}

function incrementCandidateFilterStats(stats, pool = 'generic') {
  if (!stats || typeof stats !== 'object' || Array.isArray(stats)) return;
  const token = String(pool || '').trim().toLowerCase();
  if (token === 'competitors') {
    stats.competitors_dropped_non_skincare = Number(stats.competitors_dropped_non_skincare || 0) + 1;
    return;
  }
  if (token === 'related_products' || token === 'related') {
    stats.related_dropped_non_skincare = Number(stats.related_dropped_non_skincare || 0) + 1;
    return;
  }
  if (token === 'dupes' || token === 'dupe') {
    stats.dupes_dropped_non_skincare = Number(stats.dupes_dropped_non_skincare || 0) + 1;
  }
}

function hasCandidateFilterDropStats(stats) {
  if (!stats || typeof stats !== 'object' || Array.isArray(stats)) return false;
  return Number(stats.competitors_dropped_non_skincare || 0) > 0
    || Number(stats.related_dropped_non_skincare || 0) > 0
    || Number(stats.dupes_dropped_non_skincare || 0) > 0;
}

function sanitizeCompetitorCandidates(candidates, max = 10, options = null) {
  const opts = options && typeof options === 'object' && !Array.isArray(options) ? options : {};
  const enforceSkincare = opts.enforce_skincare == null
    ? (opts.enforceSkincare == null ? true : Boolean(opts.enforceSkincare))
    : Boolean(opts.enforce_skincare);
  const strictFilter = opts.strictFilter == null ? AURORA_PRODUCT_STRICT_SKINCARE_FILTER : Boolean(opts.strictFilter);
  const stats = opts.stats && typeof opts.stats === 'object' && !Array.isArray(opts.stats) ? opts.stats : null;
  const pool = String(opts.pool || 'generic').trim().toLowerCase();
  const out = [];
  const seen = new Set();
  for (const item of Array.isArray(candidates) ? candidates : []) {
    const row = item && typeof item === 'object' && !Array.isArray(item) ? item : null;
    if (!row) continue;
    const name = pickFirstTrimmed(row.name, row.display_name);
    if (!name || isLikelyNoiseCompetitorName(name)) continue;
    if ((pool === 'related_products' || pool === 'related') && isLikelyGenericRelatedCandidateName(name, row)) continue;
    if (enforceSkincare) {
      const guard = evaluateAnchorProductSkincareGuard(row, { strictFilter });
      if (!guard.ok && (guard.reason === 'non_skincare_blacklist' || guard.reason === 'non_skincare_category')) {
        incrementCandidateFilterStats(stats, pool);
        continue;
      }
      if (guard.low_relevance === true || guard.reason === 'non_skincare_soft') {
        row.low_relevance = true;
        row.relevance_flags = uniqCaseInsensitiveStrings(
          [...(Array.isArray(row.relevance_flags) ? row.relevance_flags : []), 'non_skincare_soft'],
          6,
        );
      }
    }
    const brand = pickFirstTrimmed(row.brand);
    const key = `${String(brand || '').toLowerCase()}::${String(name).toLowerCase()}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({ ...row, name });
    if (out.length >= Math.max(1, Math.min(12, Number(max) || 10))) break;
  }
  return out;
}

const RECO_PRICE_BANDS = new Set(['budget', 'mid', 'premium', 'luxury', 'unknown']);
const RECO_COMPETITOR_BLOCKED_SOURCE_TYPES = new Set(['on_page_related', 'aurora_alternatives']);

function normalizeRecoSourceObject(raw) {
  if (isPlainObject(raw)) {
    const type = String(raw.type || '').trim();
    if (type) {
      return {
        type,
        ...(typeof raw.name === 'string' && raw.name.trim() ? { name: raw.name.trim() } : {}),
        ...(typeof raw.url === 'string' && raw.url.trim() ? { url: raw.url.trim() } : {}),
      };
    }
  }
  if (typeof raw === 'string' && raw.trim()) return { type: raw.trim() };
  return { type: 'unknown' };
}

function getRecoCandidateSourceTypeToken(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  return String((row.source && row.source.type) || row.source_type || row.sourceType || '')
    .trim()
    .toLowerCase();
}

function isBlockedCompetitorSourceType(sourceType) {
  const token = String(sourceType || '').trim().toLowerCase();
  if (!token) return false;
  return RECO_COMPETITOR_BLOCKED_SOURCE_TYPES.has(token);
}

function filterBlockedCompetitorSourceCandidates(rows) {
  return (Array.isArray(rows) ? rows : []).filter((row) => !isBlockedCompetitorSourceType(getRecoCandidateSourceTypeToken(row)));
}

function normalizeRecoEvidenceRefs(raw) {
  const out = [];
  for (const item of Array.isArray(raw) ? raw : []) {
    if (isPlainObject(item)) {
      out.push(item);
      if (out.length >= 8) break;
      continue;
    }
    if (typeof item === 'string' && item.trim()) {
      out.push({ id: item.trim() });
      if (out.length >= 8) break;
    }
  }
  return out;
}

function normalizeRecoSocialSummaryKeyword(raw) {
  const text = String(raw == null ? '' : raw).trim();
  if (!text) return '';
  if (text.length < 2 || text.length > 40) return '';
  if (/https?:\/\//i.test(text)) return '';
  if (/@/.test(text)) return '';
  if (/^(?:route_|dedupe_|internal_|fallback_|ref_)/i.test(text)) return '';
  if (/完美平替|100%\s*(?:相同|一样|identical|same)|miracle\s+dupe|无敌平替/i.test(text)) return '';
  return text;
}

const RECO_SOCIAL_VOLUME_BUCKETS = new Set(['low', 'mid', 'high', 'unknown']);

function normalizeRecoSocialSummaryUserVisible(raw) {
  const obj = isPlainObject(raw) ? raw : null;
  if (!obj) return null;
  const themes = uniqCaseInsensitiveStrings(Array.isArray(obj.themes) ? obj.themes : [])
    .slice(0, 3);
  if (!themes.length) return null;

  const topKeywords = uniqCaseInsensitiveStrings(
    (Array.isArray(obj.top_keywords) ? obj.top_keywords : [])
      .map((item) => normalizeRecoSocialSummaryKeyword(item))
      .filter(Boolean),
  ).slice(0, 6);
  const sentimentHint = typeof obj.sentiment_hint === 'string' ? obj.sentiment_hint.trim() : '';
  const volumeRaw = String(obj.volume_bucket || '').trim().toLowerCase();
  const volumeBucket = RECO_SOCIAL_VOLUME_BUCKETS.has(volumeRaw) ? volumeRaw : 'unknown';

  return {
    themes,
    ...(topKeywords.length ? { top_keywords: topKeywords } : {}),
    ...(sentimentHint ? { sentiment_hint: sentimentHint } : {}),
    volume_bucket: volumeBucket,
  };
}

function inferRecoPriceBand(rawBand, row) {
  const explicit = String(rawBand || '').trim().toLowerCase();
  if (RECO_PRICE_BANDS.has(explicit)) return explicit;
  const price = Number(
    row?.price ??
      row?.price_value ??
      row?.priceValue ??
      row?.amount ??
      row?.offer_price ??
      row?.offerPrice ??
      NaN,
  );
  if (!Number.isFinite(price) || price <= 0) return 'unknown';
  if (price < 20) return 'budget';
  if (price < 55) return 'mid';
  if (price < 110) return 'premium';
  return 'luxury';
}

function normalizeRecoScoreBreakdown(raw, similarityHint = null) {
  const hint = normalizeMaybePercentScore(similarityHint);
  const out = normalizeCanonicalScoreBreakdown(raw, { similarityHint: hint });
  const requiredKeys = [
    'category_use_case_match',
    'ingredient_functional_similarity',
    'skin_fit_similarity',
    'social_reference_strength',
    'price_distance',
    'brand_constraint',
    'score_total',
  ];
  for (const key of requiredKeys) {
    if (out[key] == null) out[key] = 0;
  }
  if (out.quality == null) out.quality = 0;
  return out;
}

function inferRecoRecommendationIntent(row, blockType = 'competitors') {
  const explicit = String(
    row?.recommendation_intent ??
      row?.recommendationIntent ??
      '',
  ).trim().toLowerCase();
  if (explicit === 'replace' || explicit === 'pair') return explicit;
  return String(blockType || '').trim().toLowerCase() === 'related_products' ? 'pair' : 'replace';
}

function buildRecoRecommendationOutcome(row, intent = 'replace', blockType = 'competitors') {
  const explicit = pickFirstTrimmed(row?.expected_outcome, row?.expectedOutcome, row?.best_use, row?.bestUse);
  if (explicit) return truncate(explicit, 220);
  const token = String(blockType || '').trim().toLowerCase();
  if (intent === 'pair') {
    if (token === 'related_products') {
      return 'Pair to complement hydration/barrier support or texture balance around the anchor product.';
    }
    return 'Pair as a companion step instead of replacing the anchor product.';
  }
  if (token === 'dupes') return 'Closest dupe candidate for replacement with similar use-case.';
  return 'Replacement candidate with similar category/use-case and ingredient direction.';
}

function buildRecoTradeoffNotes(row, intent = 'replace') {
  const notes = uniqCaseInsensitiveStrings([
    ...asStringArray(row?.tradeoff_notes ?? row?.tradeoffNotes),
    ...asStringArray(row?.compare_highlights ?? row?.compareHighlights),
  ]).slice(0, 4);
  if (notes.length) return notes;
  return [
    intent === 'pair'
      ? 'Adds a complementary function; keep routine layering simple to control irritation risk.'
      : 'May differ in texture/finish and tolerance profile; patch-test and adjust frequency.',
  ];
}

function normalizeRecoCandidateForContract(item, { blockType = 'competitors' } = {}) {
  const row = isPlainObject(item) ? item : null;
  if (!row) return null;
  const similarityRaw = normalizeMaybePercentScore(row.similarity_score ?? row.similarityScore);
  const whyCandidate = normalizeWhyCandidateObject(row.why_candidate ?? row.whyCandidate, {
    lang: 'EN',
  });
  const source = normalizeRecoSourceObject(row.source ?? row.source_type ?? row.sourceType);
  const evidenceRefs = normalizeRecoEvidenceRefs(row.evidence_refs ?? row.evidenceRefs);
  const priceBand = inferRecoPriceBand(row.price_band ?? row.priceBand, row);
  const socialSummary = normalizeRecoSocialSummaryUserVisible(
    row.social_summary_user_visible ?? row.socialSummaryUserVisible,
  );
  const recommendationIntent = inferRecoRecommendationIntent(row, blockType);
  const expectedOutcome = buildRecoRecommendationOutcome(row, recommendationIntent, blockType);
  const tradeoffNotes = buildRecoTradeoffNotes(row, recommendationIntent);
  const bestUse = pickFirstTrimmed(row?.best_use, row?.bestUse, expectedOutcome);
  const reasonType = recommendationIntent === 'pair' ? 'pairing_complement' : 'replace_alternative';
  const next = {
    ...row,
    ...(similarityRaw != null ? { similarity_score: similarityRaw } : {}),
    why_candidate: whyCandidate,
    score_breakdown: normalizeRecoScoreBreakdown(row.score_breakdown ?? row.scoreBreakdown, similarityRaw),
    source,
    evidence_refs: evidenceRefs,
    price_band: priceBand,
    recommendation_intent: recommendationIntent,
    recommendation_reason_type: reasonType,
    expected_outcome: expectedOutcome,
    best_use: bestUse,
    tradeoff_notes: tradeoffNotes,
    ...(socialSummary ? { social_summary_user_visible: socialSummary } : {}),
  };
  delete next.social_raw;
  delete next.socialRaw;
  delete next.__dag_source;
  delete next.__social_channels_used;
  if (!socialSummary) delete next.social_summary_user_visible;
  return next;
}

function normalizeRecoBlockForContract(rawBlock, { max = 10 } = {}) {
  const block = isPlainObject(rawBlock) ? rawBlock : {};
  const blockType = String(block.block_type || block.blockType || block.pool || '').trim().toLowerCase() || 'competitors';
  const candidates = sanitizeCompetitorCandidates(block.candidates, max)
    .map((item) => normalizeRecoCandidateForContract(item, { blockType }))
    .filter(Boolean);
  return {
    ...block,
    ...(blockType ? { block_type: blockType } : {}),
    candidates,
  };
}

function normalizeRecoConfidenceEntry(raw, fallbackReason = 'contract_default') {
  const obj = isPlainObject(raw) ? raw : {};
  const scoreRaw = normalizeMaybePercentScore(obj.score);
  const score = scoreRaw == null ? 0 : scoreRaw;
  const levelRaw = String(obj.level || '').trim().toLowerCase();
  const level = levelRaw === 'high' || levelRaw === 'med' || levelRaw === 'low'
    ? levelRaw
    : score >= 0.75
      ? 'high'
      : score >= 0.4
        ? 'med'
        : 'low';
  const reasons = uniqCaseInsensitiveStrings(Array.isArray(obj.reasons) ? obj.reasons : []);
  if (!reasons.length) reasons.push(fallbackReason);
  return {
    score,
    level,
    reasons: reasons.slice(0, 8),
  };
}

function normalizeRecoConfidenceByBlock(raw) {
  const out = {};
  const src = isPlainObject(raw) ? raw : {};
  for (const [key, value] of Object.entries(src)) {
    const token = String(key || '').trim();
    if (!token) continue;
    out[token] = normalizeRecoConfidenceEntry(value, `${token}_default`);
  }
  const requiredBlocks = ['competitors', 'related_products', 'dupes'];
  for (const block of requiredBlocks) {
    if (!out[block]) out[block] = normalizeRecoConfidenceEntry(null, `${block}_default`);
  }
  return out;
}

function normalizeRecoProvenance(raw, payload) {
  const src = isPlainObject(raw) ? raw : {};
  const socialChannelsUsed = extractWhitelistedSocialChannels({
    channels: [
      ...(Array.isArray(src.social_channels_used) ? src.social_channels_used : []),
      ...(Array.isArray(src.socialChannelsUsed) ? src.socialChannelsUsed : []),
    ],
  });
  const contractVersion =
    (typeof src.contract_version === 'string' && src.contract_version.trim()) ||
    (typeof payload?.product_intel_contract_version === 'string' && payload.product_intel_contract_version.trim()) ||
    'aurora.product_intel.contract.v2';
  return {
    ...src,
    generated_at:
      (typeof src.generated_at === 'string' && src.generated_at.trim()) || new Date().toISOString(),
    contract_version: contractVersion,
    pipeline: (typeof src.pipeline === 'string' && src.pipeline.trim()) || 'aurora_product_intel_main_path',
    source: (typeof src.source === 'string' && src.source.trim()) || 'aurora_bff_routes',
    validation_mode: (typeof src.validation_mode === 'string' && src.validation_mode.trim()) || 'soft_fail',
    ...(socialChannelsUsed.length ? { social_channels_used: socialChannelsUsed } : {}),
  };
}

function normalizeRecoGuardBrandId(value) {
  return String(value == null ? '' : value).trim().toLowerCase();
}

function getRecoGuardAnchorBrandId(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const assessment = isPlainObject(p.assessment) ? p.assessment : {};
  const anchor = isPlainObject(assessment.anchor_product || assessment.anchorProduct)
    ? (assessment.anchor_product || assessment.anchorProduct)
    : {};
  return pickFirstTrimmed(
    anchor.brand_id,
    anchor.brandId,
    anchor.brand,
    anchor.brand_name,
    anchor.brandName,
    p.anchor_brand_id,
    p.anchorBrandId,
  );
}

function getRecoGuardCandidateBrandId(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  return pickFirstTrimmed(row.brand_id, row.brandId, row.brand, row.brand_name, row.brandName);
}

function getRecoGuardCandidateSourceType(candidate) {
  return getRecoCandidateSourceTypeToken(candidate);
}

function getRecoGuardTopFeatureKeys(block) {
  const token = String(block || '').trim().toLowerCase();
  if (token === 'related_products') return ['brand_affinity', 'co_view', 'kb_routine'];
  if (token === 'dupes') {
    return [
      'category_use_case_match',
      'ingredient_functional_similarity',
      'skin_fit_similarity',
      'social_reference_strength',
      'price_distance',
      'brand_constraint',
    ];
  }
  return [
    'category_use_case_match',
    'ingredient_functional_similarity',
    'skin_fit_similarity',
    'social_reference_strength',
    'price_distance',
    'quality',
    'brand_constraint',
  ];
}

const RECO_GUARD_FEATURE_REASON_KEYWORDS = {
  category_use_case_match: ['category', 'use-case', 'scenario', '品类', '场景'],
  ingredient_functional_similarity: ['ingredient', 'active', '成分', '活性'],
  skin_fit_similarity: ['skin profile', 'skin type', 'sensitive', '肤质', '敏感'],
  social_reference_strength: ['social', 'public', 'community', '社交', '反馈'],
  price_distance: ['price', 'budget', 'cost', '价格', '预算'],
  quality: ['source quality', 'evidence', '来源质量', '证据'],
  brand_constraint: ['cross-brand', '品牌'],
  brand_affinity: ['brand affinity', '品牌关联'],
  co_view: ['co-view', '共现'],
  kb_routine: ['routine', '组合', '搭配'],
};

function normalizeRecoGuardWhyCandidateText(whyCandidate) {
  if (!whyCandidate) return '';
  if (Array.isArray(whyCandidate)) return whyCandidate.map((item) => String(item || '').toLowerCase()).join(' | ');
  if (isPlainObject(whyCandidate)) {
    const reasons = Array.isArray(whyCandidate.reasons_user_visible) ? whyCandidate.reasons_user_visible : [];
    const summary = typeof whyCandidate.summary === 'string' ? whyCandidate.summary : '';
    return [summary, ...reasons].map((item) => String(item || '').toLowerCase()).join(' | ');
  }
  return String(whyCandidate || '').toLowerCase();
}

function isRecoGuardExplanationAlignedAt3(candidate, block) {
  const row = isPlainObject(candidate) ? candidate : {};
  const scoreBreakdown = isPlainObject(row.score_breakdown) ? row.score_breakdown : {};
  const scored = [];
  for (const key of getRecoGuardTopFeatureKeys(block)) {
    const value = normalizeMaybePercentScore(scoreBreakdown[key]);
    if (value == null) continue;
    scored.push({ key, value });
  }
  if (!scored.length) return false;
  scored.sort((a, b) => {
    if (b.value !== a.value) return b.value - a.value;
    return a.key.localeCompare(b.key);
  });
  const reasonsText = normalizeRecoGuardWhyCandidateText(row.why_candidate);
  if (!reasonsText.trim()) return false;
  const top3 = scored.slice(0, 3);
  return top3.every((item) =>
    (RECO_GUARD_FEATURE_REASON_KEYWORDS[item.key] || []).some((keyword) =>
      reasonsText.includes(String(keyword || '').trim().toLowerCase()),
    ),
  );
}

function observeRecoGuardrailBlockMetrics(payload, { mode = 'main_path', anchorBrandId = '' } = {}) {
  const p = isPlainObject(payload) ? payload : {};
  const modeToken = normalizeRecoGuardMode(mode);
  const anchorBrandToken = normalizeRecoGuardBrandId(anchorBrandId || getRecoGuardAnchorBrandId(p));
  let competitorsTotal = 0;
  let competitorsSameBrand = 0;
  let competitorsOnPage = 0;
  let alignmentTotal = 0;
  let alignmentAligned = 0;

  for (const block of ['competitors', 'related_products', 'dupes']) {
    const blockObj = isPlainObject(p[block]) ? p[block] : {};
    const candidates = Array.isArray(blockObj.candidates) ? blockObj.candidates : [];
    for (const candidate of candidates) {
      const sourceType = getRecoGuardCandidateSourceType(candidate) || 'unknown';
      const candidateBrandToken = normalizeRecoGuardBrandId(getRecoGuardCandidateBrandId(candidate));
      const brandRelation =
        anchorBrandToken && candidateBrandToken
          ? anchorBrandToken === candidateBrandToken
            ? 'same_brand'
            : 'cross_brand'
          : 'unknown';
      recordRecoCandidate({
        block,
        sourceType,
        brandRelation,
        mode: modeToken,
      });

      const aligned = isRecoGuardExplanationAlignedAt3(candidate, block);
      recordRecoExplanationAlignment({
        block,
        aligned,
        mode: modeToken,
      });
      alignmentTotal += 1;
      if (aligned) alignmentAligned += 1;

      if (block === 'competitors') {
        competitorsTotal += 1;
        if (sourceType === 'on_page_related') competitorsOnPage += 1;
        if (brandRelation === 'same_brand') competitorsSameBrand += 1;
      }
    }
  }

  const sameBrandRate = competitorsTotal > 0 ? competitorsSameBrand / competitorsTotal : 0;
  const onPageRate = competitorsTotal > 0 ? competitorsOnPage / competitorsTotal : 0;
  const alignmentRate = alignmentTotal > 0 ? alignmentAligned / alignmentTotal : 0;
  setRecoGuardrailRates({
    competitorsSameBrandRate: sameBrandRate,
    competitorsOnPageSourceRate: onPageRate,
    explanationAlignmentAt3: alignmentRate,
  });
  return {
    competitors_total: competitorsTotal,
    competitors_same_brand_hits: competitorsSameBrand,
    competitors_on_page_hits: competitorsOnPage,
    explanation_alignment_at3: alignmentRate,
  };
}

function applyRecoGuardrailToProductAnalysisPayload(
  payload,
  { logger, requestId = 'unknown', mode = 'main_path' } = {},
) {
  const p = isPlainObject(payload) ? payload : null;
  if (!p) return payload;
  const modeToken = normalizeRecoGuardMode(mode);
  const anchorBrandId = normalizeRecoGuardBrandId(getRecoGuardAnchorBrandId(p));
  const telemetry = observeRecoGuardrailBlockMetrics(p, { mode: modeToken, anchorBrandId });
  if (!AURORA_BFF_RECO_GUARD_ENABLED) return p;
  const telemetryOnly = AURORA_PRODUCT_GUARDRAIL_TELEMETRY_ONLY;
  const circuitGuardEnabled = AURORA_BFF_RECO_GUARD_CIRCUIT_ENABLED && !telemetryOnly;

  const competitorsObj = isPlainObject(p.competitors) ? p.competitors : {};
  const rawCandidates = Array.isArray(competitorsObj.candidates) ? competitorsObj.candidates : [];
  const nowMs = Date.now();
  const circuitBefore = getRecoGuardrailCircuitSnapshot(modeToken, nowMs);
  let circuitOpen = Boolean(circuitBefore.open);
  let circuitUntilMs = Number(circuitBefore.open_until_ms || 0);
  let autoRollbackFlag = false;
  let circuitRecovered = false;
  const violations = [];
  let filteredCandidates = [];
  if (telemetryOnly) {
    circuitOpen = false;
    circuitUntilMs = 0;
  }

  for (const candidate of rawCandidates) {
    const sourceType = getRecoGuardCandidateSourceType(candidate);
    const candidateBrandId = normalizeRecoGuardBrandId(getRecoGuardCandidateBrandId(candidate));
    const sameBrandBlocked =
      AURORA_BFF_RECO_GUARD_STRICT_DEFAULT_MODE &&
      Boolean(anchorBrandId) &&
      Boolean(candidateBrandId) &&
      anchorBrandId === candidateBrandId;
    const onPageBlocked = sourceType === 'on_page_related';
    const legacySourceBlocked = sourceType === 'aurora_alternatives';
    if (!sameBrandBlocked && !onPageBlocked && !legacySourceBlocked) {
      filteredCandidates.push(candidate);
      continue;
    }
    if (sameBrandBlocked) {
      violations.push({
        violation_type: 'same_brand',
        source_type: sourceType || 'unknown',
        candidate_brand_id: candidateBrandId || '',
      });
    }
    if (onPageBlocked) {
      violations.push({
        violation_type: 'on_page_source',
        source_type: sourceType || 'unknown',
        candidate_brand_id: candidateBrandId || '',
      });
    }
    if (legacySourceBlocked) {
      violations.push({
        violation_type: 'legacy_alternatives_source',
        source_type: sourceType || 'unknown',
        candidate_brand_id: candidateBrandId || '',
      });
    }
    if (telemetryOnly) {
      const row = isPlainObject(candidate) ? { ...candidate } : candidate;
      if (isPlainObject(row)) {
        row.guardrail_flags = uniqCaseInsensitiveStrings(
          [
            ...(Array.isArray(row.guardrail_flags) ? row.guardrail_flags : []),
            ...(sameBrandBlocked ? ['same_brand'] : []),
            ...(onPageBlocked ? ['on_page_source'] : []),
            ...(legacySourceBlocked ? ['legacy_alternatives_source'] : []),
          ],
          8,
        );
        row.low_relevance = true;
      }
      filteredCandidates.push(row);
    }
  }

  if (circuitOpen && circuitGuardEnabled) {
    if (!violations.length && filteredCandidates.length) {
      const state = getRecoGuardrailCircuitState(modeToken);
      state.open_until_ms = 0;
      state.consecutive_violations = 0;
      state.last_violations = [];
      circuitOpen = false;
      circuitUntilMs = 0;
      circuitRecovered = true;
      logger?.info?.(
        {
          event_name: 'reco_guardrail_circuit_recovered',
          request_id: requestId,
          mode: modeToken,
          block: 'competitors',
          candidates_after: filteredCandidates.length,
        },
        'aurora bff: reco guardrail circuit recovered',
      );
    } else {
      autoRollbackFlag = true;
      filteredCandidates = [];
    }
  }

  const violationTypes = uniqCaseInsensitiveStrings(
    violations.map((item) => item.violation_type),
    8,
  );
  let circuitOpenedNow = false;
  if (violations.length && !circuitOpen && circuitGuardEnabled) {
    const circuitUpdate = markRecoGuardrailCircuitViolation(modeToken, violationTypes, nowMs);
    circuitOpenedNow = Boolean(circuitUpdate.opened);
    circuitOpen = Boolean(circuitUpdate.snapshot.open);
    circuitUntilMs = Number(circuitUpdate.snapshot.open_until_ms || 0);
    if (circuitOpenedNow) {
      autoRollbackFlag = true;
      filteredCandidates = [];
      recordRecoGuardrailCircuitOpen({ mode: modeToken });
      logger?.warn(
        {
          event_name: 'reco_guardrail_circuit_opened',
          request_id: requestId,
          mode: modeToken,
          block: 'competitors',
          circuit_open: true,
          circuit_until_ms: circuitUntilMs,
          auto_rollback_flag: true,
        },
        'aurora bff: reco guardrail circuit opened',
      );
    }
  } else if (!circuitOpen && circuitGuardEnabled) {
    markRecoGuardrailCircuitSuccess(modeToken);
  }

  const effectiveCandidates = circuitOpen && circuitGuardEnabled ? [] : filteredCandidates;
  const hasSanitizeAction = !telemetryOnly && (effectiveCandidates.length !== rawCandidates.length || violations.length > 0);
  const guardrailApplied = !telemetryOnly && Boolean(hasSanitizeAction || (circuitOpen && circuitGuardEnabled));

  for (const violation of violations) {
    recordRecoGuardrailViolation({
      block: 'competitors',
      violationType: violation.violation_type,
      mode: modeToken,
      action: telemetryOnly ? 'telemetry_only' : (circuitOpen ? 'circuit_drop' : 'sanitize'),
    });
    logger?.warn(
      {
        event_name: 'reco_guardrail_violation',
        request_id: requestId,
        mode: modeToken,
        block: 'competitors',
        violation_type: violation.violation_type,
        source_type: violation.source_type || 'unknown',
        anchor_brand_id: anchorBrandId || '',
        candidate_brand_id: violation.candidate_brand_id || '',
        action: telemetryOnly ? 'telemetry_only' : (circuitOpen ? 'circuit_drop' : 'sanitize'),
        circuit_open: Boolean(circuitOpen),
        circuit_until_ms: circuitOpen ? circuitUntilMs : 0,
        auto_rollback_flag: Boolean(autoRollbackFlag),
      },
      'aurora bff: reco guardrail violation',
    );
  }

  const existingCodes = getProductAnalysisInternalMissingCodes(p);
  const guardCodes = [];
  if (guardrailApplied) guardCodes.push('reco_guardrail_applied');
  if (telemetryOnly && violationTypes.length) guardCodes.push('reco_guardrail_telemetry_only');
  if (violationTypes.includes('same_brand') && !telemetryOnly) guardCodes.push('reco_guardrail_same_brand_filtered');
  if (violationTypes.includes('on_page_source') && !telemetryOnly) guardCodes.push('reco_guardrail_on_page_filtered');
  if (circuitOpen) guardCodes.push('reco_guardrail_circuit_open');
  if (circuitRecovered) guardCodes.push('reco_guardrail_circuit_recovered');
  const nextInternalCodes = uniqCaseInsensitiveStrings(
    [...existingCodes, ...guardCodes],
    32,
  );

  const confidenceByBlock = normalizeRecoConfidenceByBlock(p.confidence_by_block);
  if (guardrailApplied && !telemetryOnly) {
    const prevCompetitorConfidence = isPlainObject(confidenceByBlock.competitors)
      ? confidenceByBlock.competitors
      : normalizeRecoConfidenceEntry(null, 'competitors_default');
    const reasons = uniqCaseInsensitiveStrings(
      [
        ...((Array.isArray(prevCompetitorConfidence.reasons) ? prevCompetitorConfidence.reasons : [])),
        ...(violationTypes.includes('same_brand') ? ['guardrail_same_brand_filtered'] : []),
        ...(violationTypes.includes('on_page_source') ? ['guardrail_on_page_filtered'] : []),
        ...(violationTypes.includes('legacy_alternatives_source') ? ['guardrail_legacy_alternatives_source_filtered'] : []),
        ...(circuitOpen ? ['guardrail_circuit_open'] : []),
      ],
      8,
    );
    confidenceByBlock.competitors = {
      score: Math.min(circuitOpen ? 0.05 : 0.2, Number(prevCompetitorConfidence.score) || 1),
      level: 'low',
      reasons: reasons.length ? reasons : ['guardrail_applied'],
    };
  }

  const provenanceObj = isPlainObject(p.provenance) ? p.provenance : {};
  const nextProvenance = {
    ...provenanceObj,
    guardrail_applied: guardrailApplied,
    guardrail_mode: telemetryOnly ? 'telemetry_only' : 'enforce',
    guardrail_violations: uniqCaseInsensitiveStrings(
      [
        ...(Array.isArray(provenanceObj.guardrail_violations) ? provenanceObj.guardrail_violations : []),
        ...violationTypes,
        ...(circuitOpen ? ['circuit_open'] : []),
      ],
      8,
    ),
    guardrail_circuit_open: Boolean(circuitOpen),
    guardrail_circuit_until_ms: circuitOpen ? circuitUntilMs : 0,
    auto_rollback_flag: Boolean(autoRollbackFlag),
  };

  logger?.info?.(
    {
      event_name: 'reco_guardrail_gate_result',
      request_id: requestId,
      mode: modeToken,
      block: 'competitors',
      violation_count: violations.length,
      action: telemetryOnly ? 'telemetry_only' : (circuitOpen ? 'circuit_drop' : hasSanitizeAction ? 'sanitize' : 'pass'),
      circuit_open: Boolean(circuitOpen),
      circuit_until_ms: circuitOpen ? circuitUntilMs : 0,
      auto_rollback_flag: Boolean(autoRollbackFlag),
      candidates_before: rawCandidates.length,
      candidates_after: effectiveCandidates.length,
      competitors_same_brand_rate: telemetry.competitors_total > 0
        ? telemetry.competitors_same_brand_hits / telemetry.competitors_total
        : 0,
      competitors_on_page_source_rate: telemetry.competitors_total > 0
        ? telemetry.competitors_on_page_hits / telemetry.competitors_total
        : 0,
      explanation_alignment_at3: telemetry.explanation_alignment_at3,
    },
    'aurora bff: reco guardrail gate result',
  );

  return applyProductAnalysisGapContract({
    ...p,
    competitors: {
      ...competitorsObj,
      candidates: effectiveCandidates,
    },
    confidence_by_block: confidenceByBlock,
    provenance: nextProvenance,
    internal_debug_codes: nextInternalCodes,
    missing_info_internal: nextInternalCodes,
  });
}

function finalizeProductAnalysisRecoContract(payload, { logger, requestId = 'unknown', mode = 'main_path' } = {}) {
  const p = isPlainObject(payload) ? payload : {};
  const internalCodes = uniqCaseInsensitiveStrings(
    [
      ...getProductAnalysisInternalMissingCodes(p),
      ...(Array.isArray(p.missing_info_internal) ? p.missing_info_internal : []),
      ...(Array.isArray(p.internal_debug_codes) ? p.internal_debug_codes : []),
    ],
    32,
  );
  const normalized = applyProductAnalysisGapContract({
    ...p,
    competitors: normalizeRecoBlockForContract({
      ...(isPlainObject(p.competitors) ? p.competitors : {}),
      block_type: 'competitors',
    }),
    related_products: normalizeRecoBlockForContract({
      ...(isPlainObject(p.related_products) ? p.related_products : {}),
      block_type: 'related_products',
    }),
    dupes: normalizeRecoBlockForContract({
      ...(isPlainObject(p.dupes) ? p.dupes : {}),
      block_type: 'dupes',
    }),
    confidence_by_block: normalizeRecoConfidenceByBlock(p.confidence_by_block),
    provenance: normalizeRecoProvenance(p.provenance, p),
    missing_info_internal: internalCodes,
    internal_debug_codes: internalCodes,
  });

  const validation = validateRecoBlocksResponse(normalized);
  if (validation.ok) {
    return applyRecoGuardrailToProductAnalysisPayload(normalized, {
      logger,
      requestId,
      mode,
    });
  }

  const fallbackCodes = uniqCaseInsensitiveStrings(
    [...internalCodes, 'reco_blocks_schema_invalid'],
    32,
  );
  logger?.warn(
    { errors: validation.errors.slice(0, 8) },
    'aurora bff: reco blocks schema invalid; soft-fail fallback applied',
  );
  const fallbackPayload = applyProductAnalysisGapContract({
    ...normalized,
    competitors: { candidates: [] },
    related_products: { candidates: [] },
    dupes: { candidates: [] },
    confidence_by_block: normalizeRecoConfidenceByBlock({}),
    provenance: normalizeRecoProvenance(normalized.provenance, normalized),
    missing_info_internal: fallbackCodes,
    internal_debug_codes: fallbackCodes,
  });
  return applyRecoGuardrailToProductAnalysisPayload(fallbackPayload, {
    logger,
    requestId,
    mode,
  });
}

function buildRouterAnchorFromProductLike(anchorProduct) {
  const anchor = anchorProduct && typeof anchorProduct === 'object' && !Array.isArray(anchorProduct) ? anchorProduct : null;
  if (!anchor) return {};
  return {
    brand_id: pickFirstTrimmed(anchor.brand_id, anchor.brandId, anchor.brand, anchor.brand_name, anchor.brandName),
    category_taxonomy: anchor.category_taxonomy || anchor.categoryTaxonomy || anchor.category || null,
    price: anchor.price || null,
  };
}

function summarizeRouterReasonCodes(routeOut) {
  return collectRouterReasonCodeTokens(routeOut).map((token) => `router.${token}`).slice(0, 24);
}

function collectRouterReasonCodeTokens(routeOut) {
  const out = [];
  const seen = new Set();
  for (const row of Array.isArray(routeOut?.internal_reason_codes) ? routeOut.internal_reason_codes : []) {
    const reasons = Array.isArray(row?.reason_codes) ? row.reason_codes : [];
    for (const raw of reasons) {
      const token = String(raw || '').trim();
      if (!token) continue;
      const key = token.toLowerCase();
      if (seen.has(key)) continue;
      seen.add(key);
      out.push(token);
      if (out.length >= 32) return out;
    }
  }
  return out;
}

function routeCompetitorCandidatePools({
  anchorProduct = null,
  candidates = [],
  ctx = null,
  maxCandidates = PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
} = {}) {
  const routed = routeCandidates(
    buildRouterAnchorFromProductLike(anchorProduct),
    Array.isArray(candidates) ? candidates : [],
    ctx || {
      allow_same_brand_competitors: false,
      allow_same_brand_dupes: false,
    },
  );
  const candidateFilterStats = initCandidateFilterStats();
  const routeReasonCodesRaw = collectRouterReasonCodeTokens(routed);
  return {
    routed,
    routeReasonCodesRaw,
    candidateFilterStats,
    compPool: filterBlockedCompetitorSourceCandidates(
      sanitizeCompetitorCandidates(routed?.comp_pool, maxCandidates, {
        enforceSkincare: true,
        pool: 'competitors',
        stats: candidateFilterStats,
      }),
    ),
    relPool: sanitizeCompetitorCandidates(routed?.rel_pool, maxCandidates, {
      enforceSkincare: true,
      pool: 'related_products',
      stats: candidateFilterStats,
    }),
    dupePool: filterBlockedCompetitorSourceCandidates(
      sanitizeCompetitorCandidates(routed?.dupe_pool, maxCandidates, {
        enforceSkincare: true,
        pool: 'dupes',
        stats: candidateFilterStats,
      }),
    ),
  };
}

function buildRecoBlocksTimeouts() {
  return {
    catalog_ann: AURORA_BFF_RECO_BLOCKS_TIMEOUT_CATALOG_ANN_MS,
    ingredient_index: AURORA_BFF_RECO_BLOCKS_TIMEOUT_INGREDIENT_INDEX_MS,
    skin_fit_light: AURORA_BFF_RECO_BLOCKS_TIMEOUT_SKIN_FIT_LIGHT_MS,
    kb_backfill: AURORA_BFF_RECO_BLOCKS_TIMEOUT_KB_BACKFILL_MS,
    dupe_pipeline: AURORA_BFF_RECO_BLOCKS_TIMEOUT_DUPE_PIPELINE_MS,
    on_page_related: AURORA_BFF_RECO_BLOCKS_TIMEOUT_ON_PAGE_RELATED_MS,
  };
}

function buildRecoBlocksRouterCtx() {
  return {
    allow_same_brand_competitors: false,
    allow_same_brand_dupes: false,
  };
}

function getRecoDogfoodSessionId(req, ctx, explicitSessionId = '') {
  const fromBody = pickFirstTrimmed(explicitSessionId);
  if (fromBody) return fromBody;
  const fromHeader = pickFirstTrimmed(
    req?.get?.('X-Session-ID'),
    req?.get?.('x-session-id'),
    req?.headers?.['x-session-id'],
  );
  if (fromHeader) return fromHeader;
  return pickFirstTrimmed(ctx?.aurora_uid, ctx?.trace_id, ctx?.request_id, 'anonymous');
}

function normalizeDogfoodFeaturesEffective(raw = null, { autoRollback = false } = {}) {
  const src = isPlainObject(raw) ? raw : {};
  const baseline = {
    interleave: Boolean(RECO_DOGFOOD_CONFIG.dogfood_mode && RECO_DOGFOOD_CONFIG.interleave.enabled),
    exploration: Boolean(RECO_DOGFOOD_CONFIG.dogfood_mode && RECO_DOGFOOD_CONFIG.exploration.enabled),
    async_rerank: Boolean(RECO_DOGFOOD_CONFIG.dogfood_mode && RECO_DOGFOOD_CONFIG.ui.allow_block_internal_rerank_on_async),
    show_employee_feedback_controls: Boolean(
      RECO_DOGFOOD_CONFIG.dogfood_mode && RECO_DOGFOOD_CONFIG.ui.show_employee_feedback_controls,
    ),
  };
  const merged = {
    interleave: src.interleave == null ? baseline.interleave : Boolean(src.interleave),
    exploration: src.exploration == null ? baseline.exploration : Boolean(src.exploration),
    async_rerank: src.async_rerank == null ? baseline.async_rerank : Boolean(src.async_rerank),
    show_employee_feedback_controls:
      src.show_employee_feedback_controls == null
        ? baseline.show_employee_feedback_controls
        : Boolean(src.show_employee_feedback_controls),
  };
  if (!autoRollback) return merged;
  return {
    ...merged,
    interleave: false,
    exploration: false,
    async_rerank: false,
    show_employee_feedback_controls: false,
  };
}

function getRecoBlockCandidates(payload, block) {
  const obj = isPlainObject(payload?.[block]) ? payload[block] : {};
  return Array.isArray(obj.candidates) ? obj.candidates : [];
}

function scheduleDogfoodAsyncBlockPatches({
  ticketId,
  payload,
  mode = 'main_path',
  logger,
  allowAsyncRerank = false,
  lang = 'EN',
} = {}) {
  if (!RECO_DOGFOOD_CONFIG.dogfood_mode) return;
  if (!allowAsyncRerank) return;
  const ticket = String(ticketId || '').trim();
  if (!ticket) return;
  const sourcePayload = isPlainObject(payload) ? payload : {};
  setTimeout(() => {
    social_enrich_async({
      logger,
      mode,
      lang,
      payload: sourcePayload,
      skip_kb_write: true,
      apply_async_patch: ({ block, next_candidates }) =>
        applyAsyncBlockPatch({
          ticketId: ticket,
          block,
          nextCandidates: Array.isArray(next_candidates) ? next_candidates : [],
        }),
      on_async_update: ({ block, result, changed_count }) => {
        const changedCount = Number.isFinite(Number(changed_count)) ? Math.max(0, Math.trunc(Number(changed_count))) : 0;
        const normalizedResult = String(result || '').trim().toLowerCase() || 'skipped';
        recordRecoAsyncUpdate({
          block,
          result: normalizedResult,
          mode,
          changedCount,
        });
        logger?.info?.(
          {
            event_name: 'reco_async_update',
            ticket_id: ticket,
            block,
            mode,
            result: normalizedResult,
            changed_count: changedCount,
          },
          'aurora bff: reco async update',
        );
      },
    });
  }, 180);
}

function augmentProductAnalysisPayloadForDogfood({
  payload,
  req,
  ctx,
  mode = 'main_path',
  cardId = '',
  sessionId = '',
  logger,
} = {}) {
  const p = isPlainObject(payload) ? payload : null;
  if (!p) return payload;

  const provenance = isPlainObject(p.provenance) ? { ...p.provenance } : {};
  const autoRollback = provenance.auto_rollback_flag === true || provenance.guardrail_circuit_open === true;
  const featuresEffective = normalizeDogfoodFeaturesEffective(provenance.dogfood_features_effective, {
    autoRollback,
  });
  provenance.dogfood_mode = Boolean(RECO_DOGFOOD_CONFIG.dogfood_mode);
  provenance.dogfood_features_effective = featuresEffective;
  provenance.interleave = isPlainObject(provenance.interleave)
    ? provenance.interleave
    : {
      enabled: featuresEffective.interleave,
      rankerA: RECO_DOGFOOD_CONFIG.interleave.rankerA,
      rankerB: RECO_DOGFOOD_CONFIG.interleave.rankerB,
    };
  provenance.lock_top_n_on_first_paint = RECO_DOGFOOD_CONFIG.ui.lock_top_n_on_first_paint;

  const anchorProductId = pickFirstTrimmed(
    p?.assessment?.anchor_product?.product_id,
    p?.assessment?.anchor_product?.sku_id,
    p?.assessment?.anchor_product?.name,
  );
  const blocks = {
    competitors: getRecoBlockCandidates(p, 'competitors'),
    related_products: getRecoBlockCandidates(p, 'related_products'),
    dupes: getRecoBlockCandidates(p, 'dupes'),
  };

  const trackingPayload = isPlainObject(p.candidate_tracking)
    ? p.candidate_tracking
    : isPlainObject(p.tracking)
      ? p.tracking
      : null;
  const trackingByBlock = isPlainObject(trackingPayload?.by_block) ? trackingPayload.by_block : null;
  const interleaveAttributionByBlock = isPlainObject(trackingPayload?.interleave_attribution_by_block)
    ? trackingPayload.interleave_attribution_by_block
    : null;
  const explorationKeysByBlock = isPlainObject(trackingPayload?.exploration_keys_by_block)
    ? trackingPayload.exploration_keys_by_block
    : null;

  if (RECO_DOGFOOD_CONFIG.dogfood_mode) {
    registerRecoTrackingSnapshot({
      requestId: ctx?.request_id,
      sessionId: getRecoDogfoodSessionId(req, ctx, sessionId),
      anchorProductId,
      blocks,
      trackingByBlock,
      interleaveAttribution: interleaveAttributionByBlock,
      explorationKeys: explorationKeysByBlock,
      ttlMs: RECO_DOGFOOD_CONFIG.async.poll_ttl_ms,
    });

    const ticket = createAsyncTicket({
      requestId: ctx?.request_id,
      cardId,
      lockTopN: RECO_DOGFOOD_CONFIG.ui.lock_top_n_on_first_paint,
      initialPayload: {
        competitors: p.competitors,
        related_products: p.related_products,
        dupes: p.dupes,
        provenance,
      },
      ttlMs: RECO_DOGFOOD_CONFIG.async.poll_ttl_ms,
    });
    provenance.async_ticket_id = ticket.ticketId;
    scheduleDogfoodAsyncBlockPatches({
      ticketId: ticket.ticketId,
      payload: p,
      mode,
      logger,
      allowAsyncRerank: featuresEffective.async_rerank === true,
      lang: ctx?.lang,
    });
  }

  for (const block of ['competitors', 'related_products', 'dupes']) {
    const map = isPlainObject(trackingByBlock?.[block]) ? trackingByBlock[block] : null;
    if (!map) continue;
    const explorationCount = Object.values(map).reduce(
      (sum, entry) => sum + (isPlainObject(entry) && entry.was_exploration_slot === true ? 1 : 0),
      0,
    );
    if (explorationCount > 0) {
      recordRecoExplorationSlot({
        block,
        mode,
        delta: explorationCount,
      });
    }
  }

  const nextPayload = {
    ...p,
    provenance,
  };
  delete nextPayload.candidate_tracking;
  delete nextPayload.candidate_tracking_internal;
  delete nextPayload.internal_attribution;
  delete nextPayload.tracking;
  if (isPlainObject(nextPayload.provenance)) {
    nextPayload.provenance = { ...nextPayload.provenance };
    delete nextPayload.provenance.candidate_tracking;
    delete nextPayload.provenance.candidate_tracking_internal;
    delete nextPayload.provenance.internal_attribution;
    delete nextPayload.provenance.internal_reason_codes;
  }
  return nextPayload;
}

function augmentEnvelopeProductAnalysisCardsForDogfood({
  envelope,
  req,
  ctx,
  mode = 'main_path',
  sessionId = '',
  logger,
} = {}) {
  const env = isPlainObject(envelope) ? { ...envelope } : envelope;
  if (!isPlainObject(env)) return envelope;
  const cards = Array.isArray(env.cards) ? env.cards : [];
  env.cards = cards.map((card) => {
    if (!isPlainObject(card)) return card;
    const type = String(card.type || '').trim().toLowerCase();
    if (type !== 'product_analysis') return card;
    return {
      ...card,
      payload: augmentProductAnalysisPayloadForDogfood({
        payload: card.payload,
        req,
        ctx,
        mode,
        cardId: card.card_id,
        sessionId,
        logger,
      }),
    };
  });
  return env;
}

async function augmentEnvelopeProductAnalysisCardsWithPrelabelSuggestions({
  envelope,
  logger,
} = {}) {
  if (!RECO_DOGFOOD_CONFIG.dogfood_mode || !RECO_DOGFOOD_CONFIG.prelabel?.enabled) return envelope;
  const env = isPlainObject(envelope) ? { ...envelope } : envelope;
  if (!isPlainObject(env)) return envelope;
  const cards = Array.isArray(env.cards) ? env.cards : [];
  if (!cards.length) return env;

  env.cards = await Promise.all(
    cards.map(async (card) => {
      if (!isPlainObject(card)) return card;
      const type = String(card.type || '').trim().toLowerCase();
      if (type !== 'product_analysis') return card;
      const payload = isPlainObject(card.payload) ? card.payload : null;
      if (!payload) return card;

      const anchorProductId = pickFirstTrimmed(
        payload?.assessment?.anchor_product?.product_id,
        payload?.assessment?.anchor_product?.sku_id,
        payload?.assessment?.anchorProduct?.product_id,
        payload?.assessment?.anchorProduct?.sku_id,
      );
      if (!anchorProductId) return card;

      try {
        const suggestions = await loadSuggestionsForAnchor({
          anchor_product_id: anchorProductId,
          limit: 220,
        });
        if (!Array.isArray(suggestions) || !suggestions.length) return card;
        return {
          ...card,
          payload: attachPrelabelSuggestionsToPayload(payload, suggestions),
        };
      } catch (err) {
        logger?.warn?.(
          {
            err: err?.message || String(err),
            anchor_product_id: anchorProductId,
          },
          'aurora bff: attach prelabel suggestions failed',
        );
        return card;
      }
    }),
  );
  return env;
}

const URL_FETCH_RETRYABLE_STATUSES = new Set([403, 406, 429]);
const URL_FETCH_RETRYABLE_ERROR_CODES = new Set([
  'network_error',
  'ecconnaborted',
  'econnreset',
  'enotfound',
  'eai_again',
  'etimedout',
  'timeout',
]);

const URL_FETCH_BLOCKED_STATUSES = new Set([403, 406, 429]);

function buildAlternateHostVariantUrl(rawUrl) {
  const text = String(rawUrl || '').trim();
  if (!/^https?:\/\//i.test(text)) return '';
  try {
    const parsed = new URL(text);
    const host = String(parsed.hostname || '').trim();
    if (!host || /^(localhost|\d+\.\d+\.\d+\.\d+)$/i.test(host)) return '';
    if (/^www\./i.test(host)) parsed.hostname = host.replace(/^www\./i, '');
    else parsed.hostname = `www.${host}`;
    return parsed.toString();
  } catch {
    return '';
  }
}

function detectBotChallengePage(html, status, headers = {}) {
  const text = String(html || '');
  const lowered = text.toLowerCase();
  const statusCode = Number(status);
  const headersObj = headers && typeof headers === 'object' ? headers : {};
  const serverHeader = String(headersObj.server || headersObj.Server || '').toLowerCase();
  const hasCloudflareSignal =
    lowered.includes('just a moment') ||
    lowered.includes('cf-ray') ||
    lowered.includes('challenge-platform') ||
    lowered.includes('cloudflare');
  if (hasCloudflareSignal || serverHeader.includes('cloudflare')) {
    return {
      is_challenge: true,
      challenge_type: 'cloudflare_challenge',
    };
  }
  const accessDeniedSignal =
    lowered.includes('access denied') ||
    lowered.includes("you don't have permission to access") ||
    lowered.includes('request blocked');
  if (accessDeniedSignal && (statusCode >= 400 || text.length < 3000)) {
    return {
      is_challenge: true,
      challenge_type: 'access_denied_page',
    };
  }
  if (lowered.includes('datadome') || lowered.includes('captcha-delivery.com')) {
    return {
      is_challenge: true,
      challenge_type: 'datadome_challenge',
    };
  }
  return { is_challenge: false, challenge_type: '' };
}

function buildUrlFetchFailureCode(attempts = []) {
  const rows = Array.isArray(attempts) ? attempts : [];
  const challengeTypes = rows
    .map((item) => String(item?.challenge_type || '').trim().toLowerCase())
    .filter(Boolean);
  const statuses = rows
    .map((item) => Number(item?.status))
    .filter((value) => Number.isFinite(value))
    .map((value) => Math.trunc(value));
  const errorCodes = rows
    .map((item) => String(item?.error_code || '').trim().toLowerCase())
    .filter(Boolean);

  if (challengeTypes.includes('cloudflare_challenge')) return 'url_fetch_challenge_cloudflare';
  if (challengeTypes.includes('access_denied_page')) return 'url_fetch_access_denied';
  if (statuses.includes(403)) return 'url_fetch_forbidden_403';
  if (statuses.includes(429)) return 'url_fetch_rate_limited_429';
  if (statuses.includes(406)) return 'url_fetch_not_acceptable_406';
  if (errorCodes.includes('empty_body')) return 'url_fetch_empty_body';
  if (errorCodes.some((code) => code.includes('timeout') || code === 'ecconnaborted')) return 'url_fetch_timeout';
  return 'url_fetch_failed';
}

function shouldRetryUrlFetchAttempt(attempt = null) {
  if (!attempt || typeof attempt !== 'object') return false;
  if (String(attempt.challenge_type || '').trim()) return true;
  const status = Number(attempt.status);
  if (Number.isFinite(status) && URL_FETCH_RETRYABLE_STATUSES.has(Math.trunc(status))) return true;
  const errorCode = String(attempt.error_code || '').trim().toLowerCase();
  if (!errorCode) return false;
  return URL_FETCH_RETRYABLE_ERROR_CODES.has(errorCode) || errorCode === 'empty_body';
}

function shouldTryUnblockVendor(attempts = []) {
  const rows = Array.isArray(attempts) ? attempts : [];
  if (!rows.length) return false;
  return rows.some((attempt) => {
    if (!attempt || typeof attempt !== 'object') return false;
    if (String(attempt.challenge_type || '').trim()) return true;
    const status = Number(attempt.status);
    if (Number.isFinite(status) && URL_FETCH_BLOCKED_STATUSES.has(Math.trunc(status))) return true;
    return false;
  });
}

async function fetchViaZenRows({
  productUrl,
  timeoutMs,
  jsRender = false,
} = {}) {
  if (!URL_UNBLOCK_ZENROWS_API_KEY) {
    return {
      ok: false,
      status: null,
      html: '',
      error_code: 'vendor_not_configured',
      headers: {},
    };
  }
  const requestTimeout = Math.max(800, Math.min(9000, Number(timeoutMs) || URL_UNBLOCK_TIMEOUT_MS));
  try {
    const resp = await axios.get('https://api.zenrows.com/v1/', {
      timeout: requestTimeout,
      maxContentLength: PRODUCT_URL_INGREDIENT_ANALYSIS_MAX_BYTES,
      maxBodyLength: PRODUCT_URL_INGREDIENT_ANALYSIS_MAX_BYTES,
      responseType: 'text',
      params: {
        apikey: URL_UNBLOCK_ZENROWS_API_KEY,
        url: String(productUrl || ''),
        js_render: jsRender ? 'true' : 'false',
        premium_proxy: 'true',
      },
      validateStatus: (status) => status >= 200 && status < 500,
    });
    const status = Number(resp?.status);
    const body = typeof resp?.data === 'string' ? resp.data : '';
    return {
      ok: status >= 200 && status < 400 && body.trim().length > 0,
      status: Number.isFinite(status) ? Math.trunc(status) : null,
      html: body,
      headers: resp?.headers && typeof resp.headers === 'object' ? resp.headers : {},
      error_code: '',
    };
  } catch (err) {
    const status = Number(err?.response?.status);
    return {
      ok: false,
      status: Number.isFinite(status) ? Math.trunc(status) : null,
      html: '',
      headers: {},
      error_code: String(err?.code || '').trim().toLowerCase() || 'network_error',
    };
  }
}

async function runSingleUrlFetchAttempt({
  strategy,
  provider = 'native',
  productUrl,
  timeoutMs,
  headers = {},
  jsRender = false,
} = {}) {
  if (provider === 'zenrows') {
    const out = await fetchViaZenRows({
      productUrl,
      timeoutMs,
      jsRender,
    });
    const challenge = detectBotChallengePage(out.html, out.status, out.headers);
    const hasBody = String(out.html || '').trim().length > 0;
    if (out.ok && !challenge.is_challenge) {
      return {
        ok: true,
        html: String(out.html || ''),
        status: out.status,
        attempt: {
          strategy,
          provider,
          ...(Number.isFinite(Number(out.status)) ? { status: Number(out.status) } : {}),
        },
      };
    }
    return {
      ok: false,
      html: '',
      status: out.status,
      attempt: {
        strategy,
        provider,
        ...(Number.isFinite(Number(out.status)) ? { status: Number(out.status) } : {}),
        ...(challenge.is_challenge ? { challenge_type: String(challenge.challenge_type || '').trim() } : {}),
        error_code: out.error_code || (hasBody ? 'http_error' : 'empty_body'),
      },
    };
  }

  try {
    const resp = await axios.get(productUrl, {
      timeout: timeoutMs,
      maxContentLength: PRODUCT_URL_INGREDIENT_ANALYSIS_MAX_BYTES,
      maxBodyLength: PRODUCT_URL_INGREDIENT_ANALYSIS_MAX_BYTES,
      responseType: 'text',
      headers,
      validateStatus: (status) => status >= 200 && status < 500,
    });
    const status = Number(resp?.status);
    const body = typeof resp?.data === 'string' ? resp.data : '';
    const challenge = detectBotChallengePage(body, status, resp?.headers);
    if (status >= 200 && status < 400 && body.trim() && !challenge.is_challenge) {
      return {
        ok: true,
        html: body,
        status,
        attempt: {
          strategy,
          provider,
          status: Math.trunc(status),
        },
      };
    }
    return {
      ok: false,
      html: '',
      status,
      attempt: {
        strategy,
        provider,
        ...(Number.isFinite(status) ? { status: Math.trunc(status) } : {}),
        ...(challenge.is_challenge ? { challenge_type: String(challenge.challenge_type || '').trim() } : {}),
        error_code: body.trim() ? 'http_error' : 'empty_body',
      },
    };
  } catch (err) {
    const status = Number(err?.response?.status);
    const codeToken = String(err?.code || '').trim().toLowerCase() || 'network_error';
    return {
      ok: false,
      html: '',
      status,
      attempt: {
        strategy,
        provider,
        ...(Number.isFinite(status) ? { status: Math.trunc(status) } : {}),
        error_code: codeToken,
      },
    };
  }
}

async function fetchProductHtmlWithUnblockChain({
  productUrl,
  timeoutMs = PRODUCT_URL_INGREDIENT_ANALYSIS_TIMEOUT_MS,
  allowHostVariant = true,
  logger,
} = {}) {
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) {
    return {
      ok: false,
      status: null,
      html: '',
      attempts: [{ strategy: 'input_validation', provider: 'native', error_code: 'invalid_url' }],
      final_strategy: 'none',
      failure_code: 'url_invalid',
      unblock_attempted: false,
      unblock_failed: false,
      used_unblock_vendor: false,
    };
  }

  const attemptTimeoutMs = Math.max(
    700,
    Math.min(URL_UNBLOCK_TIMEOUT_MS, Number(timeoutMs) || PRODUCT_URL_INGREDIENT_ANALYSIS_TIMEOUT_MS),
  );
  const totalDeadline = Date.now() + Math.max(attemptTimeoutMs, URL_FETCH_TOTAL_BUDGET_MS);

  const directAttemptsPlan = [
    {
      strategy: 'axios_default',
      provider: 'native',
      url: urlText,
      headers: {
        Accept: 'text/html,application/xhtml+xml',
      },
    },
    {
      strategy: 'curl_ua',
      provider: 'native',
      url: urlText,
      headers: {
        'User-Agent': 'curl/8.7.1',
        Accept: 'text/html,application/xhtml+xml',
      },
    },
  ];
  const hostVariantUrl = allowHostVariant ? buildAlternateHostVariantUrl(urlText) : '';
  if (hostVariantUrl && hostVariantUrl !== urlText) {
    directAttemptsPlan.push({
      strategy: 'host_variant_default',
      provider: 'native',
      url: hostVariantUrl,
      headers: {
        Accept: 'text/html,application/xhtml+xml',
      },
    });
  }

  const attempts = [];
  let unblockAttempted = false;
  for (let index = 0; index < directAttemptsPlan.length; index += 1) {
    if (Date.now() >= totalDeadline) break;
    const plan = directAttemptsPlan[index];
    if (index > 0 && !shouldRetryUrlFetchAttempt(attempts[attempts.length - 1])) break;
    // eslint-disable-next-line no-await-in-loop
    const out = await runSingleUrlFetchAttempt({
      strategy: plan.strategy,
      provider: plan.provider,
      productUrl: plan.url,
      timeoutMs: Math.max(700, Math.min(attemptTimeoutMs, totalDeadline - Date.now())),
      headers: plan.headers,
    });
    if (out.ok) {
      return {
        ok: true,
        status: Number.isFinite(Number(out.status)) ? Number(out.status) : null,
        html: String(out.html || ''),
        attempts: [...attempts, out.attempt],
        final_strategy: plan.strategy,
        failure_code: null,
        unblock_attempted: false,
        unblock_failed: false,
        used_unblock_vendor: false,
      };
    }
    attempts.push(out.attempt);
  }

  const shouldRunVendor =
    URL_UNBLOCK_ENABLED &&
    URL_UNBLOCK_PROVIDER === 'zenrows' &&
    (!URL_UNBLOCK_ONLY_ON_BLOCKED || shouldTryUnblockVendor(attempts));

  if (shouldRunVendor && Date.now() < totalDeadline) {
    const vendorPlans = [
      { strategy: 'zenrows_http', provider: 'zenrows', jsRender: false },
      { strategy: 'zenrows_js_render', provider: 'zenrows', jsRender: true },
    ];
    for (let idx = 0; idx < vendorPlans.length; idx += 1) {
      if (Date.now() >= totalDeadline) break;
      const plan = vendorPlans[idx];
      unblockAttempted = true;
      // eslint-disable-next-line no-await-in-loop
      const out = await runSingleUrlFetchAttempt({
        strategy: plan.strategy,
        provider: plan.provider,
        productUrl: urlText,
        timeoutMs: Math.max(700, Math.min(URL_UNBLOCK_TIMEOUT_MS, totalDeadline - Date.now())),
        jsRender: plan.jsRender,
      });
      if (out.ok) {
        return {
          ok: true,
          status: Number.isFinite(Number(out.status)) ? Number(out.status) : null,
          html: String(out.html || ''),
          attempts: [...attempts, out.attempt],
          final_strategy: plan.strategy,
          failure_code: null,
          unblock_attempted: true,
          unblock_failed: false,
          used_unblock_vendor: true,
        };
      }
      attempts.push(out.attempt);
    }
  }

  const failureCode = buildUrlFetchFailureCode(attempts);
  logger?.debug?.(
    { url: urlText, attempts, failure_code: failureCode },
    'aurora bff: product url fetch fallback failed',
  );
  return {
    ok: false,
    status: null,
    html: '',
    attempts,
    final_strategy: 'none',
    failure_code: failureCode,
    unblock_attempted: unblockAttempted,
    unblock_failed: unblockAttempted,
    used_unblock_vendor: false,
  };
}

async function fetchProductHtmlWithFallback({
  productUrl,
  timeoutMs = PRODUCT_URL_INGREDIENT_ANALYSIS_TIMEOUT_MS,
  allowHostVariant = true,
  logger,
} = {}) {
  return fetchProductHtmlWithUnblockChain({
    productUrl,
    timeoutMs,
    allowHostVariant,
    logger,
  });
}

async function fetchProductPageHtmlForReco({
  productUrl,
  timeoutMs = AURORA_BFF_RECO_BLOCKS_TIMEOUT_ON_PAGE_RELATED_MS,
  logger,
} = {}) {
  const out = await fetchProductHtmlWithFallback({
    productUrl,
    timeoutMs,
    allowHostVariant: true,
    logger,
  });
  if (!out.ok) {
    logger?.debug?.(
      {
        url: String(productUrl || ''),
        failure_code: out.failure_code,
        attempts: out.attempts,
      },
      'aurora bff: reco blocks on-page html fetch failed',
    );
  }
  return {
    html: out.ok ? String(out.html || '') : '',
    fetch_meta: out,
  };
}

async function runRecoBlocksForUrl({
  productUrl,
  anchorProduct = null,
  parsedProduct = null,
  keyIngredients = [],
  profileSummary = null,
  lang = 'EN',
  mode = 'main_path',
  logger,
  html = '',
  existingPayload = null,
  budgetMs = AURORA_BFF_RECO_BLOCKS_BUDGET_MS,
  maxCandidates = PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
} = {}) {
  if (!AURORA_BFF_RECO_BLOCKS_DAG_ENABLED) return null;
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) return null;

  const anchorObj =
    (anchorProduct && typeof anchorProduct === 'object' && !Array.isArray(anchorProduct) ? anchorProduct : null) ||
    (parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null) ||
    null;

  const payloadObj = existingPayload && typeof existingPayload === 'object' && !Array.isArray(existingPayload)
    ? existingPayload
    : null;
  const modeToken = String(mode || '').trim().toLowerCase() || 'main_path';
  const snapshotKey = buildCompetitorSnapshotKey({
    anchor_product_id: pickFirstTrimmed(anchorObj?.product_id, anchorObj?.sku_id),
    normalized_query: pickFirstTrimmed(anchorObj?.display_name, anchorObj?.name),
    product_url: urlText,
    locale: lang,
    surface: 'product_analysis',
    objective: 'competitors',
    category: pickFirstTrimmed(anchorObj?.category, anchorObj?.category_name, anchorObj?.category_taxonomy),
    price_band: inferRecoPriceBand(anchorObj?.price_band, {
      price: normalizePriceObject(anchorObj?.price)?.amount,
    }),
    skin_fit_bucket: buildProfileSkinTags(profileSummary).slice(0, 2).join('_'),
  });
  const snapshotRead = snapshotKey ? readCompetitorSnapshot(snapshotKey) : { hit: false, payload: null, meta: null };
  const snapshotPayload = snapshotRead.hit && snapshotRead.payload && typeof snapshotRead.payload === 'object'
    ? snapshotRead.payload
    : null;
  const snapshotCompetitors = sanitizeCompetitorCandidates(snapshotPayload?.competitors, maxCandidates).map((row) => ({
    ...row,
    source: normalizeRecoSourceObject(row?.source || row?.source_type || 'snapshot'),
    source_type: String(row?.source?.type || row?.source_type || 'snapshot'),
  }));
  const snapshotRelated = sanitizeCompetitorCandidates(snapshotPayload?.related_products, maxCandidates).map((row) => ({
    ...row,
    source: normalizeRecoSourceObject(row?.source || row?.source_type || 'snapshot'),
    source_type: String(row?.source?.type || row?.source_type || 'snapshot'),
  }));
  const snapshotDupes = sanitizeCompetitorCandidates(snapshotPayload?.dupes, maxCandidates).map((row) => ({
    ...row,
    source: normalizeRecoSourceObject(row?.source || row?.source_type || 'snapshot'),
    source_type: String(row?.source?.type || row?.source_type || 'snapshot'),
  }));
  const snapshotReadyForMainPath = modeToken === 'main_path' && snapshotCompetitors.length > 0;
  const snapshotMeta = snapshotRead.hit
    ? {
      key: snapshotRead.key,
      source: String(snapshotRead?.meta?.source || 'snapshot').trim() || 'snapshot',
      confidence:
        Number.isFinite(Number(snapshotRead?.meta?.confidence)) && Number(snapshotRead.meta.confidence) > 0
          ? Number(snapshotRead.meta.confidence)
          : snapshotRead.stale
            ? 0.45
            : 0.68,
      stale: Boolean(snapshotRead.stale),
      very_stale: Boolean(snapshotRead.very_stale),
      degraded: Boolean(snapshotRead.stale || snapshotRead.very_stale),
      age_sec: Number.isFinite(Number(snapshotRead.age_sec)) ? Number(snapshotRead.age_sec) : null,
      coverage: Number.isFinite(Number(snapshotRead?.meta?.coverage)) ? Number(snapshotRead.meta.coverage) : snapshotCompetitors.length,
    }
    : null;
  if (snapshotMeta) {
    recordAuroraCompSnapshotHit({
      mode: modeToken,
      source: snapshotMeta.source,
      confidence: snapshotMeta.confidence >= 0.7 ? 'high' : snapshotMeta.confidence >= 0.45 ? 'med' : 'low',
    });
    if (Number.isFinite(snapshotMeta.age_sec) && snapshotMeta.age_sec >= 0) {
      observeAuroraCompSnapshotAgeSeconds(snapshotMeta.age_sec);
    }
    if (snapshotMeta.stale || snapshotMeta.very_stale) {
      recordAuroraCompSnapshotStale({
        mode: modeToken,
        staleLevel: snapshotMeta.very_stale ? 'very_stale' : 'stale',
      });
      recordAuroraCompDegraded({
        mode: modeToken,
        reason: snapshotMeta.very_stale ? 'snapshot_very_stale' : 'snapshot_stale',
      });
    }
  }

  const kbCompetitors = sanitizeCompetitorCandidates(
    [
      ...snapshotCompetitors,
      ...(Array.isArray(payloadObj?.competitors?.candidates) ? payloadObj.competitors.candidates : []),
    ],
    maxCandidates,
  ).map((row) => ({
    ...row,
    source: normalizeRecoSourceObject(
      row?.source || row?.source_type || (snapshotCompetitors.length ? 'snapshot' : 'kb_backfill'),
    ),
    source_type: String(
      row?.source?.type || row?.source_type || (snapshotCompetitors.length ? 'snapshot' : 'kb_backfill'),
    ),
  }));
  const kbRelated = sanitizeCompetitorCandidates(
    [
      ...snapshotRelated,
      ...(Array.isArray(payloadObj?.related_products?.candidates) ? payloadObj.related_products.candidates : []),
    ],
    maxCandidates,
  ).map((row) => ({
    ...row,
    source: normalizeRecoSourceObject(
      row?.source || row?.source_type || (snapshotRelated.length ? 'snapshot' : 'on_page_related'),
    ),
    source_type: String(
      row?.source?.type || row?.source_type || (snapshotRelated.length ? 'snapshot' : 'on_page_related'),
    ),
  }));
  const kbDupes = sanitizeCompetitorCandidates(
    [
      ...snapshotDupes,
      ...(Array.isArray(payloadObj?.dupes?.candidates) ? payloadObj.dupes.candidates : []),
    ],
    maxCandidates,
  ).map((row) => ({
    ...row,
    source: normalizeRecoSourceObject(
      row?.source || row?.source_type || (snapshotDupes.length ? 'snapshot' : 'kb_backfill'),
    ),
    source_type: String(
      row?.source?.type || row?.source_type || (snapshotDupes.length ? 'snapshot' : 'kb_backfill'),
    ),
  }));

  const sourceFns = {
    catalog_ann: async ({ timeout_ms: timeoutMs, deadline_ms: deadlineMs }) => {
      if (snapshotReadyForMainPath) {
        return {
          candidates: [],
          reason: 'snapshot_short_circuit',
          meta: {
            query_attempted: 0,
            reason_counts: {
              snapshot_short_circuit: 1,
            },
          },
        };
      }
      const queryLimit =
        modeToken === 'async_backfill'
          ? PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_MAX_QUERIES
          : modeToken === 'sync_repair'
            ? PRODUCT_URL_REALTIME_COMPETITOR_SYNC_ENRICH_MAX_QUERIES
            : PRODUCT_URL_REALTIME_COMPETITOR_MAX_QUERIES;
      return buildRealtimeCompetitorCandidates({
        productUrl: urlText,
        parsedProduct: anchorObj,
        keyIngredients: Array.isArray(keyIngredients) ? keyIngredients : [],
        anchorProduct: anchorObj,
        profileSummary,
        lang,
        mode: modeToken,
        deadlineMs,
        timeoutMs: Math.max(120, Number(timeoutMs) || PRODUCT_URL_REALTIME_COMPETITOR_TIMEOUT_MS),
        maxQueries: queryLimit,
        maxCandidates,
        logger,
      });
    },
    ingredient_index: async () => ({
      candidates: [],
      meta: {
        key_ingredients: Array.isArray(keyIngredients) ? keyIngredients.slice(0, 8) : [],
      },
    }),
    skin_fit_light: async () => ({
      candidates: [],
      meta: {
        profile_skin_tags: buildProfileSkinTags(profileSummary),
      },
    }),
    kb_backfill: async () => ({
      competitors: kbCompetitors,
      related_products: kbRelated,
      dupes: kbDupes,
      candidates: [],
      meta: {
        from_existing_payload: Boolean(payloadObj),
      },
    }),
    dupe_pipeline: async () => ({
      candidates: [],
      dupes: kbDupes,
      meta: {
        mode,
      },
    }),
    on_page_related: async ({ timeout_ms: timeoutMs }) => {
      let sourceHtml = typeof html === 'string' ? html : '';
      let fetchMeta = null;
      if (!sourceHtml) {
        const fetchOut = await fetchProductPageHtmlForReco({
          productUrl: urlText,
          timeoutMs,
          logger,
        });
        sourceHtml = String(fetchOut?.html || '');
        fetchMeta =
          fetchOut && fetchOut.fetch_meta && typeof fetchOut.fetch_meta === 'object' && !Array.isArray(fetchOut.fetch_meta)
            ? fetchOut.fetch_meta
            : null;
      }
      if (!sourceHtml) {
        const failureCode = String(fetchMeta?.failure_code || '').trim().toLowerCase();
        return {
          candidates: [],
          reason: 'on_page_fetch_blocked',
          meta: {
            query_attempted: 1,
            reason_counts: {
              on_page_fetch_blocked: 1,
              ...(failureCode ? { [failureCode]: 1 } : {}),
            },
          },
        };
      }
      const recoveredWithFallback =
        fetchMeta &&
        fetchMeta.ok === true &&
        String(fetchMeta.final_strategy || '').trim().toLowerCase() &&
        String(fetchMeta.final_strategy || '').trim().toLowerCase() !== 'axios_default';
      return {
        candidates: buildOnPageCompetitorCandidates({
          html: sourceHtml,
          productUrl: urlText,
          anchorProduct: anchorObj,
          profileSummary,
          lang,
          maxCandidates,
        }),
        ...(recoveredWithFallback
          ? {
            meta: {
              reason_counts: {
                url_fetch_recovered_with_fallback: 1,
              },
            },
          }
          : {}),
      };
    },
  };

  const dagResult = await recoBlocks(
    buildRouterAnchorFromProductLike(anchorObj),
    {
      mode,
      lang,
      on_page_mode: AURORA_BFF_RECO_BLOCKS_ON_PAGE_MODE,
      logger,
      max_candidates: maxCandidates,
      timeouts_ms: (() => {
        const next = buildRecoBlocksTimeouts();
        if (modeToken === 'sync_repair') {
          next.catalog_ann = Math.max(
            next.catalog_ann,
            Math.max(
              1800,
              Math.min(PRODUCT_URL_REALTIME_COMPETITOR_SYNC_ENRICH_TIMEOUT_MS, 2600),
            ),
          );
        } else if (modeToken === 'async_backfill') {
          next.catalog_ann = Math.max(
            next.catalog_ann,
            Math.max(
              2600,
              Math.min(
                PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_TIMEOUT_MS,
                PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_TIMEOUT_CAP_MS,
              ),
            ),
          );
        }
        return next;
      })(),
      router_ctx: buildRecoBlocksRouterCtx(),
      dogfood_config: RECO_DOGFOOD_CONFIG,
      pool_size: RECO_DOGFOOD_CONFIG.retrieval.pool_size,
      sources: sourceFns,
    },
    budgetMs,
  );
  if (!dagResult || typeof dagResult !== 'object') return dagResult;
  if (snapshotMeta) {
    dagResult.snapshot_meta = snapshotMeta;
    if (
      dagResult.provenance_patch &&
      typeof dagResult.provenance_patch === 'object' &&
      !Array.isArray(dagResult.provenance_patch)
    ) {
      dagResult.provenance_patch = {
        ...dagResult.provenance_patch,
        competitor_meta: {
          source: snapshotMeta.source,
          confidence: snapshotMeta.confidence,
          snapshot_age_sec: snapshotMeta.age_sec,
          degraded: snapshotMeta.degraded,
          stale: snapshotMeta.stale,
          very_stale: snapshotMeta.very_stale,
        },
      };
    }
  }
  return dagResult;
}

function sanitizeCompetitorsInPayload(payload, { max = 10 } = {}) {
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) return payload;
  const competitorsObj = p.competitors && typeof p.competitors === 'object' && !Array.isArray(p.competitors) ? p.competitors : null;
  const rawCandidates = Array.isArray(competitorsObj?.candidates) ? competitorsObj.candidates : [];
  if (!rawCandidates.length) return payload;
  const assessment = p.assessment && typeof p.assessment === 'object' && !Array.isArray(p.assessment) ? p.assessment : null;
  const anchorProduct = assessment && typeof assessment.anchor_product === 'object' && !Array.isArray(assessment.anchor_product)
    ? assessment.anchor_product
    : null;
  const routedPools = routeCompetitorCandidatePools({
    anchorProduct,
    candidates: rawCandidates,
    maxCandidates: max,
  });
  const cleanCandidates = routedPools.compPool;
  const recoveredRelated = routedPools.relPool;
  const droppedStats = initCandidateFilterStats(routedPools?.candidateFilterStats);
  const routeReasonCodesRaw = Array.isArray(routedPools?.routeReasonCodesRaw)
    ? routedPools.routeReasonCodesRaw
    : collectRouterReasonCodeTokens(routedPools?.routed);
  const rawLen = rawCandidates.length;
  const cleanLen = cleanCandidates.length;
  const existingRelatedObj = p.related_products && typeof p.related_products === 'object' && !Array.isArray(p.related_products)
    ? p.related_products
    : null;
  const existingRelated = Array.isArray(existingRelatedObj?.candidates) ? existingRelatedObj.candidates : [];
  const mergedRelated = sanitizeCompetitorCandidates([...existingRelated, ...recoveredRelated], max);
  const hasChanged = cleanLen !== rawLen || mergedRelated.length !== existingRelated.length;
  if (!hasChanged) return payload;

  const missingInfo = getProductAnalysisInternalMissingCodes(p);
  const nextMissingInfo = cleanLen
    ? uniqCaseInsensitiveStrings(
      [
        ...stripCompetitorMissingTokens(missingInfo),
        ...(cleanLen < PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT ? ['competitors_low_coverage'] : []),
      ],
      16,
    )
    : uniqCaseInsensitiveStrings([...missingInfo, 'competitors_missing', 'competitor_candidates_filtered_noise'], 16);
  if (Number(droppedStats.competitors_dropped_non_skincare || 0) > 0) nextMissingInfo.push('competitors_non_skincare_filtered');
  if (Number(droppedStats.related_dropped_non_skincare || 0) > 0) nextMissingInfo.push('related_products_non_skincare_filtered');
  if (Number(droppedStats.dupes_dropped_non_skincare || 0) > 0) nextMissingInfo.push('dupes_non_skincare_filtered');
  if (routeReasonCodesRaw.some((code) => String(code || '').trim().toLowerCase() === 'competitor_category_unknown_blocked')) {
    nextMissingInfo.push('competitor_category_unknown_blocked');
  }
  const dedupedMissingInfo = uniqCaseInsensitiveStrings(nextMissingInfo, 20);
  const existingProvenance = p.provenance && typeof p.provenance === 'object' && !Array.isArray(p.provenance)
    ? p.provenance
    : {};
  const existingFilterStats = existingProvenance.candidate_filter_stats
    && typeof existingProvenance.candidate_filter_stats === 'object'
    && !Array.isArray(existingProvenance.candidate_filter_stats)
    ? initCandidateFilterStats(existingProvenance.candidate_filter_stats)
    : initCandidateFilterStats();
  const mergedFilterStats = {
    competitors_dropped_non_skincare: Number(existingFilterStats.competitors_dropped_non_skincare || 0) + Number(droppedStats.competitors_dropped_non_skincare || 0),
    related_dropped_non_skincare: Number(existingFilterStats.related_dropped_non_skincare || 0) + Number(droppedStats.related_dropped_non_skincare || 0),
    dupes_dropped_non_skincare: Number(existingFilterStats.dupes_dropped_non_skincare || 0) + Number(droppedStats.dupes_dropped_non_skincare || 0),
  };

  return applyProductAnalysisGapContract({
    ...p,
    competitors: {
      ...(competitorsObj || {}),
      candidates: cleanCandidates,
    },
    ...(mergedRelated.length
      ? {
        related_products: {
          ...(existingRelatedObj || {}),
          candidates: mergedRelated,
        },
      }
      : {}),
    missing_info: dedupedMissingInfo,
    provenance: {
      ...existingProvenance,
      ...(hasCandidateFilterDropStats(mergedFilterStats) ? { candidate_filter_stats: mergedFilterStats } : {}),
    },
    internal_debug_codes: uniqCaseInsensitiveStrings([
      ...dedupedMissingInfo,
      ...summarizeRouterReasonCodes(routedPools.routed),
    ], 32),
  });
}

function getCompetitorCandidatesFromPayload(payload, { max = 10 } = {}) {
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) return [];
  const competitors =
    p.competitors && typeof p.competitors === 'object' && !Array.isArray(p.competitors)
      ? p.competitors
      : null;
  return sanitizeCompetitorCandidates(competitors?.candidates, max);
}

function getEffectiveCompetitorCoverageFromPayload(payload, { max = 10 } = {}) {
  const candidates = getCompetitorCandidatesFromPayload(payload, { max });
  if (!candidates.length) return 0;
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) return candidates.length;
  const assessment =
    p.assessment && typeof p.assessment === 'object' && !Array.isArray(p.assessment)
      ? p.assessment
      : null;
  const anchorProduct =
    assessment &&
    assessment.anchor_product &&
    typeof assessment.anchor_product === 'object' &&
    !Array.isArray(assessment.anchor_product)
      ? assessment.anchor_product
      : null;
  if (!anchorProduct) return candidates.length;
  const routedPools = routeCompetitorCandidatePools({
    anchorProduct,
    candidates,
    maxCandidates: Math.max(1, Math.min(12, Number(max) || 10)),
  });
  return Array.isArray(routedPools?.compPool) ? routedPools.compPool.length : 0;
}

function hasCompetitorCandidatesInPayload(payload, { minCount = 1 } = {}) {
  const threshold = Math.max(1, Math.min(10, Number(minCount) || 1));
  return getEffectiveCompetitorCoverageFromPayload(payload, { max: 10 }) >= threshold;
}

function hasLowCoverageCompetitorsInPayload(payload, { preferredCount = 2 } = {}) {
  const target = Math.max(1, Math.min(10, Number(preferredCount) || 2));
  const count = getEffectiveCompetitorCoverageFromPayload(payload, { max: 10 });
  return count > 0 && count < target;
}

function hasLowCoverageCompetitorToken(payload) {
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) return false;
  const missingInfo = getProductAnalysisInternalMissingCodes(p);
  return missingInfo.some((raw) => {
    const token = String(raw || '').trim().toLowerCase();
    return token === 'competitors_low_coverage'
      || token === 'alternatives_limited'
      || token === 'competitors_missing'
      || token === 'alternatives_unavailable'
      || token === 'competitor_sync_aurora_fallback_used';
  });
}

function shouldRepairCompetitorCoverage(payload, { preferredCount = 2 } = {}) {
  const target = Math.max(1, Math.min(10, Number(preferredCount) || 2));
  const count = getEffectiveCompetitorCoverageFromPayload(payload, { max: 10 });
  // Empty competitors should always try a bounded repair pass, even when old KB
  // snapshots no longer carry explicit low-coverage tokens.
  if (count === 0) return true;
  if (count >= target) return false;
  return hasLowCoverageCompetitorToken(payload);
}

function getProductAnalysisInternalMissingCodes(payload) {
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) return [];
  return uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(p.internal_debug_codes) ? p.internal_debug_codes : []),
      ...(Array.isArray(p.missing_info_internal) ? p.missing_info_internal : []),
      ...(Array.isArray(p.missing_info) ? p.missing_info : []),
    ],
    32,
  );
}

function stripCompetitorMissingTokens(items) {
  const out = [];
  for (const raw of Array.isArray(items) ? items : []) {
    const token = String(raw || '').trim();
    if (!token) continue;
    if (token === 'competitors_missing') continue;
    if (token === 'competitors.competitors.candidates') continue;
    if (token === 'competitors_low_coverage') continue;
    if (token === 'alternatives_unavailable') continue;
    if (token === 'alternatives_limited') continue;
    if (token === 'competitor_candidates_filtered_noise') continue;
    if (token === 'competitors_non_skincare_filtered') continue;
    if (token === 'related_products_non_skincare_filtered') continue;
    if (token === 'dupes_non_skincare_filtered') continue;
    if (token === 'competitor_category_unknown_blocked') continue;
    if (token === 'competitor_sync_enrich_used') continue;
    if (token === 'competitor_sync_aurora_fallback_used') continue;
    if (/^competitor_recall_/i.test(token)) continue;
    out.push(token);
  }
  return Array.from(new Set(out));
}

function shouldServeProductIntelKbPayload(payload) {
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) return false;
  const assessment = p.assessment && typeof p.assessment === 'object' && !Array.isArray(p.assessment) ? p.assessment : null;
  if (!assessment) return false;

  const missingInfo = getProductAnalysisInternalMissingCodes(p);
  const hasCompetitors = hasCompetitorCandidatesInPayload(p);
  const competitorMissing = missingInfo.some((raw) => {
    const token = String(raw || '').trim().toLowerCase();
    if (!token) return false;
    return token === 'competitors_missing'
      || token === 'competitors.competitors.candidates'
      || token === 'alternatives_unavailable'
      || token === 'competitor_sync_aurora_fallback_used'
      || token.startsWith('competitor_recall_');
  });
  if (competitorMissing && !hasCompetitors) {
    return shouldRepairCompetitorCoverage(p, { preferredCount: PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT });
  }
  return true;
}

function shouldServeProductIntelKbEntry({
  kbEntry = null,
  payload = null,
  productUrl = '',
  anchorTrustContext = null,
} = {}) {
  const serveWithLabels = AURORA_KB_SERVE_POLICY === 'serve_with_labels';
  const p = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!p) {
    return {
      serve: false,
      quarantined: false,
      reason: 'payload_missing',
      reasons: ['payload_missing'],
    };
  }
  if (!PRODUCT_INTEL_KB_QUARANTINE_ENABLED) {
    return {
      serve: true,
      quarantined: false,
      reason: null,
      reasons: [],
    };
  }

  const reasons = [];
  const provenance = p.provenance && typeof p.provenance === 'object' && !Array.isArray(p.provenance) ? p.provenance : {};
  const sourceChain = Array.isArray(provenance.source_chain) ? provenance.source_chain : [];
  const sourceTypes = collectProductIntelEvidenceSourceTypes(p);
  const missingCodes = getProductAnalysisInternalMissingCodes(p).map((item) => String(item || '').trim().toLowerCase());
  const assessment = p.assessment && typeof p.assessment === 'object' && !Array.isArray(p.assessment) ? p.assessment : null;
  const verdictToken = String(assessment?.verdict || '').trim().toLowerCase();
  const isUnknownVerdict = verdictToken === 'unknown' || verdictToken === '未知';
  const hasDiagnosticCodes = missingCodes.some((token) =>
    /^(url_fetch_|on_page_fetch_blocked|regulatory_source_used|retail_source_|incidecoder_|catalog_|anchor_soft_blocked_|anchor_id_not_used_due_to_low_trust|version_verification_needed|analysis_limited|evidence_missing|kb_entry_quarantined)/.test(
      token,
    ),
  );

  if (!sourceChain.length) reasons.push('source_chain_missing');
  if (!sourceTypes.length) reasons.push('evidence_sources_missing');
  if (isUnknownVerdict && !hasDiagnosticCodes) reasons.push('unknown_without_diagnostic_codes');
  if (!sourceTypes.length && getProductAnalysisEvidenceCoverageScore(p) < 0.08) reasons.push('coverage_too_low');

  const trust = anchorTrustContext && typeof anchorTrustContext === 'object' && !Array.isArray(anchorTrustContext)
    ? anchorTrustContext
    : null;
  if (
    /^https?:\/\//i.test(String(productUrl || '').trim()) &&
    trust &&
    trust.usable_for_anchor_id === false &&
    String(trust.level || '').trim().toLowerCase() === 'soft_blocked'
  ) {
    reasons.push('anchor_untrusted_for_url');
  }

  const sourceMeta = kbEntry && kbEntry.source_meta && typeof kbEntry.source_meta === 'object' && !Array.isArray(kbEntry.source_meta)
    ? kbEntry.source_meta
    : null;
  if (sourceMeta && sourceMeta.kb_write && typeof sourceMeta.kb_write === 'object') {
    const persisted = sourceMeta.kb_write.persisted;
    if (persisted === false) reasons.push('kb_write_blocked');
  }

  if (!reasons.length) {
    return {
      serve: true,
      quarantined: false,
      reason: null,
      reasons: [],
    };
  }
  if (serveWithLabels) {
    return {
      serve: true,
      quarantined: true,
      reason: reasons[0],
      reasons,
    };
  }
  return {
    serve: false,
    quarantined: true,
    reason: reasons[0],
    reasons,
  };
}

function scheduleProductIntelCompetitorEnrichBackfill({
  productUrl,
  parsedProduct = null,
  payload = null,
  lang = 'EN',
  profileSummary = null,
  source = 'url_realtime_product_intel',
  sourceMeta = null,
  forceEnhance = false,
  refreshSnapshot = false,
  logger,
} = {}) {
  if (!PRODUCT_INTEL_KB_ASYNC_BACKFILL_ENABLED || !PRODUCT_URL_REALTIME_COMPETITOR_ASYNC_ENRICH_ENABLED) return;
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) return;
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return;
  const needsCoverageRepair = shouldRepairCompetitorCoverage(payload, {
    preferredCount: PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT,
  });
  if (forceEnhance && !refreshSnapshot && !needsCoverageRepair) return;
  if (!forceEnhance && !refreshSnapshot && (
    hasCompetitorCandidatesInPayload(payload) &&
    !hasLowCoverageCompetitorsInPayload(payload, { preferredCount: PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT })
  )) {
    return;
  }

  const payloadAssessment =
    payload && payload.assessment && typeof payload.assessment === 'object' && !Array.isArray(payload.assessment)
      ? payload.assessment
      : null;
  const payloadAnchor =
    payloadAssessment &&
    payloadAssessment.anchor_product &&
    typeof payloadAssessment.anchor_product === 'object' &&
    !Array.isArray(payloadAssessment.anchor_product)
      ? payloadAssessment.anchor_product
      : null;
  const snapshotAnchor =
    payloadAnchor ||
    (parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null);
  const snapshotKey = buildCompetitorSnapshotKey({
    anchor_product_id: pickFirstTrimmed(snapshotAnchor?.product_id, snapshotAnchor?.sku_id),
    normalized_query: pickFirstTrimmed(snapshotAnchor?.display_name, snapshotAnchor?.name),
    product_url: urlText,
    locale: lang,
    surface: 'product_analysis',
    objective: 'competitors',
    category: pickFirstTrimmed(snapshotAnchor?.category, snapshotAnchor?.category_name, snapshotAnchor?.category_taxonomy),
    price_band: inferRecoPriceBand(snapshotAnchor?.price_band, {
      price: normalizePriceObject(snapshotAnchor?.price)?.amount,
    }),
    skin_fit_bucket: buildProfileSkinTags(profileSummary).slice(0, 2).join('_'),
  });
  if (snapshotKey) {
    if (!canEnqueueCompetitorSnapshotBackfill(snapshotKey)) {
      recordAuroraCompBackfillDedupDrop({ mode: 'async_backfill' });
      return;
    }
    markCompetitorSnapshotBackfillCooldown(snapshotKey);
    recordAuroraCompBackfillEnqueued({ mode: 'async_backfill' });
  }

  let payloadSnapshot = null;
  try {
    payloadSnapshot = JSON.parse(JSON.stringify(payload));
  } catch {
    payloadSnapshot = null;
  }
  if (!payloadSnapshot || typeof payloadSnapshot !== 'object' || Array.isArray(payloadSnapshot)) return;

  setImmediate(async () => {
    try {
      const assessment =
        payloadSnapshot.assessment && typeof payloadSnapshot.assessment === 'object' && !Array.isArray(payloadSnapshot.assessment)
          ? payloadSnapshot.assessment
          : null;
      const assessmentAnchor =
        assessment &&
        assessment.anchor_product &&
        typeof assessment.anchor_product === 'object' &&
        !Array.isArray(assessment.anchor_product)
          ? assessment.anchor_product
          : null;
      const anchorForReco =
        assessmentAnchor ||
        (parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null);
      const keyIngredients =
        payloadSnapshot.evidence &&
        payloadSnapshot.evidence.science &&
        Array.isArray(payloadSnapshot.evidence.science.key_ingredients)
          ? payloadSnapshot.evidence.science.key_ingredients
          : [];

      const dagOut = await runRecoBlocksForUrl({
        productUrl: urlText,
        anchorProduct: anchorForReco,
        parsedProduct: parsedProduct,
        keyIngredients,
        profileSummary,
        lang,
        mode: 'async_backfill',
        logger,
        existingPayload: payloadSnapshot,
        budgetMs: Math.max(AURORA_BFF_RECO_BLOCKS_BUDGET_MS, PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_TIMEOUT_MS),
        maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_MAX_CANDIDATES,
      });
      if (!dagOut || typeof dagOut !== 'object') return;
      let asyncCandidates = sanitizeCompetitorCandidates(
        dagOut?.competitors?.candidates,
        PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_MAX_CANDIDATES,
      );
      let asyncRelated = sanitizeCompetitorCandidates(
        dagOut?.related_products?.candidates,
        PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_MAX_CANDIDATES,
      );
      let asyncDupes = sanitizeCompetitorCandidates(
        dagOut?.dupes?.candidates,
        PRODUCT_URL_REALTIME_COMPETITOR_BACKFILL_MAX_CANDIDATES,
      );
      if (!asyncCandidates.length && !asyncRelated.length && !asyncDupes.length) return;
      const routeReasonCodes = summarizeRouterReasonCodes({
        internal_reason_codes: Array.isArray(dagOut.internal_reason_codes) ? dagOut.internal_reason_codes : [],
      });
      const dagDiagnostics = dagOut.diagnostics && typeof dagOut.diagnostics === 'object' ? dagOut.diagnostics : null;
      const dagFallbacksUsed = uniqCaseInsensitiveStrings(
        [
          ...(Array.isArray(dagDiagnostics?.fallbacks_used) ? dagDiagnostics.fallbacks_used : []),
        ],
        12,
      );
      const dagTimedOutBlocks = Array.isArray(dagDiagnostics?.timed_out_blocks) ? dagDiagnostics.timed_out_blocks : [];

      const existingEvidence =
        payloadSnapshot.evidence && typeof payloadSnapshot.evidence === 'object' && !Array.isArray(payloadSnapshot.evidence)
          ? payloadSnapshot.evidence
          : {};
      const existingExpertNotes = Array.isArray(existingEvidence.expert_notes) ? existingEvidence.expert_notes : [];
      const existingEvidenceMissing = stripCompetitorMissingTokens(existingEvidence.missing_info || []);
      const existingProvenance =
        payloadSnapshot.provenance && typeof payloadSnapshot.provenance === 'object' && !Array.isArray(payloadSnapshot.provenance)
          ? payloadSnapshot.provenance
          : {};
      const asyncNote =
        String(lang || '').toUpperCase() === 'CN'
          ? `竞品异步补全（reco DAG）：${asyncCandidates
            .slice(0, 3)
            .map((x) => x.name)
            .join('、')}`
          : `Competitors backfilled async (reco DAG): ${asyncCandidates
            .slice(0, 3)
            .map((x) => x.name)
            .join(', ')}`;

      const mergedPayload = {
        ...payloadSnapshot,
        competitors: { candidates: asyncCandidates },
        ...(asyncRelated.length ? { related_products: { candidates: asyncRelated } } : {}),
        ...(asyncDupes.length ? { dupes: { candidates: asyncDupes } } : {}),
        evidence: {
          ...existingEvidence,
          expert_notes: uniqCaseInsensitiveStrings([...existingExpertNotes, asyncNote], 6),
          missing_info: existingEvidenceMissing,
        },
        ...(dagOut.confidence_patch && typeof dagOut.confidence_patch === 'object'
          ? { confidence_by_block: dagOut.confidence_patch }
          : {}),
        provenance: {
          ...existingProvenance,
          source: 'url_realtime_product_intel_async_backfill',
          ...(dagOut.provenance_patch && typeof dagOut.provenance_patch === 'object' ? dagOut.provenance_patch : {}),
        },
        internal_debug_codes: uniqCaseInsensitiveStrings(
          [
            ...stripCompetitorMissingTokens(getProductAnalysisInternalMissingCodes(payloadSnapshot)),
            ...(Array.isArray(asyncCandidates) && asyncCandidates.length < PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT
              ? ['competitors_low_coverage']
              : []),
            ...routeReasonCodes,
            ...dagFallbacksUsed.map((item) => `reco_dag_fallback_${String(item || '').trim().toLowerCase()}`),
            ...dagTimedOutBlocks.map((item) => `reco_dag_timeout_${String(item || '').trim().toLowerCase()}`),
            'competitor_async_backfill_used',
          ],
          32,
        ),
      };
      const enriched = enrichProductAnalysisPayload(mergedPayload, { lang, profileSummary });
      if (snapshotKey) {
        writeCompetitorSnapshot(
          snapshotKey,
          {
            competitors: asyncCandidates,
            related_products: asyncRelated,
            dupes: asyncDupes,
            competitor_queries: Array.isArray(dagOut.catalog_queries) ? dagOut.catalog_queries : [],
          },
          {
            created_at: new Date().toISOString(),
            source: 'reco_async_backfill',
            ranker_version:
              String(dagOut?.provenance_patch?.pipeline || '').trim() || 'reco_blocks_dag.v1',
            coverage: {
              competitors: asyncCandidates.length,
              related_products: asyncRelated.length,
              dupes: asyncDupes.length,
            },
            confidence:
              dagOut?.confidence_patch?.competitors?.score ??
              dagOut?.confidence_patch?.competitors?.level ??
              0.56,
            reason_flags: [
              ...(dagTimedOutBlocks.length ? ['async_backfill_after_timeout'] : []),
              ...(dagFallbacksUsed.length ? ['async_backfill_after_fallback'] : []),
            ],
          },
        );
      }
      const kbKey = buildProductIntelKbKey({
        productUrl: urlText,
        parsedProduct: assessmentAnchor || anchorForReco,
        lang,
      });
      if (!kbKey) return;
      await upsertProductIntelKbEntry({
        kb_key: kbKey,
        analysis: enriched,
        source,
        source_meta: {
          ...(sourceMeta && typeof sourceMeta === 'object' && !Array.isArray(sourceMeta) ? sourceMeta : {}),
          competitor_async_enriched: true,
          competitor_async_source: 'reco_blocks_dag',
          competitor_queries: Array.isArray(dagOut.catalog_queries) ? dagOut.catalog_queries : [],
          competitor_router_reason_codes: routeReasonCodes,
          reco_blocks_dag: dagDiagnostics
            ? {
              mode: String(dagDiagnostics.mode || 'async_backfill'),
              budget_ms: Number(dagDiagnostics.budget_ms || AURORA_BFF_RECO_BLOCKS_BUDGET_MS),
              timed_out_blocks: dagTimedOutBlocks,
              fallbacks_used: dagFallbacksUsed,
              block_stats:
                dagOut.provenance_patch && typeof dagOut.provenance_patch === 'object'
                  ? dagOut.provenance_patch.block_stats || null
                  : null,
            }
            : null,
        },
        last_success_at: new Date().toISOString(),
        last_error: null,
      });
    } catch (err) {
      logger?.warn(
        { err: err?.message || String(err), url: urlText },
        'aurora bff: async competitor enrich backfill failed',
      );
    }
  });
}

async function maybeSyncRepairLowCoverageCompetitors({
  productUrl,
  payload,
  parsedProduct = null,
  profileSummary = null,
  lang = 'EN',
  logger,
} = {}) {
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) return { payload, enhanced: false, reason: 'url_missing' };

  const payloadObj = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!payloadObj) return { payload, enhanced: false, reason: 'payload_missing' };

  const preferredCount = PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT;
  const existingCandidates = getCompetitorCandidatesFromPayload(payloadObj, {
    max: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  });
  const lowCoverageTokenPresent = hasLowCoverageCompetitorToken(payloadObj);
  if (!existingCandidates.length) {
    // Zero coverage must always attempt bounded sync repair.
  } else if (existingCandidates.length >= preferredCount) {
    return { payload: payloadObj, enhanced: false, reason: 'coverage_ok' };
  } else if (!lowCoverageTokenPresent) {
    return { payload: payloadObj, enhanced: false, reason: 'coverage_token_missing' };
  }

  const assessment =
    payloadObj.assessment && typeof payloadObj.assessment === 'object' && !Array.isArray(payloadObj.assessment)
      ? payloadObj.assessment
      : null;
  const assessmentAnchor =
    assessment &&
    assessment.anchor_product &&
    typeof assessment.anchor_product === 'object' &&
    !Array.isArray(assessment.anchor_product)
      ? assessment.anchor_product
      : null;
  const anchorForRecall =
    assessmentAnchor ||
    (parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null);
  const keyIngredients =
    payloadObj.evidence &&
    payloadObj.evidence.science &&
    Array.isArray(payloadObj.evidence.science.key_ingredients)
      ? payloadObj.evidence.science.key_ingredients
      : [];

  let dagOut = null;
  try {
    dagOut = await runRecoBlocksForUrl({
      productUrl: urlText,
      anchorProduct: anchorForRecall,
      parsedProduct: parsedProduct,
      keyIngredients,
      profileSummary,
      lang,
      mode: 'sync_repair',
      logger,
      existingPayload: payloadObj,
      budgetMs: Math.max(
        AURORA_BFF_RECO_BLOCKS_BUDGET_MS,
        PRODUCT_URL_REALTIME_COMPETITOR_SYNC_ENRICH_TIMEOUT_MS + 900,
        2500,
      ),
      maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
    });
  } catch (err) {
    logger?.warn(
      { err: err?.message || String(err), url: urlText },
      'aurora bff: sync competitor repair dag failed',
    );
    return { payload: payloadObj, enhanced: false, reason: 'reco_blocks_failed' };
  }
  if (!dagOut || typeof dagOut !== 'object') {
    return { payload: payloadObj, enhanced: false, reason: 'dag_disabled' };
  }

  let mergedCandidates = sanitizeCompetitorCandidates(
    dagOut?.competitors?.candidates,
    PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  );
  let mergedRelatedCandidates = sanitizeCompetitorCandidates(
    dagOut?.related_products?.candidates,
    PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  );
  let mergedDupeCandidates = sanitizeCompetitorCandidates(
    dagOut?.dupes?.candidates,
    PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  );
  let syncDirectRecallUsed = false;
  if (!mergedCandidates.length) {
    try {
      const directRecallTimeoutMs = Math.max(2200, PRODUCT_URL_REALTIME_COMPETITOR_SYNC_ENRICH_TIMEOUT_MS + 900);
      const directRecall = await buildRealtimeCompetitorCandidates({
        productUrl: urlText,
        parsedProduct: anchorForRecall,
        keyIngredients: Array.isArray(keyIngredients) ? keyIngredients : [],
        anchorProduct: anchorForRecall,
        profileSummary,
        lang,
        mode: 'sync_repair',
        deadlineMs: Date.now() + directRecallTimeoutMs + 600,
        timeoutMs: directRecallTimeoutMs,
        maxQueries: Math.max(1, Math.min(4, PRODUCT_URL_REALTIME_COMPETITOR_SYNC_ENRICH_MAX_QUERIES + 1)),
        maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
        logger,
      });
      const directCandidates = sanitizeCompetitorCandidates(
        directRecall?.candidates,
        PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
      );
      if (directCandidates.length) {
        const rerouted = routeCompetitorCandidatePools({
          anchorProduct: anchorForRecall,
          candidates: directCandidates,
          maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
        });
        mergedCandidates = sanitizeCompetitorCandidates(
          rerouted.compPool,
          PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
        );
        mergedRelatedCandidates = sanitizeCompetitorCandidates(
          [...mergedRelatedCandidates, ...(Array.isArray(rerouted.relPool) ? rerouted.relPool : [])],
          PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
        );
        mergedDupeCandidates = sanitizeCompetitorCandidates(
          [...mergedDupeCandidates, ...(Array.isArray(rerouted.dupePool) ? rerouted.dupePool : [])],
          PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
        );
        syncDirectRecallUsed = mergedCandidates.length > 0;
      }
    } catch (err) {
      logger?.warn?.(
        { err: err?.message || String(err), url: urlText },
        'aurora bff: sync repair direct recall failed',
      );
    }
  }
  if (!mergedCandidates.length && !mergedRelatedCandidates.length && !mergedDupeCandidates.length) {
    return { payload: payloadObj, enhanced: false, reason: 'reco_dag_empty' };
  }

  const existingKey = existingCandidates.map((row) => {
    const id = pickFirstTrimmed(row?.product_id, row?.sku_id);
    const name = pickFirstTrimmed(row?.name, row?.display_name);
    return `${String(id || '').toLowerCase()}::${String(name || '').toLowerCase()}`;
  });
  const mergedKey = mergedCandidates.map((row) => {
    const id = pickFirstTrimmed(row?.product_id, row?.sku_id);
    const name = pickFirstTrimmed(row?.name, row?.display_name);
    return `${String(id || '').toLowerCase()}::${String(name || '').toLowerCase()}`;
  });
  const existingRelatedObj =
    payloadObj.related_products && typeof payloadObj.related_products === 'object' && !Array.isArray(payloadObj.related_products)
      ? payloadObj.related_products
      : null;
  const existingRelatedCandidates = sanitizeCompetitorCandidates(
    existingRelatedObj?.candidates,
    PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  );
  const existingRelatedKey = existingRelatedCandidates.map((row) => {
    const id = pickFirstTrimmed(row?.product_id, row?.sku_id);
    const name = pickFirstTrimmed(row?.name, row?.display_name);
    return `${String(id || '').toLowerCase()}::${String(name || '').toLowerCase()}`;
  });
  const mergedRelatedKey = mergedRelatedCandidates.map((row) => {
    const id = pickFirstTrimmed(row?.product_id, row?.sku_id);
    const name = pickFirstTrimmed(row?.name, row?.display_name);
    return `${String(id || '').toLowerCase()}::${String(name || '').toLowerCase()}`;
  });

  const existingDupeCandidates = sanitizeCompetitorCandidates(
    payloadObj?.dupes?.candidates,
    PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  );
  const existingDupeKey = existingDupeCandidates.map((row) => {
    const id = pickFirstTrimmed(row?.product_id, row?.sku_id);
    const name = pickFirstTrimmed(row?.name, row?.display_name);
    return `${String(id || '').toLowerCase()}::${String(name || '').toLowerCase()}`;
  });
  const mergedDupeKey = mergedDupeCandidates.map((row) => {
    const id = pickFirstTrimmed(row?.product_id, row?.sku_id);
    const name = pickFirstTrimmed(row?.name, row?.display_name);
    return `${String(id || '').toLowerCase()}::${String(name || '').toLowerCase()}`;
  });

  const changed = mergedKey.join('|') !== existingKey.join('|');
  const relatedChanged = mergedRelatedKey.join('|') !== existingRelatedKey.join('|');
  const dupeChanged = mergedDupeKey.join('|') !== existingDupeKey.join('|');
  const coverageImproved = mergedCandidates.length >= preferredCount;
  if (!changed && !coverageImproved && !relatedChanged && !dupeChanged) {
    return { payload: payloadObj, enhanced: false, reason: 'no_delta' };
  }

  const dagDiagnostics = dagOut.diagnostics && typeof dagOut.diagnostics === 'object' ? dagOut.diagnostics : null;
  const dagFallbacksUsed = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(dagDiagnostics?.fallbacks_used) ? dagDiagnostics.fallbacks_used : []),
      ...(syncDirectRecallUsed ? ['sync_direct_catalog_recall'] : []),
    ],
    12,
  );
  const dagTimedOutBlocks = Array.isArray(dagDiagnostics?.timed_out_blocks) ? dagDiagnostics.timed_out_blocks : [];
  const routeReasonCodes = summarizeRouterReasonCodes({
    internal_reason_codes: Array.isArray(dagOut.internal_reason_codes) ? dagOut.internal_reason_codes : [],
  });
  const existingMissingInfo = getProductAnalysisInternalMissingCodes(payloadObj);
  const mergedMissingInfo = uniqCaseInsensitiveStrings(
    [
      ...stripCompetitorMissingTokens(existingMissingInfo),
      ...(mergedCandidates.length < preferredCount ? ['competitors_low_coverage'] : []),
      ...routeReasonCodes,
      ...dagFallbacksUsed.map((item) => `reco_dag_fallback_${String(item || '').trim().toLowerCase()}`),
      ...dagTimedOutBlocks.map((item) => `reco_dag_timeout_${String(item || '').trim().toLowerCase()}`),
      ...(syncDirectRecallUsed ? ['competitor_sync_direct_recall_used'] : []),
      'competitor_sync_enrich_used',
    ],
    32,
  );

  const evidenceObj =
    payloadObj.evidence && typeof payloadObj.evidence === 'object' && !Array.isArray(payloadObj.evidence)
      ? payloadObj.evidence
      : {};
  const evidenceMissing = uniqCaseInsensitiveStrings(
    [
      ...stripCompetitorMissingTokens(evidenceObj.missing_info || []),
      ...(mergedCandidates.length < preferredCount ? ['competitors_low_coverage'] : []),
    ],
    16,
  );
  const existingExpertNotes = Array.isArray(evidenceObj.expert_notes) ? evidenceObj.expert_notes : [];
  const syncNote = (() => {
    const isCn = String(lang || '').toUpperCase() === 'CN';
    if (mergedCandidates.length) {
      return isCn
        ? `竞品主链路实时补全：${mergedCandidates
          .slice(0, 3)
          .map((x) => x.name)
          .join('、')}`
        : `Competitors refreshed on main path: ${mergedCandidates
          .slice(0, 3)
          .map((x) => x.name)
          .join(', ')}`;
    }
    if (mergedRelatedCandidates.length) {
      return isCn
        ? `同页相关产品已更新（related_products）：${mergedRelatedCandidates
          .slice(0, 3)
          .map((x) => x.name)
          .join('、')}`
        : `Related products refreshed on main path: ${mergedRelatedCandidates
          .slice(0, 3)
          .map((x) => x.name)
          .join(', ')}`;
    }
    if (mergedDupeCandidates.length) {
      return isCn
        ? `dupe 候选已补齐：${mergedDupeCandidates
          .slice(0, 3)
          .map((x) => x.name)
          .join('、')}`
        : `Dupe candidates refreshed: ${mergedDupeCandidates
          .slice(0, 3)
          .map((x) => x.name)
          .join(', ')}`;
    }
    return '';
  })();

  const existingProvenance =
    payloadObj.provenance && typeof payloadObj.provenance === 'object' && !Array.isArray(payloadObj.provenance)
      ? payloadObj.provenance
      : {};
  const nextProvenancePatch =
    dagOut.provenance_patch && typeof dagOut.provenance_patch === 'object' && !Array.isArray(dagOut.provenance_patch)
      ? dagOut.provenance_patch
      : null;

  const mergedPayload = {
    ...payloadObj,
    competitors: { candidates: mergedCandidates },
    ...(mergedRelatedCandidates.length ? { related_products: { candidates: mergedRelatedCandidates } } : {}),
    ...(mergedDupeCandidates.length ? { dupes: { candidates: mergedDupeCandidates } } : {}),
    evidence: {
      ...evidenceObj,
      expert_notes: uniqCaseInsensitiveStrings([...existingExpertNotes, syncNote], 8),
      missing_info: evidenceMissing,
    },
    ...(dagOut.confidence_patch && typeof dagOut.confidence_patch === 'object'
      ? { confidence_by_block: dagOut.confidence_patch }
      : {}),
    provenance: {
      ...existingProvenance,
      source: 'url_realtime_product_intel_sync_repair',
      ...(nextProvenancePatch || {}),
    },
    internal_debug_codes: mergedMissingInfo,
  };
  return { payload: mergedPayload, enhanced: true, reason: null };
}

async function buildProductAnalysisFromUrlIngredients({
  productUrl,
  lang = 'EN',
  profileSummary = null,
  parsedProduct = null,
  logger,
} = {}) {
  const urlText = String(productUrl || '').trim();
  if (!/^https?:\/\//i.test(urlText)) return null;

  let parsedUrl = null;
  try {
    parsedUrl = new URL(urlText);
  } catch {
    return null;
  }

  const parsedProductObj = parsedProduct && typeof parsedProduct === 'object' && !Array.isArray(parsedProduct) ? parsedProduct : null;
  const fetchOut = await fetchProductHtmlWithFallback({
    productUrl: parsedUrl.toString(),
    timeoutMs: PRODUCT_URL_INGREDIENT_ANALYSIS_TIMEOUT_MS,
    allowHostVariant: true,
    logger,
  });
  if (!fetchOut.ok) {
    logger?.warn?.(
      {
        url: parsedUrl.toString(),
        failure_code: fetchOut.failure_code,
        attempts: fetchOut.attempts,
      },
      'aurora bff: product URL ingredient extraction failed',
    );
  }
  const html = fetchOut.ok ? String(fetchOut.html || '') : '';
  const urlFetchRecoveredWithFallback =
    fetchOut.ok === true &&
    String(fetchOut.final_strategy || '').trim().toLowerCase() &&
    String(fetchOut.final_strategy || '').trim().toLowerCase() !== 'axios_default';
  const urlFetchFailureCode = String(fetchOut?.failure_code || '').trim().toLowerCase();
  const urlFetchChallengeBlocked =
    urlFetchFailureCode === 'url_fetch_challenge_cloudflare' || urlFetchFailureCode === 'url_fetch_access_denied';

  const inciList = extractInciListFromHtml(html);
  const keyHints = extractKeyIngredientsFromHtml(html);

  let regulatorySupplement = null;
  let incidecoderSupplement = null;
  let retailSupplement = null;
  if (!html || !inciList.length) {
    try {
      regulatorySupplement = await fetchDailyMedRegulatorySupplement({
        parsedProduct: parsedProductObj,
        productUrl: parsedUrl.toString(),
        lang,
        logger,
      });
    } catch (err) {
      logger?.warn?.(
        {
          url: parsedUrl.toString(),
          err: err?.message || String(err),
        },
        'aurora bff: regulatory supplement lookup failed',
      );
      regulatorySupplement = null;
    }
  }

  if (PRODUCT_INTEL_INCIDECODER_ENABLED && (!html || !inciList.length)) {
    try {
      incidecoderSupplement = await fetchIncidecoderIngredientSupplement({
        parsedProduct: parsedProductObj,
        productUrl: parsedUrl.toString(),
        timeoutMs: PRODUCT_INTEL_INCIDECODER_TIMEOUT_MS,
        logger,
      });
    } catch (err) {
      logger?.warn?.(
        {
          url: parsedUrl.toString(),
          err: err?.message || String(err),
        },
        'aurora bff: inci decoder supplement lookup failed',
      );
      incidecoderSupplement = {
        ok: false,
        query: '',
        reason: 'incidecoder_fetch_failed',
      };
    }
  }
  if (PRODUCT_INTEL_RETAIL_FALLBACK_ENABLED && (!html || !inciList.length)) {
    try {
      retailSupplement = await fetchRetailIngredientSupplement({
        parsedProduct: parsedProductObj,
        productUrl: parsedUrl.toString(),
        timeoutMs: Math.max(2200, Math.min(8000, PRODUCT_URL_INGREDIENT_ANALYSIS_TIMEOUT_MS + 2800)),
        logger,
      });
    } catch (err) {
      logger?.warn?.(
        {
          url: parsedUrl.toString(),
          err: err?.message || String(err),
        },
        'aurora bff: retail supplement lookup failed',
      );
      retailSupplement = {
        ok: false,
        query: '',
        reason: 'retail_source_no_match',
      };
    }
  }

  const regulatoryActiveInci =
    regulatorySupplement && regulatorySupplement.ok && Array.isArray(regulatorySupplement.active_ingredients)
      ? regulatorySupplement.active_ingredients
      : [];
  const retailInci =
    retailSupplement && retailSupplement.ok && Array.isArray(retailSupplement.ingredients)
      ? retailSupplement.ingredients
      : [];
  const incidecoderInci =
    incidecoderSupplement && incidecoderSupplement.ok && Array.isArray(incidecoderSupplement.ingredients)
      ? incidecoderSupplement.ingredients
      : [];

  const descriptor = buildProductDescriptorFromInput({ parsedProduct: parsedProductObj, productUrl: parsedUrl.toString() });
  let llmVerificationResult = null;
  try {
    llmVerificationResult = await fetchLlmIngredientVerification({
      brand: descriptor.brand,
      productName: descriptor.name,
      extractedInci: [...inciList, ...regulatoryActiveInci, ...retailInci, ...incidecoderInci],
      timeoutMs: 6000,
      logger,
    });
  } catch (err) {
    logger?.warn?.({ err: err?.message || String(err) }, 'aurora bff: LLM ingredient verification failed');
    llmVerificationResult = null;
  }
  const llmVerifiedInci =
    llmVerificationResult && llmVerificationResult.ok && Array.isArray(llmVerificationResult.ingredients)
      ? llmVerificationResult.ingredients
      : [];
  const llmMatchScore =
    llmVerificationResult && llmVerificationResult.ok ? (llmVerificationResult.match_score || 0) : 0;

  const ingredientConsensus = buildIngredientConsensus({
    official: inciList,
    regulatory: regulatoryActiveInci,
    retail: retailInci,
    inciDecoder: incidecoderInci,
    llmVerified: llmVerifiedInci,
    llmMatchScore,
  });
  const normalizedInci = ingredientConsensus.merged;
  const officialInciNormalized = canonicalizeIngredientCandidates([...inciList, ...regulatoryActiveInci], { max: 140 });
  const incidecoderOverlapCount = Number(ingredientConsensus?.stats?.overlap_inci_official || 0);
  const ingredientConfidenceTier = String(ingredientConsensus?.confidence_tier || 'none').toLowerCase();
  const inciStatusGapCodes = [
    ...(!html && !fetchOut.ok ? ['on_page_fetch_blocked'] : []),
    ...(regulatorySupplement && regulatorySupplement.ok ? ['regulatory_source_used'] : []),
    ...(retailSupplement && retailSupplement.ok ? ['retail_source_used'] : []),
    ...(incidecoderSupplement && incidecoderSupplement.ok ? ['incidecoder_source_used'] : []),
    ...(llmVerificationResult && llmVerificationResult.ok ? ['llm_verification_used'] : []),
    ...(!normalizedInci.length ? ['evidence_missing'] : []),
  ];
  const inciStatusSources = [
    ...(html
      ? [{
        type: 'official_page',
        url: parsedUrl.toString(),
        confidence: 0.78,
        ingredient_count: canonicalizeIngredientCandidates(inciList, { max: 260 }).length,
      }]
      : []),
    ...(regulatorySupplement && regulatorySupplement.ok
      ? [{
        type: 'regulatory',
        url: String(regulatorySupplement.source?.url || regulatorySupplement.source_url || ''),
        confidence: 0.72,
        ingredient_count: canonicalizeIngredientCandidates(regulatoryActiveInci, { max: 220 }).length,
      }]
      : []),
    ...(retailSupplement && retailSupplement.ok
      ? [{
        type: 'retail_page',
        url: String(retailSupplement.source?.url || retailSupplement.source_url || ''),
        confidence: Number(retailSupplement.source?.confidence || 0.58),
        ingredient_count: canonicalizeIngredientCandidates(retailInci, { max: 220 }).length,
      }]
      : []),
    ...(incidecoderSupplement && incidecoderSupplement.ok
      ? [{
        type: 'inci_decoder',
        url: String(incidecoderSupplement.source?.url || incidecoderSupplement.source_url || ''),
        confidence: Number(incidecoderSupplement.source?.confidence || 0.55),
        ingredient_count: canonicalizeIngredientCandidates(incidecoderInci, { max: 220 }).length,
      }]
      : []),
    ...(llmVerificationResult && llmVerificationResult.ok && llmVerificationResult.source
      ? [{
        type: 'llm_verification',
        url: '',
        confidence: Number(llmVerificationResult.source?.confidence || 0.55),
        ingredient_count: llmVerifiedInci.length,
      }]
      : []),
  ];
  const inciStatus = buildInciStatus({
    gapCodes: inciStatusGapCodes,
    consensusResult: ingredientConsensus,
    sources: inciStatusSources,
  });
  const keyIngredients = deriveKeyIngredientsForAnalysis(
    normalizedInci,
    keyHints.map((item) => normalizeInciIngredientName(item)),
  );
  const mechanisms = deriveIngredientMechanisms(keyIngredients, lang);
  const riskNotes = uniqCaseInsensitiveStrings(
    [
      ...deriveIngredientRiskNotes(normalizedInci, profileSummary || {}, lang, inciStatus),
      ...(regulatorySupplement && regulatorySupplement.ok && Array.isArray(regulatorySupplement.risk_notes)
        ? regulatorySupplement.risk_notes
        : []),
    ],
    6,
  );
  const socialSignals = html
    ? extractRealtimeSocialSignalsFromHtml(html, { lang, riskNotes })
    : {
      has_signal: false,
      platform_scores: {},
      typical_positive: [],
      typical_negative: [],
      risk_for_groups: [],
      notes: [],
    };

  const isCn = String(lang || '').toUpperCase() === 'CN';
  const skinType = String(profileSummary?.skinType || '').trim().toLowerCase();
  const sensitivity = String(profileSummary?.sensitivity || '').trim().toLowerCase();
  const barrier = String(profileSummary?.barrierStatus || '').trim().toLowerCase();
  const highSensitivity = sensitivity === 'high' || barrier === 'impaired';
  const mediumSensitivity = sensitivity === 'medium';
  const lowerInci = normalizedInci.join(' | ').toLowerCase();
  const hasAcidLike = /\b(aha|bha|pha|glycolic|lactic|mandelic|salicylic|retinol|retinal|adapalene|tretinoin)\b/.test(lowerInci);
  const hasFragranceLike = /\b(fragrance|parfum|linalool|limonene|citral|geraniol)\b/.test(lowerInci);
  const hasCommonSunscreenIrritants = /\b(oxybenzone|octocrylene)\b/.test(lowerInci);
  const hasAnyIngredientSignals = normalizedInci.length > 0 || keyIngredients.length > 0;

  const verdict =
    !hasAnyIngredientSignals
      ? isCn
        ? '未知'
        : 'Unknown'
      : highSensitivity && (hasAcidLike || hasFragranceLike || hasCommonSunscreenIrritants)
      ? isCn
        ? '谨慎'
        : 'Caution'
      : mediumSensitivity && (hasAcidLike || hasCommonSunscreenIrritants)
        ? isCn
          ? '谨慎'
          : 'Caution'
        : isCn
          ? '较适配'
          : 'Likely Suitable';

  const fitNotes = uniqCaseInsensitiveStrings([
    skinType === 'oily'
      ? (isCn ? '油皮场景通常更关注控油与不闷闭口。' : 'Oily-skin context generally prioritizes oil control and low-clog load.')
      : '',
    skinType === 'dry'
      ? (isCn ? '干皮场景通常更关注保湿与屏障支持。' : 'Dry-skin context generally prioritizes hydration and barrier support.')
      : '',
    (sensitivity === 'medium' || sensitivity === 'high' || barrier === 'impaired') && (hasAcidLike || hasFragranceLike || hasCommonSunscreenIrritants)
      ? (isCn ? '敏感/屏障不稳时建议低频起步并减少同晚叠加强活性。' : 'For sensitive or impaired-barrier days, start low-frequency and avoid same-night stacking of strong actives.')
      : '',
    ingredientConfidenceTier === 'low' || ingredientConfidenceTier === 'none'
      ? (isCn ? '成分证据一致度偏低，建议继续核对包装 INCI。' : 'Ingredient-source consistency is limited; cross-check with package INCI.')
      : '',
  ], 4);

  const hostName = String(parsedUrl.hostname || '').replace(/^www\./i, '');
  const pageTitle = extractPageTitleFromHtml(html);
  const extractedPrice = extractProductPriceFromHtml(html);
  const anchorBrand = pickFirstTrimmed(
    parsedProductObj?.brand,
    pageTitle.includes('|') ? pageTitle.split('|').slice(-1)[0] : '',
  );
  const anchorName = pickFirstTrimmed(
    parsedProductObj?.name,
    pageTitle.includes('|') ? pageTitle.split('|')[0] : pageTitle,
    parsedProductObj?.display_name,
  );
  const anchorDisplayName = pickFirstTrimmed(
    parsedProductObj?.display_name,
    joinBrandAndName(anchorBrand, anchorName),
    anchorName,
  );
  const concentrationSignals = extractConcentrationSignals({
    pageTitle,
    anchorName,
    anchorDisplayName,
    keyIngredients,
  });
  const reasons = uniqCaseInsensitiveStrings(
    [
      html && inciList.length
        ? isCn
          ? `已从产品页解析到 INCI 成分表（共 ${normalizedInci.length} 项），用于本次评估。`
          : `I extracted the INCI list directly from the product page (${normalizedInci.length} entries) for this assessment.`
        : regulatorySupplement && regulatorySupplement.ok
          ? isCn
            ? `官网成分抓取受限，已改用监管源（DailyMed）补充活性信息（${regulatoryActiveInci.length} 项）。`
            : `Official-page INCI extraction was blocked; a regulatory source (DailyMed) was used as backup (${regulatoryActiveInci.length} active entries).`
          : retailSupplement && retailSupplement.ok
            ? isCn
              ? `官网成分抓取受限，已改用主流零售页补充成分线索（${retailInci.length} 项，需与包装 INCI 复核）。`
              : `Official-page INCI extraction was blocked; a retail PDP was used as supplemental evidence (${retailInci.length} entries, package INCI cross-check required).`
          : incidecoderSupplement && incidecoderSupplement.ok
            ? isCn
              ? `官网成分抓取受限，已改用 INCIDecoder 补充成分线索（${incidecoderInci.length} 项，需与包装 INCI 复核）。`
              : `Official-page INCI extraction was blocked; INCIDecoder was used as a supplemental source (${incidecoderInci.length} entries, package INCI cross-check required).`
          : isCn
            ? '当前未能稳定抓取到官网 INCI 成分表，证据有限。'
            : 'The official product page could not be parsed reliably, so evidence is currently limited.',
      keyIngredients.length
        ? isCn
          ? `识别到的关键成分：${keyIngredients.slice(0, 5).join('、')}。`
          : `Detected key ingredients: ${keyIngredients.slice(0, 5).join(', ')}.`
        : '',
      riskNotes.length ? riskNotes[0] : '',
      socialSignals.typical_positive.length
        ? isCn
          ? `页面舆情信号偏正向：${socialSignals.typical_positive.slice(0, 2).join('、')}。`
          : `On-page sentiment leans positive: ${socialSignals.typical_positive.slice(0, 2).join(', ')}.`
        : '',
      concentrationSignals.length
        ? isCn
          ? `页面已识别浓度信号：${concentrationSignals.slice(0, 2).join('、')}（仅作参考）。`
          : `Detected concentration signal on page: ${concentrationSignals.slice(0, 2).join(', ')} (reference only).`
        : isCn
          ? '边界说明：成分浓度与批次差异不可见，建议先做局部测试并从低频开始。'
          : 'Boundary: concentration and batch variance are unknown; patch test first and start at low frequency.',
      !html && !regulatorySupplement?.ok && !retailSupplement?.ok
        ? isCn
          ? urlFetchChallengeBlocked
            ? '目标站点启用了反爬挑战页。请上传包装 INCI 图、粘贴成分表，或提供可访问的零售 PDP 链接后重试。'
            : '请粘贴包装上的完整 INCI，或换一个可公开访问的官方商品页链接后重试。'
          : urlFetchChallengeBlocked
            ? 'The target site is blocked by anti-bot challenge. Upload package INCI, paste ingredients, or share an accessible retail PDP URL to retry.'
            : 'Please paste the full INCI from your package or share another publicly accessible official page URL and retry.'
        : '',
      regulatorySupplement && regulatorySupplement.ok
        ? isCn
          ? '监管源可用，但不同地区/批次配方可能不同；建议继续核对实物包装。'
          : 'Regulatory evidence is available, but market/batch formulas can differ; verify against your actual package.'
        : '',
      retailSupplement && retailSupplement.ok
        ? isCn
          ? '零售页成分仅作补充证据，请继续以官方/监管信息与实物包装 INCI 交叉验证。'
          : 'Retail PDP ingredients are supplemental evidence only; cross-check with official/regulatory info and package INCI.'
        : '',
      incidecoderSupplement && incidecoderSupplement.ok
        ? isCn
          ? 'INCIDecoder 为补充证据源，不作为单一权威来源；建议与官方/监管信息交叉验证。'
          : 'INCIDecoder is a supplemental source and should be cross-validated with official/regulatory evidence.'
        : '',
    ],
    6,
  );
  const parsedPrice = normalizePriceObject(
    parsedProductObj?.price ??
      parsedProductObj?.price_amount ??
      parsedProductObj?.priceAmount ??
      parsedProductObj?.offer_price ??
      parsedProductObj?.price_usd ??
      parsedProductObj?.priceUsd ??
      parsedProductObj?.price_cny ??
      parsedProductObj?.priceCny,
  );
  const anchorPrice = (() => {
    const nowIso = new Date().toISOString();
    if (parsedPrice) {
      return {
        ...parsedPrice,
        source: 'parsed_anchor_price',
        captured_at: nowIso,
      };
    }
    const extractedNormalized = normalizePriceObject(extractedPrice);
    if (!extractedNormalized) return null;
    const sourceToken = pickFirstTrimmed(extractedPrice?.source, 'page_price_signal');
    return {
      ...extractedNormalized,
      ...(sourceToken ? { source: sourceToken } : {}),
      captured_at: nowIso,
    };
  })();
  const anchorProduct = {
    ...(parsedProductObj?.product_id ? { product_id: String(parsedProductObj.product_id).trim() } : {}),
    ...(parsedProductObj?.sku_id ? { sku_id: String(parsedProductObj.sku_id).trim() } : {}),
    ...(anchorBrand ? { brand: anchorBrand } : {}),
    ...(anchorName ? { name: anchorName } : {}),
    ...(anchorDisplayName ? { display_name: anchorDisplayName } : {}),
    ...(anchorPrice ? { price: anchorPrice } : {}),
    url: parsedUrl.toString(),
  };

  let competitorOut = { candidates: [], queries: [], reason: 'dag_not_used' };
  let competitorSource = 'catalog';
  let competitorReason = null;
  let routedPools = { compPool: [], relPool: [], dupePool: [], routed: { internal_reason_codes: [] } };
  let dagDiagnostics = null;
  let dagReasonCodes = [];
  let dagConfidencePatch = null;
  let dagProvenancePatch = null;
  let dagTracking = null;
  let competitorSnapshotMeta = null;
  let candidateFilterStats = initCandidateFilterStats();
  const htmlForReco = html || (!fetchOut.ok ? '<!--on_page_fetch_blocked-->' : '');

  const dagOut = await runRecoBlocksForUrl({
    productUrl: parsedUrl.toString(),
    anchorProduct,
    parsedProduct: parsedProductObj,
    keyIngredients,
    profileSummary,
    lang,
    mode: 'main_path',
    logger,
    html: htmlForReco,
    budgetMs: AURORA_BFF_RECO_BLOCKS_BUDGET_MS,
    maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
  });

  if (dagOut && typeof dagOut === 'object') {
    const dagFilterStats = initCandidateFilterStats();
    const compPool = sanitizeCompetitorCandidates(
      dagOut?.competitors?.candidates,
      PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
      {
        enforceSkincare: true,
        pool: 'competitors',
        stats: dagFilterStats,
      },
    );
    const relPool = sanitizeCompetitorCandidates(
      dagOut?.related_products?.candidates,
      PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
      {
        enforceSkincare: true,
        pool: 'related_products',
        stats: dagFilterStats,
      },
    );
    const dupePool = sanitizeCompetitorCandidates(
      dagOut?.dupes?.candidates,
      PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
      {
        enforceSkincare: true,
        pool: 'dupes',
        stats: dagFilterStats,
      },
    );
    candidateFilterStats = dagFilterStats;
    routedPools = {
      compPool,
      relPool,
      dupePool,
      routed: {
        internal_reason_codes: Array.isArray(dagOut.internal_reason_codes) ? dagOut.internal_reason_codes : [],
      },
      routeReasonCodesRaw: collectRouterReasonCodeTokens({
        internal_reason_codes: Array.isArray(dagOut.internal_reason_codes) ? dagOut.internal_reason_codes : [],
      }),
      candidateFilterStats: dagFilterStats,
    };
    competitorOut = {
      candidates: compPool,
      queries: Array.isArray(dagOut.catalog_queries) ? dagOut.catalog_queries : [],
      reason: null,
    };
    dagDiagnostics = dagOut.diagnostics || null;
    dagConfidencePatch =
      dagOut.confidence_patch && typeof dagOut.confidence_patch === 'object' && !Array.isArray(dagOut.confidence_patch)
        ? dagOut.confidence_patch
        : null;
    dagProvenancePatch =
      dagOut.provenance_patch && typeof dagOut.provenance_patch === 'object' && !Array.isArray(dagOut.provenance_patch)
        ? dagOut.provenance_patch
        : null;
    dagTracking =
      dagOut.tracking && typeof dagOut.tracking === 'object' && !Array.isArray(dagOut.tracking)
        ? dagOut.tracking
        : null;
    competitorSnapshotMeta =
      dagOut.snapshot_meta && typeof dagOut.snapshot_meta === 'object' && !Array.isArray(dagOut.snapshot_meta)
        ? dagOut.snapshot_meta
        : null;
    competitorSource = 'reco_blocks_dag';
    if (competitorSnapshotMeta && compPool.length) {
      competitorSource = 'snapshot';
    }
    dagReasonCodes = summarizeRouterReasonCodes(routedPools.routed);
    if (!compPool.length) {
      const fallbackUsed = Array.isArray(dagDiagnostics?.fallbacks_used) ? dagDiagnostics.fallbacks_used : [];
      const timedOut = Array.isArray(dagDiagnostics?.timed_out_blocks) ? dagDiagnostics.timed_out_blocks : [];
      const onPageReasonCounts =
        dagDiagnostics &&
        dagDiagnostics.blocks &&
        dagDiagnostics.blocks.on_page_related &&
        typeof dagDiagnostics.blocks.on_page_related === 'object' &&
        dagDiagnostics.blocks.on_page_related.reason_counts &&
        typeof dagDiagnostics.blocks.on_page_related.reason_counts === 'object'
          ? dagDiagnostics.blocks.on_page_related.reason_counts
          : {};
      const onPageFetchBlockedObserved =
        Number(onPageReasonCounts.on_page_fetch_blocked || 0) > 0 || (!html && !fetchOut.ok);
      if (fallbackUsed.includes('related_on_page_fallback') && relPool.length) {
        competitorSource = 'on_page_related_only';
      }
      if (onPageFetchBlockedObserved) {
        competitorReason = 'on_page_fetch_blocked';
      } else {
        competitorReason =
          timedOut.length || fallbackUsed.length
            ? 'dag_timeout_or_empty'
            : 'dag_empty';
      }
    }
  } else {
    competitorOut = await buildRealtimeCompetitorCandidates({
      productUrl: parsedUrl.toString(),
      parsedProduct: parsedProductObj,
      keyIngredients,
      anchorProduct,
      profileSummary,
      lang,
      logger,
    });
    const recalledCandidates = sanitizeCompetitorCandidates(
      competitorOut?.candidates,
      PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
      { enforceSkincare: true, pool: 'competitors', stats: candidateFilterStats },
    );
    let onPageCandidates = [];
    competitorSource = 'catalog';
    competitorReason = competitorOut?.reason ? String(competitorOut.reason) : null;
    if (!recalledCandidates.length) {
      onPageCandidates = buildOnPageCompetitorCandidates({
        html,
        productUrl: parsedUrl.toString(),
        anchorProduct,
        profileSummary,
        lang,
        maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
      });
    }
    routedPools = routeCompetitorCandidatePools({
      anchorProduct,
      candidates: [...recalledCandidates, ...onPageCandidates],
      maxCandidates: PRODUCT_URL_REALTIME_COMPETITOR_MAX_CANDIDATES,
    });
    candidateFilterStats = initCandidateFilterStats(routedPools?.candidateFilterStats);
    if (!routedPools.compPool.length) {
      if (onPageCandidates.length || routedPools.relPool.length) {
        competitorSource = 'on_page_related_only';
        competitorReason = competitorReason || 'hard_gate_filtered';
      } else if (recalledCandidates.length) {
        competitorReason = competitorReason || 'hard_gate_filtered';
      }
    }
    if (!html && !fetchOut.ok && !competitorReason) {
      competitorReason = 'on_page_fetch_blocked';
    }
  }
  const competitorCandidates = routedPools.compPool;
  const relatedCandidates = routedPools.relPool;
  const dupeCandidates = routedPools.dupePool;
  const relatedSemanticsReclassified = relatedCandidates.some((candidate) => {
    const raw = String(candidate?.recommendation_intent ?? candidate?.recommendationIntent ?? '').trim().toLowerCase();
    return raw !== 'replace' && raw !== 'pair';
  });
  const routeReasonCodesRaw = Array.isArray(routedPools?.routeReasonCodesRaw)
    ? routedPools.routeReasonCodesRaw
    : collectRouterReasonCodeTokens(routedPools?.routed);
  const hasCategoryUnknownBlocked = routeReasonCodesRaw.some(
    (code) => String(code || '').trim().toLowerCase() === 'competitor_category_unknown_blocked',
  );
  const hasDroppedNonSkincare = hasCandidateFilterDropStats(candidateFilterStats);
  const urlSkincareSignalStrong = /\b(skincare|moisturizer|moisturiser|serum|cream|lotion|cleanser|toner|essence|sunscreen|spf|face)\b/i
    .test(`${parsedUrl.hostname} ${parsedUrl.pathname}`);
  if (hasDroppedNonSkincare && urlSkincareSignalStrong) {
    logger?.warn?.(
      {
        url: parsedUrl.toString(),
        dropped_stats: candidateFilterStats,
      },
      'aurora bff: competitor category drift filtered for skincare URL',
    );
  }
  const competitorMissing = !competitorCandidates.length;
  const socialMissing = !socialSignals.has_signal;

  let confidence = Number(
    Math.max(
      0.28,
      Math.min(
        0.84,
        0.42 +
          (normalizedInci.length >= 15 ? 0.12 : 0.04) +
          (keyIngredients.length >= 4 ? 0.1 : 0.04) +
          (riskNotes.length ? 0.04 : 0) +
          (!html ? -0.1 : 0) +
          (regulatorySupplement && regulatorySupplement.ok ? 0.05 : 0) +
          (retailSupplement && retailSupplement.ok ? 0.03 : 0) +
          (socialMissing ? 0 : 0.05) +
          (competitorMissing ? 0 : 0.05),
      ),
    ).toFixed(3),
  );
  const hasAuthoritativeSource = Boolean(html || (regulatorySupplement && regulatorySupplement.ok));
  if (!hasAuthoritativeSource && retailSupplement && retailSupplement.ok && incidecoderSupplement && incidecoderSupplement.ok) {
    confidence = Number(Math.min(confidence, 0.62).toFixed(3));
  }

  const dagFallbacksUsed = Array.isArray(dagDiagnostics?.fallbacks_used) ? dagDiagnostics.fallbacks_used : [];
  const dagTimedOutBlocks = Array.isArray(dagDiagnostics?.timed_out_blocks) ? dagDiagnostics.timed_out_blocks : [];
  const routeReasonCodes = dagReasonCodes.length ? dagReasonCodes : summarizeRouterReasonCodes(routedPools.routed);
  const catalogAnnStats =
    dagProvenancePatch &&
    typeof dagProvenancePatch === 'object' &&
    !Array.isArray(dagProvenancePatch) &&
    dagProvenancePatch.block_stats &&
    typeof dagProvenancePatch.block_stats === 'object' &&
    !Array.isArray(dagProvenancePatch.block_stats) &&
    dagProvenancePatch.block_stats.catalog_ann &&
    typeof dagProvenancePatch.block_stats.catalog_ann === 'object' &&
    !Array.isArray(dagProvenancePatch.block_stats.catalog_ann)
      ? dagProvenancePatch.block_stats.catalog_ann
      : {};
  const catalogAnnReasonCounts =
    catalogAnnStats.reason_counts &&
    typeof catalogAnnStats.reason_counts === 'object' &&
    !Array.isArray(catalogAnnStats.reason_counts)
      ? catalogAnnStats.reason_counts
      : {};
  const catalogAnnTransientFailureCount =
    Number(catalogAnnStats.transient_failure_count || 0) ||
    Number(catalogAnnReasonCounts.upstream_timeout || 0) +
      Number(catalogAnnReasonCounts.upstream_error || 0) +
      Number(catalogAnnReasonCounts.rate_limited || 0);
  const catalogSourceTemporarilyDeprioritized = catalogAnnStats.source_temporarily_deprioritized === true;
  const resolverFirstSkippedForAurora = catalogAnnStats.resolver_first_skipped_for_aurora === true;
  const retrievalAttemptedSources = uniqCaseInsensitiveStrings(
    Array.isArray(catalogAnnStats.attempted_sources) ? catalogAnnStats.attempted_sources : [],
    8,
  );
  const retrievalBudgetProfile =
    catalogAnnStats.budget_profile &&
    typeof catalogAnnStats.budget_profile === 'object' &&
    !Array.isArray(catalogAnnStats.budget_profile)
      ? catalogAnnStats.budget_profile
      : null;
  const competitorRecallTransientDegraded =
    catalogAnnTransientFailureCount > 0 &&
    competitorSource === 'on_page_related_only' &&
    relatedCandidates.length > 0 &&
    competitorCandidates.length === 0;
  const retrievalDegradation = {
    transient_failure_count: Math.max(0, Math.trunc(Number(catalogAnnTransientFailureCount) || 0)),
    attempted_sources: retrievalAttemptedSources,
    resolver_first_applied: catalogAnnStats.resolver_first_applied === true,
    resolver_first_skipped_for_aurora: resolverFirstSkippedForAurora,
    source_temporarily_deprioritized: catalogSourceTemporarilyDeprioritized,
    ...(retrievalBudgetProfile ? { budget_profile: retrievalBudgetProfile } : {}),
    degraded:
      catalogAnnTransientFailureCount > 0 ||
      competitorSource === 'on_page_related_only' ||
      dagTimedOutBlocks.includes('catalog_ann'),
  };

  const evidenceMissingInfo = [];
  if (!html && !fetchOut.ok && fetchOut.failure_code) evidenceMissingInfo.push(String(fetchOut.failure_code));
  if (!html && !fetchOut.ok) evidenceMissingInfo.push('on_page_fetch_blocked');
  if (urlFetchRecoveredWithFallback) evidenceMissingInfo.push('url_fetch_recovered_with_fallback');
  if (fetchOut?.used_unblock_vendor) evidenceMissingInfo.push('url_fetch_vendor_unblock_used');
  if (!fetchOut?.ok && fetchOut?.unblock_attempted && fetchOut?.unblock_failed) {
    evidenceMissingInfo.push('url_fetch_vendor_unblock_failed');
  }
  if (regulatorySupplement && regulatorySupplement.ok) {
    evidenceMissingInfo.push('regulatory_source_used', 'version_verification_needed');
  }
  if (retailSupplement && retailSupplement.ok) {
    evidenceMissingInfo.push('retail_source_used', 'version_verification_needed');
  } else if (retailSupplement && retailSupplement.reason) {
    if (!html) {
      const retailReason = String(retailSupplement.reason || '').trim().toLowerCase();
      if (retailReason.includes('no_match') || retailReason.includes('retail')) evidenceMissingInfo.push('retail_source_no_match');
    }
  }
  if (incidecoderSupplement && incidecoderSupplement.ok) {
    evidenceMissingInfo.push('incidecoder_source_used', 'version_verification_needed');
  } else if (incidecoderSupplement && incidecoderSupplement.reason) {
    const reasonToken = String(incidecoderSupplement.reason || '').trim().toLowerCase();
    if (reasonToken === 'incidecoder_no_match') evidenceMissingInfo.push('incidecoder_no_match');
    else if (reasonToken.includes('fetch')) evidenceMissingInfo.push('incidecoder_fetch_failed');
  }
  if (llmVerificationResult && llmVerificationResult.ok) {
    evidenceMissingInfo.push('llm_verification_used');
  }
  if (!normalizedInci.length) evidenceMissingInfo.push('evidence_missing');
  if (ingredientConsensus.has_conflict) evidenceMissingInfo.push('ingredient_source_conflict');
  if (!concentrationSignals.length) evidenceMissingInfo.push('concentration_unknown');
  if (!anchorPrice) evidenceMissingInfo.push('price_unknown');
  if (socialMissing) evidenceMissingInfo.push('social_signals_missing');
  if (competitorMissing) evidenceMissingInfo.push('competitors_missing');
  if (!competitorMissing && competitorCandidates.length < PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT) {
    evidenceMissingInfo.push('competitors_low_coverage');
  }
  if (catalogAnnTransientFailureCount > 0) evidenceMissingInfo.push('catalog_ann_transient_failure');
  if (catalogSourceTemporarilyDeprioritized) evidenceMissingInfo.push('catalog_source_temporarily_deprioritized');
  if (resolverFirstSkippedForAurora) evidenceMissingInfo.push('resolver_first_skipped_for_aurora');
  if (competitorRecallTransientDegraded) evidenceMissingInfo.push('competitor_recall_transient_degraded');
  if (Number(candidateFilterStats.competitors_dropped_non_skincare || 0) > 0) {
    evidenceMissingInfo.push('competitors_non_skincare_filtered');
  }
  if (Number(candidateFilterStats.related_dropped_non_skincare || 0) > 0) {
    evidenceMissingInfo.push('related_products_non_skincare_filtered');
  }
  if (Number(candidateFilterStats.dupes_dropped_non_skincare || 0) > 0) {
    evidenceMissingInfo.push('dupes_non_skincare_filtered');
  }
  if (relatedSemanticsReclassified) evidenceMissingInfo.push('related_semantics_reclassified');
  if (hasCategoryUnknownBlocked) evidenceMissingInfo.push('competitor_category_unknown_blocked');
  if (competitorMissing && competitorReason) evidenceMissingInfo.push(`competitor_recall_${String(competitorReason).toLowerCase()}`);

  const defaultConfidenceByBlock = {
    competitors: {
      score: competitorMissing ? 0.18 : 0.62,
      level: competitorMissing ? 'low' : 'med',
      reasons: competitorMissing ? ['competitors_missing'] : ['competitors_available'],
    },
    related_products: {
      score: relatedCandidates.length ? 0.62 : 0.42,
      level: relatedCandidates.length ? 'med' : 'low',
      reasons: relatedCandidates.length ? ['related_products_available'] : ['related_products_sparse'],
    },
    dupes: {
      score: dupeCandidates.length ? 0.58 : 0.38,
      level: dupeCandidates.length ? 'med' : 'low',
      reasons: dupeCandidates.length ? ['dupes_available'] : ['dupes_sparse'],
    },
  };

  const evidenceSources = [];
  if (html) {
    evidenceSources.push({
      type: 'official_page',
      url: parsedUrl.toString(),
      label: hostName || 'Official page',
      confidence: 0.78,
    });
  }
  if (regulatorySupplement && regulatorySupplement.ok) {
    evidenceSources.push({
      type: 'regulatory',
      url: String(regulatorySupplement.source?.url || regulatorySupplement.source_url || ''),
      label: 'DailyMed',
      confidence: 0.72,
    });
  }
  if (retailSupplement && retailSupplement.ok) {
    evidenceSources.push({
      type: 'retail_page',
      url: String(retailSupplement.source?.url || retailSupplement.source_url || ''),
      label: String(retailSupplement.source?.label || 'Retail PDP'),
      confidence: Number(retailSupplement.source?.confidence || 0.58),
    });
  }
  if (incidecoderSupplement && incidecoderSupplement.ok) {
    evidenceSources.push({
      type: 'inci_decoder',
      url: String(incidecoderSupplement.source?.url || incidecoderSupplement.source_url || ''),
      label: 'INCIDecoder',
      confidence: Number(incidecoderSupplement.source?.confidence || 0.55),
    });
  }
  const normalizedEvidenceSources = evidenceSources
    .map((item) => ({
      type: String(item?.type || '').trim().toLowerCase(),
      url: String(item?.url || '').trim(),
      label: String(item?.label || '').trim(),
      confidence: Number(item?.confidence),
    }))
    .filter((item) => /^https?:\/\//i.test(item.url))
    .slice(0, 4);

  const urlFetchProvenance = {
    final_strategy: String(fetchOut?.final_strategy || 'none').trim() || 'none',
    attempts: (Array.isArray(fetchOut?.attempts) ? fetchOut.attempts : []).slice(0, 6).map((item) => ({
      strategy: String(item?.strategy || '').trim() || 'unknown',
      provider: String(item?.provider || 'native').trim().toLowerCase() || 'native',
      ...(Number.isFinite(Number(item?.status)) ? { status: Number(item.status) } : {}),
      ...(item?.error_code ? { error_code: String(item.error_code).trim().toLowerCase() } : {}),
      ...(item?.challenge_type ? { challenge_type: String(item.challenge_type).trim().toLowerCase() } : {}),
    })),
    ...(fetchOut?.failure_code ? { failure_code: String(fetchOut.failure_code).trim().toLowerCase() } : {}),
    ...(fetchOut?.used_unblock_vendor ? { vendor_unblock_used: true } : {}),
    ...(fetchOut?.unblock_attempted ? { vendor_unblock_attempted: true } : {}),
    ...(fetchOut?.unblock_failed ? { vendor_unblock_failed: true } : {}),
    ...(urlFetchChallengeBlocked
      ? {
        failure_detail: {
          challenge_type: urlFetchFailureCode === 'url_fetch_access_denied' ? 'access_denied_page' : 'cloudflare_challenge',
          next_step: 'provide_inci_or_accessible_retail_pdp',
        },
      }
      : {}),
  };
  const sourceChain = uniqCaseInsensitiveStrings(
    [
      html ? 'official_page' : '',
      regulatorySupplement && regulatorySupplement.ok ? 'regulatory' : '',
      retailSupplement && retailSupplement.ok ? 'retail_page' : '',
      incidecoderSupplement && incidecoderSupplement.ok ? 'inci_decoder' : '',
      'llm_extraction',
    ],
    6,
  );

	  const raw = {
	    assessment: {
	      verdict,
	      reasons,
	      summary: selectAssessmentSummary({
	        summary: reasons[0] || '',
	        reasons,
	        fallbacks: [fitNotes[0], mechanisms[0]],
	      }),
	      ingredient_confidence_tier: ingredientConfidenceTier,
	      anchor_product: anchorProduct,
	    },
    evidence: {
      science: {
        key_ingredients: keyIngredients,
        mechanisms,
        fit_notes: fitNotes,
        risk_notes: riskNotes,
      },
      social_signals: {
        ...(Object.keys(socialSignals.platform_scores || {}).length
          ? { platform_scores: socialSignals.platform_scores }
          : {}),
        typical_positive: socialSignals.typical_positive,
        typical_negative: socialSignals.typical_negative,
        risk_for_groups: socialSignals.risk_for_groups,
      },
      expert_notes: uniqCaseInsensitiveStrings(
        [
          html
            ? isCn
              ? `证据来源：${hostName || 'product page'} 官方产品页成分表抓取。`
              : `Evidence source: ingredient list parsed from ${hostName || 'product page'}.`
            : isCn
              ? '官网页面抓取受站点策略限制（403/反爬），本次走了可诊断降级。'
              : 'Official-page extraction was blocked by site policy (403/anti-bot); a diagnosable degraded path was used.',
          urlFetchRecoveredWithFallback
            ? isCn
              ? 'URL 抓取已通过回退策略恢复（默认请求失败后切换 UA）。'
              : 'URL extraction recovered via fallback strategy (alternate UA profile).'
            : '',
          fetchOut?.used_unblock_vendor
            ? isCn
              ? 'URL 抓取已使用第三方解封服务恢复（ZenRows）。'
              : 'URL extraction recovered via vendor unblock service (ZenRows).'
            : '',
          regulatorySupplement && regulatorySupplement.ok
            ? isCn
              ? `监管源补充：DailyMed 活性信息已接入（query=${regulatorySupplement.query || 'n/a'}）。`
              : `Regulatory supplement loaded from DailyMed (query=${regulatorySupplement.query || 'n/a'}).`
            : '',
          retailSupplement && retailSupplement.ok
            ? isCn
              ? `零售页补充：${String(retailSupplement.source?.label || 'Retail PDP')} 已解析 ${retailInci.length} 项成分线索（match=${Number(retailSupplement.match_score || 0).toFixed(2)}）。`
              : `Retail PDP supplement loaded from ${String(retailSupplement.source?.label || 'Retail PDP')} (${retailInci.length} ingredients, match=${Number(retailSupplement.match_score || 0).toFixed(2)}).`
            : '',
          incidecoderSupplement && incidecoderSupplement.ok
            ? isCn
              ? `INCIDecoder 补充：已解析 ${incidecoderInci.length} 项成分线索（match=${Number(incidecoderSupplement.match_score || 0).toFixed(2)}）。`
              : `INCIDecoder supplement loaded (${incidecoderInci.length} ingredients, match=${Number(incidecoderSupplement.match_score || 0).toFixed(2)}).`
            : '',
          anchorPrice
            ? isCn
              ? `页面价格信号：${anchorPrice.currency || 'USD'} ${anchorPrice.amount}（用于同类对比）`
              : `Price signal from page: ${anchorPrice.currency || 'USD'} ${anchorPrice.amount} (used for comparable matching).`
            : '',
          ...socialSignals.notes,
          competitorOut?.queries?.length
            ? isCn
              ? `竞品召回查询：${competitorOut.queries.join(' | ')}`
              : `Competitor recall queries: ${competitorOut.queries.join(' | ')}`
            : '',
          dagFallbacksUsed.length
            ? isCn
              ? `DAG 降级轨迹：${dagFallbacksUsed.join(', ')}。`
              : `DAG fallback trace: ${dagFallbacksUsed.join(', ')}.`
            : '',
          dagTimedOutBlocks.length
            ? isCn
              ? `DAG 超时分支：${dagTimedOutBlocks.join(', ')}。`
              : `DAG timed-out branches: ${dagTimedOutBlocks.join(', ')}.`
            : '',
          competitorSource === 'on_page_related_only'
            ? isCn
              ? '同页 related products 已分流到 related_products，未进入 competitors（硬约束）。'
              : 'On-page related products were routed to related_products and blocked from competitors by hard gates.'
            : '',
          !html && !regulatorySupplement?.ok && !retailSupplement?.ok
            ? isCn
              ? urlFetchChallengeBlocked
                ? '下一步：请上传包装 INCI 图、粘贴成分表，或改用可访问的零售 PDP 链接继续。'
                : '下一步：请贴包装 INCI 或换一个可公开访问的官方页面链接，以提升分析信息量。'
              : urlFetchChallengeBlocked
                ? 'Next step: upload package INCI, paste ingredient list, or use an accessible retail PDP URL.'
                : 'Next step: paste package INCI or share a publicly accessible official product page to improve evidence quality.'
            : '',
        ],
        8,
      ),
      ...(normalizedEvidenceSources.length ? { sources: normalizedEvidenceSources } : {}),
      confidence,
      missing_info: evidenceMissingInfo,
    },
    inci_status: inciStatus,
    confidence,
    confidence_by_block: dagConfidencePatch || defaultConfidenceByBlock,
    provenance: {
      source: 'url_realtime_product_intel',
      pipeline: dagProvenancePatch?.pipeline || 'url_realtime_product_intel_v1',
      validation_mode: dagProvenancePatch?.validation_mode || 'soft_fail',
      ...(dagProvenancePatch && typeof dagProvenancePatch === 'object' ? dagProvenancePatch : {}),
      url_fetch: urlFetchProvenance,
      ...(sourceChain.length ? { source_chain: sourceChain } : {}),
      ...(relatedSemanticsReclassified ? { related_semantics_reclassified: true } : {}),
      ...(ingredientConsensus && typeof ingredientConsensus === 'object'
        ? {
          ingredient_consensus: {
            confidence_tier: ingredientConfidenceTier,
            has_conflict: Boolean(ingredientConsensus.has_conflict),
            ...(ingredientConsensus.stats && typeof ingredientConsensus.stats === 'object'
              ? { stats: ingredientConsensus.stats }
              : {}),
          },
        }
        : {}),
      social_enrichment_status: 'pending_async',
      retrieval_degradation: retrievalDegradation,
      ...(hasCandidateFilterDropStats(candidateFilterStats)
        ? {
          candidate_filter_stats: {
            competitors_dropped_non_skincare: Number(candidateFilterStats.competitors_dropped_non_skincare || 0),
            related_dropped_non_skincare: Number(candidateFilterStats.related_dropped_non_skincare || 0),
            dupes_dropped_non_skincare: Number(candidateFilterStats.dupes_dropped_non_skincare || 0),
          },
        }
        : {}),
      ...(regulatorySupplement && regulatorySupplement.ok
        ? {
          regulatory_source: {
            provider: 'dailymed',
            url: String(regulatorySupplement.source_url || ''),
            query: String(regulatorySupplement.query || ''),
          },
        }
        : {}),
      ...(retailSupplement && retailSupplement.ok
        ? {
          retail_source: {
            provider: String(retailSupplement.source?.label || 'retail_pdp').trim().toLowerCase(),
            url: String(retailSupplement.source_url || ''),
            query: String(retailSupplement.query || ''),
            match_score: Number(retailSupplement.match_score || 0),
            ingredient_count: retailInci.length,
          },
        }
        : {}),
      ...(incidecoderSupplement && incidecoderSupplement.ok
        ? {
          inci_decoder: {
            provider: 'incidecoder',
            url: String(incidecoderSupplement.source_url || ''),
            query: String(incidecoderSupplement.query || ''),
            match_score: Number(incidecoderSupplement.match_score || 0),
            ingredient_count: incidecoderInci.length,
            overlap_count: incidecoderOverlapCount,
          },
        }
        : {}),
      ...(competitorSnapshotMeta
        ? {
          competitor_meta: {
            source: String(competitorSnapshotMeta.source || 'snapshot'),
            confidence: Number.isFinite(Number(competitorSnapshotMeta.confidence))
              ? Number(competitorSnapshotMeta.confidence)
              : null,
            snapshot_age_sec: Number.isFinite(Number(competitorSnapshotMeta.age_sec))
              ? Number(competitorSnapshotMeta.age_sec)
              : null,
            degraded: Boolean(competitorSnapshotMeta.degraded),
            stale: Boolean(competitorSnapshotMeta.stale),
            very_stale: Boolean(competitorSnapshotMeta.very_stale),
          },
        }
        : {}),
    },
    missing_info: uniqCaseInsensitiveStrings(
      [
        'url_ingredient_analysis_used',
        'url_realtime_product_intel_used',
        ...(fetchOut?.failure_code ? [String(fetchOut.failure_code)] : []),
        ...(!html && !fetchOut.ok ? ['on_page_fetch_blocked'] : []),
        ...(urlFetchRecoveredWithFallback ? ['url_fetch_recovered_with_fallback'] : []),
        ...(fetchOut?.used_unblock_vendor ? ['url_fetch_vendor_unblock_used'] : []),
        ...(!fetchOut?.ok && fetchOut?.unblock_attempted && fetchOut?.unblock_failed ? ['url_fetch_vendor_unblock_failed'] : []),
        ...(regulatorySupplement && regulatorySupplement.ok ? ['regulatory_source_used', 'version_verification_needed'] : []),
        ...(retailSupplement && retailSupplement.ok ? ['retail_source_used', 'version_verification_needed'] : []),
        ...(retailSupplement && !retailSupplement.ok && retailSupplement.reason && !html ? ['retail_source_no_match'] : []),
        ...(incidecoderSupplement && incidecoderSupplement.ok ? ['incidecoder_source_used', 'version_verification_needed'] : []),
        ...(
          incidecoderSupplement && !incidecoderSupplement.ok && incidecoderSupplement.reason
            ? [String(incidecoderSupplement.reason)]
            : []
        ),
        ...(llmVerificationResult && llmVerificationResult.ok ? ['llm_verification_used'] : []),
        ...(!normalizedInci.length ? ['evidence_missing'] : []),
        ...(!anchorPrice ? ['price_unknown'] : []),
        ...(socialMissing ? ['social_signals_missing'] : []),
        ...(competitorMissing ? ['competitors_missing'] : []),
        ...(!competitorMissing && competitorCandidates.length < PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT ? ['competitors_low_coverage'] : []),
        ...(catalogAnnTransientFailureCount > 0 ? ['catalog_ann_transient_failure'] : []),
        ...(catalogSourceTemporarilyDeprioritized ? ['catalog_source_temporarily_deprioritized'] : []),
        ...(resolverFirstSkippedForAurora ? ['resolver_first_skipped_for_aurora'] : []),
        ...(competitorRecallTransientDegraded ? ['competitor_recall_transient_degraded'] : []),
        ...(Number(candidateFilterStats.competitors_dropped_non_skincare || 0) > 0 ? ['competitors_non_skincare_filtered'] : []),
        ...(Number(candidateFilterStats.related_dropped_non_skincare || 0) > 0 ? ['related_products_non_skincare_filtered'] : []),
        ...(Number(candidateFilterStats.dupes_dropped_non_skincare || 0) > 0 ? ['dupes_non_skincare_filtered'] : []),
        ...(hasCategoryUnknownBlocked ? ['competitor_category_unknown_blocked'] : []),
        competitorMissing && competitorReason ? `competitor_recall_${String(competitorReason).toLowerCase()}` : '',
      ],
      12,
    ),
    ...(competitorCandidates.length ? { competitors: { candidates: competitorCandidates } } : {}),
    ...(relatedCandidates.length ? { related_products: { candidates: relatedCandidates } } : {}),
    ...(dupeCandidates.length ? { dupes: { candidates: dupeCandidates } } : {}),
    ...(dagTracking ? { candidate_tracking: dagTracking } : {}),
  };

  const competitorSnapshotKey = buildCompetitorSnapshotKey({
    anchor_product_id: pickFirstTrimmed(anchorProduct?.product_id, anchorProduct?.sku_id),
    normalized_query: pickFirstTrimmed(anchorDisplayName, anchorName),
    product_url: parsedUrl.toString(),
    locale: lang,
    surface: 'product_analysis',
    objective: 'competitors',
    category: pickFirstTrimmed(anchorProduct?.category, anchorProduct?.category_name, parsedProductObj?.category_taxonomy),
    price_band: inferRecoPriceBand(anchorProduct?.price_band, {
      price: normalizePriceObject(anchorProduct?.price)?.amount,
    }),
    skin_fit_bucket: buildProfileSkinTags(profileSummary).slice(0, 2).join('_'),
  });
  if (competitorSnapshotKey && competitorCandidates.length) {
    writeCompetitorSnapshot(
      competitorSnapshotKey,
      {
        competitors: competitorCandidates,
        related_products: relatedCandidates,
        dupes: dupeCandidates,
        competitor_queries: competitorOut?.queries || [],
      },
      {
        created_at: new Date().toISOString(),
        source: competitorSource === 'snapshot' ? 'snapshot' : 'realtime_main',
        ranker_version: String(dagProvenancePatch?.pipeline || 'reco_blocks_dag.v1'),
        coverage: {
          competitors: competitorCandidates.length,
          related_products: relatedCandidates.length,
          dupes: dupeCandidates.length,
        },
        confidence:
          dagConfidencePatch?.competitors?.score ??
          dagConfidencePatch?.competitors?.level ??
          confidence,
        reason_flags: [
          ...(competitorMissing ? ['competitors_missing'] : []),
          ...(dagTimedOutBlocks.length ? ['timed_out_blocks_present'] : []),
          ...(dagFallbacksUsed.length ? ['fallbacks_used_present'] : []),
        ],
      },
    );
  }

  const norm = normalizeProductAnalysis(raw);
  const payloadInternalCodes = Array.isArray(norm.payload?.internal_debug_codes) ? norm.payload.internal_debug_codes : [];
  const mergedInternalCodes = Array.from(
    new Set([
      ...payloadInternalCodes,
      'url_ingredient_analysis_used',
      'url_realtime_product_intel_used',
      ...(fetchOut?.failure_code ? [String(fetchOut.failure_code)] : []),
      ...(!html && !fetchOut.ok ? ['on_page_fetch_blocked'] : []),
      ...(urlFetchRecoveredWithFallback ? ['url_fetch_recovered_with_fallback'] : []),
      ...(fetchOut?.used_unblock_vendor ? ['url_fetch_vendor_unblock_used'] : []),
      ...(!fetchOut?.ok && fetchOut?.unblock_attempted && fetchOut?.unblock_failed ? ['url_fetch_vendor_unblock_failed'] : []),
      ...(regulatorySupplement && regulatorySupplement.ok ? ['regulatory_source_used', 'version_verification_needed'] : []),
      ...(retailSupplement && retailSupplement.ok ? ['retail_source_used', 'version_verification_needed'] : []),
      ...(retailSupplement && !retailSupplement.ok && retailSupplement.reason ? ['retail_source_no_match'] : []),
      ...(incidecoderSupplement && incidecoderSupplement.ok ? ['incidecoder_source_used', 'version_verification_needed'] : []),
      ...(incidecoderSupplement && !incidecoderSupplement.ok && incidecoderSupplement.reason ? [String(incidecoderSupplement.reason)] : []),
      ...(!normalizedInci.length ? ['evidence_missing'] : []),
      ...(socialMissing ? ['social_signals_missing'] : []),
      ...(competitorMissing ? ['competitors_missing'] : []),
      ...(!competitorMissing && competitorCandidates.length < PRODUCT_URL_REALTIME_COMPETITOR_PREFERRED_COUNT ? ['competitors_low_coverage'] : []),
      ...(catalogAnnTransientFailureCount > 0 ? ['catalog_ann_transient_failure'] : []),
      ...(catalogSourceTemporarilyDeprioritized ? ['catalog_source_temporarily_deprioritized'] : []),
      ...(resolverFirstSkippedForAurora ? ['resolver_first_skipped_for_aurora'] : []),
      ...(competitorRecallTransientDegraded ? ['competitor_recall_transient_degraded'] : []),
      ...(Number(candidateFilterStats.competitors_dropped_non_skincare || 0) > 0 ? ['competitors_non_skincare_filtered'] : []),
      ...(Number(candidateFilterStats.related_dropped_non_skincare || 0) > 0 ? ['related_products_non_skincare_filtered'] : []),
      ...(Number(candidateFilterStats.dupes_dropped_non_skincare || 0) > 0 ? ['dupes_non_skincare_filtered'] : []),
      ...(hasCategoryUnknownBlocked ? ['competitor_category_unknown_blocked'] : []),
      ...(competitorMissing && competitorReason ? [`competitor_recall_${String(competitorReason).toLowerCase()}`] : []),
      ...routeReasonCodes,
      ...dagFallbacksUsed.map((item) => `reco_dag_fallback_${String(item || '').trim().toLowerCase()}`),
      ...dagTimedOutBlocks.map((item) => `reco_dag_timeout_${String(item || '').trim().toLowerCase()}`),
    ]),
  );
  const nextPayload = reconcileProductAnalysisConsistency(applyProductAnalysisGapContract({
    ...(norm.payload && typeof norm.payload === 'object' ? norm.payload : {}),
    ...(
      raw.evidence && typeof raw.evidence === 'object' && !Array.isArray(raw.evidence)
        ? {
          evidence: {
            ...(norm.payload && typeof norm.payload.evidence === 'object' && !Array.isArray(norm.payload.evidence)
              ? norm.payload.evidence
              : {}),
            ...(raw.evidence.sources ? { sources: raw.evidence.sources } : {}),
          },
        }
        : {}
    ),
    ...(raw.confidence_by_block ? { confidence_by_block: raw.confidence_by_block } : {}),
    ...(raw.provenance ? { provenance: raw.provenance } : {}),
    internal_debug_codes: mergedInternalCodes,
  }), { lang });
  const nextFieldMissing = Array.isArray(norm.field_missing) ? norm.field_missing.filter((item) => {
    const field = String(item?.field || '').trim();
    return field !== 'assessment' && field !== 'evidence';
  }) : [];
  return {
    payload: nextPayload,
    field_missing: nextFieldMissing,
    source_meta: {
      analyzer: 'url_realtime_product_intel_v1',
      source_url: parsedUrl.toString(),
      source_host: hostName || null,
      url_fetch: urlFetchProvenance,
      competitor_queries: competitorOut?.queries || [],
      competitor_reason: competitorReason || null,
      competitor_source: competitorSource,
      retrieval_degradation: retrievalDegradation,
      ...(regulatorySupplement && regulatorySupplement.ok
        ? {
          regulatory_source: {
            provider: 'dailymed',
            url: String(regulatorySupplement.source_url || ''),
            query: String(regulatorySupplement.query || ''),
          },
        }
        : {}),
      ...(retailSupplement && retailSupplement.ok
        ? {
          retail_source: {
            provider: String(retailSupplement.source?.label || 'retail_pdp').trim().toLowerCase(),
            url: String(retailSupplement.source_url || ''),
            query: String(retailSupplement.query || ''),
            match_score: Number(retailSupplement.match_score || 0),
            ingredient_count: retailInci.length,
          },
        }
        : {}),
      ...(incidecoderSupplement && incidecoderSupplement.ok
        ? {
          incidecoder_source: {
            provider: 'incidecoder',
            url: String(incidecoderSupplement.source_url || ''),
            query: String(incidecoderSupplement.query || ''),
            match_score: Number(incidecoderSupplement.match_score || 0),
            overlap_count: incidecoderOverlapCount,
            ingredient_count: incidecoderInci.length,
          },
          inci_decoder_overlap_count: incidecoderOverlapCount,
        }
        : {}),
      competitor_snapshot_meta: competitorSnapshotMeta
        ? {
          source: String(competitorSnapshotMeta.source || 'snapshot'),
          confidence: Number.isFinite(Number(competitorSnapshotMeta.confidence))
            ? Number(competitorSnapshotMeta.confidence)
            : null,
          snapshot_age_sec: Number.isFinite(Number(competitorSnapshotMeta.age_sec))
            ? Number(competitorSnapshotMeta.age_sec)
            : null,
          degraded: Boolean(competitorSnapshotMeta.degraded),
          stale: Boolean(competitorSnapshotMeta.stale),
          very_stale: Boolean(competitorSnapshotMeta.very_stale),
        }
        : null,
      social_signal_present: !socialMissing,
      competitor_count: competitorCandidates.length,
      related_count: relatedCandidates.length,
      dupe_count: dupeCandidates.length,
      competitor_router_reason_codes: routeReasonCodes,
      ...(hasCandidateFilterDropStats(candidateFilterStats)
        ? {
          candidate_filter_stats: {
            competitors_dropped_non_skincare: Number(candidateFilterStats.competitors_dropped_non_skincare || 0),
            related_dropped_non_skincare: Number(candidateFilterStats.related_dropped_non_skincare || 0),
            dupes_dropped_non_skincare: Number(candidateFilterStats.dupes_dropped_non_skincare || 0),
          },
        }
        : {}),
      reco_blocks_dag: dagDiagnostics
        ? {
          mode: String(dagDiagnostics.mode || 'main_path'),
          budget_ms: Number(dagDiagnostics.budget_ms || AURORA_BFF_RECO_BLOCKS_BUDGET_MS),
          timed_out_blocks: dagTimedOutBlocks,
          fallbacks_used: dagFallbacksUsed,
          block_stats: dagProvenancePatch?.block_stats || null,
        }
        : null,
    },
  };
}

function applyCommerceMedicalClaimGuard(text, lang) {
  const input = String(text || '');
  if (!input.trim()) return input;
  const lowered = input.toLowerCase();
  const hit =
    /(治愈|疗效|治疗|药用|处方|皮炎|湿疹|激素)/.test(input) ||
    /\b(cure|treat|heals?|prescription|steroid|dermatitis|eczema)\b/i.test(lowered);
  if (!hit) return input;

  recordClaimsViolation({ reason: 'commerce_medical_blacklist' });
  return lang === 'CN'
    ? '我可以帮你查商品信息/成分/购买渠道，但不提供医疗诊断或治疗建议；如果你有皮炎、湿疹等情况，建议线下就医。你想查哪个品牌/单品？'
    : "I can help with product info/ingredients/where to buy, but I can't provide medical diagnosis or treatment advice. If you suspect dermatitis/eczema, please see a clinician. Which brand or product are you looking for?";
}

function normalizeIngredientRecoContextValue(raw) {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
  const query = pickFirstTrimmed(
    raw.query,
    raw.ingredient_query,
    raw.ingredientQuery,
    raw.inci,
    raw.ingredient_name,
    raw.ingredientName,
  );
  const goal = normalizeIngredientGoalToken(
    pickFirstTrimmed(raw.goal, raw.ingredient_goal, raw.ingredientGoal, raw.target_goal, raw.effect_goal),
  );
  const sensitivity = normalizeIngredientSensitivityToken(
    pickFirstTrimmed(raw.sensitivity, raw.ingredient_sensitivity, raw.ingredientSensitivity, raw.skin_sensitivity),
  );
  const candidates = normalizeIngredientCandidateList(
    Array.isArray(raw.candidates)
      ? raw.candidates
      : Array.isArray(raw.ingredient_candidates)
        ? raw.ingredient_candidates
        : Array.isArray(raw.ingredientCandidates)
          ? raw.ingredientCandidates
          : [],
    8,
  );
  const productCandidatesRaw = Array.isArray(raw.product_candidates)
    ? raw.product_candidates
    : Array.isArray(raw.productCandidates)
      ? raw.productCandidates
      : [];
  const productCandidates = productCandidatesRaw
    .filter((p) => p && typeof p === 'object' && !Array.isArray(p))
    .slice(0, 12);
  const source = pickFirstTrimmed(raw.source, raw.entry_source, raw.trigger_source, raw.route_source);
  const updatedRaw = Number(raw.updated_at_ms || raw.updatedAtMs || 0);
  if (!query && !goal && candidates.length === 0) return null;
  const out = {
    ...(query ? { query: String(query).slice(0, 120) } : {}),
    ...(goal ? { goal } : {}),
    ...(candidates.length ? { candidates } : {}),
    ...(candidates.length ? { ingredient_candidates: candidates } : {}),
    ...(productCandidates.length ? { product_candidates: productCandidates } : {}),
    sensitivity: sensitivity || 'unknown',
    ...(source ? { source: String(source).slice(0, 48) } : {}),
  };
  if (Number.isFinite(updatedRaw) && updatedRaw > 0) {
    out.updated_at_ms = Math.trunc(updatedRaw);
  }
  return out;
}

function mergeIngredientRecoContextValue(base, patch) {
  const left = normalizeIngredientRecoContextValue(base);
  const right = normalizeIngredientRecoContextValue(patch);
  if (!left) return right;
  if (!right) return left;
  const mergedCandidates = normalizeIngredientCandidateList(
    [
      ...(Array.isArray(left.candidates) ? left.candidates : []),
      ...(Array.isArray(right.candidates) ? right.candidates : []),
    ],
    8,
  );
  const mergedProductCandidates = [
    ...(Array.isArray(right.product_candidates) ? right.product_candidates : []),
    ...(Array.isArray(left.product_candidates) ? left.product_candidates : []),
  ].filter((p) => p && typeof p === 'object' && !Array.isArray(p)).slice(0, 12);
  return {
    ...left,
    ...right,
    query: right.query || left.query || '',
    goal: right.goal || left.goal || '',
    ...(mergedCandidates.length ? { candidates: mergedCandidates, ingredient_candidates: mergedCandidates } : {}),
    ...(mergedProductCandidates.length ? { product_candidates: mergedProductCandidates } : {}),
    sensitivity: right.sensitivity || left.sensitivity || 'unknown',
    source: right.source || left.source || '',
    updated_at_ms: Math.max(
      Number.isFinite(Number(left.updated_at_ms)) ? Number(left.updated_at_ms) : 0,
      Number.isFinite(Number(right.updated_at_ms)) ? Number(right.updated_at_ms) : 0,
    ) || Date.now(),
  };
}

function buildRecoCatalogQueries({ profileSummary, lang, ingredientContext } = {}) {
  const raw = RECO_CATALOG_GROUNDED_QUERIES;
  const fromEnv = raw
    ? raw
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean)
      .slice(0, 8)
    : null;

  const base = fromEnv && fromEnv.length > 0 ? fromEnv : ['cleanser', 'moisturizer', 'sunscreen'];

  const goalPrimaryRaw = profileSummary && typeof profileSummary.goal_primary === 'string' ? profileSummary.goal_primary.trim().toLowerCase() : '';
  const goals = Array.isArray(profileSummary?.goals) ? profileSummary.goals : [];
  const goalsText = [goalPrimaryRaw, ...goals.map((g) => String(g || '').trim().toLowerCase())].filter(Boolean).join(' ');
  const hasAcne = /\b(acne|breakout|breakouts)\b/.test(goalsText) || /痘/.test(goalsText);

  const isCn = String(lang || '').toUpperCase() === 'CN';
  const stepLabels = {
    cleanser: isCn ? '洁面' : 'Cleanser',
    moisturizer: isCn ? '保湿' : 'Moisturizer',
    sunscreen: isCn ? '防晒' : 'Sunscreen',
    treatment: isCn ? '功效' : 'Treatment',
  };

  const items = base.map((q, idx) => {
    const key = String(q || '').trim().toLowerCase();
    const step = stepLabels[key] || (isCn ? `推荐 ${idx + 1}` : `Recommendation ${idx + 1}`);
    const slot = idx === 0 ? 'am' : idx === 1 ? 'pm' : 'other';
    const query = hasAcne && key === 'cleanser' ? 'acne cleanser' : q;
    return { query: String(query || '').trim(), step, slot };
  });

  const normalizedIngredientContext = normalizeIngredientRecoContextValue(ingredientContext);
  const ingredientCandidates = normalizeIngredientCandidateList(
    normalizedIngredientContext && normalizedIngredientContext.candidates,
    4,
  );
  if (
    normalizedIngredientContext &&
    (normalizedIngredientContext.query || ingredientCandidates.length > 0)
  ) {
    const ingredientSeed = String(normalizedIngredientContext.query || ingredientCandidates[0] || '').trim();
    const goalSeed = normalizeIngredientGoalToken(normalizedIngredientContext.goal);
    const goalLabelMap = {
      acne: isCn ? '祛痘' : 'acne',
      brightening: isCn ? '提亮' : 'brightening',
      barrier: isCn ? '修护' : 'barrier',
      antiaging: isCn ? '抗老' : 'anti-aging',
      hydration: isCn ? '保湿' : 'hydration',
    };
    const goalLabel = goalSeed ? goalLabelMap[goalSeed] : '';
    const seededQueries = [
      ingredientSeed ? `${ingredientSeed} skincare` : '',
      goalLabel ? `${ingredientSeed || goalLabel} ${goalLabel}` : '',
      isCn ? `${ingredientSeed || goalLabel} 成分 护肤` : `${ingredientSeed || goalLabel} ingredient skincare`,
      ...ingredientCandidates.map((candidate) => `${candidate} skincare`),
    ]
      .map((v) => String(v || '').trim())
      .filter(Boolean);
    for (const query of seededQueries) {
      items.unshift({
        query,
        step: stepLabels.treatment,
        slot: 'other',
      });
    }
  }

  const deduped = [];
  const seen = new Set();
  for (const item of items) {
    const query = String(item && item.query ? item.query : '').trim();
    if (!query) continue;
    const step = String(item && item.step ? item.step : stepLabels.treatment).trim();
    const slot = String(item && item.slot ? item.slot : 'other').trim().toLowerCase();
    const key = `${query.toLowerCase()}::${slot}`;
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push({ query, step, slot: slot || 'other' });
    if (deduped.length >= 8) break;
  }

  return deduped;
}

function normalizeRecoGroundingStatus(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (token === 'grounded' || token === 'partially_grounded' || token === 'ungrounded') return token;
  if (token === 'editorial') return 'ungrounded';
  return '';
}

function isRecoUngroundedItem(item) {
  if (!isPlainObject(item)) return false;
  const token = normalizeRecoGroundingStatus(
    item.grounding_status
    || item.groundingStatus
    || item?.recommendation_meta?.grounding_status
    || item?.metadata?.grounding_status,
  );
  return token === 'ungrounded';
}

function normalizeRecoPlanStringArray(raw, max = 6) {
  return uniqCaseInsensitiveStrings(asStringArray(raw), max);
}

function humanizeRecoProductType(productType, lang = 'EN') {
  const token = String(productType || '').trim().toLowerCase();
  const isCn = String(lang || '').trim().toUpperCase() === 'CN';
  const mapEn = {
    cleanser: 'gentle cleanser',
    moisturizer: 'barrier-friendly moisturizer',
    sunscreen: 'broad-spectrum sunscreen',
    serum: 'targeted serum',
    treatment: 'targeted treatment',
    other: 'skincare product',
  };
  const mapCn = {
    cleanser: '温和洁面',
    moisturizer: '屏障友好保湿',
    sunscreen: '广谱防晒',
    serum: '功效精华',
    treatment: '针对性护理',
    other: '护肤产品',
  };
  return (isCn ? mapCn[token] : mapEn[token]) || (isCn ? '护肤产品' : 'skincare product');
}

function normalizeRecoPlanQueryTerms(raw, max = 4) {
  const input = Array.isArray(raw)
    ? raw
    : typeof raw === 'string'
      ? raw.split(/[,\n;|/]+/)
      : [];
  return uniqCaseInsensitiveStrings(
    input
      .map((item) => String(item || '').trim())
      .filter(Boolean)
      .map((item) => item.slice(0, 80)),
    max,
  );
}

function deriveRecoPlanQueryTerms(item, lang = 'EN') {
  const base = isPlainObject(item) ? item : {};
  const provided = normalizeRecoPlanQueryTerms(base.query_terms || base.queryTerms, 4);
  if (provided.length) return provided;
  const productType = pickFirstTrimmed(base.product_type, base.productType, base.step, base.category, 'skincare');
  const concernMatch = normalizeRecoPlanStringArray(base.concern_match || base.concernMatch, 3);
  const useCase = pickFirstTrimmed(base.use_case, base.useCase);
  const displayName = pickFirstTrimmed(base.display_name, base.displayName, base.name, base.title);
  const out = [];
  if (displayName) out.push(displayName);
  if (useCase) out.push(useCase);
  if (productType && concernMatch.length) {
    for (const concern of concernMatch) {
      out.push(`${productType} ${concern}`.trim());
    }
  }
  if (productType) out.push(productType);
  if (String(lang || '').toUpperCase() === 'CN' && productType) {
    out.push(`${productType} 护肤`);
  } else if (productType) {
    out.push(`${productType} skincare`);
  }
  return normalizeRecoPlanQueryTerms(out, 4);
}

function normalizeRecoPlanRecommendation(item, { lang = 'EN', index = 0 } = {}) {
  const base = isPlainObject(item) ? { ...item } : {};
  const slotRaw = String(base.slot || '').trim().toLowerCase();
  const slot = slotRaw === 'am' || slotRaw === 'pm' ? slotRaw : 'other';
  const productType = pickFirstTrimmed(base.product_type, base.productType, base.step, base.category, 'other')
    .trim()
    .toLowerCase();
  const step = pickFirstTrimmed(base.step, humanizeRecoProductType(productType, lang), 'Recommendation');
  const concernMatch = normalizeRecoPlanStringArray(base.concern_match || base.concernMatch, 4);
  const skinFit = normalizeRecoPlanStringArray(base.skin_fit || base.skinFit, 4);
  const constraintNotes = normalizeRecoPlanStringArray(base.constraint_notes || base.constraintNotes, 4);
  const useCase = pickFirstTrimmed(base.use_case, base.useCase, concernMatch[0], humanizeRecoProductType(productType, lang));
  const displayName = pickFirstTrimmed(
    base.display_name,
    base.displayName,
    base.name,
    base.title,
    useCase,
    humanizeRecoProductType(productType, lang),
  );
  const name = pickFirstTrimmed(base.name, displayName, useCase, humanizeRecoProductType(productType, lang));
  const brand = pickFirstTrimmed(base.brand);
  const reasons = normalizeRecoPlanStringArray(base.reasons || base.notes || base.why, 3);
  const queryTerms = deriveRecoPlanQueryTerms(base, lang);
  const score = Number.isFinite(Number(base.score)) ? Math.max(0, Math.min(100, Math.trunc(Number(base.score)))) : Math.max(60, 92 - index * 4);
  const skuBase = isPlainObject(base.sku) ? { ...base.sku } : {};
  return {
    ...base,
    slot,
    step,
    score,
    product_type: productType || 'other',
    brand: brand || null,
    name: name || null,
    title: pickFirstTrimmed(base.title, displayName, name) || null,
    display_name: displayName || null,
    use_case: useCase || null,
    concern_match: concernMatch,
    skin_fit: skinFit,
    constraint_notes: constraintNotes,
    query_terms: queryTerms,
    reasons,
    grounding_status: normalizeRecoGroundingStatus(base.grounding_status) || 'ungrounded',
    sku: {
      ...skuBase,
      ...(brand ? { brand } : {}),
      ...(name ? { name } : {}),
      ...(displayName ? { display_name: displayName } : {}),
      ...(productType ? { category: productType, product_type: productType } : {}),
    },
  };
}

function buildRecoGroundingQueriesFromPlanItem(item, { lang = 'EN' } = {}) {
  const base = normalizeRecoPlanRecommendation(item, { lang });
  const queries = [];
  const primaryTerms = normalizeRecoPlanQueryTerms(base.query_terms, 4);
  for (const term of primaryTerms) queries.push(term);
  const productType = pickFirstTrimmed(base.product_type, base.step, 'skincare');
  const concernMatch = normalizeRecoPlanStringArray(base.concern_match, 2);
  if (productType && concernMatch.length) {
    for (const concern of concernMatch) {
      queries.push(`${productType} ${concern}`.trim());
    }
  }
  const displayName = pickFirstTrimmed(base.display_name, base.name, base.use_case);
  if (displayName) queries.push(displayName);
  return normalizeRecoPlanQueryTerms(queries, 4);
}

function mergeRecoPlanWithGroundedCandidate(planItem, product) {
  const plan = normalizeRecoPlanRecommendation(planItem);
  const normalizedProduct = normalizeRecoCatalogProduct(product);
  if (!isPlainObject(normalizedProduct)) {
    return { ...plan, grounding_status: 'ungrounded' };
  }
  const canonicalRef = normalizeCanonicalProductRef(
    normalizedProduct.canonical_product_ref || {
      product_id: pickFirstString(normalizedProduct.product_id, normalizedProduct.productId),
      merchant_id: pickFirstString(normalizedProduct.merchant_id, normalizedProduct.merchantId),
    },
    { requireMerchant: true, allowOpaqueProductId: false },
  );
  const mergedReasons = uniqCaseInsensitiveStrings(
    [
      ...normalizeRecoPlanStringArray(plan.reasons, 3),
      ...normalizeRecoPlanStringArray([pickFirstTrimmed(normalizedProduct.why_match, normalizedProduct.retrieval_reason)], 2),
    ],
    4,
  );
  return {
    ...plan,
    grounding_status: 'grounded',
    product_id: pickFirstTrimmed(normalizedProduct.product_id, normalizedProduct.productId, plan.product_id),
    merchant_id: pickFirstTrimmed(normalizedProduct.merchant_id, normalizedProduct.merchantId, plan.merchant_id),
    brand: pickFirstTrimmed(normalizedProduct.brand, plan.brand),
    name: pickFirstTrimmed(normalizedProduct.name, normalizedProduct.title, plan.name),
    title: pickFirstTrimmed(normalizedProduct.title, normalizedProduct.name, plan.title),
    display_name: pickFirstTrimmed(normalizedProduct.display_name, normalizedProduct.displayName, normalizedProduct.name, plan.display_name),
    category: pickFirstTrimmed(normalizedProduct.category, normalizedProduct.category_name, normalizedProduct.product_type, plan.product_type),
    retrieval_source: pickFirstTrimmed(normalizedProduct.retrieval_source, normalizedProduct.retrievalSource, 'catalog'),
    retrieval_reason: pickFirstTrimmed(normalizedProduct.retrieval_reason, normalizedProduct.retrievalReason, 'catalog_query_match'),
    ...(canonicalRef ? { canonical_product_ref: canonicalRef } : {}),
    ...(pickFirstTrimmed(normalizedProduct.purchase_path, normalizedProduct.purchasePath) ? { purchase_path: pickFirstTrimmed(normalizedProduct.purchase_path, normalizedProduct.purchasePath) } : {}),
    ...(pickFirstTrimmed(normalizedProduct.canonical_pdp_url, normalizedProduct.canonicalPdpUrl) ? { canonical_pdp_url: pickFirstTrimmed(normalizedProduct.canonical_pdp_url, normalizedProduct.canonicalPdpUrl) } : {}),
    ...(isPlainObject(normalizedProduct.pdp_open) ? { pdp_open: normalizedProduct.pdp_open } : {}),
    reasons: mergedReasons,
    sku: {
      ...normalizedProduct,
      ...(plan.product_type ? { product_type: plan.product_type } : {}),
    },
  };
}

async function groundRecoRecommendationsFromCatalog({
  recommendations,
  ctx,
  logger,
} = {}) {
  const recs = (Array.isArray(recommendations) ? recommendations : [])
    .map((item, index) => normalizeRecoPlanRecommendation(item, { lang: ctx && ctx.lang ? ctx.lang : 'EN', index }))
    .filter((item) => isPlainObject(item));

  if (!recs.length) {
    return {
      recommendations: [],
      grounding_status: 'ungrounded',
      grounded_count: 0,
      ungrounded_count: 0,
      mainline_status: 'empty_structured',
      catalog_skip_reason: null,
      telemetry_reason: null,
      debug: {
        enabled: RECO_CATALOG_GROUNDED_ENABLED,
        query_count: 0,
        candidate_count_before_filter: 0,
        candidate_count_after_filter: 0,
        candidates_rejected: 0,
      },
    };
  }

  if (!RECO_CATALOG_GROUNDED_ENABLED) {
    return {
      recommendations: recs,
      grounding_status: 'ungrounded',
      grounded_count: 0,
      ungrounded_count: recs.length,
      mainline_status: 'catalog_skipped_disabled',
      catalog_skip_reason: 'disabled',
      telemetry_reason: null,
      debug: {
        enabled: false,
        query_count: 0,
        candidate_count_before_filter: 0,
        candidate_count_after_filter: 0,
        candidates_rejected: 0,
      },
    };
  }

  const failFastSnapshot = getRecoCatalogFailFastSnapshot(Date.now());
  if (failFastSnapshot && failFastSnapshot.open) {
    return {
      recommendations: recs,
      grounding_status: 'ungrounded',
      grounded_count: 0,
      ungrounded_count: recs.length,
      mainline_status: 'catalog_skipped_fail_fast',
      catalog_skip_reason: 'fail_fast_open',
      telemetry_reason: 'timeout_degraded',
      debug: {
        enabled: true,
        query_count: 0,
        candidate_count_before_filter: 0,
        candidate_count_after_filter: 0,
        candidates_rejected: 0,
        fail_fast: failFastSnapshot,
      },
    };
  }

  const usedProductIds = new Set();
  const next = [];
  let queryCount = 0;
  let candidateCountBeforeFilter = 0;
  let candidateCountAfterFilter = 0;
  let candidatesRejected = 0;
  let timeoutCount = 0;

  for (const rec of recs) {
    const queries = buildRecoGroundingQueriesFromPlanItem(rec, { lang: ctx && ctx.lang ? ctx.lang : 'EN' });
    let groundedProduct = null;
    for (const query of queries) {
      queryCount += 1;
      const out = await searchPivotaBackendProducts({
        query,
        limit: 6,
        logger,
        timeoutMs: RECO_CATALOG_SEARCH_TIMEOUT_MS,
        allowExternalSeed: false,
        fastMode: true,
      });
      const reason = String(out && out.reason ? out.reason : '').trim().toLowerCase();
      if (reason === 'upstream_timeout') timeoutCount += 1;
      const products = Array.isArray(out && out.products) ? out.products : [];
      candidateCountBeforeFilter += products.length;
      for (const product of products) {
        const normalized = normalizeRecoCatalogProduct(product);
        if (!isPlainObject(normalized)) continue;
        const productId = pickFirstTrimmed(normalized.product_id, normalized.productId);
        if (productId && usedProductIds.has(productId)) continue;
        if (isBlacklistedCategoryOrTitle(normalized) || !isSkincareCategory(normalized)) {
          candidatesRejected += 1;
          continue;
        }
        groundedProduct = normalized;
        if (productId) usedProductIds.add(productId);
        candidateCountAfterFilter += 1;
        break;
      }
      if (groundedProduct) break;
    }
    next.push(groundedProduct ? mergeRecoPlanWithGroundedCandidate(rec, groundedProduct) : rec);
  }

  const groundedCount = next.filter((item) => normalizeRecoGroundingStatus(item.grounding_status) === 'grounded').length;
  const ungroundedCount = Math.max(0, next.length - groundedCount);
  const groundingStatus =
    groundedCount === 0
      ? 'ungrounded'
      : groundedCount === next.length
        ? 'grounded'
        : 'partially_grounded';
  const mainlineStatus =
    groundingStatus === 'grounded'
      ? 'grounded_success'
      : groundingStatus === 'partially_grounded'
        ? 'partially_grounded'
        : 'ungrounded_success';

  return {
    recommendations: next,
    grounding_status: groundingStatus,
    grounded_count: groundedCount,
    ungrounded_count: ungroundedCount,
    mainline_status: mainlineStatus,
    catalog_skip_reason: null,
    telemetry_reason: timeoutCount > 0 ? 'timeout_degraded' : null,
    debug: {
      enabled: true,
      query_count: queryCount,
      candidate_count_before_filter: candidateCountBeforeFilter,
      candidate_count_after_filter: candidateCountAfterFilter,
      candidates_rejected: candidatesRejected,
      timeout_count: timeoutCount,
    },
  };
}

function shouldUseRecoCatalogTransientFallback(catalogDebug) {
  if (!RECO_CATALOG_TRANSIENT_FALLBACK_ENABLED) return false;
  if (!catalogDebug || typeof catalogDebug !== 'object' || Array.isArray(catalogDebug)) return false;
  const queryCount = Number.isFinite(Number(catalogDebug.query_count)) ? Math.trunc(Number(catalogDebug.query_count)) : 0;
  const okCount = Number.isFinite(Number(catalogDebug.ok_count)) ? Math.trunc(Number(catalogDebug.ok_count)) : 0;
  if (queryCount <= 0 || okCount > 0) return false;

  const timeoutCount = Number.isFinite(Number(catalogDebug.timeout_count)) ? Math.trunc(Number(catalogDebug.timeout_count)) : 0;
  const statusCounts =
    catalogDebug.status_counts && typeof catalogDebug.status_counts === 'object' && !Array.isArray(catalogDebug.status_counts)
      ? catalogDebug.status_counts
      : null;
  const timeoutByStatus = Number.isFinite(Number(statusCounts?.upstream_timeout))
    ? Math.trunc(Number(statusCounts?.upstream_timeout))
    : 0;
  const upstreamErrorByStatus = Number.isFinite(Number(statusCounts?.upstream_error))
    ? Math.trunc(Number(statusCounts?.upstream_error))
    : 0;
  const rateLimitedByStatus = Number.isFinite(Number(statusCounts?.rate_limited))
    ? Math.trunc(Number(statusCounts?.rate_limited))
    : 0;
  const transientByStatus = timeoutByStatus + upstreamErrorByStatus + rateLimitedByStatus;
  const skippedReason = String(catalogDebug.skipped_reason || '').trim().toLowerCase();
  const failFastAfter =
    catalogDebug.fail_fast_after && typeof catalogDebug.fail_fast_after === 'object' && !Array.isArray(catalogDebug.fail_fast_after)
      ? catalogDebug.fail_fast_after
      : null;
  const failFastAfterOpen = Boolean(failFastAfter && failFastAfter.open === true);
  const failFastAfterReason = String(failFastAfter && failFastAfter.last_reason ? failFastAfter.last_reason : '')
    .trim()
    .toLowerCase();
  const failFastAfterTransient =
    failFastAfterReason === 'all_queries_failed' || failFastAfterReason === 'probe_transient_errors';

  if (skippedReason === 'fail_fast_open') return true;
  if (timeoutCount >= Math.max(1, queryCount)) return true;
  if (transientByStatus >= Math.max(1, queryCount)) return true;
  if (failFastAfterOpen && failFastAfterTransient) return true;
  return false;
}

function buildRecoCatalogTransientFallbackStructured({ ctx } = {}) {
  const isCn = String(ctx && ctx.lang ? ctx.lang : '').toUpperCase() === 'CN';
  const stableSeeds = [
    {
      query: 'Winona Soothing Repair Serum',
      brand: isCn ? '薇诺娜' : 'Winona',
      name: isCn ? '舒缓修护精华' : 'Soothing Repair Serum',
      display_name: isCn ? '薇诺娜 舒缓修护精华' : 'Winona Soothing Repair Serum',
      step: isCn ? '修护精华' : 'Barrier Serum',
      slot: 'pm',
      reasons: isCn
        ? ['优先修护屏障与舒缓不适，可作为晚间核心修护步骤。']
        : ['Prioritizes barrier repair and soothing support for PM recovery.'],
    },
    {
      query: 'The Ordinary Niacinamide 10% + Zinc 1%',
      brand: 'The Ordinary',
      name: 'Niacinamide 10% + Zinc 1%',
      display_name: 'The Ordinary Niacinamide 10% + Zinc 1%',
      step: isCn ? '控油精华' : 'Balancing Serum',
      slot: 'am',
      reasons: isCn
        ? ['聚焦提亮与毛孔困扰，适合作为白天轻量功效步骤。']
        : ['Targets uneven tone and pores with a light daytime active step.'],
    },
    {
      query: 'IPSA Time Reset Aqua',
      brand: 'IPSA',
      name: 'Time Reset Aqua',
      display_name: 'IPSA Time Reset Aqua',
      step: isCn ? '补水打底' : 'Hydration Base',
      slot: 'am',
      reasons: isCn
        ? ['偏向基础保湿与稳定耐受，适合和功效产品搭配。']
        : ['Provides hydration baseline and tolerance support for layering.'],
    },
  ];

  const recos = [];
  const seenProductIds = new Set();
  for (const seed of stableSeeds) {
    if (recos.length >= RECO_CATALOG_TRANSIENT_FALLBACK_MAX_ITEMS) break;
    const match = resolveRecoStableAliasRefByQuery(seed.query);
    if (!match || !match.canonicalProductRef) continue;
    const productId = String(match.canonicalProductRef.product_id || '').trim();
    const merchantId = String(match.canonicalProductRef.merchant_id || '').trim();
    if (!productId || !merchantId || seenProductIds.has(productId)) continue;
    seenProductIds.add(productId);
    recos.push({
      slot: seed.slot,
      step: seed.step,
      score: 90 - recos.length * 2,
      product_id: productId,
      merchant_id: merchantId,
      brand: seed.brand,
      name: seed.name,
      display_name: seed.display_name,
      category: 'skincare',
      retrieval_source: 'catalog',
      retrieval_reason: 'catalog_transient_fallback',
      canonical_product_ref: {
        product_id: productId,
        merchant_id: merchantId,
      },
      sku: {
        product_id: productId,
        merchant_id: merchantId,
        brand: seed.brand,
        name: seed.name,
        display_name: seed.display_name,
        canonical_product_ref: {
          product_id: productId,
          merchant_id: merchantId,
        },
      },
      reasons: seed.reasons,
      warnings: [
        isCn
          ? '商品库上游暂时波动，已使用稳定候选作为快速兜底。'
          : 'Catalog upstream is unstable; showing stable fallback picks for faster response.',
      ],
    });
  }

  if (!recos.length) return null;
  return {
    recommendations: recos,
    evidence: null,
    confidence: 0.62,
    missing_info: [],
    warnings: [
      isCn
        ? '商品库服务波动，当前先返回稳定候选；稍后可再次刷新获取更多选项。'
        : 'Catalog service is unstable right now; returning stable fallback picks first.',
    ],
  };
}

async function buildPurchasableFallbackCandidates({
  query,
  logger,
  timeoutMs,
  deadlineMs = 0,
  limit = 6,
  allowExternalSeed = false,
  externalSeedStrategy = 'supplement_internal_first',
  searchFn,
} = {}) {
  const runSearch = typeof searchFn === 'function' ? searchFn : searchPivotaBackendProducts;
  const q = String(query || '').trim();
  if (!q) return { ok: false, products: [], reason: 'query_missing', selected_source: 'none', stages: {} };

  const primary = await runSearch({
    query: q,
    limit,
    logger,
    timeoutMs,
    deadlineMs,
    allowExternalSeed: false,
    fastMode: true,
  });
  const primaryProducts = Array.isArray(primary?.products) ? primary.products : [];
  const primaryReason = String(primary?.reason || '').trim().toLowerCase();
  const primaryTransientFailure =
    primary?.ok !== true &&
    (
      primaryReason === 'upstream_timeout' ||
      primaryReason === 'upstream_error' ||
      primaryReason === 'rate_limited' ||
      primaryReason === 'budget_exhausted'
    );

  let supplemental = null;
  if (allowExternalSeed) {
    const strategy = String(externalSeedStrategy || '').trim().toLowerCase();
    const shouldSupplement =
      !primaryTransientFailure &&
      (
        primaryProducts.length === 0 ||
        strategy.includes('supplement') ||
        strategy.includes('fallback')
      );
    if (shouldSupplement) {
      supplemental = await runSearch({
        query: q,
        limit,
        logger,
        timeoutMs,
        deadlineMs,
        allowExternalSeed: true,
        externalSeedStrategy,
        fastMode: true,
      });
    }
  }
  const supplementalProducts = Array.isArray(supplemental?.products) ? supplemental.products : [];
  const primaryOk = Boolean(primary && primary.ok === true);
  const supplementalOk = Boolean(supplemental && supplemental.ok === true);

  const merged = [];
  const seen = new Set();
  const pushProduct = (product, fallbackSource) => {
    if (!isPlainObject(product)) return;
    const productId = pickFirstString(product.product_id, product.productId);
    const merchantId = pickFirstString(product.merchant_id, product.merchantId);
    const key = `${String(productId || '').trim()}::${String(merchantId || '').trim()}`;
    if (key === '::') return;
    if (seen.has(key)) return;
    seen.add(key);
    const sourceToken = pickFirstString(product.source, product.source_type, fallbackSource).toLowerCase() || fallbackSource;
    const retrievalSource =
      sourceToken && sourceToken.includes('external')
        ? 'external_seed'
        : sourceToken && sourceToken.includes('llm')
          ? 'llm_fallback'
          : 'catalog';
    merged.push({
      ...product,
      source: sourceToken,
      retrieval_source: retrievalSource,
      retrieval_reason: retrievalSource === 'external_seed' ? 'external_seed_supplement' : 'catalog_search_match',
    });
  };
  for (const product of primaryProducts) pushProduct(product, 'catalog');
  for (const product of supplementalProducts) pushProduct(product, 'external_seed');

  const selectedSource =
    merged.length === 0
      ? 'none'
      : merged.some((row) => String(row.source || '').toLowerCase().includes('external'))
        ? merged.some((row) => String(row.source || '').toLowerCase() === 'catalog')
          ? 'catalog_plus_external_seed'
          : 'external_seed'
        : 'catalog';

  const reason =
    merged.length > 0
      ? null
      : String(
          supplemental && supplemental.reason
            ? supplemental.reason
            : primary && primary.reason
              ? primary.reason
              : 'empty',
        );

  return {
    ok: merged.length > 0 || primaryOk || supplementalOk,
    products: merged,
    reason,
    selected_source: selectedSource,
    stages: {
      catalog: primary,
      external_seed: supplemental,
    },
  };
}

async function buildRecoGenerateFromCatalog({ ctx, profileSummary, ingredientContext, debug, logger } = {}) {
  const startedAt = Date.now();
  const failFastBefore = getRecoCatalogFailFastSnapshot(startedAt);
  let probeWhileOpen = false;
  let searchTimeoutEffectiveMs = RECO_CATALOG_SEARCH_TIMEOUT_MS;
  const fallbackEnabled = AURORA_PURCHASABLE_FALLBACK_ENABLED === true;
  const allowExternalSeedSupplement = fallbackEnabled && AURORA_EXTERNAL_SEED_SUPPLEMENT_ENABLED === true;
  const debugInfo = {
    enabled: RECO_CATALOG_GROUNDED_ENABLED,
    search_timeout_ms: RECO_CATALOG_SEARCH_TIMEOUT_MS,
    search_concurrency: RECO_CATALOG_SEARCH_CONCURRENCY,
    purchasable_fallback_enabled: fallbackEnabled,
    external_seed_supplement_enabled: allowExternalSeedSupplement,
    fail_fast: failFastBefore,
  };

  if (!RECO_CATALOG_GROUNDED_ENABLED) {
    return { structured: null, debug: { ...debugInfo, skipped_reason: 'disabled', total_ms: Date.now() - startedAt } };
  }
  const catalogSearchBaseUrls = buildRecoCatalogSearchBaseUrlCandidates({
    includeLocalFallback:
      RECO_PDP_LOCAL_INVOKE_FALLBACK_CHAT_ENABLED &&
      RECO_PDP_LOCAL_INVOKE_FALLBACK_ENABLED,
  });
  debugInfo.catalog_search_sources = catalogSearchBaseUrls.slice(0, 6);
  debugInfo.catalog_search_source_health = getRecoCatalogSearchSourceHealthSnapshot(Date.now());
  if (!catalogSearchBaseUrls.length) {
    return {
      structured: null,
      debug: { ...debugInfo, skipped_reason: 'pivota_backend_not_configured', total_ms: Date.now() - startedAt },
    };
  }
  if (failFastBefore.open) {
    probeWhileOpen = beginRecoCatalogFailFastProbe(startedAt);
    if (!probeWhileOpen) {
      return { structured: null, debug: { ...debugInfo, skipped_reason: 'fail_fast_open', total_ms: Date.now() - startedAt } };
    }
    searchTimeoutEffectiveMs = Math.min(RECO_CATALOG_SEARCH_TIMEOUT_MS, RECO_CATALOG_FAIL_FAST_PROBE_SEARCH_TIMEOUT_MS);
  }

  const queries = buildRecoCatalogQueries({
    profileSummary,
    lang: ctx && ctx.lang ? ctx.lang : 'EN',
    ingredientContext,
  });
  if (!queries.length) {
    return { structured: null, debug: { ...debugInfo, skipped_reason: 'queries_empty', total_ms: Date.now() - startedAt } };
  }

  const results = await mapWithConcurrency(queries, RECO_CATALOG_SEARCH_CONCURRENCY, async (q) => {
    const out = fallbackEnabled
      ? await buildPurchasableFallbackCandidates({
          query: q.query,
          limit: 6,
          logger,
          timeoutMs: searchTimeoutEffectiveMs,
          allowExternalSeed: allowExternalSeedSupplement,
          // Keep catalog pass single-call when primary search already returned products.
          externalSeedStrategy: 'on_empty_only',
        })
      : await searchPivotaBackendProducts({
          query: q.query,
          limit: 6,
          logger,
          timeoutMs: searchTimeoutEffectiveMs,
        });
    return { ...q, ...out };
  });

  const usedProductIds = new Set();
  const recos = [];
  for (const r of results) {
    const products = Array.isArray(r?.products) ? r.products : [];
    const picked = products.find((p) => p && p.product_id && !usedProductIds.has(p.product_id));
    if (!picked) continue;
    usedProductIds.add(picked.product_id);
    const canonicalRef = normalizeCanonicalProductRef(
      {
        product_id: pickFirstString(picked.product_id, picked.productId),
        merchant_id: pickFirstString(picked.merchant_id, picked.merchantId),
      },
      { requireMerchant: true, allowOpaqueProductId: false },
    );
    recos.push({
      slot: r.slot || 'other',
      step: r.step || (ctx && ctx.lang === 'CN' ? '推荐' : 'Recommendation'),
      score: 95,
      product_id: pickFirstString(picked.product_id, picked.productId),
      merchant_id: pickFirstString(picked.merchant_id, picked.merchantId),
      brand: pickFirstString(picked.brand, picked.brand_name, picked.brandName),
      name: pickFirstString(picked.name, picked.title, picked.display_name, picked.displayName),
      display_name: pickFirstString(picked.display_name, picked.displayName, picked.name, picked.title),
      category: pickFirstString(
        picked.category,
        picked.category_name,
        picked.categoryName,
        picked.product_type,
        picked.productType,
        picked.type,
        r.step,
        r.slot,
      ),
      retrieval_source: pickFirstString(picked.retrieval_source, picked.retrievalSource, 'catalog'),
      retrieval_reason: pickFirstString(picked.retrieval_reason, picked.retrievalReason, 'catalog_search_match'),
      ...(canonicalRef ? { canonical_product_ref: canonicalRef } : {}),
      ...(pickFirstString(picked.canonical_pdp_url, picked.canonicalPdpUrl) ? { canonical_pdp_url: pickFirstString(picked.canonical_pdp_url, picked.canonicalPdpUrl) } : {}),
      ...(pickFirstString(picked.purchase_path, picked.purchasePath) ? { purchase_path: pickFirstString(picked.purchase_path, picked.purchasePath) } : {}),
      ...(isPlainObject(picked.pdp_open) ? { pdp_open: picked.pdp_open } : {}),
      sku: picked,
      ...(debug
        ? {
          notes:
            ctx && ctx.lang === 'CN'
              ? ['来自 Pivota 商品库（PDP 测试模式）']
              : ['From Pivota catalog (PDP test mode)'],
        }
        : {}),
    });
  }

  const statusCounts = {};
  const sourceCounts = {};
  let okCount = 0;
  let emptyCount = 0;
  let timeoutCount = 0;
  let externalSeedUsedCount = 0;
  for (const r of results) {
    const reason = String(r?.reason || (r?.ok ? 'ok' : 'unknown')).trim() || 'unknown';
    statusCounts[reason] = (statusCounts[reason] || 0) + 1;
    if (r?.ok) okCount += 1;
    if (r?.ok && (!Array.isArray(r?.products) || r.products.length === 0)) emptyCount += 1;
    if (reason === 'upstream_timeout') timeoutCount += 1;
    const source = String(r?.selected_source || 'none').trim() || 'none';
    sourceCounts[source] = (sourceCounts[source] || 0) + 1;
    if (source.includes('external_seed')) externalSeedUsedCount += 1;
  }

  const transientReasons = new Set(['upstream_timeout', 'upstream_error', 'rate_limited']);
  const hasOnlyTransientErrors = results.length > 0 && results.every((r) => !r?.ok && transientReasons.has(String(r?.reason || '')));
  const hasTransientErrors = results.some((r) => !r?.ok && transientReasons.has(String(r?.reason || '')));
  const healthyProbeResult = okCount > 0 && !hasTransientErrors;
  if (probeWhileOpen) {
    if (!healthyProbeResult && (hasOnlyTransientErrors || hasTransientErrors)) {
      markRecoCatalogFailFastFailure('probe_transient_errors', Date.now());
    }
  } else if (okCount > 0) {
    markRecoCatalogFailFastSuccess();
  } else if (hasOnlyTransientErrors) {
    markRecoCatalogFailFastFailure('all_queries_failed', Date.now());
  }

  const debugPayload = {
    ...debugInfo,
    query_count: queries.length,
    ok_count: okCount,
    picked_count: recos.length,
    probe_while_open: probeWhileOpen,
    search_timeout_effective_ms: searchTimeoutEffectiveMs,
    total_ms: Date.now() - startedAt,
    fail_fast_after: getRecoCatalogFailFastSnapshot(Date.now()),
    timeout_count: timeoutCount,
    status_counts: statusCounts,
    selected_source_counts: sourceCounts,
    external_seed_used_count: externalSeedUsedCount,
    external_seed_used_rate: results.length > 0 ? Number((externalSeedUsedCount / results.length).toFixed(4)) : 0,
    ...(debug
      ? {
        empty_count: emptyCount,
      }
      : {}),
  };

  const candidatePool = [];
  for (const r of results) {
    const products = Array.isArray(r?.products) ? r.products : [];
    for (const product of products) {
      candidatePool.push(product);
      if (candidatePool.length >= 24) break;
    }
    if (candidatePool.length >= 24) break;
  }

  if (!recos.length) {
    return {
      structured: null,
      candidate_pool: candidatePool,
      debug: debugPayload,
    };
  }

  return {
    structured: {
      recommendations: recos,
      evidence: null,
      confidence: 0.9,
      missing_info: [],
      warnings: [],
    },
    candidate_pool: candidatePool,
    debug: debugPayload,
  };
}

function deriveRecoPdpFastFallbackReasonCode(catalogDebug) {
  const debugObj = catalogDebug && typeof catalogDebug === 'object' ? catalogDebug : null;
  if (!debugObj) return null;
  if (String(debugObj.skipped_reason || '').trim() === 'fail_fast_open') return 'upstream_timeout';
  const okCount = Number.isFinite(Number(debugObj.ok_count)) ? Math.trunc(Number(debugObj.ok_count)) : 0;
  const timeoutCount = Number.isFinite(Number(debugObj.timeout_count)) ? Math.trunc(Number(debugObj.timeout_count)) : 0;
  const queryCount = Number.isFinite(Number(debugObj.query_count)) ? Math.trunc(Number(debugObj.query_count)) : 0;
  const statusCounts =
    debugObj.status_counts && typeof debugObj.status_counts === 'object' && !Array.isArray(debugObj.status_counts)
      ? debugObj.status_counts
      : null;
  const timeoutByStatus = Number.isFinite(Number(statusCounts?.upstream_timeout))
    ? Math.trunc(Number(statusCounts?.upstream_timeout))
    : 0;
  const failFastAfter =
    debugObj.fail_fast_after && typeof debugObj.fail_fast_after === 'object' && !Array.isArray(debugObj.fail_fast_after)
      ? debugObj.fail_fast_after
      : null;
  const failFastAfterOpen = Boolean(failFastAfter && failFastAfter.open === true);
  const failFastAfterReason = String(failFastAfter && failFastAfter.last_reason ? failFastAfter.last_reason : '')
    .trim()
    .toLowerCase();
  const failFastAfterTransient =
    failFastAfterReason === 'all_queries_failed' || failFastAfterReason === 'probe_transient_errors';
  if (okCount > 0) return null;
  if (timeoutCount > 0 && timeoutCount >= Math.max(1, queryCount)) return 'upstream_timeout';
  if (timeoutByStatus > 0 && timeoutByStatus >= Math.max(1, queryCount)) return 'upstream_timeout';
  if (failFastAfterOpen && failFastAfterTransient) return 'upstream_timeout';
  return null;
}

function normalizeHeatmapStepLabel(raw, { slot } = {}) {
  const slotPrefix = String(slot || '').trim().toUpperCase();
  const base =
    raw && typeof raw === 'object'
      ? String(raw.step || raw.category || raw.slot_step || raw.title || raw.name || raw.display_name || '').trim()
      : String(raw || '').trim();
  const label = base || '';
  if (!label) return '';
  if (!slotPrefix) return label.slice(0, 60);
  return `${slotPrefix} ${label}`.slice(0, 60);
}

function buildHeatmapStepsFromRoutine(routine, { testProduct } = {}) {
  const routineObj = routine && typeof routine === 'object' ? routine : {};
  const am = Array.isArray(routineObj.am) ? routineObj.am : [];
  const pm = Array.isArray(routineObj.pm) ? routineObj.pm : [];
  const out = [];

  for (const item of am) {
    const label = normalizeHeatmapStepLabel(item, { slot: 'AM' });
    out.push(label || item);
    if (out.length >= 16) return out;
  }
  for (const item of pm) {
    const label = normalizeHeatmapStepLabel(item, { slot: 'PM' });
    out.push(label || item);
    if (out.length >= 16) return out;
  }
  if (testProduct) {
    const label = normalizeHeatmapStepLabel(testProduct, { slot: 'TEST' });
    out.push(label || testProduct);
  }
  return out;
}

function extractHeatmapStepsFromConflictDetector({ conflictDetector, contextRaw } = {}) {
  if (conflictDetector && typeof conflictDetector === 'object') {
    const candidates = [
      conflictDetector.steps,
      conflictDetector.routine_steps,
      conflictDetector.routineSteps,
      conflictDetector.routineStepsV1,
      conflictDetector.routine && conflictDetector.routine.steps,
      conflictDetector.routine && conflictDetector.routine.routine_steps,
      conflictDetector.routine && conflictDetector.routine.routineSteps,
    ];
    for (const candidate of candidates) {
      if (Array.isArray(candidate) && candidate.length) return candidate;
    }
    const routineCandidate =
      conflictDetector.routine && typeof conflictDetector.routine === 'object'
        ? conflictDetector.routine
        : null;
    if (routineCandidate) {
      const steps = buildHeatmapStepsFromRoutine(routineCandidate);
      if (steps.length) return steps;
    }
  }

  if (contextRaw && typeof contextRaw === 'object') {
    const candidates = [
      contextRaw.routine,
      contextRaw.routine_v1,
      contextRaw.routineV1,
      contextRaw.current_routine,
      contextRaw.currentRoutine,
      contextRaw.recommended_routine,
      contextRaw.recommendedRoutine,
    ];
    for (const candidate of candidates) {
      if (Array.isArray(candidate) && candidate.length) return candidate;
      if (candidate && typeof candidate === 'object') {
        const steps = buildHeatmapStepsFromRoutine(candidate);
        if (steps.length) return steps;
      }
    }
  }

  return [];
}

let openaiClient;
let openaiCtor;
let openaiCtorResolved = false;
function getOpenAIConstructor() {
  if (openaiCtorResolved) return openaiCtor;
  openaiCtorResolved = true;
  try {
    const mod = require('openai');
    if (typeof mod === 'function') {
      openaiCtor = mod;
      return openaiCtor;
    }
    if (mod && typeof mod.OpenAI === 'function') {
      openaiCtor = mod.OpenAI;
      return openaiCtor;
    }
    if (mod && typeof mod.default === 'function') {
      openaiCtor = mod.default;
      return openaiCtor;
    }
  } catch (_err) {
    openaiCtor = null;
  }
  return openaiCtor;
}
function getOpenAIClient() {
  if (!OPENAI_API_KEY) return null;
  const OpenAI = getOpenAIConstructor();
  if (!OpenAI) return null;
  if (!openaiClient) {
    openaiClient = new OpenAI({
      apiKey: OPENAI_API_KEY,
      ...(OPENAI_BASE_URL ? { baseURL: OPENAI_BASE_URL } : {}),
    });
  }
  return openaiClient;
}

function getGeminiClient() {
  const resolved = getAuroraGeminiClient(AURORA_GEMINI_KEY_FEATURE_ENV);
  if (resolved && resolved.client) return { client: resolved.client, init_error: null };
  if (resolved && resolved.init_error === 'MISSING_GEMINI_KEY') {
    return { client: null, init_error: VisionUnavailabilityReason.VISION_MISSING_KEY };
  }
  return { client: null, init_error: VisionUnavailabilityReason.VISION_UNKNOWN };
}

function resolveVisionProviderSelection() {
  const hasGemini = hasAuroraGeminiApiKey(AURORA_GEMINI_KEY_FEATURE_ENV);
  if (AURORA_DIAG_FORCE_GEMINI) {
    return { provider: 'gemini', apiKeyConfigured: hasGemini, requested: 'forced_gemini' };
  }
  const requested = SKIN_VISION_PROVIDER;
  if (requested === 'openai') {
    return { provider: 'openai', apiKeyConfigured: Boolean(OPENAI_API_KEY), requested };
  }
  if (requested === 'gemini') {
    return { provider: 'gemini', apiKeyConfigured: hasGemini, requested };
  }

  if (hasGemini) return { provider: 'gemini', apiKeyConfigured: true, requested };
  if (OPENAI_API_KEY) return { provider: 'openai', apiKeyConfigured: true, requested };
  return { provider: 'gemini', apiKeyConfigured: false, requested };
}

async function withVisionTimeout(promise, timeoutMs) {
  let timeoutRef = null;
  try {
    return await Promise.race([
      promise,
      new Promise((_, reject) => {
        timeoutRef = setTimeout(() => {
          const err = new Error(`vision timeout after ${timeoutMs}ms`);
          err.name = 'AbortError';
          reject(err);
        }, timeoutMs);
      }),
    ]);
  } finally {
    if (timeoutRef) clearTimeout(timeoutRef);
  }
}

async function extractTextFromGeminiResponse(response) {
  if (!response) return '';
  if (typeof response.text === 'function') {
    const maybe = await response.text();
    if (typeof maybe === 'string' && maybe.trim()) return maybe;
  }
  if (typeof response.text === 'string' && response.text.trim()) return response.text;

  const candidates = Array.isArray(response.candidates) ? response.candidates : [];
  const parts = [];
  for (const candidate of candidates) {
    const contentParts =
      candidate && candidate.content && Array.isArray(candidate.content.parts) ? candidate.content.parts : [];
    for (const part of contentParts) {
      if (part && typeof part.text === 'string' && part.text.trim()) parts.push(part.text);
    }
  }
  return parts.join('\n').trim();
}

async function callOpenAiJsonObject({
  model,
  systemPrompt,
  userPrompt,
  timeoutMs = 3000,
  maxTokens = 600,
  temperature = 0,
} = {}) {
  const client = getOpenAIClient();
  if (!client) return { ok: false, reason: 'openai_client_unavailable' };
  try {
    const resp = await withTimeout(
      client.chat.completions.create({
        model: model || ANALYSIS_STORY_MODEL_OPENAI,
        temperature,
        max_tokens: maxTokens,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: String(systemPrompt || 'Return strict JSON only.') },
          { role: 'user', content: String(userPrompt || '') },
        ],
      }),
      timeoutMs,
      'OPENAI_JSON_TIMEOUT',
    );
    const content =
      resp && resp.choices && resp.choices[0] && resp.choices[0].message
        ? resp.choices[0].message.content
        : '';
    const parsed = parseJsonOnlyObject(unwrapCodeFence(content));
    if (!parsed || typeof parsed !== 'object') return { ok: false, reason: 'openai_json_invalid' };
    return { ok: true, json: parsed };
  } catch (err) {
    return {
      ok: false,
      reason: err && err.code ? String(err.code) : 'openai_error',
      detail: err && err.message ? String(err.message) : null,
    };
  }
}
let callOpenAiJsonObjectImpl = callOpenAiJsonObject;

