const productDualQaCache = new Map();

function getProductDualQaCache(key) {
  if (!key) return null;
  const row = productDualQaCache.get(key);
  if (!row || typeof row !== 'object') return null;
  if (Number(row.expireAt || 0) <= Date.now()) {
    productDualQaCache.delete(key);
    return null;
  }
  return row.value === true;
}

function setProductDualQaCache(key, value) {
  if (!key) return;
  productDualQaCache.set(key, {
    value: value === true,
    expireAt: Date.now() + PRODUCT_INTEL_DUAL_QA_CACHE_TTL_MS,
  });
}

function buildProductDualQaCacheKey(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const material = [
    pickFirstString(row.product_id, row.productId),
    pickFirstString(row.name, row.title, row.display_name, row.displayName),
    pickFirstString(row.category, row.category_name, row.product_type, row.type),
    pickFirstString(row.brand, row.source),
    extractCandidateOpenUrl(row),
  ]
    .map((v) => String(v || '').trim().toLowerCase())
    .join('||');
  if (!material.replace(/\|/g, '').trim()) return '';
  return crypto.createHash('sha1').update(material).digest('hex');
}

function resolveQaMode(mode) {
  const token = String(mode || '')
    .trim()
    .toLowerCase();
  if (token === 'off' || token === 'single' || token === 'dual') return token;
  return AURORA_LLM_QA_MODE;
}

function resolveQaSingleProvider(provider) {
  if (AURORA_DIAG_FORCE_GEMINI) return 'gemini';
  const token = String(provider || '')
    .trim()
    .toLowerCase();
  if (token === 'google') return 'gemini';
  if (token === 'gemini' || token === 'openai') return token;
  return AURORA_LLM_SINGLE_PROVIDER;
}

function resolveQaProviderAvailability(provider) {
  if (provider === 'gemini') return hasAuroraGeminiApiKey(AURORA_GEMINI_KEY_FEATURE_ENV);
  if (provider === 'openai') return Boolean(OPENAI_API_KEY);
  return false;
}

function getQaRemainingBudgetMs(qaContext) {
  const ctx = isPlainObject(qaContext) ? qaContext : null;
  if (!ctx) return null;
  const budgetMs = Number(ctx.budget_ms);
  const startedAtMs = Number(ctx.started_at_ms);
  if (!Number.isFinite(budgetMs) || !Number.isFinite(startedAtMs) || budgetMs <= 0 || startedAtMs <= 0) return null;
  const elapsed = Date.now() - startedAtMs;
  return Math.max(0, Math.trunc(budgetMs - Math.max(0, elapsed)));
}

function markQaContextSkip(qaContext, stage, reason) {
  const ctx = isPlainObject(qaContext) ? qaContext : null;
  if (!ctx) return;
  const bucket = String(stage || '').trim() === 'relevance' ? 'relevance' : 'story';
  if (!isPlainObject(ctx[`${bucket}_meta`])) ctx[`${bucket}_meta`] = {};
  const meta = ctx[`${bucket}_meta`];
  meta.skipped = true;
  meta.skipped_reason = pickFirstString(reason, meta.skipped_reason, 'qa_skipped');
}

function markQaContextCall(qaContext, stage, provider, outcome = 'ok', details = null) {
  const ctx = isPlainObject(qaContext) ? qaContext : null;
  if (!ctx) return;
  const bucket = String(stage || '').trim() === 'relevance' ? 'relevance' : 'story';
  if (!isPlainObject(ctx[`${bucket}_meta`])) ctx[`${bucket}_meta`] = {};
  const meta = ctx[`${bucket}_meta`];
  meta.provider = pickFirstString(provider, meta.provider);
  meta.outcome = pickFirstString(outcome, meta.outcome);
  meta.called = true;
  const extra = details && typeof details === 'object' && !Array.isArray(details) ? details : null;
  if (extra) {
    if (extra.route) meta.route = String(extra.route).trim();
    if (extra.model) meta.model = String(extra.model).trim();
    if (extra.result_reason) meta.result_reason = String(extra.result_reason).trim();
    if (extra.timeout_stage) meta.timeout_stage = String(extra.timeout_stage).trim();
    if (Number.isFinite(Number(extra.prompt_bytes))) meta.prompt_bytes = Math.max(0, Math.trunc(Number(extra.prompt_bytes)));
    if (Number.isFinite(Number(extra.schema_bytes))) meta.schema_bytes = Math.max(0, Math.trunc(Number(extra.schema_bytes)));
    if (Number.isFinite(Number(extra.max_output_tokens))) meta.max_output_tokens = Math.max(0, Math.trunc(Number(extra.max_output_tokens)));
    if (Number.isFinite(Number(extra.gate_wait_ms))) meta.gate_wait_ms = Math.max(0, Math.trunc(Number(extra.gate_wait_ms)));
    if (Number.isFinite(Number(extra.upstream_ms))) meta.upstream_ms = Math.max(0, Math.trunc(Number(extra.upstream_ms)));
    if (Number.isFinite(Number(extra.total_ms))) meta.total_ms = Math.max(0, Math.trunc(Number(extra.total_ms)));
  }
}

function shouldSkipQaByBudget({ qaContext, stage } = {}) {
  const ctx = isPlainObject(qaContext) ? qaContext : null;
  if (!ctx) return false;
  const remainingMs = getQaRemainingBudgetMs(ctx);
  if (!Number.isFinite(remainingMs)) return false;
  ctx.remaining_budget_ms = remainingMs;
  const thresholdMs = Number.isFinite(Number(ctx.min_budget_ms))
    ? Math.max(1, Math.trunc(Number(ctx.min_budget_ms)))
    : AURORA_LLM_QA_MIN_REMAINING_BUDGET_MS;
  if (remainingMs >= thresholdMs) return false;
  markQaContextSkip(ctx, stage, 'analysis_budget_low_skip_qa');
  return true;
}

function pickDualQaProviders({ primary = 'gemini' } = {}) {
  const providers = [];
  const hasGemini = hasAuroraGeminiApiKey(AURORA_GEMINI_KEY_FEATURE_ENV);
  const hasOpenAi = Boolean(OPENAI_API_KEY);
  if (primary === 'gemini' && hasGemini) providers.push('gemini');
  if (primary === 'openai' && hasOpenAi) providers.push('openai');
  if (hasGemini && !providers.includes('gemini')) providers.push('gemini');
  if (hasOpenAi && !providers.includes('openai')) providers.push('openai');
  return providers.slice(0, 2);
}

function pickQaProvidersForMode({
  mode,
  singleProvider,
  allowOpenAiFallback = false,
} = {}) {
  if (AURORA_DIAG_FORCE_GEMINI) {
    return resolveQaProviderAvailability('gemini') ? ['gemini'] : [];
  }
  const qaMode = resolveQaMode(mode);
  if (qaMode === 'off') return [];
  if (qaMode === 'dual') {
    return pickDualQaProviders({ primary: resolveQaSingleProvider(singleProvider) });
  }
  const primary = resolveQaSingleProvider(singleProvider);
  const providers = [];
  if (resolveQaProviderAvailability(primary)) providers.push(primary);
  if (
    allowOpenAiFallback === true &&
    primary === 'gemini' &&
    resolveQaProviderAvailability('openai') &&
    !providers.includes('openai')
  ) {
    providers.push('openai');
  }
  if (
    allowOpenAiFallback === true &&
    primary === 'openai' &&
    resolveQaProviderAvailability('gemini') &&
    !providers.includes('gemini')
  ) {
    providers.push('gemini');
  }
  return providers.slice(0, 2);
}

async function callDualQaProvider({
  provider,
  systemPrompt,
  userPrompt,
  timeoutMs,
  responseSchema = null,
  responseJsonSchema = null,
  maxOutputTokens = null,
  geminiUseCase = 'eval_judge',
} = {}) {
  if (provider === 'openai') {
    return callOpenAiJsonObject({
      model: ANALYSIS_STORY_MODEL_OPENAI,
      systemPrompt,
      userPrompt,
      timeoutMs,
      temperature: 0,
      maxTokens: 500,
    });
  }
  if (String(geminiUseCase || '').trim().toLowerCase() === 'runtime_story_generate') {
    return callRuntimeQaJson({
      kind: 'story_generate',
      systemPrompt,
      userPrompt,
      timeoutMs,
      temperature: 0,
      maxOutputTokens,
      responseSchema: responseSchema || responseJsonSchema,
    });
  }
  if (String(geminiUseCase || '').trim().toLowerCase() === 'runtime_story_review') {
    return callRuntimeQaJson({
      kind: 'story_review',
      systemPrompt,
      userPrompt,
      timeoutMs,
      temperature: 0,
      maxOutputTokens,
      responseSchema: responseSchema || responseJsonSchema,
    });
  }
  if (String(geminiUseCase || '').trim().toLowerCase() === 'runtime_product_relevance') {
    return callRuntimeQaJson({
      kind: 'product_relevance',
      systemPrompt,
      userPrompt,
      timeoutMs,
      temperature: 0,
      maxOutputTokens,
      responseSchema: responseSchema || responseJsonSchema,
    });
  }
  return callEvalJudgeJson({
    systemPrompt,
    userPrompt,
    timeoutMs,
    responseSchema: responseSchema || responseJsonSchema,
    maxOutputTokens,
    temperature: 0,
  });
}
let callDualQaProviderImpl = callDualQaProvider;

function chooseVisionPhoto(passedPhotos) {
  if (!Array.isArray(passedPhotos) || !passedPhotos.length) return null;
  return (
    passedPhotos.find((p) => String(p.slot_id || '').trim().toLowerCase() === 'daylight') ||
    passedPhotos[0] ||
    null
  );
}

function isSignedUrlExpiredSignal({ status, detail, code } = {}) {
  const statusNum = Number(status || 0);
  const combined = `${detail || ''} ${code || ''}`.toLowerCase();
  const token = /(expired|request has expired|x-amz-expires|signature.*expired|token.*expired|expiredtoken|expiration)/i;
  if (token.test(combined)) return true;
  return statusNum === 410;
}

function classifySignedUrlFetchFailure({ status, detail, code } = {}) {
  if (isSignedUrlExpiredSignal({ status, detail, code })) {
    return { failure_code: 'DOWNLOAD_URL_EXPIRED', retryable: false };
  }
  const statusNum = Number(status || 0);
  const errorCode = String(code || '').toUpperCase();
  if (statusNum === 408) {
    return { failure_code: 'DOWNLOAD_URL_TIMEOUT', retryable: true };
  }
  if (statusNum >= 500 && statusNum < 600) {
    return { failure_code: 'DOWNLOAD_URL_FETCH_5XX', retryable: true };
  }
  if (statusNum >= 400 && statusNum < 500) {
    return { failure_code: 'DOWNLOAD_URL_FETCH_4XX', retryable: false };
  }
  if (errorCode === 'ECONNABORTED' || errorCode === 'ETIMEDOUT' || /timeout/i.test(String(detail || ''))) {
    return { failure_code: 'DOWNLOAD_URL_TIMEOUT', retryable: true };
  }
  if (errorCode === 'ENOTFOUND' || errorCode === 'EAI_AGAIN' || errorCode === 'EAI_FAIL') {
    return { failure_code: 'DOWNLOAD_URL_DNS', retryable: true };
  }
  return { failure_code: 'DOWNLOAD_URL_FETCH_5XX', retryable: true };
}

function classifyDownloadUrlGenerateFailure({ status, detail, code } = {}) {
  if (isSignedUrlExpiredSignal({ status, detail, code })) {
    // Retry once to refresh signed URL; some upstreams may return near-expired links under load.
    return { failure_code: 'DOWNLOAD_URL_EXPIRED', retryable: true };
  }
  const statusNum = Number(status || 0);
  const errorCode = String(code || '').toUpperCase();
  if (statusNum === 408 || statusNum === 429 || (statusNum >= 500 && statusNum < 600)) {
    return { failure_code: 'DOWNLOAD_URL_GENERATE_FAILED', retryable: true };
  }
  if (statusNum >= 400 && statusNum < 500) {
    return { failure_code: 'DOWNLOAD_URL_GENERATE_FAILED', retryable: false };
  }
  if (errorCode === 'ECONNABORTED' || errorCode === 'ETIMEDOUT' || /timeout/i.test(String(detail || ''))) {
    return { failure_code: 'DOWNLOAD_URL_TIMEOUT', retryable: true };
  }
  if (errorCode === 'ENOTFOUND' || errorCode === 'EAI_AGAIN' || errorCode === 'EAI_FAIL') {
    return { failure_code: 'DOWNLOAD_URL_DNS', retryable: true };
  }
  return { failure_code: 'DOWNLOAD_URL_GENERATE_FAILED', retryable: true };
}

async function requestPhotoDownloadUrlOnce({ photoId, authHeaders } = {}) {
  let upstreamResp = null;
  try {
    upstreamResp = await axios.get(`${PIVOTA_BACKEND_BASE_URL}/photos/download-url`, {
      timeout: PHOTO_DOWNLOAD_URL_TIMEOUT_MS,
      validateStatus: () => true,
      headers: authHeaders,
      params: { upload_id: photoId },
    });
  } catch (err) {
    const failure = classifyDownloadUrlGenerateFailure({
      status: null,
      detail: err && err.message ? err.message : null,
      code: err && err.code ? err.code : null,
    });
    return {
      ok: false,
      reason: 'download_url_generate_failed',
      failure_code: failure.failure_code,
      status: null,
      detail: err && (err.code || err.message) ? String(err.code || err.message) : null,
      retryable: failure.retryable,
    };
  }

  const download = upstreamResp && upstreamResp.data && upstreamResp.data.download ? upstreamResp.data.download : null;
  const downloadUrl = download && typeof download.url === 'string' ? download.url.trim() : '';
  if (upstreamResp.status !== 200 || !downloadUrl) {
    const detail = pickUpstreamErrorDetail(upstreamResp.data);
    const failure = classifyDownloadUrlGenerateFailure({
      status: upstreamResp.status,
      detail,
    });
    return {
      ok: false,
      reason: 'download_url_generate_failed',
      failure_code: failure.failure_code,
      status: upstreamResp.status,
      detail: detail || null,
      retryable: failure.retryable,
    };
  }

  return {
    ok: true,
    upstreamResp,
    download,
    downloadUrl,
  };
}

async function fetchBytesFromSignedUrl(downloadUrl) {
  const startedAt = Date.now();
  let lastFailure = null;
  const totalAttempts = PHOTO_FETCH_RETRIES + 1;

  for (let attempt = 0; attempt < totalAttempts; attempt += 1) {
    const elapsed = Date.now() - startedAt;
    const remaining = PHOTO_FETCH_TOTAL_TIMEOUT_MS - elapsed;
    if (remaining <= 0) {
      return {
        ok: false,
        failure_code: 'DOWNLOAD_URL_TIMEOUT',
        reason: 'download_url_fetch_timeout',
        status: null,
        detail: 'signed_url_fetch_total_timeout',
      };
    }

    const perAttemptTimeout = Math.min(PHOTO_FETCH_TIMEOUT_MS, remaining);
    try {
      const blobResp = await axios.get(downloadUrl, {
        timeout: perAttemptTimeout,
        validateStatus: () => true,
        responseType: 'arraybuffer',
        maxBodyLength: 15 * 1024 * 1024,
        maxContentLength: 15 * 1024 * 1024,
      });
      const detail = pickUpstreamErrorDetail(blobResp.data);
      if (blobResp.status >= 200 && blobResp.status < 300 && blobResp.data) {
        const contentTypeHeader =
          blobResp.headers && (blobResp.headers['content-type'] || blobResp.headers['Content-Type'])
            ? String(blobResp.headers['content-type'] || blobResp.headers['Content-Type']).trim()
            : null;
        return {
          ok: true,
          buffer: Buffer.from(blobResp.data),
          contentTypeHeader,
        };
      }

      const failure = classifySignedUrlFetchFailure({ status: blobResp.status, detail });
      lastFailure = {
        ok: false,
        failure_code: failure.failure_code,
        reason: String(failure.failure_code || 'download_url_fetch_failed').toLowerCase(),
        status: blobResp.status,
        detail: detail || null,
      };
      if (!failure.retryable || attempt >= totalAttempts - 1) return lastFailure;
    } catch (err) {
      const failure = classifySignedUrlFetchFailure({
        status: null,
        detail: err && err.message ? err.message : null,
        code: err && err.code ? err.code : null,
      });
      lastFailure = {
        ok: false,
        failure_code: failure.failure_code,
        reason: String(failure.failure_code || 'download_url_fetch_failed').toLowerCase(),
        status: null,
        detail: err && (err.code || err.message) ? String(err.code || err.message) : null,
      };
      if (!failure.retryable || attempt >= totalAttempts - 1) return lastFailure;
    }

    const backoffMs = Math.min(
      PHOTO_FETCH_RETRY_BASE_MS * (2 ** attempt),
      Math.max(0, PHOTO_FETCH_TOTAL_TIMEOUT_MS - (Date.now() - startedAt)),
    );
    if (backoffMs > 0) await sleep(backoffMs);
  }

  return (
    lastFailure || {
      ok: false,
      failure_code: 'DOWNLOAD_URL_FETCH_5XX',
      reason: 'download_url_fetch_failed',
      status: null,
      detail: null,
    }
  );
}

async function fetchPhotoBytesFromPivotaBackend({ req, photoId } = {}) {
  const auroraUid = getAuroraUidFromReq(req);
  if (!photoId) return { ok: false, reason: 'photo_id_missing', failure_code: 'DOWNLOAD_URL_GENERATE_FAILED' };

  const cached = getPhotoBytesCache({ photoId, auroraUid });
  if (cached) {
    return {
      ok: true,
      buffer: Buffer.from(cached.buffer),
      contentType: cached.contentType || 'image/jpeg',
      source: 'upload_cache',
    };
  }

  if (!PIVOTA_BACKEND_BASE_URL) {
    return {
      ok: false,
      reason: 'pivota_backend_not_configured',
      failure_code: 'DOWNLOAD_URL_GENERATE_FAILED',
    };
  }

  const authHeaders = buildPivotaBackendAuthHeaders(req);
  if (!Object.keys(authHeaders).length) {
    return {
      ok: false,
      reason: 'pivota_backend_auth_not_configured',
      failure_code: 'DOWNLOAD_URL_GENERATE_FAILED',
    };
  }

  const generateAttempts = PHOTO_DOWNLOAD_URL_RETRIES + 1;
  let upstreamResp = null;
  let download = null;
  let downloadUrl = '';
  let lastGenerateFailure = null;
  for (let attempt = 0; attempt < generateAttempts; attempt += 1) {
    const generated = await requestPhotoDownloadUrlOnce({ photoId, authHeaders });
    if (generated && generated.ok) {
      upstreamResp = generated.upstreamResp;
      download = generated.download;
      downloadUrl = generated.downloadUrl;
      break;
    }
    lastGenerateFailure = generated
      ? {
          ok: false,
          reason: generated.reason || 'download_url_generate_failed',
          failure_code: generated.failure_code || 'DOWNLOAD_URL_GENERATE_FAILED',
          status: generated.status == null ? null : generated.status,
          detail: generated.detail || null,
        }
      : {
          ok: false,
          reason: 'download_url_generate_failed',
          failure_code: 'DOWNLOAD_URL_GENERATE_FAILED',
          status: null,
          detail: null,
        };
    if (!generated || !generated.retryable || attempt >= generateAttempts - 1) {
      return lastGenerateFailure;
    }
    const backoffMs = Math.min(PHOTO_DOWNLOAD_URL_RETRY_BASE_MS * (2 ** attempt), PHOTO_DOWNLOAD_URL_TIMEOUT_MS);
    if (backoffMs > 0) await sleep(backoffMs);
  }
  if (!upstreamResp || !downloadUrl) {
    return (
      lastGenerateFailure || {
        ok: false,
        reason: 'download_url_generate_failed',
        failure_code: 'DOWNLOAD_URL_GENERATE_FAILED',
        status: null,
        detail: null,
      }
    );
  }

  const downloadExpiresAt =
    (download && typeof download.expires_at === 'string' && download.expires_at) ||
    (upstreamResp.data && typeof upstreamResp.data.expires_at === 'string' && upstreamResp.data.expires_at) ||
    null;
  const secLeft = secondsUntilIso(downloadExpiresAt);
  if (secLeft != null && secLeft <= 0) {
    return {
      ok: false,
      reason: 'download_url_expired',
      failure_code: 'DOWNLOAD_URL_EXPIRED',
      status: 410,
      detail: 'signed_url_expired_before_fetch',
    };
  }

  const contentTypeUpstream =
    typeof upstreamResp.data.content_type === 'string' && upstreamResp.data.content_type.trim()
      ? upstreamResp.data.content_type.trim()
      : null;
  const blobResp = await fetchBytesFromSignedUrl(downloadUrl);
  if (!blobResp || !blobResp.ok) return blobResp || { ok: false, reason: 'download_url_fetch_failed' };

  const buffer = blobResp.buffer;
  const contentTypeHeader = blobResp.contentTypeHeader;
  const finalContentType = contentTypeHeader || contentTypeUpstream || 'image/jpeg';
  setPhotoBytesCache({ photoId, auroraUid, buffer, contentType: finalContentType });
  return {
    ok: true,
    buffer,
    contentType: finalContentType,
    source: 'signed_url',
  };
}

function isPassedPhotoQcStatus(qcStatus) {
  return normalizePhotoQcStatus(qcStatus) === 'passed';
}

function normalizePhotoQcStatus(rawStatus) {
  const token = String(rawStatus || '')
    .trim()
    .toLowerCase();
  if (!token) return '';
  if (token === 'passed' || token === 'pass' || token === 'ok' || token === 'success' || token === 'succeeded') {
    return 'passed';
  }
  if (token === 'degraded' || token === 'warn' || token === 'warning' || token === 'low') {
    return 'degraded';
  }
  if (token === 'fail' || token === 'failed' || token === 'reject' || token === 'rejected' || token === 'bad') {
    return 'failed';
  }
  return '';
}

function resolvePhotoQcStatus(payload) {
  const source = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!source) return null;
  const nestedQc = source.qc && typeof source.qc === 'object' && !Array.isArray(source.qc) ? source.qc : null;
  const candidates = [
    source.qc_status,
    nestedQc && nestedQc.qc_status,
    source.status,
    nestedQc && nestedQc.status,
    source.result,
    nestedQc && nestedQc.result,
    source.state,
    nestedQc && nestedQc.state,
  ];
  for (const candidate of candidates) {
    const normalized = normalizePhotoQcStatus(candidate);
    if (normalized) return normalized;
  }
  return null;
}

function isPendingQcAdvice(advice) {
  if (!advice || typeof advice !== 'object' || Array.isArray(advice)) return false;
  const summary = String(advice.summary || '')
    .trim()
    .toLowerCase();
  if (!summary) return false;
  return summary.includes('pending') || summary.includes('processing');
}

function buildDefaultQcAdvice({ status, language, tips } = {}) {
  const lang = String(language || '').trim().toUpperCase() === 'CN' ? 'CN' : 'EN';
  if (status === 'passed') {
    return {
      summary: lang === 'CN' ? '照片质检通过。' : 'Photo QC passed.',
      suggestions: [lang === 'CN' ? '正在进入皮肤分析流程。' : 'Proceeding to skin analysis.'],
      ...(tips && typeof tips === 'object' && !Array.isArray(tips) ? { tips } : {}),
      retryable: false,
    };
  }
  if (status === 'degraded') {
    return {
      summary: lang === 'CN' ? '照片可用，但质量一般。' : 'Photo is usable but quality is degraded.',
      suggestions: [
        lang === 'CN'
          ? '建议在更稳定光线和清晰对焦下重拍，以提升分析准确性。'
          : 'Retake with stable lighting and sharp focus to improve analysis accuracy.',
      ],
      ...(tips && typeof tips === 'object' && !Array.isArray(tips) ? { tips } : {}),
      retryable: true,
    };
  }
  return {
    summary: lang === 'CN' ? '照片质检未通过，建议重拍。' : 'Photo QC failed; please retake.',
    suggestions: [lang === 'CN' ? '请按引导框重拍并保持清晰对焦。' : 'Retake with the guide frame and keep sharp focus.'],
    ...(tips && typeof tips === 'object' && !Array.isArray(tips) ? { tips } : {}),
    retryable: true,
  };
}

function harmonizePhotoQcCardPayload({ qcStatus, qc, nextPollMs, language } = {}) {
  let normalizedStatus = normalizePhotoQcStatus(qcStatus);
  let normalizedQc = qc && typeof qc === 'object' && !Array.isArray(qc) ? { ...qc } : null;
  let normalizedNextPollMs = typeof nextPollMs === 'number' ? nextPollMs : null;

  if (!normalizedStatus && normalizedQc) {
    normalizedStatus = resolvePhotoQcStatus({ qc: normalizedQc });
  }

  if (normalizedStatus) {
    const tips = normalizedQc && normalizedQc.advice && typeof normalizedQc.advice === 'object' && !Array.isArray(normalizedQc.advice)
      ? normalizedQc.advice.tips
      : null;
    if (!normalizedQc) normalizedQc = {};
    normalizedQc.state = 'done';
    normalizedQc.qc_status = normalizedStatus;
    const advice = normalizedQc.advice && typeof normalizedQc.advice === 'object' && !Array.isArray(normalizedQc.advice)
      ? normalizedQc.advice
      : null;
    if (!advice || isPendingQcAdvice(advice)) {
      normalizedQc.advice = buildDefaultQcAdvice({ status: normalizedStatus, language, tips });
    }
    normalizedNextPollMs = null;
  }

  return {
    qcStatus: normalizedStatus || null,
    qc: normalizedQc,
    nextPollMs: normalizedNextPollMs,
  };
}

function hasNonEmptyRoutineInput(routineCandidate) {
  return Boolean(
    routineCandidate != null &&
      (typeof routineCandidate === 'string'
        ? String(routineCandidate).trim().length > 0
        : Array.isArray(routineCandidate)
          ? routineCandidate.length > 0
          : typeof routineCandidate === 'object'
            ? Object.keys(routineCandidate).length > 0
            : false),
  );
}

function normalizeQualityGradeForMetrics(grade) {
  const token = String(grade || '')
    .trim()
    .toLowerCase();
  if (token === 'pass' || token === 'degraded' || token === 'fail') return token;
  return 'unknown';
}

function normalizePipelineVersionForMetrics(version) {
  const token = String(version || '')
    .trim()
    .toLowerCase();
  if (token === 'a' || token === 'legacy' || token === 'v1') return 'A';
  if (token === 'b' || token === 'v2') return 'B';
  return 'unknown';
}

function inferDeviceClassForMetrics(req) {
  const explicit = req && typeof req.get === 'function' ? req.get('X-Device-Class') : null;
  if (explicit && String(explicit).trim()) return String(explicit).trim().slice(0, 64);
  const ua = req && typeof req.get === 'function' ? String(req.get('User-Agent') || '') : '';
  const lowered = ua.toLowerCase();
  if (!lowered) return 'unknown';
  if (/(iphone|android|ipad|mobile)/.test(lowered)) return 'mobile';
  if (/(macintosh|windows|linux|x11)/.test(lowered)) return 'desktop';
  return 'unknown';
}

function buildPhotoAutoNoticeMessage({ language, failureCode }) {
  const code = String(failureCode || 'DOWNLOAD_URL_GENERATE_FAILED').trim().toUpperCase();
  if (language === 'CN') {
    return `本次未能读取并分析照片（原因：${code}），以下结果仅基于你的问卷/历史信息。请重传后重试。`;
  }
  return `We couldn't analyze your photo this time (reason: ${code}). Results below are based on your answers/history only. Please re-upload and retry.`;
}

function isHttpUrlToken(rawValue) {
  const value = String(rawValue || '').trim();
  if (!value) return false;
  try {
    const parsed = new URL(value);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch (_error) {
    return false;
  }
}

function resolveSkinmaskModelDownloadUrl() {
  if (isHttpUrlToken(DIAG_SKINMASK_MODEL_URL)) return DIAG_SKINMASK_MODEL_URL;
  if (isHttpUrlToken(DIAG_SKINMASK_MODEL_PATH)) return DIAG_SKINMASK_MODEL_PATH;
  return null;
}

function resolveLocalSkinmaskModelPath(downloadUrl) {
  if (DIAG_SKINMASK_MODEL_CACHE_PATH) return path.resolve(DIAG_SKINMASK_MODEL_CACHE_PATH);
  if (DIAG_SKINMASK_MODEL_PATH && !isHttpUrlToken(DIAG_SKINMASK_MODEL_PATH)) {
    return path.resolve(DIAG_SKINMASK_MODEL_PATH);
  }
  let fileName = 'skinmask_v2.onnx';
  if (downloadUrl) {
    try {
      const parsed = new URL(downloadUrl);
      const token = path.basename(parsed.pathname || '').trim();
      if (token) fileName = token;
    } catch (_error) {
      // ignore parse failure and keep fallback filename
    }
  }
  const safeName = fileName.replace(/[^a-zA-Z0-9._-]/g, '_') || 'skinmask_v2.onnx';
  return path.join(os.tmpdir(), 'aurora_skinmask', safeName);
}

function isExistingFile(filePath) {
  if (!filePath) return false;
  try {
    const stat = fs.statSync(filePath);
    return stat.isFile() && stat.size > 0;
  } catch (_error) {
    return false;
  }
}

async function fetchSkinmaskModelBytes({ url, timeoutMs } = {}) {
  const modelUrl = String(url || '').trim();
  if (!modelUrl) {
    const error = new Error('skinmask_model_url_missing');
    error.code = 'MODEL_URL_MISSING';
    throw error;
  }
  const response = await axios.get(modelUrl, {
    responseType: 'arraybuffer',
    timeout: timeoutMs,
    maxContentLength: DIAG_SKINMASK_MODEL_MAX_BYTES,
    maxBodyLength: DIAG_SKINMASK_MODEL_MAX_BYTES,
    validateStatus(status) {
      return Number(status) >= 200 && Number(status) < 300;
    },
  });
  const bytes = Buffer.isBuffer(response && response.data) ? response.data : Buffer.from((response && response.data) || []);
  if (!bytes.length) {
    const error = new Error('skinmask_model_download_empty');
    error.code = 'MODEL_DOWNLOAD_EMPTY';
    throw error;
  }
  if (bytes.length > DIAG_SKINMASK_MODEL_MAX_BYTES) {
    const error = new Error('skinmask_model_too_large');
    error.code = 'MODEL_TOO_LARGE';
    throw error;
  }
  return bytes;
}

let fetchSkinmaskModelBytesImpl = fetchSkinmaskModelBytes;
let ensureSkinmaskModelPathPromise = null;
let ensuredSkinmaskModelPath = null;

async function ensureSkinmaskModelPathForInference({ logger, requestId } = {}) {
  const downloadUrl = resolveSkinmaskModelDownloadUrl();
  const localModelPath = resolveLocalSkinmaskModelPath(downloadUrl);
  if (ensuredSkinmaskModelPath && ensuredSkinmaskModelPath === localModelPath && isExistingFile(localModelPath)) {
    return { ok: true, modelPath: localModelPath, downloaded: false };
  }
  if (isExistingFile(localModelPath)) {
    ensuredSkinmaskModelPath = localModelPath;
    return { ok: true, modelPath: localModelPath, downloaded: false };
  }
  if (!downloadUrl) {
    return {
      ok: false,
      reason: 'MODEL_MISSING',
      detail: 'skinmask_model_not_found_and_model_url_not_configured',
    };
  }
  if (ensureSkinmaskModelPathPromise) return ensureSkinmaskModelPathPromise;

  ensureSkinmaskModelPathPromise = (async () => {
    try {
      const bytes = await fetchSkinmaskModelBytesImpl({
        url: downloadUrl,
        timeoutMs: DIAG_SKINMASK_MODEL_DOWNLOAD_TIMEOUT_MS,
      });
      if (!bytes || !bytes.length) {
        return {
          ok: false,
          reason: 'MODEL_MISSING',
          detail: 'skinmask_model_download_empty',
        };
      }
      await fs.promises.mkdir(path.dirname(localModelPath), { recursive: true });
      const tmpPath = `${localModelPath}.tmp-${Date.now()}-${crypto.randomBytes(4).toString('hex')}`;
      try {
        await fs.promises.writeFile(tmpPath, bytes);
        await fs.promises.rename(tmpPath, localModelPath);
      } finally {
        try {
          if (isExistingFile(tmpPath)) await fs.promises.unlink(tmpPath);
        } catch (_error) {
          // no-op cleanup best effort
        }
      }
      ensuredSkinmaskModelPath = localModelPath;
      logger?.info?.(
        {
          request_id: requestId || null,
          model_path: localModelPath,
          model_bytes: bytes.length,
        },
        'aurora bff: skinmask model downloaded for inference',
      );
      return { ok: true, modelPath: localModelPath, downloaded: true };
    } catch (error) {
      logger?.warn?.(
        {
          request_id: requestId || null,
          model_path: localModelPath,
          model_url: downloadUrl,
          err: error && error.message ? error.message : String(error),
          code: error && error.code ? String(error.code) : null,
        },
        'aurora bff: skinmask model download failed',
      );
      return {
        ok: false,
        reason: 'MODEL_MISSING',
        detail: error && error.message ? String(error.message) : 'skinmask_model_download_failed',
      };
    } finally {
      ensureSkinmaskModelPathPromise = null;
    }
  })();
  return ensureSkinmaskModelPathPromise;
}

let inferSkinMaskOnFaceCropImpl = inferSkinMaskOnFaceCrop;

function computeElapsedMs(startHrTime) {
  if (typeof startHrTime !== 'bigint') return 0;
  return Number(process.hrtime.bigint() - startHrTime) / 1e6;
}

function withTimeout(promise, timeoutMs, timeoutCode) {
  const ms = Number.isFinite(Number(timeoutMs)) ? Math.max(1, Math.trunc(Number(timeoutMs))) : 0;
  if (!ms) return promise;
  let timer = null;
  const timeoutPromise = new Promise((_, reject) => {
    timer = setTimeout(() => {
      const err = new Error(timeoutCode || 'timeout');
      err.code = timeoutCode || 'TIMEOUT';
      reject(err);
    }, ms);
    if (timer && typeof timer.unref === 'function') timer.unref();
  });
  return Promise.race([promise, timeoutPromise]).finally(() => {
    if (timer) clearTimeout(timer);
  });
}

function normalizeSkinmaskFallbackReason(rawReason, detail) {
  const reason = String(rawReason || '').trim().toUpperCase();
  const info = String(detail || '').trim().toUpperCase();
  if (reason === 'DISABLED') return 'DISABLED';
  if (reason.includes('TIMEOUT') || info.includes('TIMEOUT')) return 'TIMEOUT';
  if (
    reason === 'MODEL_MISSING' ||
    reason === 'MODEL_PATH_MISSING' ||
    reason === 'ONNXRUNTIME_MISSING' ||
    reason === 'SESSION_UNAVAILABLE' ||
    reason === 'SESSION_LOAD_FAILED' ||
    info.includes('ENOENT') ||
    info.includes('NO SUCH FILE')
  ) {
    return 'MODEL_MISSING';
  }
  return 'ONNX_FAIL';
}

function normalizeSkinmaskSource(rawSource) {
  const token = String(rawSource || '').trim().toLowerCase();
  if (token === 'onnx' || token === 'diagnosis_bbox' || token === 'none') return token;
  return 'none';
}

function resolveSkinmaskFallbackBBoxNorm(diagnosisInternal) {
  const internal = diagnosisInternal && typeof diagnosisInternal === 'object' ? diagnosisInternal : null;
  const normalizedSkinBBox = sanitizeBBoxNorm(internal && internal.skin_bbox_norm);
  if (normalizedSkinBBox.ok && normalizedSkinBBox.bbox) return normalizedSkinBBox.bbox;

  const faceCrop = internal && typeof internal.face_crop === 'object' ? internal.face_crop : null;
  const bboxPx = faceCrop && typeof faceCrop.bbox_px === 'object' ? faceCrop.bbox_px : null;
  const faceCropSize = faceCrop && typeof faceCrop.orig_size_px === 'object' ? faceCrop.orig_size_px : null;
  const internalSize = internal && typeof internal.orig_size_px === 'object' ? internal.orig_size_px : null;
  const size = faceCropSize || internalSize;
  if (!bboxPx || !size) return null;

  const width = Number(size.w);
  const height = Number(size.h);
  const x = Number(bboxPx.x);
  const y = Number(bboxPx.y);
  const w = Number(bboxPx.w);
  const h = Number(bboxPx.h);
  if (!Number.isFinite(width) || !Number.isFinite(height) || width <= 1 || height <= 1) return null;
  if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(w) || !Number.isFinite(h)) return null;
  if (w <= 1 || h <= 1) return null;

  const normalizedFaceCropBBox = sanitizeBBoxNorm({
    x0: x / width,
    y0: y / height,
    x1: (x + w) / width,
    y1: (y + h) / height,
  });
  if (!normalizedFaceCropBBox.ok || !normalizedFaceCropBBox.bbox) return null;
  return normalizedFaceCropBBox.bbox;
}

function buildSkinMaskFromDiagnosisBBox({ diagnosisInternal, fallbackReason } = {}) {
  if (!DIAG_SKINMASK_BBOX_FALLBACK_ENABLED) return null;
  const bboxNorm = resolveSkinmaskFallbackBBoxNorm(diagnosisInternal);
  if (!bboxNorm) return null;
  const width = clamp01Score(Number(bboxNorm.x1) - Number(bboxNorm.x0));
  const height = clamp01Score(Number(bboxNorm.y1) - Number(bboxNorm.y0));
  if (width <= 0.001 || height <= 0.001) return null;
  const reason = String(fallbackReason || 'ONNX_FAIL').trim().toUpperCase() || 'ONNX_FAIL';
  const positiveRatio = clamp01Score(width * height);
  return {
    ok: true,
    skinmask_source: 'diagnosis_bbox',
    skinmask_fallback_reason: reason,
    bbox: {
      x: clamp01Score(bboxNorm.x0),
      y: clamp01Score(bboxNorm.y0),
      w: width,
      h: height,
    },
    positive_ratio: Math.round(positiveRatio * 1000) / 1000,
  };
}

function attachSkinmaskRuntimeMeta(mask, { onnxInferMs = null, skinmaskModelLoaded = null } = {}) {
  if (!mask || typeof mask !== 'object') return mask;
  const inferLatency = Number.isFinite(Number(onnxInferMs))
    ? Math.max(0, Math.round(Number(onnxInferMs) * 1000) / 1000)
    : null;
  const modelLoaded = typeof skinmaskModelLoaded === 'boolean' ? skinmaskModelLoaded : null;
  return {
    ...mask,
    ...(inferLatency == null ? {} : { onnx_infer_ms: inferLatency }),
    ...(modelLoaded == null ? {} : { skinmask_model_loaded: modelLoaded }),
  };
}

function maybeBuildPhotoModulesCardForAnalysis({
  requestId,
  analysis,
  usedPhotos,
  photoQuality,
  photoNotice,
  diagnosisInternal,
  sourcePhoto,
  profileSummary,
  language,
  skinMask,
} = {}) {
  if (!DIAG_PHOTO_MODULES_CARD) return null;
  if (DIAG_OVERLAY_MODE !== 'client') return null;

  const photoNoticeText =
    typeof photoNotice === 'string'
      ? photoNotice
      : photoNotice && typeof photoNotice.message === 'string'
        ? photoNotice.message
        : null;

  const built = buildPhotoModulesCard({
    requestId,
    analysis,
    usedPhotos: Boolean(usedPhotos),
    photoQuality,
    photoNotice: photoNoticeText,
    diagnosisInternal,
    sourcePhoto,
    profileSummary,
    language,
    ingredientRecEnabled: DIAG_INGREDIENT_REC,
    productRecEnabled: DIAG_PRODUCT_REC,
    productRecMinCitations: DIAG_PRODUCT_REC_MIN_CITATIONS,
    productRecMinEvidenceGrade: DIAG_PRODUCT_REC_MIN_EVIDENCE_GRADE,
    productRecRepairOnlyWhenDegraded: DIAG_PRODUCT_REC_REPAIR_ONLY_WHEN_DEGRADED,
    internalTestMode: INTERNAL_TEST_MODE,
    ingredientKbArtifactPath: DIAG_INGREDIENT_KB_V2_PATH,
    productCatalogPath: DIAG_PRODUCT_CATALOG_PATH,
    skinMask,
  });
  if (!built || !built.card) return null;

  const metrics = built.metrics && typeof built.metrics === 'object' ? built.metrics : {};
  recordPhotoModulesCardEmitted({
    qualityGrade: metrics.quality_grade || (photoQuality && photoQuality.grade),
  });

  const regionCounts = Array.isArray(metrics.regionCounts) ? metrics.regionCounts : [];
  for (const row of regionCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordRegionsEmitted({
      regionType: row.region_type,
      issueType: row.issue_type,
      delta,
    });
  }

  const moduleIssueCounts = Array.isArray(metrics.moduleIssueCounts) ? metrics.moduleIssueCounts : [];
  for (const row of moduleIssueCounts) {
    const count = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (count <= 0) continue;
    recordModulesIssueCountHistogram({
      moduleId: row.module_id,
      issueType: row.issue_type,
      count,
    });
  }

  const ingredientActionCounts = Array.isArray(metrics.ingredientActionCounts) ? metrics.ingredientActionCounts : [];
  for (const row of ingredientActionCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordIngredientActionsEmitted({
      moduleId: row.module_id,
      issueType: row.issue_type,
      delta,
    });
  }

  const productRecEmittedCounts = Array.isArray(metrics.productRecEmittedCounts) ? metrics.productRecEmittedCounts : [];
  for (const row of productRecEmittedCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordProductRecEmitted({
      market: row.market,
      qualityGrade: row.quality_grade,
      delta,
    });
  }

  const productRecSuppressedCounts = Array.isArray(metrics.productRecSuppressedCounts) ? metrics.productRecSuppressedCounts : [];
  for (const row of productRecSuppressedCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordProductRecSuppressed({
      reason: row.reason,
      delta,
    });
  }

  const claimsTemplateFallbackCounts = Array.isArray(metrics.claimsTemplateFallbackCounts) ? metrics.claimsTemplateFallbackCounts : [];
  for (const row of claimsTemplateFallbackCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordClaimsTemplateFallback({
      reason: row.reason,
      delta,
    });
  }

  const claimsViolationCounts = Array.isArray(metrics.claimsViolationCounts) ? metrics.claimsViolationCounts : [];
  for (const row of claimsViolationCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordClaimsViolation({
      reason: row.reason,
      delta,
    });
  }

  const geometryDropCounts = Array.isArray(metrics.geometryDropCounts) ? metrics.geometryDropCounts : [];
  for (const row of geometryDropCounts) {
    const delta = Number.isFinite(Number(row?.count)) ? Number(row?.count) : 0;
    if (delta <= 0) continue;
    recordGeometrySanitizerDropReason({
      reason: row.reason,
      regionType: row.region_type,
      delta,
    });
  }

  return built.card;
}

function derivePhotoModulesMarket({ profileSummary, language } = {}) {
  const profileMarket = pickFirstString(profileSummary && profileSummary.region).toUpperCase();
  if (profileMarket) return profileMarket;
  return String(language || '').trim().toUpperCase() === 'CN' ? 'CN' : 'US';
}

function derivePhotoModulesRiskTier(profileSummary) {
  const pregnancyStatus = pickFirstString(
    profileSummary && profileSummary.pregnancy_status,
    profileSummary && profileSummary.pregnancyStatus,
  )
    .trim()
    .toLowerCase();
  if (pregnancyStatus === 'pregnant' || pregnancyStatus === 'trying') return 'pregnancy_unknown';

  const contraindications = Array.isArray(profileSummary && profileSummary.contraindications)
    ? profileSummary.contraindications
    : [];
  const contraindicationText = contraindications
    .map((item) => String(item || '').trim().toLowerCase())
    .filter(Boolean)
    .join(' ');
  if (/(pregnan|pregnancy|breastfeed|哺乳|妊娠|授乳)/i.test(contraindicationText)) return 'pregnancy_unknown';

  const barrier = pickFirstString(profileSummary && profileSummary.barrierStatus).toLowerCase();
  if (barrier === 'impaired' || barrier === 'damaged' || barrier === 'fragile') return 'barrier_irritated';

  const sensitivity = pickFirstString(profileSummary && profileSummary.sensitivity).toLowerCase();
  if (sensitivity === 'high' || sensitivity === 'reactive' || sensitivity === 'sensitive') return 'sensitive';
  return 'low';
}

function pickActionIssueType(action, moduleIssues) {
  const actionIssueType = pickFirstString(
    Array.isArray(action && action.evidence_issue_types) ? action.evidence_issue_types[0] : '',
  )
    .trim()
    .toLowerCase();
  if (actionIssueType) return actionIssueType;
  const moduleIssueType = pickFirstString(
    moduleIssues && moduleIssues[0] && moduleIssues[0].issue_type,
  )
    .trim()
    .toLowerCase();
  return moduleIssueType || 'redness';
}

const PHOTO_MODULES_INGREDIENT_ALIAS_MAP = Object.freeze({
  ceramides: 'ceramide_np',
  niacinamide_low_pct: 'niacinamide',
  bha_gentle: 'salicylic_acid',
  bha_lha: 'salicylic_acid',
  bha: 'salicylic_acid',
  retinoid_later: 'retinol',
  vitamin_c_gentle: 'ascorbic_acid',
  benzoyl_peroxide_spot: 'benzoyl_peroxide',
});

function resolvePhotoModuleCanonicalIngredientId(action) {
  const canonical = pickFirstString(
    action && action.ingredient_canonical_id,
    action && action.ingredientCanonicalId,
  )
    .trim()
    .toLowerCase();
  if (canonical) return canonical;
  const ingredientId = pickFirstString(action && action.ingredient_id, action && action.ingredientId)
    .trim()
    .toLowerCase();
  if (!ingredientId) return '';
  return PHOTO_MODULES_INGREDIENT_ALIAS_MAP[ingredientId] || ingredientId;
}

function buildPhotoModuleRecoCacheKey({
  ingredientId,
  issueType,
  market,
  lang,
  riskTier,
  qualityGrade,
} = {}) {
  return [
    String(ingredientId || '').trim().toLowerCase(),
    String(issueType || '').trim().toLowerCase(),
    String(market || '').trim().toLowerCase(),
    String(lang || '').trim().toLowerCase(),
    String(riskTier || '').trim().toLowerCase(),
    String(qualityGrade || '').trim().toLowerCase(),
  ].join('::');
}

async function enrichPhotoModulesCardWithIngredientProducts({
  photoModulesCard,
  profileSummary,
  language,
  logger,
} = {}) {
  if (!isPlainObject(photoModulesCard)) return photoModulesCard;
  if (String(photoModulesCard.type || '').trim().toLowerCase() !== 'photo_modules_v1') return photoModulesCard;

  const payload = isPlainObject(photoModulesCard.payload) ? { ...photoModulesCard.payload } : null;
  if (!payload || !Array.isArray(payload.modules) || payload.modules.length === 0) return photoModulesCard;

  const qualityGrade = pickFirstString(payload.quality_grade).toLowerCase() || 'unknown';
  const lang = String(language || '').trim().toUpperCase() === 'CN' ? 'zh' : 'en';
  const market = derivePhotoModulesMarket({ profileSummary, language });
  const riskTier = derivePhotoModulesRiskTier(profileSummary);
  const recCache = new Map();
  let networkFallbackActionsUsed = 0;
  const uniqueActionRecoKeys = new Set();

  for (const moduleRowRaw of payload.modules) {
    const moduleRow = isPlainObject(moduleRowRaw) ? moduleRowRaw : {};
    const moduleIssues = Array.isArray(moduleRow.issues) ? moduleRow.issues : [];
    const moduleActions = Array.isArray(moduleRow.actions) ? moduleRow.actions : [];
    for (const actionRaw of moduleActions) {
      const action = isPlainObject(actionRaw) ? actionRaw : {};
      const issueType = pickActionIssueType(action, moduleIssues);
      const ingredientId = resolvePhotoModuleCanonicalIngredientId(action);
      if (!ingredientId) continue;
      uniqueActionRecoKeys.add(
        buildPhotoModuleRecoCacheKey({
          ingredientId,
          issueType,
          market,
          lang,
          riskTier,
          qualityGrade,
        }),
      );
    }
  }

  const dynamicNetworkFallbackBudget = Math.min(
    PHOTO_MODULES_ACTION_RECO_NETWORK_HARD_CAP,
    Math.max(PHOTO_MODULES_ACTION_RECO_NETWORK_BASE_BUDGET, uniqueActionRecoKeys.size),
  );

  const fallbackCandidateBuilder =
    AURORA_PURCHASABLE_FALLBACK_ENABLED === true
      ? async ({ query, limit = 6, allowExternalSeed = true } = {}) =>
          buildPurchasableFallbackCandidates({
            query,
            logger,
            timeoutMs: PHOTO_MODULES_ACTION_RECO_SEARCH_TIMEOUT_MS,
            limit: Math.max(1, Math.min(12, Number(limit) || 6)),
            allowExternalSeed: Boolean(allowExternalSeed) && AURORA_EXTERNAL_SEED_SUPPLEMENT_ENABLED === true,
            // Keep source-neutral pool quality by supplementing internal hits with external candidates.
            externalSeedStrategy: 'supplement_internal_first',
          })
      : null;

  const llmFallbackRecoverFn =
    AURORA_PRODUCT_LOOKUP_LLM_FALLBACK_ENABLED === true
      ? async ({ queries = [], maxProducts = 6 } = {}) =>
          recoverProductsWithLlmFallbackFromQueries({
            queries,
            strictFilter: true,
            singleProvider: AURORA_LLM_SINGLE_PROVIDER,
            allowOpenAiFallback: AURORA_LLM_OPENAI_FALLBACK_ENABLED,
            logger,
            guardrailRuleId: 'photo_modules_reco_guardrail',
            maxProducts: Math.max(1, Math.min(12, Number(maxProducts) || 6)),
          })
      : null;

  const nextModules = await Promise.all(
    payload.modules.map(async (moduleRowRaw, moduleIndex) => {
      const moduleRow = isPlainObject(moduleRowRaw) ? moduleRowRaw : {};
      const moduleId = pickFirstString(moduleRow.module_id, `module_${moduleIndex + 1}`);
      const moduleIssues = Array.isArray(moduleRow.issues) ? moduleRow.issues : [];
      const moduleActions = Array.isArray(moduleRow.actions) ? moduleRow.actions : [];
      if (!moduleActions.length) return moduleRowRaw;

      const nextActions = await Promise.all(
        moduleActions.map(async (actionRaw) => {
          const action = isPlainObject(actionRaw) ? actionRaw : {};
          const issueType = pickActionIssueType(action, moduleIssues);
          const ingredientId = resolvePhotoModuleCanonicalIngredientId(action);
          const ingredientName = pickFirstString(action.ingredient_name, action.ingredient);

          if (!ingredientId) {
            const fallbackQuery = ingredientName || issueType || moduleId || 'skincare ingredient';
            const fallbackCtas = dedupeExternalSearchCtas(
              [buildExternalSearchCta({ name: fallbackQuery }, 'ingredient_id_missing')],
              3,
            );
            const nextAction = {
              ...action,
              products: [],
              products_empty_reason: 'ingredient_id_missing',
              ...(fallbackCtas.length ? { external_search_ctas: fallbackCtas } : {}),
            };
            if (!fallbackCtas.length && Object.prototype.hasOwnProperty.call(nextAction, 'external_search_ctas')) {
              delete nextAction.external_search_ctas;
            }
            return nextAction;
          }

          const cacheKey = buildPhotoModuleRecoCacheKey({
            ingredientId,
            issueType,
            market,
            lang,
            riskTier,
            qualityGrade,
          });
          if (!recCache.has(cacheKey)) {
            const allowNetworkFallbackForAction =
              networkFallbackActionsUsed < dynamicNetworkFallbackBudget;
            if (allowNetworkFallbackForAction) networkFallbackActionsUsed += 1;
            recCache.set(
              cacheKey,
              buildIngredientProductRecommendationsNeutral({
                moduleId,
                ingredientId,
                ingredientName,
                issueType,
                market,
                lang,
                riskTier,
                qualityGrade,
                minCitations: DIAG_PRODUCT_REC_MIN_CITATIONS,
                minEvidenceGrade: DIAG_PRODUCT_REC_MIN_EVIDENCE_GRADE,
                repairOnlyWhenDegraded: DIAG_PRODUCT_REC_REPAIR_ONLY_WHEN_DEGRADED,
                internalTestMode: INTERNAL_TEST_MODE,
                artifactPath: DIAG_INGREDIENT_KB_V2_PATH,
                catalogPath: DIAG_PRODUCT_CATALOG_PATH,
                maxProducts: 6,
                fallbackCandidateBuilder: allowNetworkFallbackForAction ? fallbackCandidateBuilder : null,
                llmFallbackRecoverFn: allowNetworkFallbackForAction ? llmFallbackRecoverFn : null,
                externalSearchCtaBuilder: buildExternalSearchCta,
                dedupeExternalSearchCtas,
              }).catch((error) => {
                logger?.warn?.(
                  {
                    err: error && error.message ? error.message : String(error),
                    module_id: moduleId,
                    ingredient_id: ingredientId,
                    issue_type: issueType,
                  },
                  'aurora bff: photo module ingredient neutral reco failed',
                );
                return {
                  products: [],
                  products_empty_reason: 'lookup_error',
                  external_search_ctas: [],
                  suppressed_reason: 'NO_MATCH',
                  debug: {
                    module_id: moduleId,
                    ingredient_id: ingredientId,
                    issue_type: issueType,
                    reason: 'lookup_error',
                  },
                };
              }),
            );
          }

          const recResult = await recCache.get(cacheKey);
          const products = Array.isArray(recResult && recResult.products) ? recResult.products.slice(0, 6) : [];
          const actionCtas = dedupeExternalSearchCtas(
            Array.isArray(recResult && recResult.external_search_ctas) ? recResult.external_search_ctas : [],
            6,
          );
          const nextAction = {
            ...action,
            products,
            ...(pickFirstString(recResult && recResult.products_empty_reason)
              ? { products_empty_reason: pickFirstString(recResult && recResult.products_empty_reason) }
              : {}),
            ...(actionCtas.length ? { external_search_ctas: actionCtas } : {}),
            ingredient_canonical_id: ingredientId,
            rec_debug: {
              ...(isPlainObject(recResult && recResult.debug) ? recResult.debug : {}),
              network_fallback_budget: dynamicNetworkFallbackBudget,
              network_fallback_used: networkFallbackActionsUsed,
            },
          };
          if (!pickFirstString(recResult && recResult.products_empty_reason) && Object.prototype.hasOwnProperty.call(nextAction, 'products_empty_reason')) {
            delete nextAction.products_empty_reason;
          }
          if (!actionCtas.length && Object.prototype.hasOwnProperty.call(nextAction, 'external_search_ctas')) {
            delete nextAction.external_search_ctas;
          }
          return nextAction;
        }),
      );

      const moduleProducts = [];
      const seenModuleProduct = new Set();
      const moduleEmptyReasons = [];
      const moduleSearchCtas = [];

      for (const action of nextActions) {
        const rows = Array.isArray(action && action.products) ? action.products : [];
        for (const row of rows) {
          const productId = pickFirstString(row && row.product_id, row && row.productId);
          const merchantId = pickFirstString(row && row.merchant_id, row && row.merchantId);
          const directUrl = pickFirstString(
            row && row.pdp_url,
            row && row.url,
            row && row.product_url,
            row && row.purchase_path,
          ).toLowerCase();
          const key = `${productId.toLowerCase()}::${merchantId.toLowerCase()}::${directUrl}`;
          if (seenModuleProduct.has(key)) continue;
          seenModuleProduct.add(key);
          moduleProducts.push(row);
        }
        const emptyReason = pickFirstString(action && action.products_empty_reason);
        if (emptyReason) moduleEmptyReasons.push(emptyReason);
        const ctas = Array.isArray(action && action.external_search_ctas) ? action.external_search_ctas : [];
        for (const cta of ctas) moduleSearchCtas.push(cta);
      }

      moduleProducts.sort((left, right) => {
        const leftScore = Number(left && left.suitability_score || 0);
        const rightScore = Number(right && right.suitability_score || 0);
        if (rightScore !== leftScore) return rightScore - leftScore;
        return String(left && left.name || '').localeCompare(String(right && right.name || ''));
      });

      const dedupedModuleCtas = dedupeExternalSearchCtas(moduleSearchCtas, 8);
      const topModuleProducts = moduleProducts.slice(0, 6);
      const nextModule = {
        ...moduleRow,
        actions: nextActions,
        products: topModuleProducts,
        ...(topModuleProducts.length === 0 && moduleEmptyReasons.length
          ? { products_empty_reason: moduleEmptyReasons[0] }
          : {}),
        ...(dedupedModuleCtas.length ? { external_search_ctas: dedupedModuleCtas } : {}),
      };
      if (topModuleProducts.length > 0 && Object.prototype.hasOwnProperty.call(nextModule, 'products_empty_reason')) {
        delete nextModule.products_empty_reason;
      }
      if (!dedupedModuleCtas.length && Object.prototype.hasOwnProperty.call(nextModule, 'external_search_ctas')) {
        delete nextModule.external_search_ctas;
      }
      return nextModule;
    }),
  );

  payload.modules = nextModules;
  return {
    ...photoModulesCard,
    payload,
  };
}

async function enrichPhotoModulesCardWithIngredientProductsBounded({
  photoModulesCard,
  profileSummary,
  language,
  logger,
} = {}) {
  if (!photoModulesCard) return photoModulesCard;
  try {
    return await withTimeout(
      enrichPhotoModulesCardWithIngredientProducts({
        photoModulesCard,
        profileSummary,
        language,
        logger,
      }),
      PHOTO_MODULES_ACTION_RECO_ENRICH_TIMEOUT_MS,
      'PHOTO_MODULES_ACTION_RECO_ENRICH_TIMEOUT',
    );
  } catch (error) {
    logger?.warn?.(
      {
        err: error && error.message ? error.message : String(error),
        code: error && error.code ? String(error.code) : null,
        timeout_ms: PHOTO_MODULES_ACTION_RECO_ENRICH_TIMEOUT_MS,
      },
      'aurora bff: photo modules action-level reco enrich skipped',
    );
    return photoModulesCard;
  }
}

async function maybeInferSkinMaskForPhotoModules({ imageBuffer, diagnosisInternal, logger, requestId } = {}) {
  const maybeBuildFallback = ({
    fallbackReason,
    reason,
    detail,
    message,
    skinmaskModelLoaded = null,
    onnxInferMs = null,
  } = {}) => {
    const normalizedReason = normalizeSkinmaskFallbackReason(fallbackReason || reason, detail);
    const fallbackMask = buildSkinMaskFromDiagnosisBBox({
      diagnosisInternal,
      fallbackReason: normalizedReason,
    });
    if (fallbackMask) {
      logger?.warn(
        {
          request_id: requestId || null,
          fallback_reason: normalizedReason,
          reason: reason || normalizedReason,
          detail: detail || null,
          skinmask_source: 'diagnosis_bbox',
        },
        'aurora bff: skinmask fallback using diagnosis bbox',
      );
      return attachSkinmaskRuntimeMeta(fallbackMask, {
        onnxInferMs,
        skinmaskModelLoaded,
      });
    }
    logger?.warn(
      {
        request_id: requestId || null,
        fallback_reason: normalizedReason,
        reason: reason || normalizedReason,
        detail: detail || null,
        skinmask_source: 'none',
      },
      message || 'aurora bff: skinmask unavailable',
    );
    return attachSkinmaskRuntimeMeta(
      {
        ok: false,
        skinmask_source: 'none',
        skinmask_fallback_reason: normalizedReason,
      },
      {
        onnxInferMs,
        skinmaskModelLoaded,
      },
    );
  };

  if (!DIAG_SKINMASK_ENABLED) {
    recordSkinmaskFallback({ reason: 'DISABLED' });
    return maybeBuildFallback({
      fallbackReason: 'DISABLED',
      reason: 'DISABLED',
      message: 'aurora bff: skinmask onnx inference disabled',
      skinmaskModelLoaded: false,
    });
  }
  if (!imageBuffer || !Buffer.isBuffer(imageBuffer) || !imageBuffer.length) {
    return null;
  }
  recordSkinmaskEnabled();
  const resolvedModel = await ensureSkinmaskModelPathForInference({ logger, requestId });
  if (!resolvedModel || !resolvedModel.ok || !resolvedModel.modelPath) {
    recordSkinmaskFallback({ reason: 'MODEL_MISSING' });
    return maybeBuildFallback({
      fallbackReason: 'MODEL_MISSING',
      reason: 'MODEL_MISSING',
      detail: resolvedModel && resolvedModel.detail ? resolvedModel.detail : null,
      message: 'aurora bff: skinmask onnx inference skipped',
      skinmaskModelLoaded: false,
    });
  }
  const inferenceModelPath = String(resolvedModel.modelPath || '').trim();

  const inferStartedAt = process.hrtime.bigint();
  try {
    const inferred = await withTimeout(
      Promise.resolve(
        inferSkinMaskOnFaceCropImpl({
          imageBuffer,
          diagnosisInternal,
          modelPath: inferenceModelPath,
        }),
      ),
      DIAG_SKINMASK_TIMEOUT_MS,
      'SKINMASK_TIMEOUT',
    );
    const inferLatencyMs = computeElapsedMs(inferStartedAt);
    observeSkinmaskInferLatency({ latencyMs: inferLatencyMs });
    if (!inferred || !inferred.ok) {
      const fallbackReason = normalizeSkinmaskFallbackReason(inferred && inferred.reason, inferred && inferred.detail);
      recordSkinmaskFallback({ reason: fallbackReason });
      return maybeBuildFallback({
        fallbackReason,
        reason: inferred && inferred.reason ? inferred.reason : 'unknown',
        detail: inferred && inferred.detail ? inferred.detail : null,
        message: 'aurora bff: skinmask onnx inference skipped',
        onnxInferMs: inferLatencyMs,
        skinmaskModelLoaded: fallbackReason !== 'MODEL_MISSING',
      });
    }
    const normalizedSource = normalizeSkinmaskSource(inferred && inferred.skinmask_source);
    return attachSkinmaskRuntimeMeta(
      {
        ...inferred,
        skinmask_source: normalizedSource === 'none' ? 'onnx' : normalizedSource,
        skinmask_fallback_reason: null,
      },
      {
        onnxInferMs: inferLatencyMs,
        skinmaskModelLoaded: true,
      },
    );
  } catch (error) {
    const inferLatencyMs = computeElapsedMs(inferStartedAt);
    observeSkinmaskInferLatency({ latencyMs: inferLatencyMs });
    const fallbackReason = normalizeSkinmaskFallbackReason(error && error.code ? error.code : null, error && error.message);
    recordSkinmaskFallback({ reason: fallbackReason });
    return maybeBuildFallback({
      fallbackReason,
      reason: error && error.code ? String(error.code) : 'unknown',
      detail: error && error.message ? error.message : String(error),
      message: 'aurora bff: skinmask onnx inference failed',
      onnxInferMs: inferLatencyMs,
      skinmaskModelLoaded: fallbackReason !== 'MODEL_MISSING',
    });
  }
}

async function buildAutoAnalysisFromConfirmedPhoto({ req, ctx, photoId, slotId, qcStatus, logger, identity } = {}) {
  if (!PHOTO_AUTO_ANALYZE_AFTER_CONFIRM) return null;
  if (!photoId || !isPassedPhotoQcStatus(qcStatus)) return null;

  const language = ctx && ctx.lang === 'CN' ? 'CN' : 'EN';
  const slot = String(slotId || 'daylight').trim() || 'daylight';
  const qc = String(qcStatus || 'passed').trim().toLowerCase() || 'passed';

  let profile = null;
  let recentLogs = [];
  let resolvedIdentity = identity || null;
  try {
    resolvedIdentity = resolvedIdentity || (await resolveIdentity(req, ctx));
    profile = await getProfileForIdentity({ auroraUid: resolvedIdentity.auroraUid, userId: resolvedIdentity.userId });
    recentLogs = await getRecentSkinLogsForIdentity({ auroraUid: resolvedIdentity.auroraUid, userId: resolvedIdentity.userId }, 7);
  } catch (err) {
    logger?.warn({ err: err && err.message ? err.message : String(err) }, 'aurora bff: auto analysis failed to load memory context');
  }

  const profileSummary = summarizeProfileForContext(profile);
  const recentLogsSummary = Array.isArray(recentLogs) ? recentLogs.slice(0, 7) : [];
  const routineCandidate = profileSummary && profileSummary.currentRoutine;
  const hasPrimaryInput = hasNonEmptyRoutineInput(routineCandidate) || recentLogsSummary.length > 0;
  const detectorConfidence = inferDetectorConfidence({ profileSummary, recentLogsSummary, routineCandidate });
  const photoQuality = classifyPhotoQuality([{ slot_id: slot, photo_id: photoId, qc_status: qc }]);

  const fieldMissing = [];
  const qualityReasons = [];

  let usedPhotos = false;
  let analysisSource = hasPrimaryInput ? 'rule_based_with_photo_qc' : 'baseline_low_confidence';
  let diagnosisV1 = null;
  let diagnosisV1Internal = null;
  let diagnosisPhotoBytes = null;
  let analysis = null;
  let photoNotice = null;

  try {
    const photoResp = await fetchPhotoBytesFromPivotaBackend({ req, photoId });
    if (photoResp && photoResp.ok && photoResp.buffer && Buffer.isBuffer(photoResp.buffer) && photoResp.buffer.length > 0) {
      diagnosisPhotoBytes = photoResp.buffer;
      const profiler = createStageProfiler();
      const diag = await runSkinDiagnosisV1({
        imageBuffer: diagnosisPhotoBytes,
        language,
        profileSummary,
        recentLogsSummary,
        profiler,
      });
      if (diag && diag.ok && diag.diagnosis) {
        diagnosisV1 = diag.diagnosis;
        diagnosisV1Internal = diag.internal || null;
        usedPhotos = true;
        const qGrade = String(diagnosisV1?.quality?.grade || '').trim().toLowerCase();
        if (qGrade === 'fail') {
          analysis = buildRetakeSkinAnalysis({ language, photoQuality: diagnosisV1.quality || photoQuality });
          analysisSource = 'retake';
          qualityReasons.push(
            language === 'CN'
              ? '已读取照片，但像素质量不足；建议重拍并复核。'
              : 'Photo was read, but pixel quality is insufficient; please retake and recheck.',
          );
        } else {
          analysis = buildSkinAnalysisFromDiagnosisV1(diagnosisV1, { language, profileSummary });
          analysisSource = 'diagnosis_v1_template';
        }
        if (qGrade === 'degraded') {
          qualityReasons.push(
            language === 'CN'
              ? '已完成照片分析（质量一般）：结论会更保守。'
              : 'Photo analysis completed (degraded quality): conclusions are conservative.',
          );
        } else if (qGrade !== 'fail') {
          qualityReasons.push(language === 'CN' ? '已基于照片完成自动皮肤分析。' : 'Auto skin analysis completed from your photo.');
        }
      } else {
        const failureCode = 'diagnosis_failed';
        fieldMissing.push({ field: 'analysis.used_photos', reason: failureCode });
        photoNotice = {
          failure_code: failureCode,
          message: buildPhotoAutoNoticeMessage({ language, failureCode }),
        };
        qualityReasons.push(
          language === 'CN'
            ? '照片读取成功，但分析模块未稳定完成；已退回问卷/历史基线。'
            : 'Photo bytes were loaded, but diagnosis did not complete reliably; fell back to answers/history baseline.',
        );
      }
    } else {
      const failureCode = String(photoResp && (photoResp.failure_code || photoResp.reason) ? photoResp.failure_code || photoResp.reason : 'DOWNLOAD_URL_GENERATE_FAILED')
        .trim()
        .toUpperCase();
      fieldMissing.push({ field: 'analysis.used_photos', reason: failureCode });
      photoNotice = {
        failure_code: failureCode,
        message: buildPhotoAutoNoticeMessage({ language, failureCode }),
      };
      qualityReasons.push(language === 'CN' ? `照片读取失败（${failureCode}）。` : `Photo fetch failed (${failureCode}).`);
    }
  } catch (err) {
    const failureCode = 'DOWNLOAD_URL_FETCH_5XX';
    fieldMissing.push({ field: 'analysis.used_photos', reason: failureCode });
    photoNotice = {
      failure_code: failureCode,
      message: buildPhotoAutoNoticeMessage({ language, failureCode }),
    };
    qualityReasons.push(language === 'CN' ? `照片读取异常（${failureCode}）。` : `Photo fetch error (${failureCode}).`);
    logger?.warn(
      { err: err && err.message ? err.message : String(err) },
      'aurora bff: auto analysis photo fetch failed',
    );
  }

  if (!analysis) {
    if (hasPrimaryInput) {
      analysis = buildRuleBasedSkinAnalysis({ profile: profileSummary || profile, recentLogs, language });
      analysisSource = 'rule_based_with_photo_qc';
    } else {
      fieldMissing.push({ field: 'analysis.used_photos', reason: 'routine_or_recent_logs_required' });
      qualityReasons.push(
        language === 'CN'
          ? '缺少“正在用什么/最近打卡”等关键信息；先返回低风险基线。'
          : 'Routine/recent logs are missing; returning a low-risk baseline first.',
      );
      analysis = buildLowConfidenceBaselineSkinAnalysis({ profile: profileSummary || profile, language });
      analysisSource = 'baseline_low_confidence';
    }
  }

  if (analysis && diagnosisV1 && usedPhotos) {
    analysis = mergePhotoFindingsIntoAnalysis({
      analysis,
      diagnosisV1,
      language,
      profileSummary,
    });
  }

  analysis = buildExecutablePlanForAnalysis({
    analysis,
    language,
    usedPhotos,
    photoQuality: diagnosisV1 && diagnosisV1.quality ? diagnosisV1.quality : photoQuality,
    profileSummary,
    photoNoticeOverride: photoNotice && typeof photoNotice.message === 'string' ? photoNotice.message : '',
    photoFailureCode: photoNotice && typeof photoNotice.failure_code === 'string' ? photoNotice.failure_code : '',
    photosProvided: true,
  });
  analysis = attachRoutineExpertToAnalysis({
    analysis,
    routineCandidate,
    profileSummary,
    recentLogs: recentLogsSummary,
    language,
  });
  const geometrySanitizer =
    analysis && analysis.__geometry_sanitizer && typeof analysis.__geometry_sanitizer === 'object'
      ? analysis.__geometry_sanitizer
      : null;
  if (analysis && Object.prototype.hasOwnProperty.call(analysis, '__geometry_sanitizer')) {
    delete analysis.__geometry_sanitizer;
  }

  const qualityGradeForMetrics = normalizeQualityGradeForMetrics(diagnosisV1?.quality?.grade || photoQuality?.grade);
  const pipelineVersionForMetrics = normalizePipelineVersionForMetrics(String(process.env.DIAG_PIPELINE_VERSION || 'legacy'));
  const deviceClassForMetrics = inferDeviceClassForMetrics(req);
  const sanitizerTotals = geometrySanitizer || { checked_n: 0, dropped_n: 0, clipped_n: 0 };
  recordAnalyzeRequest({
    issueType: 'all',
    qualityGrade: qualityGradeForMetrics,
    pipelineVersion: pipelineVersionForMetrics,
    deviceClass: deviceClassForMetrics,
  });
  recordGeometrySanitizerTotals({
    issueType: 'all',
    qualityGrade: qualityGradeForMetrics,
    pipelineVersion: pipelineVersionForMetrics,
    deviceClass: deviceClassForMetrics,
    dropped: sanitizerTotals.dropped_n,
    clipped: sanitizerTotals.clipped_n,
  });
  const sanitizerByIssue =
    geometrySanitizer && geometrySanitizer.by_issue && typeof geometrySanitizer.by_issue === 'object'
      ? geometrySanitizer.by_issue
      : {};
  for (const [issueType, issueStatsRaw] of Object.entries(sanitizerByIssue)) {
    const issueStats = issueStatsRaw && typeof issueStatsRaw === 'object' ? issueStatsRaw : {};
    const checkedN = Number(issueStats.checked_n || 0);
    if (checkedN <= 0) continue;
    recordAnalyzeRequest({
      issueType,
      qualityGrade: qualityGradeForMetrics,
      pipelineVersion: pipelineVersionForMetrics,
      deviceClass: deviceClassForMetrics,
    });
    recordGeometrySanitizerTotals({
      issueType,
      qualityGrade: qualityGradeForMetrics,
      pipelineVersion: pipelineVersionForMetrics,
      deviceClass: deviceClassForMetrics,
      dropped: issueStats.dropped_n,
      clipped: issueStats.clipped_n,
    });
  }

  const effectivePhotoQuality = {
    grade: String(diagnosisV1?.quality?.grade || photoQuality?.grade || 'unknown').toLowerCase(),
    reasons:
      Array.isArray(diagnosisV1?.quality?.reasons) && diagnosisV1.quality.reasons.length
        ? diagnosisV1.quality.reasons
        : Array.isArray(photoQuality?.reasons)
          ? photoQuality.reasons
          : [],
    metrics: diagnosisV1?.quality?.metrics || photoQuality?.metrics || {},
  };
  const qualityObj = buildQualityObject(effectivePhotoQuality);

  const cappedAnalysis = analysis ? applyConfidenceCaps(analysis, qualityObj.grade) : analysis;
  const dedupedAnalysis = cappedAnalysis ? dedupeAndCapOutput(cappedAnalysis) : cappedAnalysis;
  let enrichedAnalysis = dedupedAnalysis ? {
    ...dedupedAnalysis,
    quality: qualityObj,
    findings: Array.isArray(dedupedAnalysis.findings) ? dedupedAnalysis.findings : [],
    guidance_brief: Array.isArray(dedupedAnalysis.guidance_brief) ? dedupedAnalysis.guidance_brief : [],
    insufficient_visual_detail: Boolean(dedupedAnalysis.insufficient_visual_detail) || detectInsufficientVisualDetail(Array.isArray(dedupedAnalysis.findings) ? dedupedAnalysis.findings : []),
  } : dedupedAnalysis;
  if (analysisSource === 'retake') {
    enrichedAnalysis = ensureRetakeFeatureObservation(enrichedAnalysis, { language });
  }

  const payload = {
    analysis: enrichedAnalysis,
    low_confidence: analysisSource === 'baseline_low_confidence',
    photos_provided: true,
    photo_qc: [`${slot}:${qc}`],
    used_photos: usedPhotos,
    analysis_source: !usedPhotos && analysisSource !== 'retake' ? 'rule_based_with_photo_qc' : analysisSource,
    ...(photoNotice ? { photo_notice: photoNotice } : {}),
    quality_report: {
      photo_quality: { grade: effectivePhotoQuality.grade, reasons: effectivePhotoQuality.reasons },
      detector_confidence: detectorConfidence,
      degraded_mode: SKIN_DEGRADED_MODE,
      llm: {
        vision: { decision: 'skip', reasons: ['auto_analysis_diagnosis_v1_only'], downgrade_confidence: false },
        report: { decision: 'skip', reasons: ['auto_analysis_diagnosis_v1_only'], downgrade_confidence: false },
      },
      reasons: qualityReasons.slice(0, 8),
    },
  };

  const photoModulesSkinMask = await maybeInferSkinMaskForPhotoModules({
    imageBuffer: diagnosisPhotoBytes,
    diagnosisInternal: diagnosisV1Internal,
    logger,
    requestId: ctx.request_id,
  });

  let photoModulesCard = maybeBuildPhotoModulesCardForAnalysis({
    requestId: ctx.request_id,
    analysis,
    usedPhotos,
    photoQuality: diagnosisV1 && diagnosisV1.quality ? diagnosisV1.quality : photoQuality,
    photoNotice,
    diagnosisInternal: diagnosisV1Internal,
    sourcePhoto: { slot_id: slot, photo_id: photoId },
    profileSummary,
    language,
    skinMask: photoModulesSkinMask,
  });
  if (photoModulesCard) {
    photoModulesCard = await enrichPhotoModulesCardWithIngredientProductsBounded({
      photoModulesCard,
      profileSummary,
      language,
      logger,
    });
  }

  const cards = [
    {
      card_id: `analysis_${ctx.request_id}`,
      type: 'analysis_summary',
      payload,
      ...(fieldMissing.length ? { field_missing: fieldMissing } : {}),
    },
    ...(photoModulesCard ? [photoModulesCard] : []),
  ];

  return {
    cards,
    session_patch: { next_state: 'S5_ANALYSIS_SUMMARY' },
    event: makeEvent(ctx, 'value_moment', {
      kind: 'skin_analysis',
      used_photos: usedPhotos,
      analysis_source: payload.analysis_source,
      source: 'photo_auto',
    }),
  };
}

async function safeBuildAutoAnalysisFromConfirmedPhoto({ req, ctx, photoId, slotId, qcStatus, logger, identity } = {}) {
  try {
    return await buildAutoAnalysisFromConfirmedPhoto({ req, ctx, photoId, slotId, qcStatus, logger, identity });
  } catch (err) {
    const message = err && err.message ? err.message : String(err);
    const code = err && err.code ? String(err.code) : 'PHOTO_AUTO_ANALYSIS_FAILED';
    logger?.error(
      {
        err: message,
        code,
        request_id: ctx && ctx.request_id ? ctx.request_id : null,
        trace_id: ctx && ctx.trace_id ? ctx.trace_id : null,
        aurora_uid: ctx && ctx.aurora_uid ? ctx.aurora_uid : null,
        photo_id: photoId || null,
        slot_id: slotId || null,
      },
      'aurora bff: auto analysis failed unexpectedly; returning photo_confirm only',
    );
    return {
      cards: [],
      session_patch: {},
      event: makeEvent(ctx, 'error', { code }),
    };
  }
}

async function runOpenAIVisionSkinAnalysis({
  imageBuffer,
  language,
  photoQuality,
  diagnosisPolicy,
  diagnosisV1,
  profileSummary,
  recentLogsSummary,
  profiler,
  promptVersion,
} = {}) {
  const startedAt = Date.now();
  if (!SKIN_VISION_ENABLED) {
    return {
      ok: false,
      provider: 'openai',
      reason: VisionUnavailabilityReason.VISION_DISABLED_BY_FLAG,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: { attempted: 0, final: 'fail', last_reason: VisionUnavailabilityReason.VISION_DISABLED_BY_FLAG },
    };
  }
  const client = getOpenAIClient();
  if (!client) {
    return {
      ok: false,
      provider: 'openai',
      reason: VisionUnavailabilityReason.VISION_MISSING_KEY,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: { attempted: 0, final: 'fail', last_reason: VisionUnavailabilityReason.VISION_MISSING_KEY },
    };
  }
  if (!imageBuffer || !Buffer.isBuffer(imageBuffer) || !imageBuffer.length) {
    return {
      ok: false,
      provider: 'openai',
      reason: VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: { attempted: 0, final: 'fail', last_reason: VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED },
    };
  }

  const optimized =
    profiler && typeof profiler.time === 'function'
      ? await profiler.time(
          'decode',
          async () =>
            sharp(imageBuffer)
              .rotate()
              .resize({ width: 1024, height: 1024, fit: 'inside', withoutEnlargement: true })
              .jpeg({ quality: 82 })
              .toBuffer(),
          { kind: 'vision_prepare' },
        )
      : await sharp(imageBuffer)
          .rotate()
          .resize({ width: 1024, height: 1024, fit: 'inside', withoutEnlargement: true })
          .jpeg({ quality: 82 })
          .toBuffer();
  const dataUrl = `data:image/jpeg;base64,${optimized.toString('base64')}`;

  const promptBase = buildSkinVisionPrompt({
    language,
    photoQuality,
    diagnosisPolicy,
    diagnosisV1,
    profileSummary,
    recentLogsSummary,
    promptVersion,
  });

  const attemptResult = await executeVisionWithRetry({
    maxRetries: SKIN_VISION_RETRY_MAX,
    baseDelayMs: SKIN_VISION_RETRY_BASE_MS,
    classifyError: classifyVisionProviderFailure,
    operation: async () => {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), SKIN_VISION_TIMEOUT_MS);
      try {
        const callOpenAI = async () =>
          client.chat.completions.create(
            {
              model: SKIN_VISION_MODEL_OPENAI,
              temperature: 0.2,
              max_tokens: 480,
              response_format: { type: 'json_object' },
              messages: [
                { role: 'system', content: 'You are an objective and conservative cosmetic skincare assistant.' },
                {
                  role: 'user',
                  content: [
                    {
                      type: 'text',
                      text: promptBase,
                    },
                    { type: 'image_url', image_url: { url: dataUrl } },
                  ],
                },
              ],
            },
            { signal: controller.signal },
          );

        const resp =
          profiler && typeof profiler.timeLlmCall === 'function'
            ? await profiler.timeLlmCall({ provider: 'openai', model: SKIN_VISION_MODEL_OPENAI, kind: 'skin_vision' }, callOpenAI)
            : await callOpenAI();

        const content = resp && resp.choices && resp.choices[0] && resp.choices[0].message ? resp.choices[0].message.content : '';
        const jsonOnly = unwrapCodeFence(content);
        const parsedObj = parseJsonOnlyObject(jsonOnly);
        const analysis = normalizeSkinAnalysisFromLLM(parsedObj, { language });
        if (!analysis) {
          const schemaErr = new Error('vision schema invalid');
          schemaErr.__vision_reason = VisionUnavailabilityReason.VISION_SCHEMA_INVALID;
          throw schemaErr;
        }
        return { analysis };
      } finally {
        clearTimeout(timer);
      }
    },
  });

  if (attemptResult && attemptResult.ok && attemptResult.result && attemptResult.result.analysis) {
    return {
      ok: true,
      provider: 'openai',
      analysis: attemptResult.result.analysis,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: attemptResult.retry,
    };
  }

  return {
    ok: false,
    provider: 'openai',
    reason: normalizeVisionReason(attemptResult && attemptResult.reason),
    upstream_status_code: toNullableInt(attemptResult && attemptResult.upstream_status_code),
    error: attemptResult && attemptResult.error_code ? String(attemptResult.error_code) : null,
    latency_ms: Date.now() - startedAt,
    retry:
      (attemptResult && attemptResult.retry) ||
      { attempted: 0, final: 'fail', last_reason: normalizeVisionReason(attemptResult && attemptResult.reason) },
  };
}

async function runGeminiVisionSkinAnalysis({
  imageBuffer,
  language,
  photoQuality,
  diagnosisPolicy,
  diagnosisV1,
  profileSummary,
  recentLogsSummary,
  profiler,
  promptVersion,
} = {}) {
  const startedAt = Date.now();
  if (!SKIN_VISION_ENABLED) {
    return {
      ok: false,
      provider: 'gemini',
      reason: VisionUnavailabilityReason.VISION_DISABLED_BY_FLAG,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: { attempted: 0, final: 'fail', last_reason: VisionUnavailabilityReason.VISION_DISABLED_BY_FLAG },
    };
  }

  const gemini = getGeminiClient();
  if (!gemini || !gemini.client) {
    const reason =
      gemini && gemini.init_error ? normalizeVisionReason(gemini.init_error) : VisionUnavailabilityReason.VISION_MISSING_KEY;
    return {
      ok: false,
      provider: 'gemini',
      reason,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: { attempted: 0, final: 'fail', last_reason: reason },
    };
  }

  if (!imageBuffer || !Buffer.isBuffer(imageBuffer) || !imageBuffer.length) {
    return {
      ok: false,
      provider: 'gemini',
      reason: VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: { attempted: 0, final: 'fail', last_reason: VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED },
    };
  }

  const optimized =
    profiler && typeof profiler.time === 'function'
      ? await profiler.time(
          'decode',
          async () =>
            sharp(imageBuffer)
              .rotate()
              .resize({ width: 1024, height: 1024, fit: 'inside', withoutEnlargement: true })
              .jpeg({ quality: 82 })
              .toBuffer(),
          { kind: 'vision_prepare' },
        )
      : await sharp(imageBuffer)
          .rotate()
          .resize({ width: 1024, height: 1024, fit: 'inside', withoutEnlargement: true })
          .jpeg({ quality: 82 })
          .toBuffer();

  const promptBase = buildSkinVisionPrompt({
    language,
    photoQuality,
    diagnosisPolicy,
    diagnosisV1,
    profileSummary,
    recentLogsSummary,
    promptVersion,
  });

  const attemptResult = await executeVisionWithRetry({
    maxRetries: SKIN_VISION_RETRY_MAX,
    baseDelayMs: SKIN_VISION_RETRY_BASE_MS,
    classifyError: classifyVisionProviderFailure,
    operation: async () => {
      const callGemini = async () =>
        withVisionTimeout(
          callAuroraGeminiGenerateContent({
            featureEnvVar: AURORA_GEMINI_KEY_FEATURE_ENV,
            route: 'aurora_routes_vision',
            request: {
            model: SKIN_VISION_MODEL_GEMINI,
            contents: [
              {
                role: 'user',
                parts: [
                  {
                    inlineData: {
                      mimeType: 'image/jpeg',
                      data: optimized.toString('base64'),
                    },
                  },
                  {
                    text: promptBase,
                  },
                ],
              },
            ],
            config: {
              temperature: 0.2,
              responseMimeType: 'application/json',
            },
            },
          }),
          SKIN_VISION_TIMEOUT_MS,
        );

      const resp =
        profiler && typeof profiler.timeLlmCall === 'function'
          ? await profiler.timeLlmCall({ provider: 'gemini', model: SKIN_VISION_MODEL_GEMINI, kind: 'skin_vision' }, callGemini)
          : await callGemini();

      const content = await extractTextFromGeminiResponse(resp);
      const jsonOnly = unwrapCodeFence(content);
      const parsedObj = parseJsonOnlyObject(jsonOnly);
      const analysis = normalizeSkinAnalysisFromLLM(parsedObj, { language });
      if (!analysis) {
        const schemaErr = new Error('vision schema invalid');
        schemaErr.__vision_reason = VisionUnavailabilityReason.VISION_SCHEMA_INVALID;
        throw schemaErr;
      }
      return { analysis };
    },
  });

  if (attemptResult && attemptResult.ok && attemptResult.result && attemptResult.result.analysis) {
    return {
      ok: true,
      provider: 'gemini',
      analysis: attemptResult.result.analysis,
      upstream_status_code: null,
      latency_ms: Date.now() - startedAt,
      retry: attemptResult.retry,
    };
  }

  return {
    ok: false,
    provider: 'gemini',
    reason: normalizeVisionReason(attemptResult && attemptResult.reason),
    upstream_status_code: toNullableInt(attemptResult && attemptResult.upstream_status_code),
    error: attemptResult && attemptResult.error_code ? String(attemptResult.error_code) : null,
    latency_ms: Date.now() - startedAt,
    retry:
      (attemptResult && attemptResult.retry) ||
      { attempted: 0, final: 'fail', last_reason: normalizeVisionReason(attemptResult && attemptResult.reason) },
  };
}

let runGeminiVisionSkinAnalysisImpl = runGeminiVisionSkinAnalysis;
let runOpenAIVisionSkinAnalysisImpl = runOpenAIVisionSkinAnalysis;
let runGeminiVisionStrategyImpl = runGeminiVisionStrategy;
let runGeminiReportStrategyImpl = runGeminiReportStrategy;
let runGeminiDeepeningStrategyImpl = runGeminiDeepeningStrategy;

function classifyAuroraOptionalStepError(err) {
  const raw =
    (err && (err.code || err.reason || err.name || err.message)) ||
    'unknown_optional_step_error';
  const normalized = String(raw)
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return normalized || 'unknown_optional_step_error';
}

async function executeAuroraOptionalStep({
  logger,
  route,
  stepId,
  criticality = 'optional',
  metricStage = null,
  fn,
} = {}) {
  if (typeof fn !== 'function') {
    throw new Error('executeAuroraOptionalStep requires a function');
  }
  try {
    const value = await fn();
    if (metricStage) recordAuroraSkinFlowMetric({ stage: metricStage, outcome: 'hit' });
    return {
      ok: true,
      value,
      fallback_applied: false,
      error_class: null,
      error: null,
    };
  } catch (err) {
    const errorClass = classifyAuroraOptionalStepError(err);
    if (metricStage) recordAuroraSkinFlowMetric({ stage: metricStage, outcome: 'miss' });
    logger?.warn(
      {
        route: route || null,
        step_id: String(stepId || 'unknown_optional_step'),
        criticality,
        fallback_applied: true,
        error_class: errorClass,
        err: err && err.message ? err.message : String(err),
        code: err && err.code ? String(err.code) : null,
      },
      'aurora bff: optional step failed',
    );
    return {
      ok: false,
      value: null,
      fallback_applied: true,
      error_class: errorClass,
      error: err,
    };
  }
}

function shouldAttemptOpenAiFallbackFromGemini({ photoQuality, llmKillSwitch } = {}) {
  if (AURORA_DIAG_FORCE_GEMINI) return false;
  if (llmKillSwitch) return false;
  const grade = String(photoQuality && photoQuality.grade ? photoQuality.grade : '')
    .trim()
    .toLowerCase();
  if (grade === 'fail') return false;
  return true;
}

async function runVisionSkinAnalysis({ provider, llmKillSwitch, photoQuality, ...rest } = {}) {
  const target = String(provider || 'gemini')
    .trim()
    .toLowerCase();
  if (target === 'gemini') {
    const gemini = await runGeminiVisionSkinAnalysisImpl({ photoQuality, ...rest });
    if (gemini && gemini.ok) {
      return {
        ...gemini,
        attempted_providers: ['gemini'],
      };
    }
    if (shouldAttemptOpenAiFallbackFromGemini({ photoQuality, llmKillSwitch })) {
      const openai = await runOpenAIVisionSkinAnalysisImpl({ photoQuality, ...rest });
      if (openai && openai.ok) {
        return {
          ...openai,
          fallback_from: 'gemini',
          primary_failure_reason: normalizeVisionReason(gemini && gemini.reason),
          attempted_providers: ['gemini', 'openai'],
        };
      }
      return {
        ...(openai || {}),
        ok: false,
        provider: 'openai',
        reason: normalizeVisionReason((openai && openai.reason) || (gemini && gemini.reason)),
        fallback_from: 'gemini',
        primary_failure_reason: normalizeVisionReason(gemini && gemini.reason),
        attempted_providers: ['gemini', 'openai'],
      };
    }
    return {
      ...gemini,
      attempted_providers: ['gemini'],
    };
  }
  const openai = await runOpenAIVisionSkinAnalysisImpl({ photoQuality, ...rest });
  return {
    ...openai,
    attempted_providers: ['openai'],
  };
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function toNullableInt(value) {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  if (num <= 0) return null;
  return Math.trunc(num);
}

function toNullableNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  return num;
}

function secondsUntilIso(iso) {
  if (!iso || typeof iso !== 'string') return null;
  const ms = Date.parse(iso);
  if (!Number.isFinite(ms)) return null;
  return Math.max(0, Math.round((ms - Date.now()) / 1000));
}

function pickUpstreamErrorDetail(data) {
  if (!data) return null;
  if (typeof data === 'string') return data;
  if (data.detail) return data.detail;
  if (data.error) return data.error;
  if (data.message) return data.message;
  return null;
}

function normalizeSkinAnalysisFromLLM(obj, { language } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const o = obj && typeof obj === 'object' && !Array.isArray(obj) ? obj : null;
  if (!o) return null;

  const forbiddenRegex =
    lang === 'CN'
      ? /玫瑰痤疮|湿疹|银屑病|皮炎|感染|抗生素|激素|氢化可的松|维A酸|异维A酸|阿达帕林|克林霉素|多西环素|甲硝唑/i
      : /rosacea|eczema|psoriasis|dermatitis|melanoma|infection|antibiotic|steroid|hydrocortisone|tretinoin|adapalene|isotretinoin|accutane|clindamycin|doxycycline|metronidazole/i;

  function clampText(raw, maxLen) {
    const s = typeof raw === 'string' ? raw.trim() : '';
    if (!s) return '';
    if (s.length <= maxLen) return s;
    return `${s.slice(0, Math.max(0, maxLen - 1))}…`;
  }

  const featuresRaw = Array.isArray(o.features) ? o.features : [];
  const features = [];
  for (const raw of featuresRaw) {
    const f = raw && typeof raw === 'object' && !Array.isArray(raw) ? raw : null;
    if (!f) continue;
    const observation = clampText(f.observation, 120);
    if (!observation) continue;
    if (forbiddenRegex.test(observation)) return null;
    const c = typeof f.confidence === 'string' ? f.confidence.trim() : '';
    const confidence = c === 'pretty_sure' || c === 'somewhat_sure' || c === 'not_sure' ? c : 'somewhat_sure';
    features.push({ observation, confidence });
  }

  const normalizeStringArray = (value, maxItems = 3, maxLen = 180) => {
    if (!Array.isArray(value)) return [];
    const out = [];
    for (const item of value) {
      const s = clampText(item, maxLen);
      if (!s) continue;
      if (forbiddenRegex.test(s)) return [];
      if (out.includes(s)) continue;
      out.push(s);
      if (out.length >= maxItems) break;
    }
    return out;
  };

  let strategyRaw = clampText(o.strategy, 700);
  const needsRiskCheckRaw = o.needs_risk_check ?? o.needsRiskCheck;
  const needs_risk_check = typeof needsRiskCheckRaw === 'boolean' ? needsRiskCheckRaw : false;
  if (strategyRaw && forbiddenRegex.test(strategyRaw)) return null;

  const fallbackStrategy =
    lang === 'CN'
      ? 'AM: 温和清洁+保湿+防晒。PM: 温和清洁+保湿。若出现持续刺激，立即简化护理并暂停新增活性。'
      : 'AM: gentle cleanse + moisturizer + sunscreen. PM: gentle cleanse + moisturizer. If irritation persists, simplify and pause new actives.';
  const strategy = strategyRaw || fallbackStrategy;

  if (features.length < 2 && !strategyRaw) return null;

  const ask3Raw = normalizeStringArray(o.ask_3_questions ?? o.ask3Questions ?? o.followup_questions, 3, 140);
  const primaryQuestionRaw = clampText(o.primary_question ?? o.primaryQuestion, 140);
  const primary_question =
    primaryQuestionRaw && !forbiddenRegex.test(primaryQuestionRaw)
      ? primaryQuestionRaw
      : ask3Raw[0] ||
        (lang === 'CN' ? '你最近是否有刺痛/泛红？' : 'Have you noticed stinging or redness recently?');
  const conditional_followups = normalizeStringArray(o.conditional_followups ?? o.conditionalFollowups, 2, 140).filter(
    (line) => line !== primary_question,
  );
  const ask_3_questions = [];
  for (const q of [primary_question, ...conditional_followups, ...ask3Raw]) {
    if (!q || ask_3_questions.includes(q)) continue;
    ask_3_questions.push(q);
    if (ask_3_questions.length >= 3) break;
  }

  return {
    features: features.slice(0, 6),
    strategy,
    needs_risk_check,
    ...(ask_3_questions.length ? { ask_3_questions } : {}),
    ...(primary_question ? { primary_question } : {}),
    ...(conditional_followups.length ? { conditional_followups } : {}),
  };
}

function mergePhotoFindingsIntoAnalysis({ analysis, diagnosisV1, language, profileSummary } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const base = analysis && typeof analysis === 'object' && !Array.isArray(analysis) ? { ...analysis } : null;
  if (!base) return analysis;
  const diagnosis = diagnosisV1 && typeof diagnosisV1 === 'object' && !Array.isArray(diagnosisV1) ? diagnosisV1 : null;
  if (!diagnosis) return base;

  const normalizeFinding = (raw) => {
    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
    const issueType = typeof raw.issue_type === 'string' ? raw.issue_type.trim() : '';
    const subtype = typeof raw.subtype === 'string' ? raw.subtype.trim() : '';
    if (!issueType) return null;
    const severity = Number.isFinite(raw.severity) ? Math.max(0, Math.min(4, Math.round(raw.severity))) : 0;
    const confidence = Number.isFinite(raw.confidence) ? Math.max(0, Math.min(1, Number(raw.confidence))) : 0;
    return {
      issue_type: issueType,
      subtype: subtype || null,
      severity,
      confidence,
      evidence: typeof raw.evidence === 'string' ? raw.evidence.trim() : '',
      computed_features: raw.computed_features && typeof raw.computed_features === 'object' ? raw.computed_features : {},
      geometry: raw.geometry && typeof raw.geometry === 'object' ? raw.geometry : null,
      ...(raw.uncertain === true ? { uncertain: true } : {}),
    };
  };

  const normalizeTakeaway = (raw) => {
    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
    const source = typeof raw.source === 'string' && raw.source.trim() ? raw.source.trim() : 'mixed';
    const textRaw = typeof raw.text === 'string' ? raw.text.trim() : '';
    if (!textRaw) return null;
    const text =
      source === 'photo' && !/^from photo:/i.test(textRaw)
        ? `${lang === 'CN' ? 'From photo: ' : 'From photo: '}${textRaw}`
        : textRaw;
    return {
      source,
      issue_type: typeof raw.issue_type === 'string' && raw.issue_type.trim() ? raw.issue_type.trim() : null,
      text,
      confidence: Number.isFinite(raw.confidence) ? Math.max(0, Math.min(1, Number(raw.confidence))) : 0.5,
    };
  };

  const incomingFindings = [];
  for (const finding of Array.isArray(diagnosis.photo_findings) ? diagnosis.photo_findings : []) {
    const normalized = normalizeFinding(finding);
    if (normalized) incomingFindings.push(normalized);
  }

  const existingFindings = [];
  const existingFromPhoto = Array.isArray(base.photo_findings) ? base.photo_findings : [];
  const existingFromFindings = Array.isArray(base.findings) ? base.findings : [];
  for (const finding of [...existingFromPhoto, ...existingFromFindings]) {
    const normalized = normalizeFinding(finding);
    if (normalized) existingFindings.push(normalized);
  }

  const mergedFindings = [];
  const findingSeen = new Set();
  for (const finding of [...existingFindings, ...incomingFindings]) {
    const key = `${finding.issue_type}::${finding.subtype || ''}`;
    if (findingSeen.has(key)) continue;
    findingSeen.add(key);
    mergedFindings.push(finding);
  }

  if (mergedFindings.length) {
    base.photo_findings = mergedFindings.slice(0, 10);
    base.findings = mergedFindings.slice(0, 10);
  }

  const existingTakeaways = Array.isArray(base.takeaways) ? base.takeaways : [];
  const diagnosisTakeaways = Array.isArray(diagnosis.takeaways) ? diagnosis.takeaways : [];
  const mergedTakeaways = [];
  const takeawaySeen = new Set();

  const addTakeaway = (candidate) => {
    const normalized = normalizeTakeaway(candidate);
    if (!normalized) return;
    const key = `${normalized.source}::${normalized.text.toLowerCase()}`;
    if (takeawaySeen.has(key)) return;
    takeawaySeen.add(key);
    mergedTakeaways.push(normalized);
  };

  for (const takeaway of existingTakeaways) addTakeaway(takeaway);
  for (const takeaway of diagnosisTakeaways) addTakeaway(takeaway);

  const goals = profileSummary && Array.isArray(profileSummary.goals) ? profileSummary.goals.filter((item) => typeof item === 'string') : [];
  if (goals.length) {
    addTakeaway({
      source: 'user',
      issue_type: 'goal',
      text: lang === 'CN' ? `You mentioned your goals: ${goals.slice(0, 3).join(', ')}.` : `You mentioned your goals: ${goals.slice(0, 3).join(', ')}.`,
      confidence: 1,
    });
  }

  if (mergedTakeaways.length) base.takeaways = mergedTakeaways.slice(0, 12);
  return base;
}

function normalizePlanTakeaway(raw, { language } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
  const sourceRaw = typeof raw.source === 'string' ? raw.source.trim().toLowerCase() : '';
  const source = sourceRaw === 'photo' || sourceRaw === 'user' || sourceRaw === 'mixed' ? sourceRaw : 'mixed';
  let text = typeof raw.text === 'string' ? raw.text.trim() : '';
  if (!text) return null;
  if (source === 'photo' && !/^from photo:/i.test(text)) text = `${lang === 'CN' ? 'From photo: ' : 'From photo: '}${text}`;
  if (source === 'user' && /^you reported/i.test(text)) text = text.replace(/^you reported/i, 'You mentioned');
  return {
    takeaway_id: typeof raw.takeaway_id === 'string' && raw.takeaway_id.trim() ? raw.takeaway_id.trim() : null,
    source,
    issue_type: typeof raw.issue_type === 'string' && raw.issue_type.trim() ? raw.issue_type.trim() : null,
    text,
    confidence: Number.isFinite(raw.confidence) ? Math.max(0, Math.min(1, Number(raw.confidence))) : 0.55,
    linked_finding_ids: Array.isArray(raw.linked_finding_ids)
      ? raw.linked_finding_ids.filter((item) => typeof item === 'string' && item.trim()).slice(0, 8)
      : [],
    linked_issue_types: Array.isArray(raw.linked_issue_types)
      ? raw.linked_issue_types.filter((item) => typeof item === 'string' && item.trim()).slice(0, 8)
      : [],
  };
}

function renderPlanAsStrategy({ plan, language, photoNotice } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  if (!plan || typeof plan !== 'object') return '';
  const getWhat = (step) => (step && typeof step.what === 'string' ? step.what.trim() : '');
  const am = Array.isArray(plan?.today?.am_steps) ? plan.today.am_steps.map(getWhat).filter(Boolean) : [];
  const pm = Array.isArray(plan?.today?.pm_steps) ? plan.today.pm_steps.map(getWhat).filter(Boolean) : [];
  const pause = Array.isArray(plan?.today?.pause_now) ? plan.today.pause_now.map(getWhat).filter(Boolean) : [];
  const rule = Array.isArray(plan?.next_7_days?.rules) ? plan.next_7_days.rules.filter((item) => typeof item === 'string' && item.trim()).slice(0, 2) : [];
  const lines = [];
  if (photoNotice) lines.push(photoNotice);
  lines.push(lang === 'CN' ? 'Today' : 'Today');
  lines.push(`${lang === 'CN' ? 'AM' : 'AM'}: ${am.length ? am.join(' -> ') : (lang === 'CN' ? '以重拍和观察为主' : 'retake + observe')}`);
  lines.push(`${lang === 'CN' ? 'PM' : 'PM'}: ${pm.length ? pm.join(' -> ') : (lang === 'CN' ? '以重拍和观察为主' : 'retake + observe')}`);
  if (pause.length) lines.push(`${lang === 'CN' ? 'Pause now' : 'Pause now'}: ${pause.join(' / ')}`);
  if (rule.length) lines.push(`${lang === 'CN' ? 'Next 7 days' : 'Next 7 days'}: ${rule.join(' | ')}`);
  const retakeDays = Number.isFinite(plan?.tracking?.retake_after_days) ? Number(plan.tracking.retake_after_days) : 7;
  lines.push(lang === 'CN' ? `Re-evaluate in ${retakeDays} days.` : `Re-evaluate in ${retakeDays} days.`);
  return lines.join('\n').slice(0, 1200);
}

function normalizePhotoFailureCodeForFallback(code) {
  const normalized = String(code || '').trim().toUpperCase();
  if (!normalized) return '';
  if (
    normalized === 'DOWNLOAD_URL_GENERATE_FAILED' ||
    normalized === 'DOWNLOAD_URL_FETCH_4XX' ||
    normalized === 'DOWNLOAD_URL_FETCH_5XX' ||
    normalized === 'DOWNLOAD_URL_TIMEOUT' ||
    normalized === 'DOWNLOAD_URL_EXPIRED' ||
    normalized === 'DOWNLOAD_URL_DNS' ||
    normalized === 'MISSING_PRIMARY_INPUT'
  ) {
    return normalized;
  }
  return '';
}

function buildPhotoFallbackActionCard({
  language,
  qualityFail,
  failureCode,
  photosProvided,
} = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const normalizedFailure = normalizePhotoFailureCodeForFallback(failureCode);
  const reasonByCodeEn = {
    DOWNLOAD_URL_GENERATE_FAILED: "We couldn't generate a secure photo download link.",
    DOWNLOAD_URL_FETCH_4XX: "Photo access was rejected while fetching bytes (4xx).",
    DOWNLOAD_URL_FETCH_5XX: 'Photo storage returned a server error while fetching bytes (5xx).',
    DOWNLOAD_URL_TIMEOUT: 'Photo download timed out before bytes were received.',
    DOWNLOAD_URL_EXPIRED: 'The signed photo link expired before analysis could start.',
    DOWNLOAD_URL_DNS: 'Photo storage host lookup failed (DNS/network resolution).',
    MISSING_PRIMARY_INPUT:
      'Routine/recent logs are missing, so this run starts from a conservative photo-first baseline before deeper personalization.',
  };
  const reasonByCodeZh = {
    DOWNLOAD_URL_GENERATE_FAILED: '系统未能生成可用的照片下载链接。',
    DOWNLOAD_URL_FETCH_4XX: '下载照片时访问被拒绝（4xx）。',
    DOWNLOAD_URL_FETCH_5XX: '下载照片时存储服务返回服务器错误（5xx）。',
    DOWNLOAD_URL_TIMEOUT: '下载照片超时，未能及时拿到图像字节。',
    DOWNLOAD_URL_EXPIRED: '签名照片链接已过期，分析前无法继续读取。',
    DOWNLOAD_URL_DNS: '照片存储域名解析失败（DNS/网络异常）。',
    MISSING_PRIMARY_INPUT: '缺少 routine/recent logs，本次先走“照片优先 + 保守基线”，再逐步个性化。',
  };

  let primaryReason = '';
  if (qualityFail) {
    primaryReason =
      lang === 'CN'
        ? '照片质量未通过（光线/清晰度/覆盖不足），本次无法做可靠的图像分析。'
        : 'Photo quality failed (lighting/focus/coverage), so image-based analysis is unavailable for this run.';
  } else if (normalizedFailure) {
    primaryReason = lang === 'CN' ? reasonByCodeZh[normalizedFailure] || '' : reasonByCodeEn[normalizedFailure] || '';
  } else if (photosProvided === false) {
    primaryReason = lang === 'CN' ? '本次没有可用照片，因此无法进行图像分析。' : 'No photo was provided in this run, so image-based analysis is unavailable.';
  } else {
    primaryReason =
      lang === 'CN'
        ? '本次未能成功读取照片字节，因此无法进行图像分析。'
        : "We couldn't read photo bytes for this run, so image-based analysis is unavailable.";
  }

  const guardrailReason =
    lang === 'CN'
      ? '为避免误导，本次结果仅基于问卷/历史信息，不会输出照片结论。'
      : 'To avoid misleading conclusions, this run is questionnaire/history-only.';

  const retakeGuide =
    lang === 'CN'
      ? [
          '自然光拍摄：正对窗户，避免背光与强阴影。',
          '距离 30–50cm，正脸平视，按引导框对齐：额头和下巴都在框内，鼻子尽量在中心线附近。',
          '关闭美颜/滤镜，确保对焦清晰且无遮挡（头发/口罩/手）。',
        ]
      : [
          'Use daylight facing a window; avoid backlight and strong shadows.',
          'Keep 30–50cm distance and align with the guide frame: forehead/chin inside the frame and nose near center line.',
          'Turn off beauty filters, keep sharp focus, and remove obstructions (hair/mask/hand).',
        ];

  const meanwhilePlan =
    lang === 'CN'
      ? [
          '如果有刺痛或泛红：暂停潜在刺激活性 5–7 天，仅保留温和洁面 + 保湿 + 白天防晒。',
          '如果出油但同时紧绷：减少清洁强度/次数，补一层轻薄保湿。',
          '如果连续 3 天稳定：仅恢复 1 个产品，每周 1–2 次，出现不适立即停用。',
        ]
      : [
          'If stinging or redness appears: pause potentially irritating actives for 5–7 days; keep gentle cleanser + moisturizer + daytime SPF only.',
          'If skin feels oily but tight: reduce cleansing intensity/frequency and add a light moisturizer layer.',
          'If stable for 3 straight days: re-introduce only one product at 1–2 nights/week; stop immediately if irritation returns.',
        ];

  const ask3 =
    lang === 'CN'
      ? [
          '最近 72 小时是否有刺痛/灼热？通常发生在第几步之后？',
          '你当前 AM/PM 每一步具体用了什么产品？各自频率是多少？',
          '最近是否有环境变化（出差/气候/作息/压力）影响皮肤状态？',
        ]
      : [
          'Any stinging or burning in the last 72 hours, and after which routine step?',
          'What exact products are you using in AM/PM, and how often for each?',
          'Any recent environment/lifestyle shift (travel, climate, sleep, stress) affecting your skin?',
        ];

  return {
    why_i_cant_analyze: [primaryReason, guardrailReason].filter(Boolean).slice(0, 2),
    retake_guide: retakeGuide.slice(0, 3),
    meanwhile_plan: meanwhilePlan.slice(0, 3),
    ask_3_questions: ask3.slice(0, 3),
  };
}

function renderPhotoFallbackStrategy({ language, photoNotice, actionCard } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const card = actionCard && typeof actionCard === 'object' ? actionCard : null;
  if (!card) return '';
  const lines = [];
  if (photoNotice) lines.push(photoNotice);
  lines.push(lang === 'CN' ? '为何暂时无法分析' : "Why I can't analyze");
  for (const item of Array.isArray(card.why_i_cant_analyze) ? card.why_i_cant_analyze.slice(0, 2) : []) lines.push(`- ${item}`);
  lines.push(lang === 'CN' ? '重拍指引' : 'Retake guide');
  for (const item of Array.isArray(card.retake_guide) ? card.retake_guide.slice(0, 3) : []) lines.push(`- ${item}`);
  lines.push(lang === 'CN' ? '7 天临时方案' : 'Meanwhile plan (7 days)');
  for (const item of Array.isArray(card.meanwhile_plan) ? card.meanwhile_plan.slice(0, 3) : []) lines.push(`- ${item}`);
  lines.push(lang === 'CN' ? '补充 3 个问题' : 'Ask-3 questions');
  for (const item of Array.isArray(card.ask_3_questions) ? card.ask_3_questions.slice(0, 3) : []) lines.push(`- ${item}`);
  return lines.join('\n').slice(0, 1200);
}

function scheduleSkinAnalysisKbBackfill({
  ctx,
  identity,
  analysisSummaryPayload,
  analysisMeta = null,
  logger,
} = {}) {
  if (!PRODUCT_INTEL_KB_ASYNC_BACKFILL_ENABLED) return;
  const payload = analysisSummaryPayload && typeof analysisSummaryPayload === 'object' && !Array.isArray(analysisSummaryPayload)
    ? analysisSummaryPayload
    : null;
  if (!payload || !payload.analysis || typeof payload.analysis !== 'object') return;
  const identityObj = identity && typeof identity === 'object' ? identity : {};
  const confidenceScoreRaw = Number(
    payload.analysis?.overall_confidence?.score ??
      payload.analysis?.confidence?.score ??
      (payload.low_confidence === true ? 0.35 : NaN),
  );
  const confidenceScore = Number.isFinite(confidenceScoreRaw)
    ? Math.max(0, Math.min(1, confidenceScoreRaw))
    : null;
  const confidenceLevel =
    confidenceScore == null
      ? null
      : confidenceScore >= 0.75
        ? 'high'
        : confidenceScore >= 0.45
          ? 'medium'
          : 'low';
  const qualityGrade = String(payload?.quality_report?.photo_quality?.grade || 'unknown').trim().toLowerCase() || 'unknown';
  const guardrailFlags = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(payload?.quality_report?.llm?.vision?.reasons) ? payload.quality_report.llm.vision.reasons : []),
      ...(Array.isArray(payload?.quality_report?.llm?.report?.reasons) ? payload.quality_report.llm.report.reasons : []),
    ],
    16,
  );
  let snapshot = null;
  try {
    snapshot = JSON.parse(JSON.stringify(payload));
  } catch {
    snapshot = null;
  }
  if (!snapshot || typeof snapshot !== 'object' || Array.isArray(snapshot)) return;

  const artifact = {
    artifact_id: createArtifactId(),
    created_at: new Date().toISOString(),
    artifact_type: 'skin_analysis_kb_snapshot_v1',
    analysis_summary: snapshot,
    overall_confidence: {
      score: confidenceScore,
      level: confidenceLevel,
    },
    provenance: {
      source_chain: ['skin_analysis', 'analysis_summary'],
      confidence_band: confidenceLevel || 'unknown',
      quality_grade: qualityGrade,
      guardrail_flags: guardrailFlags,
      gate_relax_mode: AURORA_RULE_RELAX_MODE,
      model_provenance:
        analysisMeta && typeof analysisMeta === 'object' && !Array.isArray(analysisMeta)
          ? analysisMeta
          : {},
    },
  };

  setImmediate(() => {
    saveDiagnosisArtifact({
      auroraUid: identityObj.auroraUid || ctx?.aurora_uid || null,
      userId: identityObj.userId || null,
      sessionId: ctx?.brief_id || null,
      artifact,
      artifactId: artifact.artifact_id,
    }).catch((err) => {
      logger?.warn(
        {
          err: err?.message || String(err),
          request_id: ctx?.request_id || null,
          trace_id: ctx?.trace_id || null,
        },
        'aurora bff: skin analysis async kb backfill failed',
      );
    });
  });
}

function clampGeometry01(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return 0;
  if (numeric <= 0) return 0;
  if (numeric >= 1) return 1;
  return numeric;
}

function sanitizeBBoxNorm(rawBBox) {
  if (!rawBBox || typeof rawBBox !== 'object') return { ok: false, clipped: false, bbox: null };
  const raw = {
    x0: Number(rawBBox.x0),
    y0: Number(rawBBox.y0),
    x1: Number(rawBBox.x1),
    y1: Number(rawBBox.y1),
  };
  if (!Number.isFinite(raw.x0) || !Number.isFinite(raw.y0) || !Number.isFinite(raw.x1) || !Number.isFinite(raw.y1)) {
    return { ok: false, clipped: false, bbox: null };
  }

  const clamped = {
    x0: clampGeometry01(raw.x0),
    y0: clampGeometry01(raw.y0),
    x1: clampGeometry01(raw.x1),
    y1: clampGeometry01(raw.y1),
  };
  let clipped =
    clamped.x0 !== raw.x0 ||
    clamped.y0 !== raw.y0 ||
    clamped.x1 !== raw.x1 ||
    clamped.y1 !== raw.y1;

  const ordered = {
    x0: Math.min(clamped.x0, clamped.x1),
    y0: Math.min(clamped.y0, clamped.y1),
    x1: Math.max(clamped.x0, clamped.x1),
    y1: Math.max(clamped.y0, clamped.y1),
  };
  if (ordered.x0 !== clamped.x0 || ordered.y0 !== clamped.y0 || ordered.x1 !== clamped.x1 || ordered.y1 !== clamped.y1) {
    clipped = true;
  }

  if (ordered.x1 - ordered.x0 <= 0.001 || ordered.y1 - ordered.y0 <= 0.001) {
    return { ok: false, clipped: true, bbox: null };
  }
  return { ok: true, clipped, bbox: ordered };
}

function sanitizeGridGeometry(rawGeometry) {
  if (!rawGeometry || typeof rawGeometry !== 'object') return { ok: false, clipped: false, grid: null };
  const rawRows = Number(rawGeometry.rows);
  const rawCols = Number(rawGeometry.cols);
  const rawValues = Array.isArray(rawGeometry.values) ? rawGeometry.values : null;
  if (!Number.isFinite(rawRows) || !Number.isFinite(rawCols) || !rawValues) {
    return { ok: false, clipped: false, grid: null };
  }

  const rows = Math.max(1, Math.min(64, Math.trunc(rawRows)));
  const cols = Math.max(1, Math.min(64, Math.trunc(rawCols)));
  const expected = rows * cols;
  let clipped = rows !== rawRows || cols !== rawCols;
  if (rawValues.length < expected) {
    return { ok: false, clipped: true, grid: null };
  }

  const values = rawValues.slice(0, expected).map((item) => {
    const numeric = Number(item);
    if (!Number.isFinite(numeric)) {
      clipped = true;
      return 0;
    }
    const normalized = clampGeometry01(numeric);
    if (normalized !== numeric) clipped = true;
    return normalized;
  });
  return {
    ok: true,
    clipped,
    grid: {
      type: 'grid',
      rows,
      cols,
      values,
    },
  };
}

function sanitizeFindingGeometry(rawGeometry) {
  if (!rawGeometry || typeof rawGeometry !== 'object') {
    return { geometry: null, checked_n: 0, dropped_n: 0, clipped_n: 0 };
  }

  let checked = 0;
  let dropped = 0;
  let clipped = 0;
  const geometry = {};
  let hasGeometry = false;

  if (rawGeometry.bbox_norm && typeof rawGeometry.bbox_norm === 'object') {
    checked += 1;
    const bbox = sanitizeBBoxNorm(rawGeometry.bbox_norm);
    if (bbox.ok && bbox.bbox) {
      geometry.bbox_norm = bbox.bbox;
      hasGeometry = true;
    } else {
      dropped += 1;
    }
    if (bbox.clipped) clipped += 1;
  }

  if (
    rawGeometry.type === 'grid' ||
    (Number.isFinite(Number(rawGeometry.rows)) && Number.isFinite(Number(rawGeometry.cols)) && Array.isArray(rawGeometry.values))
  ) {
    checked += 1;
    const grid = sanitizeGridGeometry(rawGeometry);
    if (grid.ok && grid.grid) {
      geometry.type = 'grid';
      geometry.rows = grid.grid.rows;
      geometry.cols = grid.grid.cols;
      geometry.values = grid.grid.values;
      hasGeometry = true;
    } else {
      dropped += 1;
    }
    if (grid.clipped) clipped += 1;
  }

  return {
    geometry: hasGeometry ? geometry : null,
    checked_n: checked,
    dropped_n: dropped,
    clipped_n: clipped,
  };
}

function mergeGeometrySanitizerByIssue(target, issueType, stats) {
  const issue = String(issueType || 'unknown').trim().toLowerCase() || 'unknown';
  if (!target[issue]) {
    target[issue] = { checked_n: 0, dropped_n: 0, clipped_n: 0, fixed_n: 0 };
  }
  target[issue].checked_n += Number(stats.checked_n || 0);
  target[issue].dropped_n += Number(stats.dropped_n || 0);
  target[issue].clipped_n += Number(stats.clipped_n || 0);
  target[issue].fixed_n += Number(stats.fixed_n != null ? stats.fixed_n : stats.clipped_n || 0);
}

function buildExecutablePlanForAnalysis({
  analysis,
  language,
  usedPhotos,
  photoQuality,
  profileSummary,
  photoNoticeOverride,
  photoFailureCode,
  photosProvided,
} = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const base = analysis && typeof analysis === 'object' && !Array.isArray(analysis) ? { ...analysis } : null;
  if (!base) return analysis;

  const quality = photoQuality && typeof photoQuality === 'object' ? photoQuality : { grade: 'unknown', reasons: [] };
  const qualityFail = String(quality.grade || '').trim().toLowerCase() === 'fail';
  const fallbackMode = qualityFail || !usedPhotos;
  const profileGoals =
    profileSummary && Array.isArray(profileSummary.goals)
      ? profileSummary.goals.filter((item) => typeof item === 'string' && item.trim())
      : [];
  const hasQuestionnaireSignals = Boolean(
    profileSummary &&
      typeof profileSummary === 'object' &&
      !Array.isArray(profileSummary) &&
      (
        (typeof profileSummary.skinType === 'string' && profileSummary.skinType.trim()) ||
        (typeof profileSummary.barrierStatus === 'string' && profileSummary.barrierStatus.trim()) ||
        (typeof profileSummary.sensitivity === 'string' && profileSummary.sensitivity.trim()) ||
        profileGoals.length > 0 ||
        (Array.isArray(profileSummary.concerns) && profileSummary.concerns.some((item) => typeof item === 'string' && item.trim())) ||
        hasNonEmptyRoutineInput(profileSummary.currentRoutine)
      ),
  );
  const hardFallbackMode = fallbackMode && !hasQuestionnaireSignals;
  const defaultPhotoNotice = qualityFail
    ? lang === 'CN'
      ? '照片质量未通过，本次仅基于问卷/历史信息给出临时建议。'
      : 'Photo quality failed, so this run uses questionnaire/history only.'
    : usedPhotos
      ? null
      : 'Based on your answers only (photo not analyzed).';
  const overrideNotice = typeof photoNoticeOverride === 'string' ? photoNoticeOverride.trim() : '';
  const photoNotice = overrideNotice ? [overrideNotice, defaultPhotoNotice].filter(Boolean).join(' ') : defaultPhotoNotice;

  const findingsInput = usedPhotos && !qualityFail
    ? Array.isArray(base.photo_findings)
      ? base.photo_findings
      : Array.isArray(base.findings)
        ? base.findings
        : []
    : [];
  const geometrySanitizer = {
    checked_n: 0,
    dropped_n: 0,
    clipped_n: 0,
    fixed_n: 0,
    by_issue: {},
  };
  const photoFindings = [];
  const issueToFindingIds = new Map();
  for (let i = 0; i < findingsInput.length; i += 1) {
    const finding = findingsInput[i];
    if (!finding || typeof finding !== 'object') continue;
    const issueType = typeof finding.issue_type === 'string' ? finding.issue_type.trim() : '';
    if (!issueType) continue;
    const findingIdRaw = typeof finding.finding_id === 'string' && finding.finding_id.trim() ? finding.finding_id.trim() : `pf_${issueType}_${i + 1}`;
    const geometryStats = sanitizeFindingGeometry(finding.geometry);
    geometrySanitizer.checked_n += Number(geometryStats.checked_n || 0);
    geometrySanitizer.dropped_n += Number(geometryStats.dropped_n || 0);
    geometrySanitizer.clipped_n += Number(geometryStats.clipped_n || 0);
    geometrySanitizer.fixed_n += Number(geometryStats.clipped_n || 0);
    if (Number(geometryStats.checked_n || 0) > 0) {
      mergeGeometrySanitizerByIssue(geometrySanitizer.by_issue, issueType, {
        checked_n: geometryStats.checked_n,
        dropped_n: geometryStats.dropped_n,
        clipped_n: geometryStats.clipped_n,
        fixed_n: geometryStats.clipped_n,
      });
    }
    const normalizedFinding = {
      finding_id: findingIdRaw,
      issue_type: issueType,
      subtype: typeof finding.subtype === 'string' && finding.subtype.trim() ? finding.subtype.trim() : null,
      severity: Number.isFinite(finding.severity) ? Math.max(0, Math.min(4, Math.round(finding.severity))) : 0,
      confidence: Number.isFinite(finding.confidence) ? Math.max(0, Math.min(1, Number(finding.confidence))) : 0,
      evidence: typeof finding.evidence === 'string' ? finding.evidence.trim() : '',
      computed_features: finding.computed_features && typeof finding.computed_features === 'object' ? finding.computed_features : {},
      geometry: geometryStats.geometry,
      ...(finding.uncertain === true ? { uncertain: true } : {}),
    };
    photoFindings.push(normalizedFinding);
    const list = issueToFindingIds.get(issueType) || [];
    list.push(findingIdRaw);
    issueToFindingIds.set(issueType, list);
  }
  base.photo_findings = photoFindings;
  base.findings = photoFindings;
  if (usedPhotos && !qualityFail && photoFindings.length) {
    const evidenceRegions = [];
    for (const finding of photoFindings) {
      const geometry = finding && finding.geometry && typeof finding.geometry === 'object' ? finding.geometry : null;
      if (!geometry) continue;
      if (geometry.bbox_norm && typeof geometry.bbox_norm === 'object') {
        evidenceRegions.push({
          concern_type: finding.issue_type,
          severity: finding.severity,
          confidence: finding.confidence,
          region: { kind: 'bbox', bbox_norm: geometry.bbox_norm },
          evidence_text: finding.evidence || '',
        });
      }
      if (
        geometry.type === 'grid' &&
        Number.isFinite(Number(geometry.rows)) &&
        Number.isFinite(Number(geometry.cols)) &&
        Array.isArray(geometry.values)
      ) {
        const rows = Math.max(1, Math.min(64, Math.trunc(Number(geometry.rows))));
        const cols = Math.max(1, Math.min(64, Math.trunc(Number(geometry.cols))));
        const values = geometry.values
          .slice(0, rows * cols)
          .map((value) => (Number.isFinite(Number(value)) ? Math.max(0, Math.min(1, Number(value))) : 0));
        if (values.length === rows * cols) {
          evidenceRegions.push({
            concern_type: finding.issue_type,
            severity: finding.severity,
            confidence: finding.confidence,
            region: { kind: 'heatmap', rows, cols, values },
            evidence_text: finding.evidence || '',
          });
        }
      }
    }
    if (evidenceRegions.length) base.evidence_regions = evidenceRegions.slice(0, 48);
    else delete base.evidence_regions;
  } else {
    delete base.evidence_regions;
  }

  const takeawaysInput = Array.isArray(base.takeaways) ? base.takeaways : [];
  const takeaways = [];
  const seenTakeawayText = new Set();
  for (const item of takeawaysInput) {
    const normalized = normalizePlanTakeaway(item, { language: lang });
    if (!normalized) continue;
    if (fallbackMode && normalized.source === 'photo') continue;
    if (normalized.source === 'photo' && normalized.linked_finding_ids.length === 0 && normalized.issue_type) {
      normalized.linked_finding_ids = (issueToFindingIds.get(normalized.issue_type) || []).slice(0, 8);
    }
    if (normalized.source === 'photo' && normalized.linked_issue_types.length === 0 && normalized.issue_type) {
      normalized.linked_issue_types = [normalized.issue_type];
    }
    const key = `${normalized.source}:${normalized.text.toLowerCase()}`;
    if (seenTakeawayText.has(key)) continue;
    seenTakeawayText.add(key);
    takeaways.push(normalized);
  }

  if (!hardFallbackMode) {
    if (profileGoals.length) {
      const text = `You mentioned your goals: ${profileGoals.slice(0, 3).join(', ')}.`;
      const key = `user:${text.toLowerCase()}`;
      if (!seenTakeawayText.has(key)) {
        takeaways.push({
          takeaway_id: 'tw_user_goals_plan',
          source: 'user',
          issue_type: 'goal',
          text,
          confidence: 1,
          linked_finding_ids: [],
          linked_issue_types: ['goal'],
        });
        seenTakeawayText.add(key);
      }
    }
    if (profileSummary && profileSummary.barrierStatus === 'impaired') {
      const text = 'You mentioned stinging/redness and barrier stress recently.';
      const key = `user:${text.toLowerCase()}`;
      if (!seenTakeawayText.has(key)) {
        takeaways.push({
          takeaway_id: 'tw_user_barrier_stress',
          source: 'user',
          issue_type: 'barrier',
          text,
          confidence: 0.9,
          linked_finding_ids: [],
          linked_issue_types: ['barrier'],
        });
        seenTakeawayText.add(key);
      }
    }
  }

  if (usedPhotos && !qualityFail && photoFindings.length) {
    for (const finding of photoFindings) {
      const alreadyLinked = takeaways.some((item) => item.source === 'photo' && item.linked_finding_ids.includes(finding.finding_id));
      if (alreadyLinked) continue;
      takeaways.push({
        takeaway_id: `tw_photo_${finding.finding_id}`,
        source: 'photo',
        issue_type: finding.issue_type,
        text: `From photo: ${finding.issue_type} signal observed in the highlighted area.`,
        confidence: finding.confidence,
        linked_finding_ids: [finding.finding_id],
        linked_issue_types: [finding.issue_type],
      });
    }
  }

  const takeawaysByIssue = new Map();
  for (const item of takeaways) {
    if (!item.issue_type) continue;
    const list = takeawaysByIssue.get(item.issue_type) || [];
    list.push(item.takeaway_id);
    takeawaysByIssue.set(item.issue_type, list);
  }

  const makeStep = ({ what, why, whenToStop, priority, linkedIssueTypes = [], linkedFindingIds = [] } = {}) => ({
    what: String(what || '').trim(),
    why: String(why || '').trim(),
    when_to_stop: String(whenToStop || '').trim(),
    priority: priority === 'P0' || priority === 'P1' || priority === 'P2' ? priority : 'P1',
    linked_issue_types: linkedIssueTypes.filter((item) => typeof item === 'string' && item.trim()).slice(0, 6),
    linked_finding_ids: linkedFindingIds.filter((item) => typeof item === 'string' && item.trim()).slice(0, 8),
    linked_takeaway_ids: linkedIssueTypes
      .flatMap((issueType) => (takeawaysByIssue.get(issueType) || []).filter((item) => typeof item === 'string' && item.trim()))
      .slice(0, 8),
  });

  const requiredCheckboxes = [
    { metric: 'redness_stinging', label: 'redness/stinging', options: ['↓', '→', '↑'] },
    { metric: 'new_breakouts', label: 'new breakouts', options: ['↓', '→', '↑'] },
    { metric: 'shine_oil_control', label: 'shine/oil control', options: ['↓', '→', '↑'] },
  ];

  let plan = null;
  const fallbackActionCard = fallbackMode
    ? buildPhotoFallbackActionCard({
      language: lang,
      qualityFail,
      failureCode: photoFailureCode,
      photosProvided,
    })
    : null;
  if (hardFallbackMode) {
    plan = {
      today: {
        am_steps: [],
        pm_steps: [],
        pause_now: [
          makeStep({
            what:
              lang === 'CN'
                ? '按重拍指引补拍一张照片（自然光、无遮挡、无滤镜）。'
                : 'Retake one photo using the retake guide (daylight, unobstructed, no filter).',
            why: (fallbackActionCard.why_i_cant_analyze && fallbackActionCard.why_i_cant_analyze[0]) || '',
            whenToStop:
              lang === 'CN'
                ? '连续 2 次仍不通过时，先继续问卷流程并稍后再拍。'
                : 'If QC still fails after 2 attempts, continue with questionnaire flow and retry later.',
            priority: 'P0',
            linkedIssueTypes: ['quality'],
            linkedFindingIds: [],
          }),
        ],
      },
      next_7_days: {
        rules:
          lang === 'CN'
            ? ['在照片不可用期间，先执行保守的 7 天临时方案。', '尽快重拍并通过 QC 后再恢复照片分析。']
            : ['Use a conservative 7-day temporary plan while photo evidence is unavailable.', 'Retake as soon as possible and resume photo analysis after QC passes.'],
        steps: [
          makeStep({
            what: fallbackActionCard.meanwhile_plan[0] || '',
            why:
              lang === 'CN'
                ? '先控制刺激风险，避免在证据不足时过度调整。'
                : 'Control irritation risk first while evidence is incomplete.',
            whenToStop:
              lang === 'CN'
                ? '若刺痛/泛红连续减轻 3 天可进入下一步。'
                : 'Move to next step after 3 consecutive days of stable or improved comfort.',
            priority: 'P0',
            linkedIssueTypes: ['fallback'],
            linkedFindingIds: [],
          }),
          makeStep({
            what: fallbackActionCard.meanwhile_plan[1] || '',
            why:
              lang === 'CN'
                ? '先修正清洁和保湿平衡，降低“外油内干”波动。'
                : 'Re-balance cleansing and hydration to reduce rebound fluctuations.',
            whenToStop:
              lang === 'CN'
                ? '若紧绷/泛红加重，继续简化并暂停新增产品。'
                : 'If tightness/redness worsens, simplify further and pause new products.',
            priority: 'P1',
            linkedIssueTypes: ['fallback'],
            linkedFindingIds: [],
          }),
          makeStep({
            what: fallbackActionCard.meanwhile_plan[2] || '',
            why:
              lang === 'CN'
                ? '通过低频恢复来确认耐受，避免一次叠加多个变化。'
                : 'Low-frequency reintroduction helps verify tolerance without stacking changes.',
            whenToStop:
              lang === 'CN'
                ? '出现持续不适时，回到“仅基础三步”并等待复拍结果。'
                : 'If persistent discomfort returns, revert to basic 3-step care and wait for retake results.',
            priority: 'P1',
            linkedIssueTypes: ['fallback'],
            linkedFindingIds: [],
          }),
        ],
      },
      after_calm: {
        entry_criteria:
          lang === 'CN'
            ? ['照片 QC 至少达到 pass/degraded。', '可重复同一光线与角度。']
            : ['Photo QC reaches pass/degraded.', 'Same lighting and angle are reproducible.'],
        steps: [],
      },
      tracking: {
        checkboxes: requiredCheckboxes,
        retake_prompt:
          lang === 'CN'
            ? '7 天内按同一光线/角度重拍，并按引导框对齐（额头/下巴入框，鼻子靠近中心线）。'
            : 'Retake within 7 days with the same lighting/angle, and align to the guide frame (forehead/chin inside, nose near center line).',
        retake_after_days: 7,
      },
    };
  } else {
    const rednessFindingIds = issueToFindingIds.get('redness') || [];
    const shineFindingIds = issueToFindingIds.get('shine') || [];
    const textureFindingIds = issueToFindingIds.get('texture') || [];
    const toneFindingIds = issueToFindingIds.get('tone') || [];
    const hasRedness = rednessFindingIds.length > 0;
    const hasShine = shineFindingIds.length > 0;
    const hasTexture = textureFindingIds.length > 0;
    const hasTone = toneFindingIds.length > 0;

    const amSteps = [
      makeStep({
        what: 'Use gentle cleanser, then moisturizer.',
        why: hasRedness ? `Linked evidence: ${rednessFindingIds.join(', ')} (photo redness) and barrier-related takeaways.` : 'Linked evidence: user-input sensitivity/barrier context.',
        whenToStop: 'Stop if burning >10 minutes or persistent stinging.',
        priority: 'P0',
        linkedIssueTypes: hasRedness ? ['redness'] : ['barrier'],
        linkedFindingIds: rednessFindingIds,
      }),
      makeStep({
        what: 'Apply broad-spectrum SPF as last AM step.',
        why: hasTone ? `Linked evidence: ${toneFindingIds.join(', ')} (uneven tone proxy).` : 'Linked evidence: prevention baseline and user goals.',
        whenToStop: 'Stop only if rash or swelling appears.',
        priority: 'P0',
        linkedIssueTypes: hasTone ? ['tone'] : ['goal'],
        linkedFindingIds: toneFindingIds,
      }),
    ];

    const pmSteps = [
      makeStep({
        what: 'Cleanse gently and moisturize; keep PM routine simple for 7 days.',
        why: hasRedness ? `Linked evidence: ${rednessFindingIds.join(', ')} indicates irritation risk.` : 'Linked evidence: user-reported sensitivity context.',
        whenToStop: 'Stop and simplify further if redness/stinging increases for 2 consecutive days.',
        priority: 'P0',
        linkedIssueTypes: hasRedness ? ['redness'] : ['barrier'],
        linkedFindingIds: rednessFindingIds,
      }),
    ];

    if (hasShine || hasTexture) {
      pmSteps.push(
        makeStep({
          what: 'If skin stays calm for 3 nights, add one low-frequency balancing step (2 nights/week).',
          why: `Linked evidence: ${(hasTexture ? textureFindingIds : shineFindingIds).join(', ')} supports oil/texture control.`,
          whenToStop: 'Stop if peeling, burning, or new diffuse redness appears.',
          priority: 'P1',
          linkedIssueTypes: hasTexture ? ['texture'] : ['shine'],
          linkedFindingIds: hasTexture ? textureFindingIds : shineFindingIds,
        }),
      );
    }

    const pauseNow = [];
    if (hasRedness) {
      pauseNow.push(
        makeStep({
          what: 'Pause layering multiple strong actives on the same night.',
          why: `Linked evidence: ${rednessFindingIds.join(', ')} and photo-linked irritation takeaways.`,
          whenToStop: 'Resume only after 3 consecutive days with redness/stinging not increasing.',
          priority: 'P0',
          linkedIssueTypes: ['redness'],
          linkedFindingIds: rednessFindingIds,
        }),
      );
    }

    const nextSteps = [
      makeStep({
        what: 'Keep one-variable-at-a-time changes across the next 7 days.',
        why: 'Linked evidence: mixed uncertainty from photo + user signals requires controlled iteration.',
        whenToStop: 'Stop adding new steps if any metric trends upward for 2 days.',
        priority: 'P0',
        linkedIssueTypes: ['mixed'],
        linkedFindingIds: [...rednessFindingIds, ...shineFindingIds, ...textureFindingIds, ...toneFindingIds].slice(0, 8),
      }),
    ];
    if (hasShine) {
      nextSteps.push(
        makeStep({
          what: 'Track midday shine and reduce occlusive layering if shine worsens.',
          why: `Linked evidence: ${shineFindingIds.join(', ')} (shine/specular proxy).`,
          whenToStop: 'Stop reduction if tightness or flaking increases.',
          priority: 'P1',
          linkedIssueTypes: ['shine'],
          linkedFindingIds: shineFindingIds,
        }),
      );
    }

    const afterCalmSteps = [];
    if (hasTexture || hasTone) {
      afterCalmSteps.push(
        makeStep({
          what: 'After skin is calm, add one targeted step and reassess after 7 days.',
          why: `Linked evidence: ${[...textureFindingIds, ...toneFindingIds].join(', ')} and corresponding takeaways.`,
          whenToStop: 'Stop targeted step if irritation rises or breakouts increase.',
          priority: 'P2',
          linkedIssueTypes: [...(hasTexture ? ['texture'] : []), ...(hasTone ? ['tone'] : [])],
          linkedFindingIds: [...textureFindingIds, ...toneFindingIds],
        }),
      );
    }

    plan = {
      today: {
        am_steps: amSteps,
        pm_steps: pmSteps,
        pause_now: pauseNow,
      },
      next_7_days: {
        rules: [
          'Keep routine changes incremental (one new variable at a time).',
          usedPhotos ? 'Use current photo findings as baseline and compare after retake.' : 'Use symptom trend checkboxes as baseline until photo is provided.',
        ],
        steps: nextSteps,
      },
      after_calm: {
        entry_criteria: ['redness/stinging trend is ↓ or stable for 3 days', 'no sudden breakout spike', 'routine feels tolerable daily'],
        steps: afterCalmSteps,
      },
      tracking: {
        checkboxes: requiredCheckboxes,
        retake_prompt: 'Retake in 7 days with the same lighting/angle/distance, and align to the guide frame (forehead/chin inside, nose near center line).',
        retake_after_days: 7,
      },
    };
    if (fallbackMode && fallbackActionCard && typeof fallbackActionCard === 'object') {
      const retakeStep = makeStep({
        what:
          lang === 'CN'
            ? '先按当前问卷方案执行，同时补拍 daylight + indoor_white 照片。'
            : 'Start with this questionnaire-based plan now, and retake daylight + indoor_white photos.',
        why: (fallbackActionCard.why_i_cant_analyze && fallbackActionCard.why_i_cant_analyze[0]) || '',
        whenToStop:
          lang === 'CN'
            ? '重拍通过并更新分析后，按新诊断调整。'
            : 'Adjust after a successful retake and refreshed analysis.',
        priority: 'P0',
        linkedIssueTypes: ['quality'],
        linkedFindingIds: [],
      });
      const pauseNow = Array.isArray(plan.today && plan.today.pause_now) ? [...plan.today.pause_now] : [];
      const hasRetakeStep = pauseNow.some((step) => /retake|重拍|daylight|indoor_white/i.test(String((step && step.what) || '')));
      if (!hasRetakeStep) pauseNow.unshift(retakeStep);
      plan.today = { ...(plan.today || {}), pause_now: pauseNow.slice(0, 6) };

      const retakeRule =
        lang === 'CN'
          ? '继续执行当前 7 天保守方案，并尽快补拍 daylight + indoor_white 提升准确度。'
          : 'Keep this conservative 7-day plan, and retake daylight + indoor_white photos to improve precision.';
      const currentRules = Array.isArray(plan.next_7_days && plan.next_7_days.rules)
        ? plan.next_7_days.rules.filter((item) => typeof item === 'string' && item.trim())
        : [];
      if (!currentRules.some((item) => /retake|daylight|indoor_white|重拍/i.test(item))) {
        currentRules.unshift(retakeRule);
      }
      plan.next_7_days = { ...(plan.next_7_days || {}), rules: currentRules.slice(0, 3) };
    }
  }

  base.plan = plan;
  if (hardFallbackMode) {
    base.photo_findings = [];
    base.findings = [];
    base.takeaways = [];
    base.features = (fallbackActionCard.why_i_cant_analyze || []).map((text, index) => ({
      observation: text,
      confidence: index === 0 ? 'pretty_sure' : 'somewhat_sure',
    }));
    base.next_action_card = fallbackActionCard;
    base.strategy = renderPhotoFallbackStrategy({ language: lang, photoNotice, actionCard: fallbackActionCard });
  } else {
    base.takeaways = takeaways.slice(0, 14);
    if (fallbackMode && fallbackActionCard && typeof fallbackActionCard === 'object') {
      base.next_action_card = fallbackActionCard;
      const warningLine = Array.isArray(fallbackActionCard.why_i_cant_analyze)
        ? String(fallbackActionCard.why_i_cant_analyze[0] || '').trim()
        : '';
      const goalLine = profileGoals.length
        ? lang === 'CN'
          ? `先按你的目标（${profileGoals.slice(0, 2).join('、')}）执行保守方案，补拍后再精细化。`
          : `Using your goal focus (${profileGoals.slice(0, 2).join(', ')}) for a conservative starter plan; retake will refine it.`
        : '';
      const originalFeatures = Array.isArray(base.features) ? base.features : [];
      const mergedFeatures = [];
      if (warningLine) mergedFeatures.push({ observation: warningLine, confidence: 'somewhat_sure' });
      if (goalLine) mergedFeatures.push({ observation: goalLine, confidence: 'somewhat_sure' });
      for (const item of originalFeatures) {
        if (!item || typeof item !== 'object') continue;
        const observation = typeof item.observation === 'string' ? item.observation.trim() : '';
        if (!observation) continue;
        if (warningLine && observation === warningLine) continue;
        const confidence =
          item.confidence === 'pretty_sure' || item.confidence === 'somewhat_sure' || item.confidence === 'not_sure'
            ? item.confidence
            : 'somewhat_sure';
        mergedFeatures.push({ observation, confidence });
        if (mergedFeatures.length >= 5) break;
      }
      if (mergedFeatures.length) base.features = mergedFeatures;
    } else {
      delete base.next_action_card;
    }
    base.strategy = renderPlanAsStrategy({ plan, language: lang, photoNotice });
  }
  if (photoNotice) base.photo_notice = photoNotice;
  else delete base.photo_notice;
  if (fallbackMode && Array.isArray(fallbackActionCard.ask_3_questions)) {
    base.ask_3_questions = fallbackActionCard.ask_3_questions.slice(0, 3);
  } else {
    delete base.ask_3_questions;
  }
  if (fallbackMode && Array.isArray(fallbackActionCard.retake_guide)) {
    base.retake_guide = fallbackActionCard.retake_guide.slice(0, 3);
  } else {
    delete base.retake_guide;
  }
  const geometryByIssue = {};
  for (const issueType of Object.keys(geometrySanitizer.by_issue).sort((a, b) => a.localeCompare(b))) {
    const raw = geometrySanitizer.by_issue[issueType] || {};
    geometryByIssue[issueType] = {
      checked_n: Number(raw.checked_n || 0),
      dropped_n: Number(raw.dropped_n || 0),
      clipped_n: Number(raw.clipped_n || 0),
      fixed_n: Number(raw.fixed_n || 0),
    };
  }
  base.__geometry_sanitizer = {
    checked_n: Number(geometrySanitizer.checked_n || 0),
    dropped_n: Number(geometrySanitizer.dropped_n || 0),
    clipped_n: Number(geometrySanitizer.clipped_n || 0),
    fixed_n: Number(geometrySanitizer.fixed_n || 0),
    by_issue: geometryByIssue,
  };
  return base;
}

function normalizeRoutineRole(stepLabel, productLabel) {
  const joined = `${String(stepLabel || '')} ${String(productLabel || '')}`.trim().toLowerCase();
  if (!joined) return 'other';
  if (/(cleanser|cleanse|face wash|facewash|foam|wash|soap|洁面|洗面)/.test(joined)) return 'cleanser';
  if (/(spf|sunscreen|sun screen|uv|防晒)/.test(joined)) return 'spf';
  if (/(moist|cream|lotion|gel|repair|barrier|保湿|面霜|乳液)/.test(joined)) return 'moisturizer';
  if (/(serum|active|treatment|acid|retinol|retinoid|vitamin c|niacinamide|精华|活性|酸|维a|维c|烟酰胺)/.test(joined)) {
    return 'treatment';
  }
  return 'other';
}

function detectRoutineActiveFamilies(productLabel) {
  const text = String(productLabel || '').trim().toLowerCase();
  const families = [];
  if (!text) return families;
  if (/(retinol|retinal|retinoid|adapalene|tretinoin|维a|a醇|维甲酸)/.test(text)) families.push('retinoid');
  if (/(glycolic|lactic|mandelic|salicylic|aha|bha|pha|果酸|水杨酸|乳酸|杏仁酸)/.test(text)) families.push('acids');
  if (/(benzoyl|bpo|过氧化苯甲酰)/.test(text)) families.push('benzoyl_peroxide');
  if (/(vitamin c|ascorbic|l-ascorbic|维c|vc)/.test(text)) families.push('vitamin_c');
  if (/(niacinamide|烟酰胺)/.test(text)) families.push('niacinamide');
  if (/(azelaic|壬二酸)/.test(text)) families.push('azelaic_acid');
  return families;
}

function detectRoutineRiskFlags(productLabel) {
  const text = String(productLabel || '').trim().toLowerCase();
  const flags = [];
  if (!text) return flags;
  if (/(scrub|microbead|beads|exfoliating cleanser|磨砂|颗粒|去角质颗粒)/.test(text)) flags.push('physical_exfoliation_cleanser');
  if (/(deep clean|oil control cleanser|strong cleanser|foaming cleanser|强清洁|深层清洁)/.test(text)) flags.push('high_cleanse_intensity');
  if (/(fragrance|parfum|香精)/.test(text)) flags.push('fragrance_present');
  return flags;
}

function normalizeRoutineStepRow(raw) {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
  const step = String(raw.step || raw.role || raw.category || '').trim();
  const product = String(raw.product || raw.name || raw.value || '').trim();
  if (!step && !product) return null;
  const role = normalizeRoutineRole(step, product);
  return {
    role,
    step: step || role,
    product: product || step || '',
  };
}

function normalizeRoutineStepArray(input, fallbackPhase = 'am') {
  const out = [];
  if (Array.isArray(input)) {
    for (const row of input) {
      const normalized = normalizeRoutineStepRow(row);
      if (!normalized) continue;
      out.push(normalized);
      if (out.length >= 8) break;
    }
    return out;
  }
  if (!input || typeof input !== 'object' || Array.isArray(input)) return out;

  const source = input;
  const orderedKeys = fallbackPhase === 'am'
    ? ['cleanser', 'treatment', 'moisturizer', 'spf']
    : ['cleanser', 'treatment', 'moisturizer', 'spf'];
  for (const key of orderedKeys) {
    const val = String(source[key] || '').trim();
    if (!val) continue;
    out.push({ role: normalizeRoutineRole(key, val), step: key, product: val });
    if (out.length >= 8) break;
  }
  return out;
}

function parseRoutineFromPlainText(rawText) {
  const text = String(rawText || '').trim();
  const empty = { am_steps: [], pm_steps: [], notes: '' };
  if (!text) return empty;

  const maybeJson = (() => {
    const t = text.trim();
    if (!(t.startsWith('{') || t.startsWith('['))) return null;
    try {
      return JSON.parse(t);
    } catch {
      return null;
    }
  })();
  if (maybeJson && typeof maybeJson === 'object') {
    return parseRoutineIntake(maybeJson);
  }

  const lines = text.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  let phase = 'am';
  const amSteps = [];
  const pmSteps = [];
  const notes = [];

  for (const line of lines) {
    const lower = line.toLowerCase();
    if (/^(am|morning|早上|早晨)/.test(lower)) {
      phase = 'am';
      continue;
    }
    if (/^(pm|evening|night|晚上|夜间)/.test(lower)) {
      phase = 'pm';
      continue;
    }

    const match = line.match(/^([^:：]{2,30})[:：]\s*(.+)$/);
    if (match) {
      const step = String(match[1] || '').trim();
      const product = String(match[2] || '').trim();
      const row = {
        role: normalizeRoutineRole(step, product),
        step: step || 'other',
        product: product || step,
      };
      if (phase === 'am') amSteps.push(row);
      else pmSteps.push(row);
      continue;
    }
    notes.push(line);
  }

  return {
    am_steps: amSteps.slice(0, 8),
    pm_steps: pmSteps.slice(0, 8),
    notes: notes.join(' ').slice(0, 800),
  };
}

function parseRoutineIntake(routineCandidate) {
  const empty = { am_steps: [], pm_steps: [], notes: '' };
  if (routineCandidate == null) return empty;
  if (typeof routineCandidate === 'string') return parseRoutineFromPlainText(routineCandidate);
  if (Array.isArray(routineCandidate)) return empty;
  if (typeof routineCandidate !== 'object') return empty;

  const source = routineCandidate;
  const amSteps = [];
  const pmSteps = [];

  if (Array.isArray(source.am)) amSteps.push(...normalizeRoutineStepArray(source.am, 'am'));
  else if (source.am && typeof source.am === 'object') amSteps.push(...normalizeRoutineStepArray(source.am, 'am'));

  if (Array.isArray(source.pm)) pmSteps.push(...normalizeRoutineStepArray(source.pm, 'pm'));
  else if (source.pm && typeof source.pm === 'object') pmSteps.push(...normalizeRoutineStepArray(source.pm, 'pm'));

  if (!amSteps.length && Array.isArray(source.am_steps)) amSteps.push(...normalizeRoutineStepArray(source.am_steps, 'am'));
  if (!pmSteps.length && Array.isArray(source.pm_steps)) pmSteps.push(...normalizeRoutineStepArray(source.pm_steps, 'pm'));

  const notes = String(source.notes || source.note || source.memo || '').trim().slice(0, 800);
  return {
    am_steps: amSteps.slice(0, 8),
    pm_steps: pmSteps.slice(0, 8),
    notes,
  };
}

function mapFamilyTokenLabel(token, language) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const map = {
    retinoid: lang === 'CN' ? '维A类' : 'retinoid',
    acids: lang === 'CN' ? '酸类(AHA/BHA/PHA)' : 'acids (AHA/BHA/PHA)',
    benzoyl_peroxide: lang === 'CN' ? '过氧化苯甲酰' : 'benzoyl peroxide',
    vitamin_c: lang === 'CN' ? '维C' : 'vitamin C',
    niacinamide: lang === 'CN' ? '烟酰胺' : 'niacinamide',
    azelaic_acid: lang === 'CN' ? '壬二酸' : 'azelaic acid',
  };
  return map[token] || token;
}

