function buildProductDeepScanPromptV2({
  prefix = '',
  productDescriptor = '',
  strictFormulaIntent = false,
  includeVersionReminder = false,
} = {}) {
  const strictLine = strictFormulaIntent
    ? 'If formula_intent is missing or profile-only, rewrite once using product efficacy/mechanism details only.'
    : '';
  const versionLine = includeVersionReminder
    ? 'If product version cannot be confirmed, explicitly mention version verification is required.'
    : '';
  const descriptor = String(productDescriptor || '').trim();
  return `${String(prefix || '')}Task: Deep-scan this product for suitability vs the user's profile.\n` +
    `Return ONLY a JSON object with keys: assessment, evidence, confidence (0..1), missing_info (string[]).\n` +
    `assessment must include keys: verdict, summary, formula_intent, best_for, not_for, if_not_ideal, better_pairing, how_to_use, follow_up_question, reasons.\n` +
    `Field requirements:\n` +
    `- summary: 1-2 concise sentences.\n` +
    `- formula_intent: up to 3 bullets explaining product efficacy/mechanism; never repeat user profile text.\n` +
    `- best_for/not_for: concise fit or mismatch signals.\n` +
    `- if_not_ideal: immediate next actions when this product is not ideal.\n` +
    `- better_pairing: practical pairing suggestions (hydration/SPF/acne-focus depending on signals).\n` +
    `- follow_up_question: one high-value clarifying question.\n` +
    `Evidence must include science/social_signals/expert_notes.\n` +
    `${strictLine ? `${strictLine}\n` : ''}` +
    `${versionLine ? `${versionLine}\n` : ''}` +
    `Product: ${descriptor}`;
}

function buildProductDeepScanPromptV3({
  prefix = '',
  productDescriptor = '',
  strictFormulaIntent = false,
  strictNarrative = false,
  includeVersionReminder = false,
  anchorResolved = true,
} = {}) {
  const descriptor = String(productDescriptor || '').trim();
  const systemLines = [
    'You are an objective skincare product analyst.',
    'Output MUST be a single valid JSON object. No markdown, no extra keys, no commentary outside the JSON.',
    'Goal: evaluate product fit, risk, and usage against the user profile using grounded product-level reasoning.',
    'Use only the supplied product/context signals. Do NOT invent brands, sources, formulas, or ingredient certainty.',
    'Keep every field additive and non-repetitive. Do not echo the user profile as filler.',
    'Output contract:',
    '- Top-level keys: assessment, evidence, confidence, missing_info.',
    '- assessment must include keys: verdict, summary, formula_intent, best_for, not_for, if_not_ideal, better_pairing, how_to_use, follow_up_question, reasons.',
    '- evidence must include science, social_signals, expert_notes.',
    'Field requirements:',
    '- summary: 1-2 concise sentences focused on product efficacy/risk/use-case; never start with user profile labels.',
    '- formula_intent: up to 3 bullets explaining product efficacy/mechanism; never repeat user profile text.',
    '- best_for/not_for: concise fit or mismatch signals.',
    '- if_not_ideal: immediate next actions when this product is not ideal.',
    '- better_pairing: practical pairing suggestions (hydration/SPF/acne-focus depending on signals).',
    '- how_to_use: object with timing, frequency, steps[], observation_window, stop_signs[].',
    '- follow_up_question: one high-value clarifying question.',
    'Missing-data policy:',
    '- If evidence is incomplete, use missing_info[] plus cautious wording instead of guessing.',
    '- If product version cannot be confirmed, explicitly mention version verification is required.',
    '- If formula details are uncertain, keep ingredient-specific claims conservative.',
    'Hard rules:',
    '1. Do NOT return empty how_to_use objects or move follow_up_question into how_to_use.',
    '2. Do NOT repeat the same point across summary, formula_intent, reasons, and better_pairing.',
    '3. Do NOT fabricate scientific sources, clinical proof, or precise ingredient percentages.',
    '4. If the product is SPF/sunscreen, keep usage guidance daytime-only; do NOT suggest PM-first or 2-3 nights/week intro schedules.',
    '5. If the product category is already identifiable (for example cleanser, moisturizer, or sunscreen), do NOT default to "Unknown" only because full INCI is incomplete. Give a cautious category-level provisional judgment and clearly label the remaining uncertainty.',
  ];
  if (strictFormulaIntent || strictNarrative) {
    systemLines.push('6. If formula_intent is missing or profile-only, rewrite once using product efficacy/mechanism details only.');
  }
  if (strictNarrative) {
    systemLines.push(
      'Narrative quality gate (must pass):',
      '- summary must stay product-level (efficacy/risk/use-case), never user-profile recap.',
      '- Disallowed summary phrases: "Your profile", "Profile priorities", "你的情况", "匹配点".',
      '- how_to_use must be an object with keys: timing, frequency, steps (array), observation_window, stop_signs (array).',
      '- Do NOT return empty how_to_use objects or move follow_up_question into how_to_use.',
    );
  }
  if (!anchorResolved) {
    systemLines.push(
      'CRITICAL - No anchor product was resolved from catalog:',
      '- Do NOT guess or assume a specific brand or product SKU.',
      '- Do NOT map the user input to well-known products (e.g. do NOT default to SkinCeuticals C E Ferulic for "vitamin C serum").',
      '- Analyze based on the product CATEGORY and described FUNCTION only.',
      '- Do NOT populate anchor_product in the response.',
      '- hero_ingredient should describe the ingredient class (e.g. "vitamin C derivative"), not a specific product formulation.',
      '- Keep summary, formula_intent, and reasons generic to the product category, not specific to any brand.',
    );
  }

  const schemaDescription = `{
  "assessment": {
    "verdict": string,
    "summary": string,
    "formula_intent": string[],
    "best_for": string[],
    "not_for": string[],
    "if_not_ideal": string[],
    "better_pairing": string[],
    "how_to_use": {
      "timing": string,
      "frequency": string,
      "steps": string[],
      "observation_window": string,
      "stop_signs": string[]
    },
    "follow_up_question": string,
    "reasons": string[]
  },
  "evidence": {
    "science": object,
    "social_signals": object,
    "expert_notes": string[]
  },
  "confidence": number,
  "missing_info": string[]
}`;

  return `${String(prefix || '')}[SYSTEM]\n${systemLines.join('\n')}\n[/SYSTEM]\n` +
    `Task: Deep-scan this product for suitability vs the user's profile. Return ONLY a JSON object matching this schema:\n${schemaDescription}\n` +
    `Product: ${descriptor}`;
}

function buildProductDeepScanPromptV4({
  prefix = '',
  productDescriptor = '',
  productType = null,
  inciStatus = null,
  usageOverrides = null,
  anchorResolved = true,
} = {}) {
  const descriptor = String(productDescriptor || '').trim();
  const pType = String(productType || 'other').trim();
  const inciExtraction = String(inciStatus?.extraction || 'unknown');
  const inciConsensusTier = String(inciStatus?.consensus_tier || 'unknown');
  const inciVerificationRequired = Boolean(inciStatus?.verification_required);
  const totalIngredients = Number(inciStatus?.total_ingredients || 0);
  const overrides = usageOverrides && typeof usageOverrides === 'object' ? usageOverrides : {};

  const systemBlock = [
    'You are an objective skincare product analyst.',
    'Output MUST be a single valid JSON object. No markdown, no extra keys, no commentary outside the JSON.',
    'Be specific, non-repetitive, and data-bound. Distinguish CONFIRMED facts (verified INCI/source) from UNVERIFIED claims.',
    'Do NOT repeat information across fields. Each field must add unique value.',
    'If data is insufficient, state it once in data_quality_banner and proceed with best available evidence.',
    'Hard rules:',
    '1. No repetition across top_takeaways, watchouts, how_to_use, or evidence fields.',
    `2. Product type: ${pType}. If type is spf or spf_moisturizer: how_to_use.when MUST be "am", frequency MUST be "daily", include reapplication guidance. Do NOT suggest "start 2-3 nights/week" or "pm first".`,
    '3. If consensus_tier is low or verification_required is true: verdict_level MUST be "needs_verification" or "cautiously_ok". Do NOT return "recommended".',
    '4. Do NOT use placeholder strings as ingredient names.',
    `5. Fragrance/parfum risk: ONLY mark as confirmed when INCI is verified AND contains fragrance/parfum/known allergens. INCI verified: ${!inciVerificationRequired}.`,
    '6. watchouts items MUST have: {issue: string, status: "confirmed"|"possible", what_to_do: string}.',
    '   - Use "confirmed" when INCI is verified AND the ingredient is present in the list.',
    '   - Use "possible" for all other watchouts -- when there is textual evidence, brand claims, known ingredient categories, or LLM knowledge even if INCI is not fully cross-verified.',
    '   - Do NOT use "unknown" -- if there is enough evidence to raise a watchout, there is enough to call it "possible".',
    '7. key_ingredients_by_function items MUST have: {function: string, ingredients: string[], confidence: "high"|"medium"|"low"}.',
    '8. If product type is cleanser, moisturizer, spf, or spf_moisturizer, do NOT return verdict="Unknown" solely because full INCI is not verified. Use a cautious category-level provisional verdict plus explicit uncertainty.',
    ...(!anchorResolved
      ? [
          '9. Do NOT guess or assume a specific brand or SKU when no catalog anchor is resolved.',
          '10. Do NOT populate anchor_product in the response.',
          '11. Keep the analysis generic to the product category/function, not a specific product formulation.',
        ]
      : []),
  ].join('\n');

  const schemaDescription = `{
  "assessment": {
    "verdict": string,
    "verdict_level": "recommended"|"cautiously_ok"|"needs_verification"|"not_recommended",
    "data_quality_banner": string|null,
    "top_takeaways": string[],
    "best_for": string[],
    "watchouts": [{issue: string, status: "confirmed"|"possible", what_to_do: string}],
    "how_to_use": {
      "when": string,
      "frequency": string,
      "order_in_routine": string,
      "pairing_rules": string[],
      "stop_signs": string[]
    }
  },
  "evidence": {
    "product_type_reasoning": string,
    "key_functions": string[],
    "key_ingredients_by_function": [{function: string, ingredients: string[], confidence: "high"|"medium"|"low"}],
    "social_signals": {typical_positive: string[], typical_negative: string[]},
    "sources": string[]
  },
  "confidence": number,
  "missing_info": string[]
}`;

  const inciContext = inciStatus
    ? `INCI Status: extraction=${inciExtraction}, consensus_tier=${inciConsensusTier}, ` +
      `verification_required=${inciVerificationRequired}, total_ingredients=${totalIngredients}. ` +
      (inciVerificationRequired
        ? 'INCI not fully verified — qualify all watchout risks as "possible", not "confirmed". Do NOT use "unknown" status. '
        : 'INCI verified — confirmed risk claims are acceptable. ')
    : '';

  const overridesContext = Object.keys(overrides).length
    ? `Usage overrides for ${pType}: ${JSON.stringify(overrides)}. ` +
      (overrides.suppress_pm_first ? 'Do NOT suggest PM-first application. ' : '') +
      (overrides.suppress_2_3x_week ? 'Do NOT suggest 2-3x/week frequency. ' : '') +
      (overrides.reapply_guidance ? 'Include reapplication guidance (every 2h when outdoors). ' : '')
    : '';

  return `${String(prefix || '')}[SYSTEM]\n${systemBlock}\n[/SYSTEM]\n` +
    `Task: Deep-scan this product for suitability vs the user's profile. Return ONLY a JSON object matching this schema:\n${schemaDescription}\n` +
    'Context:\n' +
    `- Product type: ${pType}\n` +
    (inciContext ? `- ${inciContext}\n` : '') +
    (overridesContext ? `- ${overridesContext}\n` : '') +
    `Product: ${descriptor}`;
}

function buildProductDeepScanPrompt({
  prefix = '',
  productDescriptor = '',
  strictFormulaIntent = false,
  strictNarrative = false,
  includeVersionReminder = false,
  productType = null,
  inciStatus = null,
  usageOverrides = null,
  anchorResolved = true,
} = {}) {
  if (AURORA_PRODUCT_INTEL_PROMPT_VERSION === 'v2') {
    return buildProductDeepScanPromptV2({
      prefix,
      productDescriptor,
      strictFormulaIntent,
      includeVersionReminder,
    });
  }
  if (AURORA_PRODUCT_INTEL_PROMPT_VERSION === 'v4') {
    return buildProductDeepScanPromptV4({
      prefix,
      productDescriptor,
      productType,
      inciStatus,
      usageOverrides,
      anchorResolved,
    });
  }
  return buildProductDeepScanPromptV3({
    prefix,
    productDescriptor,
    strictFormulaIntent,
    strictNarrative,
    includeVersionReminder,
    anchorResolved,
  });
}

function buildRoutineFitSummaryPrompt({
  prefix = '',
  skinProfile = null,
  ingredientPlan = null,
  routineProducts = [],
  language = 'EN',
} = {}) {
  const isCn = language === 'CN';
  const systemBlock = [
    isCn
      ? '你是一个护肤分析师。根据用户的皮肤分析结果和当前护肤流程，评估整体匹配度。'
      : 'You are a skincare analyst. Evaluate how well the user\'s current routine matches their skin analysis results.',
    'Output MUST be a single valid JSON object. No markdown, no extra keys, no commentary outside the JSON.',
    isCn
      ? '不要逐个分析产品，而是作为整体评估 routine 对皮肤状态的匹配度。'
      : 'Do NOT analyze products individually. Evaluate the routine as a whole against the skin profile.',
    'Hard rules:',
    '1. Be concise — each string field max 1-2 sentences.',
    '2. highlights and concerns arrays: max 3 items each.',
    '3. next_questions: suggest 2-3 follow-up questions the user might want to ask.',
  ].join('\n');

  const skinCtx = [];
  if (skinProfile) {
    if (skinProfile.skin_type_tendency) skinCtx.push(`skin_type: ${skinProfile.skin_type_tendency}`);
    if (skinProfile.sensitivity_tendency) skinCtx.push(`sensitivity: ${skinProfile.sensitivity_tendency}`);
  }
  if (ingredientPlan) {
    const targets = Array.isArray(ingredientPlan.targets)
      ? ingredientPlan.targets.slice(0, 5).map((t) => `${t.ingredient_name || t.ingredient_id} (${t.role || 'support'})`).join(', ')
      : '';
    const avoid = Array.isArray(ingredientPlan.avoid)
      ? ingredientPlan.avoid.map((a) => a.ingredient_name || a.ingredient_id).join(', ')
      : '';
    if (targets) skinCtx.push(`recommended_ingredients: ${targets}`);
    if (avoid) skinCtx.push(`avoid: ${avoid}`);
  }

  const routineLines = routineProducts.map((p, i) => {
    const slot = p.slot || '';
    const step = p.step || '';
    const text = p.product_text || '';
    return `  ${i + 1}. [${slot}/${step}] ${text}`;
  }).join('\n');

  const schema = `{
  "overall_fit": "good_match"|"partial_match"|"needs_adjustment",
  "fit_score": number (0.0-1.0),
  "summary": string,
  "highlights": string[] (max 3),
  "concerns": string[] (max 3),
  "dimension_scores": {
    "ingredient_match": {"score": number, "note": string},
    "routine_completeness": {"score": number, "note": string},
    "conflict_risk": {"score": number, "note": string},
    "sensitivity_safety": {"score": number, "note": string}
  },
  "next_questions": string[] (max 3)
}`;

  return `${String(prefix || '')}[SYSTEM]\n${systemBlock}\n[/SYSTEM]\n` +
    `Task: Evaluate this routine as a whole against the user's skin analysis. Return ONLY JSON matching:\n${schema}\n\n` +
    `Skin analysis context:\n${skinCtx.length ? skinCtx.join('\n') : '(no analysis available)'}\n\n` +
    `Current routine (${routineProducts.length} products):\n${routineLines || '(empty)'}`;
}

