const PRODUCT_INTEL_SEARCH_URL_RE =
  /(google\.[^/]+\/search\?|reddit\.com\/search\/\?|amazon\.[^/]+\/s\?k=|bing\.com\/search\?|duckduckgo\.com\/\?q=|baidu\.com\/s\?wd=|youtube\.com\/results\?search_query=)/i;
const PRODUCT_INTEL_HTTP_URL_RE = /^https?:\/\/\S+/i;

