function pickFirstString(...values) {
  for (const value of values) {
    const token = String(value || '').trim();
    if (token) return token;
  }
  return '';
}

function hasFilledRoutineRows(rows) {
  return rows.some((row) => {
    if (!row) return false;
    if (typeof row === 'string') return Boolean(String(row).trim());
    if (!isPlainObject(row)) return false;
    return Boolean(
      String(row.product || '').trim() ||
      String(row.name || '').trim() ||
      String(row.step || '').trim() ||
      String(row.ingredient || '').trim()
    );
  });
}

function tryParseRoutineObject(value) {
  const normalized = normalizeRoutineInputWithPmShortcut(value);
  return isPlainObject(normalized) ? normalized : null;
}

function hasRoutineData(profile) {
  const profileState = normalizeRoutineStateFromProfile(profile);
  if (profileState.has_current_routine) return true;
  const p = isPlainObject(profile) ? profile : {};
  const routine = tryParseRoutineObject(p.currentRoutine) || tryParseRoutineObject(p.current_routine);
  if (!routine) return false;
  const am = Array.isArray(routine.am) ? routine.am : Array.isArray(routine.am_steps) ? routine.am_steps : [];
  const pm = Array.isArray(routine.pm) ? routine.pm : Array.isArray(routine.pm_steps) ? routine.pm_steps : [];
  return hasFilledRoutineRows(am) || hasFilledRoutineRows(pm);
}

function deriveRoutineMissingFields(profile) {
  const profileState = normalizeRoutineStateFromProfile(profile);
  if (Array.isArray(profileState.missing_routine_fields) && profileState.missing_routine_fields.length) {
    return profileState.missing_routine_fields;
  }
  if (profileState.current_routine_struct) {
    return buildMissingRoutineFields(profileState.current_routine_struct);
  }
  const p = isPlainObject(profile) ? profile : {};
  const routine = tryParseRoutineObject(p.currentRoutine) || tryParseRoutineObject(p.current_routine);
  if (!routine) return ['currentRoutine.am', 'currentRoutine.pm'];
  const am = Array.isArray(routine.am) ? routine.am : Array.isArray(routine.am_steps) ? routine.am_steps : [];
  const pm = Array.isArray(routine.pm) ? routine.pm : Array.isArray(routine.pm_steps) ? routine.pm_steps : [];
  const missing = [];
  if (!hasFilledRoutineRows(am)) missing.push('currentRoutine.am');
  if (!hasFilledRoutineRows(pm)) missing.push('currentRoutine.pm');
  return missing;
}

function normalizeRoutineIntakeSlot(rawSlot) {
  const token = String(rawSlot || '').trim().toLowerCase();
  if (!token) return 'am';
  if (['am', 'morning', 'day', 'daytime', '早', '早上'].includes(token)) return 'am';
  if (['pm', 'night', 'evening', 'bedtime', '晚', '晚上'].includes(token)) return 'pm';
  return token.includes('pm') || token.includes('night') || token.includes('evening') ? 'pm' : 'am';
}

function normalizeRoutineIntakeStep(rawStep) {
  const token = String(rawStep || '').trim().toLowerCase();
  if (!token) return 'other';
  if (/(cleanser|cleanse|wash|face wash|洁面|洗面|清洁)/i.test(token)) return 'cleanser';
  if (/(treatment|active|serum|essence|retinol|acid|bha|aha|niacinamide|vitamin c|精华|活性|酸|维a|维A|烟酰胺|壬二酸)/i.test(token)) return 'treatment';
  if (/(moistur|cream|lotion|gel|balm|面霜|乳液|保湿|修护霜|凝霜)/i.test(token)) return 'moisturizer';
  if (/(spf|sunscreen|sun screen|uv|防晒)/i.test(token)) return 'spf';
  return token;
}

function extractFirstHttpUrlFromText(rawText) {
  const text = String(rawText || '').trim();
  if (!text) return '';
  const matched = text.match(/https?:\/\/[^\s)>\]}]+/i);
  if (!matched || !matched[0]) return '';
  const normalized = String(matched[0]).trim().replace(/[),.;!?]+$/g, '');
  return /^https?:\/\/\S+/i.test(normalized) ? normalized : '';
}

function buildRoutineProductParsedHint(entry, { inputText = '', inputUrl = '', inciHint = '' } = {}) {
  const row = isPlainObject(entry) ? entry : null;
  const url = String(inputUrl || '').trim();
  const brand = pickFirstTrimmed(row?.brand, row?.brand_name, row?.brandName);
  const name = pickFirstTrimmed(row?.name, row?.display_name, row?.displayName, row?.title);
  const skuId = pickFirstTrimmed(row?.sku_id, row?.skuId);
  const productId = pickFirstTrimmed(row?.product_id, row?.productId, skuId);
  const displayName = pickFirstTrimmed(row?.display_name, row?.displayName, joinBrandAndName(brand, name), name, inputText);
  const hint = {
    ...(productId ? { product_id: productId } : {}),
    ...(skuId ? { sku_id: skuId } : {}),
    ...(brand ? { brand } : {}),
    ...(name ? { name } : {}),
    ...(displayName ? { display_name: displayName } : {}),
    ...(url ? { url } : {}),
    ...(inciHint ? { inci: String(inciHint).trim().slice(0, 1400) } : {}),
    category: 'product',
  };
  return Object.keys(hint).length > 1 ? hint : null;
}

function buildRoutineProductCandidateFromRow(row, { slot, step, rank }) {
  const rowObj = isPlainObject(row) ? row : null;
  const rawText = typeof row === 'string'
    ? row
    : pickFirstTrimmed(
      rowObj?.product,
      rowObj?.name,
      rowObj?.display_name,
      rowObj?.displayName,
      rowObj?.title,
      rowObj?.text,
      rowObj?.value,
    );
  const cleanedText = String(rawText || '').trim();
  const explicitUrl = pickFirstTrimmed(
    rowObj?.url,
    rowObj?.link,
    rowObj?.href,
    rowObj?.product_url,
    rowObj?.productUrl,
    rowObj?.purchase_path,
    rowObj?.purchasePath,
  );
  const inferredUrl = extractFirstHttpUrlFromText(cleanedText);
  const productUrl = /^https?:\/\/\S+/i.test(explicitUrl)
    ? explicitUrl
    : /^https?:\/\/\S+/i.test(inferredUrl)
      ? inferredUrl
      : '';
  const inciHint = pickFirstTrimmed(
    rowObj?.inci,
    rowObj?.ingredients,
    rowObj?.ingredient_list,
    rowObj?.ingredientList,
    rowObj?.ingredients_text,
    rowObj?.ingredientsText,
  );
  const textWithoutUrl = productUrl ? cleanedText.replace(productUrl, ' ').replace(/\s+/g, ' ').trim() : cleanedText;
  const productText = String(textWithoutUrl || cleanedText || '').trim().slice(0, 520);
  const lowerText = productText.toLowerCase();
  if (!productText && !productUrl) return null;
  if (['none', 'n/a', 'na', 'skip', '无', '没有', '不使用', '不用'].includes(lowerText)) return null;

  const parsedProductHint = buildRoutineProductParsedHint(rowObj, {
    inputText: productText || productUrl,
    inputUrl: productUrl,
    inciHint,
  });
  return {
    slot: normalizeRoutineIntakeSlot(slot),
    step: normalizeRoutineIntakeStep(step || rowObj?.step || ''),
    rank: Number.isFinite(Number(rank)) ? Math.trunc(Number(rank)) : 0,
    product_text: productText || productUrl,
    product_url: productUrl,
    inci_hint: inciHint ? String(inciHint).trim().slice(0, 1400) : '',
    parsed_product_hint: parsedProductHint,
  };
}

function extractRoutineProductCandidatesForDeepScan(routineInput, { maxTotal = AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT } = {}) {
  const routine = tryParseRoutineObject(routineInput) ||
    (isPlainObject(routineInput) ? routineInput : null);
  if (!routine) return [];

  const out = [];
  const seen = new Set();
  const slotOrder = { am: 0, pm: 1 };
  const stepOrder = {
    cleanser: 0,
    toner: 1,
    treatment: 2,
    essence: 3,
    moisturizer: 4,
    spf: 5,
    sunscreen: 5,
    other: 9,
  };

  const addCandidate = (candidate) => {
    const row = candidate && typeof candidate === 'object' ? candidate : null;
    if (!row || !row.product_text) return;
    const key = [
      row.slot || '',
      row.step || '',
      String(row.product_url || '').toLowerCase(),
      String(row.product_text || '').toLowerCase(),
    ].join('|');
    if (!key || seen.has(key)) return;
    seen.add(key);
    out.push(row);
  };

  const consumeRow = (row, { slot, step, rank }) => {
    const candidate = buildRoutineProductCandidateFromRow(row, { slot, step, rank });
    if (!candidate) return;
    addCandidate(candidate);
  };

  const consumeStepObject = (obj, { slot, baseRank = 0 }) => {
    const rowObj = isPlainObject(obj) ? obj : null;
    if (!rowObj) return;
    const keys = Object.keys(rowObj);
    const looksLikeSingleProductRow =
      keys.some((k) => ['product', 'name', 'display_name', 'displayName', 'url', 'link', 'href'].includes(String(k || ''))) ||
      keys.includes('step');
    if (looksLikeSingleProductRow) {
      consumeRow(rowObj, {
        slot,
        step: rowObj.step || rowObj.role || 'other',
        rank: baseRank,
      });
      return;
    }
    let offset = 0;
    for (const [rawStep, rawValue] of Object.entries(rowObj)) {
      if (rawValue == null) continue;
      if (typeof rawValue === 'string') {
        consumeRow({ product: rawValue }, { slot, step: rawStep, rank: baseRank + offset });
        offset += 1;
        continue;
      }
      if (Array.isArray(rawValue)) {
        rawValue.forEach((entry, idx) => {
          consumeRow(entry, { slot, step: rawStep, rank: baseRank + offset + idx });
        });
        offset += rawValue.length;
        continue;
      }
      if (isPlainObject(rawValue)) {
        consumeRow(rawValue, { slot, step: rawStep, rank: baseRank + offset });
        offset += 1;
      }
    }
  };

  const slotSources = [
    { slot: 'am', keys: ['am', 'am_steps', 'morning'] },
    { slot: 'pm', keys: ['pm', 'pm_steps', 'evening', 'night'] },
  ];
  let rankCounter = 0;
  for (const source of slotSources) {
    for (const key of source.keys) {
      const value = routine[key];
      if (value == null) continue;
      if (Array.isArray(value)) {
        value.forEach((entry, idx) => consumeRow(entry, { slot: source.slot, step: isPlainObject(entry) ? entry.step : '', rank: rankCounter + idx }));
        rankCounter += value.length;
        continue;
      }
      if (typeof value === 'string') {
        consumeRow({ product: value }, { slot: source.slot, step: 'other', rank: rankCounter });
        rankCounter += 1;
        continue;
      }
      consumeStepObject(value, { slot: source.slot, baseRank: rankCounter });
      rankCounter += 4;
    }
  }

  // Fallback: some clients may send a flat array/object outside am/pm.
  if (!out.length) {
    if (Array.isArray(routineInput)) {
      routineInput.forEach((entry, idx) => {
        const slot = isPlainObject(entry) ? entry.slot || entry.period || 'am' : 'am';
        consumeRow(entry, { slot, step: isPlainObject(entry) ? entry.step || 'other' : 'other', rank: idx });
      });
    } else if (isPlainObject(routineInput)) {
      consumeStepObject(routineInput, { slot: 'am', baseRank: 0 });
    }
  }

  const capped = out
    .sort((a, b) => {
      const slotCmp = (slotOrder[a.slot] ?? 8) - (slotOrder[b.slot] ?? 8);
      if (slotCmp !== 0) return slotCmp;
      const stepCmp = (stepOrder[a.step] ?? 9) - (stepOrder[b.step] ?? 9);
      if (stepCmp !== 0) return stepCmp;
      return (a.rank || 0) - (b.rank || 0);
    })
    .slice(0, Math.max(1, Math.min(40, Number(maxTotal) || AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT)));
  return capped;
}

function buildRoutineProductAnalysisFallbackPayload({
  language = 'EN',
  candidate = null,
  parsedProduct = null,
  reasonCodes = [],
} = {}) {
  const isCn = String(language || '').toUpperCase() === 'CN';
  const row = candidate && typeof candidate === 'object' ? candidate : {};
  const productName = String(row.product_text || '').trim();
  const missingInfo = Array.from(
    new Set([
      'routine_product_deepscan_degraded',
      'version_verification_needed',
      ...(Array.isArray(reasonCodes) ? reasonCodes : []),
    ].filter(Boolean)),
  );
  const stepLabel = normalizeRoutineIntakeStep(row.step || '');
  const slotLabel = normalizeRoutineIntakeSlot(row.slot || '');
  const timingLabel = isCn
    ? slotLabel === 'pm'
      ? '建议先在夜间低频测试。'
      : '建议先在白天小面积测试。'
    : slotLabel === 'pm'
      ? 'Start with a low-frequency PM patch test.'
      : 'Start with a small daytime patch test.';
  const actionLine = isCn
    ? `先从${stepLabel || '当前步骤'}保守用法开始：2-3 次/周，出现持续刺痛或泛红请暂停并只做修护。`
    : `Use a conservative ${stepLabel || 'current-step'} cadence first: 2-3x/week, and pause if stinging or redness persists.`;

  return {
    assessment: {
      verdict: isCn ? '未知' : 'Unknown',
      reasons: [
        isCn
          ? `暂时无法对「${productName || '该产品'}」完成完整成分判定，我先给你可执行的保守方案。`
          : `I cannot complete a full ingredient-level verdict for "${productName || 'this product'}" right now, so here is a conservative plan.`,
        actionLine,
      ],
      how_to_use: {
        timing: timingLabel,
        frequency: isCn ? '先从每周 2-3 次开始' : 'Start at 2-3 times per week',
        notes: [
          isCn
            ? '若刺痛/发红持续超过 5-10 分钟，暂停该产品并仅保留温和清洁+保湿。'
            : 'If stinging/redness lasts beyond 5-10 minutes, pause this product and keep only gentle cleansing + moisturizer.',
          isCn
            ? '产品版本可能因地区不同而变化，建议核对包装 INCI。'
            : 'Formula may vary by region/version; verify the package INCI.',
        ],
      },
      ...(parsedProduct && typeof parsedProduct === 'object' ? { anchor_product: parsedProduct } : {}),
    },
    evidence: {
      science: { key_ingredients: [], mechanisms: [], fit_notes: [], risk_notes: [] },
      social_signals: { typical_positive: [], typical_negative: [], risk_for_groups: [] },
      expert_notes: [
        isCn ? '当前为降级分析结果（证据不足）。' : 'Degraded analysis result (insufficient evidence).',
      ],
      confidence: 0.32,
      missing_info: ['evidence_missing', ...missingInfo].slice(0, 8),
    },
    confidence: 0.32,
    missing_info: missingInfo,
  };
}

async function deepScanRoutineProductCandidate({
  candidate,
  ctx,
  profileSummary,
  recentLogsSummary = [],
  logger,
  includeCard = true,
} = {}) {
  const row = candidate && typeof candidate === 'object' ? candidate : null;
  if (!row) return { card: null, backfilled: false, failure_reason: 'candidate_missing' };
  const lang = String(ctx && ctx.lang ? ctx.lang : 'EN').toUpperCase() === 'CN' ? 'CN' : 'EN';
  const routineAnchorGuardMode = String(process.env.AURORA_ROUTINE_AUTOSCAN_ANCHOR_GUARD_MODE || '').trim().toLowerCase();
  const routineStrictNonSkincareGuard = routineAnchorGuardMode === 'strict_non_skincare';
  const inputText = String(row.product_text || '').trim();
  const productUrl = /^https?:\/\/\S+/i.test(String(row.product_url || '').trim()) ? String(row.product_url || '').trim() : '';
  if (!inputText && !productUrl) return { card: null, backfilled: false, failure_reason: 'product_input_missing' };

  const profileCtx = isPlainObject(profileSummary) ? profileSummary : {};
  const logsCtx = Array.isArray(recentLogsSummary) ? recentLogsSummary.slice(0, 7) : [];
  const frontendResolvedCandidateRaw = isPlainObject(row.resolved_product) ? { ...row.resolved_product } : null;
  const frontendResolvedId = pickFirstTrimmed(row.resolved_product_id, row.resolvedProductId);
  if (
    frontendResolvedCandidateRaw &&
    frontendResolvedId &&
    !pickFirstTrimmed(
      frontendResolvedCandidateRaw.product_id,
      frontendResolvedCandidateRaw.productId,
      frontendResolvedCandidateRaw.sku_id,
      frontendResolvedCandidateRaw.skuId,
    )
  ) {
    frontendResolvedCandidateRaw.product_id = frontendResolvedId;
  }
  const frontendResolvedAnchor = frontendResolvedCandidateRaw
    ? (
      mapCatalogProductToAnchorProduct(frontendResolvedCandidateRaw, { fallbackName: inputText }) ||
      buildAnchorDisplayFromCandidate(frontendResolvedCandidateRaw, { fallbackName: inputText, fallbackUrl: productUrl })
    )
    : null;
  let parsedProduct =
    frontendResolvedAnchor ||
    (isPlainObject(row.parsed_product_hint) ? { ...row.parsed_product_hint } : null);
  if (!parsedProduct && productUrl) {
    parsedProduct = buildHeuristicProductFromInput({ inputText, inputUrl: productUrl });
  }
  let anchorId = '';
  let routineAnchorTrustContext = {
    level: 'none',
    usable_for_anchor_id: false,
    reasons: [],
    source: 'none',
    candidate_quality: 'none',
    url_consistency: null,
  };
  const applyRoutineAnchorGuard = (candidate, source, { preferDisplay = false } = {}) => {
    const trust = evaluateAnchorTrustForProductIntel({
      candidate,
      inputText,
      inputUrl: productUrl,
      source,
      strictFilter: AURORA_PRODUCT_STRICT_SKINCARE_FILTER,
    });
    const trustCodes = Array.isArray(trust.reason_codes) ? trust.reason_codes : [];
    const nonSkincareSoftBlocked = trustCodes.includes('anchor_soft_blocked_non_skincare');
    if (trust.display_anchor && !nonSkincareSoftBlocked && (!parsedProduct || preferDisplay || trust.usable_for_anchor_id)) {
      parsedProduct = trust.display_anchor;
    }
    if (trust.usable_for_anchor_id && trust.trusted_anchor) {
      parsedProduct = trust.trusted_anchor;
      anchorId = pickFirstTrimmed(trust.trusted_anchor.sku_id, trust.trusted_anchor.product_id) || anchorId;
    }
    if (trust.trust_level === 'trusted' || (routineAnchorTrustContext.level !== 'trusted' && trust.trust_level !== 'none')) {
      routineAnchorTrustContext = {
        level: String(trust.trust_level || 'none'),
        usable_for_anchor_id: trust.usable_for_anchor_id === true,
        reasons: trustCodes.slice(0, 6),
        source: String(source || 'unknown'),
        candidate_quality: String(trust.candidate_quality || 'none'),
        url_consistency: Number.isFinite(Number(trust.url_consistency)) ? Number(trust.url_consistency) : null,
      };
    }
    return trust;
  };
  applyRoutineAnchorGuard(
    parsedProduct,
    frontendResolvedAnchor ? 'frontend_resolved' : 'routine_candidate_hint',
    { preferDisplay: true },
  );

  let primaryAnchorResolution = null;
  if (!anchorId && inputText) {
    primaryAnchorResolution = await resolvePrimaryAnalyzeAnchorForProductInput({
      inputText,
      inputUrl: productUrl || null,
      parsedProduct: routineAnchorTrustContext.usable_for_anchor_id === true ? parsedProduct : null,
      lang,
      logger,
    });
    if (primaryAnchorResolution && primaryAnchorResolution.ok && primaryAnchorResolution.product) {
      const resolvedAnchor = mapCatalogProductToAnchorProduct(primaryAnchorResolution.product, { fallbackName: inputText });
      applyRoutineAnchorGuard(resolvedAnchor, 'routine_catalog_primary_resolve');
    }
  }

  let catalogFallback = null;
  if (!anchorId && PRODUCT_INTEL_CATALOG_FALLBACK_ENABLED && inputText) {
    catalogFallback = await resolveCatalogProductForProductInput({
      inputText,
      inputUrl: productUrl || null,
      parsedProduct: routineAnchorTrustContext.usable_for_anchor_id === true ? parsedProduct : null,
      lang,
      logger,
    });
    if (catalogFallback && catalogFallback.ok && catalogFallback.product) {
      const fallbackAnchor = mapCatalogProductToAnchorProduct(catalogFallback.product, { fallbackName: inputText });
      applyRoutineAnchorGuard(fallbackAnchor, 'routine_catalog_fallback');
    }
  }

  const routineDescriptorAnchor = routineAnchorTrustContext.usable_for_anchor_id === true ? parsedProduct : null;
  const productDescriptor = buildProductInputText(routineDescriptorAnchor, productUrl) || inputText || productUrl;
  const routineInciList = canonicalizeIngredientCandidates(
    [
      ...(Array.isArray(routineDescriptorAnchor?.ingredients) ? routineDescriptorAnchor.ingredients : []),
      ...(Array.isArray(routineDescriptorAnchor?.inci_list) ? routineDescriptorAnchor.inci_list : []),
      ...(Array.isArray(routineDescriptorAnchor?.inciList) ? routineDescriptorAnchor.inciList : []),
      ...(Array.isArray(parsedProduct?.ingredients) ? parsedProduct.ingredients : []),
      ...(Array.isArray(parsedProduct?.inci_list) ? parsedProduct.inci_list : []),
      ...(Array.isArray(parsedProduct?.inciList) ? parsedProduct.inciList : []),
    ],
    { max: 160 },
  );
  const routineProductClassification = classifyProductType({
    name: String(routineDescriptorAnchor?.name || routineDescriptorAnchor?.display_name || inputText || ''),
    url: String(productUrl || routineDescriptorAnchor?.url || ''),
    inciList: routineInciList,
  });
  const routineInciStatus = isPlainObject(routineDescriptorAnchor?.inci_status) ? routineDescriptorAnchor.inci_status : null;
  const routinePromptOptions = {
    productType: routineProductClassification.product_type,
    usageOverrides: routineProductClassification.usage_overrides,
    ...(routineInciStatus ? { inciStatus: routineInciStatus } : {}),
  };
  const contextPrefix = buildContextPrefix({
    profile: profileCtx,
    recentLogs: logsCtx,
    lang,
    state: 'S4_ANALYSIS_LOADING',
    trigger_source: 'routine_autoscan',
    intent: 'routine_product_analyze',
    action_id: 'routine.autoscan.product_analyze',
  });
  const deepScanQuery = buildProductDeepScanPrompt({
    prefix: contextPrefix,
    productDescriptor,
    includeVersionReminder: true,
    ...routinePromptOptions,
  });

  const routinePrimaryLlmRoute = resolveProductIntelLlmRoute({});
  let routineLlmRouteMeta = {
    stage: 'stage_1',
    provider: routinePrimaryLlmRoute.llm_provider || null,
    model: routinePrimaryLlmRoute.llm_model || null,
    trigger_reason: 'primary',
  };

  const runDeepScan = async (queryText, timeoutMs, llmRouteOverride = null) => {
    const effectiveRoute =
      llmRouteOverride && typeof llmRouteOverride === 'object' && !Array.isArray(llmRouteOverride)
        ? llmRouteOverride
        : routinePrimaryLlmRoute;
    try {
      return await auroraChat({
        baseUrl: AURORA_DECISION_BASE_URL,
        query: queryText,
        timeoutMs,
        ...(anchorId ? { anchor_product_id: String(anchorId) } : {}),
        ...(productUrl ? { anchor_product_url: productUrl } : {}),
        ...(effectiveRoute.llm_provider ? { llm_provider: effectiveRoute.llm_provider } : {}),
        ...(effectiveRoute.llm_model ? { llm_model: effectiveRoute.llm_model } : {}),
      });
    } catch {
      return null;
    }
  };

  let norm = { payload: null, field_missing: [] };
  let realtimeUrlNormMeta = null;
  try {
    let upstream = await runDeepScan(deepScanQuery, AURORA_ROUTINE_PRODUCT_AUTOSCAN_TIMEOUT_MS);
    norm = normalizeProductAnalysisFromUpstream(upstream);
      if (!norm.payload?.assessment) {
      const minimalPrefix = buildContextPrefix({
        lang,
        state: 'S4_ANALYSIS_LOADING',
        trigger_source: 'routine_autoscan',
        intent: 'routine_product_analyze_fallback',
        action_id: 'routine.autoscan.product_analyze_fallback',
      });
      const minimalQuery = buildProductDeepScanPrompt({
        prefix: minimalPrefix,
        productDescriptor,
        includeVersionReminder: true,
        ...routinePromptOptions,
      });
        const upstreamRetry = await runDeepScan(minimalQuery, Math.max(1200, AURORA_ROUTINE_PRODUCT_AUTOSCAN_TIMEOUT_MS - 600));
        const retryNorm = normalizeProductAnalysisFromUpstream(upstreamRetry);
        if (retryNorm.payload?.assessment) norm = retryNorm;
      }

      if (shouldRetryForNarrativeQuality(norm.payload)) {
        const formulaRetryQuery = buildProductDeepScanPrompt({
          prefix: contextPrefix,
          productDescriptor,
          strictNarrative: true,
          includeVersionReminder: true,
          ...routinePromptOptions,
        });
        const formulaRetryUpstream = await runDeepScan(
          formulaRetryQuery,
          Math.max(9000, Math.min(17000, AURORA_ROUTINE_PRODUCT_AUTOSCAN_TIMEOUT_MS + 1500)),
        );
        const formulaRetryNorm = normalizeProductAnalysisFromUpstream(formulaRetryUpstream);
        const retryCodes = collectNarrativeRetryCodes(norm.payload, formulaRetryNorm.payload);
        if (
          hasValidNarrativeQuality(formulaRetryNorm.payload) &&
          (retryCodes.length || isProductIntelPayloadCandidateBetter(formulaRetryNorm.payload, norm.payload))
        ) {
          norm = {
            payload: applyProductAnalysisGapContract({
              ...formulaRetryNorm.payload,
              internal_debug_codes: uniqCaseInsensitiveStrings(
                [...getProductAnalysisInternalMissingCodes(formulaRetryNorm.payload), ...retryCodes],
                32,
              ),
            }),
            field_missing: mergeFieldMissing(formulaRetryNorm.field_missing, norm.field_missing),
          };
        }
      }

      const routineEscalationRoute = resolveProductIntelEscalationRoute({});
      const routineEscalationAvailable =
        routineEscalationRoute &&
        routineEscalationRoute.llm_provider &&
        routineEscalationRoute.llm_model &&
        (
          String(routineEscalationRoute.llm_provider || '').trim().toLowerCase() !==
            String(routinePrimaryLlmRoute.llm_provider || '').trim().toLowerCase() ||
          String(routineEscalationRoute.llm_model || '').trim() !== String(routinePrimaryLlmRoute.llm_model || '').trim()
        );
      if (routineEscalationAvailable && shouldTriggerProductIntelEscalation(norm.payload)) {
        const escalatedUpstream = await runDeepScan(
          deepScanQuery,
          Math.max(9000, Math.min(18000, AURORA_CHAT_UPSTREAM_TIMEOUT_MS)),
          routineEscalationRoute,
        );
        const escalatedNorm = normalizeProductAnalysisFromUpstream(escalatedUpstream);
        if (isProductIntelPayloadCandidateBetter(escalatedNorm.payload, norm.payload)) {
          const escalatedCodes = getProductAnalysisInternalMissingCodes(escalatedNorm.payload);
          norm = {
            payload: applyProductAnalysisGapContract({
              ...escalatedNorm.payload,
              internal_debug_codes: uniqCaseInsensitiveStrings(
                [...escalatedCodes, 'llm_escalation_stage2_used'],
                32,
              ),
            }),
            field_missing: mergeFieldMissing(escalatedNorm.field_missing, norm.field_missing),
          };
          routineLlmRouteMeta = {
            stage: String(routineEscalationRoute.stage || 'stage_2'),
            provider: routineEscalationRoute.llm_provider || null,
            model: routineEscalationRoute.llm_model || null,
            trigger_reason: String(routineEscalationRoute.trigger_reason || 'unknown_low_evidence'),
          };
        }
      }

      const needsUrlIngredientAnalysis = (() => {
      const assessment = isPlainObject(norm.payload?.assessment) ? norm.payload.assessment : null;
      if (!assessment) return true;
      const verdict = String(assessment.verdict || '').trim().toLowerCase();
      return !verdict || verdict === 'unknown' || verdict === '未知';
    })();
    if (PRODUCT_URL_INGREDIENT_ANALYSIS_ENABLED && needsUrlIngredientAnalysis && productUrl) {
      const urlNorm = await buildProductAnalysisFromUrlIngredients({
        productUrl,
        lang,
        profileSummary: profileCtx,
        parsedProduct: routineDescriptorAnchor,
        logger,
      });
      if (urlNorm && urlNorm.payload && urlNorm.payload.assessment) {
        realtimeUrlNormMeta = urlNorm.source_meta || null;
        const mergedMissingInfo = Array.from(
          new Set([
            ...(Array.isArray(norm?.payload?.missing_info) ? norm.payload.missing_info : []),
            ...(Array.isArray(urlNorm.payload.missing_info) ? urlNorm.payload.missing_info : []),
          ]),
        );
        const mergedInternalCodes = Array.from(
          new Set([
            ...getProductAnalysisInternalMissingCodes(norm?.payload),
            ...getProductAnalysisInternalMissingCodes(urlNorm.payload),
          ]),
        );
        norm = {
          payload: applyProductAnalysisGapContract({
            ...urlNorm.payload,
            missing_info: mergedMissingInfo,
            internal_debug_codes: mergedInternalCodes,
          }),
          field_missing: mergeFieldMissing(urlNorm.field_missing, norm.field_missing),
        };
      }
    }
  } catch (err) {
    logger?.warn(
      { err: err && err.message ? err.message : String(err), product_text: inputText.slice(0, 120) },
      'aurora bff: routine autoscan deep-scan failed',
    );
  }

  let payload = enrichProductAnalysisPayload(norm.payload, { lang, profileSummary: profileCtx });
  if (catalogFallback && catalogFallback.ok && payload && typeof payload === 'object') {
    const internalCodes = getProductAnalysisInternalMissingCodes(payload);
    payload = applyProductAnalysisGapContract({
      ...payload,
      internal_debug_codes: Array.from(new Set([...internalCodes, `catalog_anchor_fallback_${catalogFallback.source || 'used'}`])),
    });
  }
  if ((!payload || !payload.assessment) && parsedProduct && typeof parsedProduct === 'object') {
    payload = buildRoutineProductAnalysisFallbackPayload({
      language: lang,
      candidate: row,
      parsedProduct: routineDescriptorAnchor,
      reasonCodes: ['upstream_assessment_missing'],
    });
  }
  if ((!payload || !payload.assessment) && !parsedProduct) {
    payload = buildRoutineProductAnalysisFallbackPayload({
      language: lang,
      candidate: row,
      parsedProduct: null,
      reasonCodes: ['upstream_assessment_missing', 'anchor_product_missing'],
    });
  }
  if (payload && typeof payload === 'object' && routineAnchorTrustContext.usable_for_anchor_id === true && parsedProduct) {
    const assessment = isPlainObject(payload.assessment) ? payload.assessment : null;
    if (assessment && !assessment.anchor_product && !assessment.anchorProduct) {
      payload = { ...payload, assessment: { ...assessment, anchor_product: parsedProduct } };
    }
  }
  if (payload && typeof payload === 'object') {
    const hasDisplayAnchor = Boolean(
      parsedProduct &&
      pickFirstTrimmed(parsedProduct.product_id, parsedProduct.sku_id, parsedProduct.display_name, parsedProduct.name, parsedProduct.url),
    );
    const routineAnchorBlockedNonSkincare =
      Array.isArray(routineAnchorTrustContext.reasons) &&
      routineAnchorTrustContext.reasons.includes('anchor_soft_blocked_non_skincare');
    payload = applyProductAnalysisGapContract({
      ...payload,
      missing_info: uniqCaseInsensitiveStrings(
        [
          ...(Array.isArray(payload.missing_info) ? payload.missing_info : []),
          ...(Array.isArray(routineAnchorTrustContext.reasons) ? routineAnchorTrustContext.reasons : []),
          ...(hasDisplayAnchor && routineAnchorTrustContext.usable_for_anchor_id !== true ? ['anchor_id_not_used_due_to_low_trust'] : []),
        ],
        16,
      ),
    });
    payload = {
      ...payload,
      provenance: {
        ...(isPlainObject(payload.provenance) ? payload.provenance : {}),
        anchor_trust: {
          level: String(routineAnchorTrustContext.level || 'none'),
          usable_for_anchor_id: routineAnchorTrustContext.usable_for_anchor_id === true,
          reasons: Array.isArray(routineAnchorTrustContext.reasons) ? routineAnchorTrustContext.reasons.slice(0, 6) : [],
          source: String(routineAnchorTrustContext.source || 'unknown'),
          candidate_quality: String(routineAnchorTrustContext.candidate_quality || 'none'),
          ...(routineStrictNonSkincareGuard && routineAnchorBlockedNonSkincare
            ? { guard_policy: 'routine_strict_non_skincare_v1' }
            : {}),
          ...(Number.isFinite(Number(routineAnchorTrustContext.url_consistency))
            ? { url_consistency: Number(routineAnchorTrustContext.url_consistency) }
            : {}),
        },
      },
    };
  }
  payload = reconcileProductAnalysisConsistency(payload, { lang });
  payload = finalizeProductAnalysisRecoContract(payload, {
    logger,
    requestId: ctx && ctx.request_id ? ctx.request_id : 'routine_autoscan',
    mode: 'main_path',
  });
  payload = appendProductIntelSourceChain(payload, ['llm_extraction']);
  payload = attachProductIntelLlmRouteProvenance(payload, routineLlmRouteMeta);
  payload = reconcileProductAnalysisConsistency(payload, { lang });
  if (realtimeUrlNormMeta && productUrl) {
    payload = applyProductAnalysisSocialProvenance(payload, {
      social_fetch_mode: 'async_refresh',
    });
  }

  const routineContext = {
    slot: normalizeRoutineIntakeSlot(row.slot),
    step: normalizeRoutineIntakeStep(row.step),
    rank: Number.isFinite(Number(row.rank)) ? Math.trunc(Number(row.rank)) : 0,
    source: 'routine_intake',
  };
  payload = {
    ...payload,
    routine_context: routineContext,
  };

  const assessmentObj = isPlainObject(payload?.assessment) ? payload.assessment : null;
  const kbBackfillAnchor =
    assessmentObj && isPlainObject(assessmentObj.anchor_product)
      ? assessmentObj.anchor_product
      : (routineAnchorTrustContext.usable_for_anchor_id === true ? parsedProduct : null);
  const keyQuality = resolveProductIntelKbKeyQuality({
    productUrl,
    parsedProduct: kbBackfillAnchor,
    productHint: inputText,
    lang,
  });
  scheduleProductIntelKbBackfill({
    productUrl,
    parsedProduct: kbBackfillAnchor,
    productHint: inputText,
    payload,
    lang,
    source: 'routine_product_deepscan',
    sourceMeta: {
      key_quality: keyQuality,
      routine_slot: routineContext.slot,
      routine_step: routineContext.step,
      routine_rank: routineContext.rank,
      product_input: inputText.slice(0, 240),
      ...(realtimeUrlNormMeta && typeof realtimeUrlNormMeta === 'object' ? { url_realtime_meta: realtimeUrlNormMeta } : {}),
    },
    logger,
  });

  return {
    card: includeCard
      ? {
        card_id: `routine_product_${ctx && ctx.request_id ? ctx.request_id : Date.now()}_${Math.max(0, Number(routineContext.rank) || 0)}`,
        type: 'product_analysis',
        payload,
        ...(Array.isArray(norm.field_missing) && norm.field_missing.length ? { field_missing: norm.field_missing.slice(0, 8) } : {}),
      }
      : null,
    backfilled: true,
    anchor_used: routineAnchorTrustContext.usable_for_anchor_id === true,
    anchor_blocked_non_skincare: Array.isArray(routineAnchorTrustContext.reasons)
      ? routineAnchorTrustContext.reasons.includes('anchor_soft_blocked_non_skincare')
      : false,
    key_quality: keyQuality,
    routine_context: routineContext,
  };
}

function coerceRecoCandidateForGuardrail(candidate) {
  const recoverRecoCandidateFromRawPdpResponse = (raw, carry = null) => {
    const source = isPlainObject(raw) ? raw : null;
    if (!source) return null;
    const hasPdpVersion = Boolean(String(source.pdp_version || source.pdpVersion || '').trim());
    const hasSubject = isPlainObject(source.subject);
    const hasModules = Array.isArray(source.modules);
    if (!hasSubject || (!hasPdpVersion && !hasModules && String(source.status || '').trim().toLowerCase() !== 'success')) {
      return null;
    }

    const modules = Array.isArray(source.modules) ? source.modules : [];
    const canonicalModule = modules.find((module) => isPlainObject(module) && String(module.type || '').trim().toLowerCase() === 'canonical');
    const canonicalData = isPlainObject(canonicalModule?.data) ? canonicalModule.data : {};
    const pdpPayload = isPlainObject(canonicalData.pdp_payload) ? canonicalData.pdp_payload : {};
    const pdpProduct = isPlainObject(pdpPayload.product) ? pdpPayload.product : {};
    const rawBrand = isPlainObject(pdpProduct.brand) ? pdpProduct.brand : {};
    const categoryPath = Array.isArray(pdpProduct.category_path)
      ? pdpProduct.category_path
          .map((value) => String(value || '').trim())
          .filter(Boolean)
      : [];
    const categoryFallback = categoryPath.length ? categoryPath[categoryPath.length - 1] : '';
    const canonicalRef = normalizeCanonicalProductRef(
      source.subject?.canonical_product_ref ||
      source.subject?.canonicalProductRef ||
      canonicalData.canonical_product_ref ||
      canonicalData.canonicalProductRef ||
      source.canonical_product_ref ||
      source.canonicalProductRef,
      { requireMerchant: false, allowOpaqueProductId: true },
    );
    const productId = pickFirstTrimmed(
      canonicalRef?.product_id,
      pdpProduct.product_id,
      pdpProduct.productId,
      source.subject?.id,
    );
    const merchantId = pickFirstTrimmed(
      canonicalRef?.merchant_id,
      pdpProduct.merchant_id,
      pdpProduct.merchantId,
    );
    const brand = pickFirstTrimmed(
      rawBrand.name,
      pdpProduct.brand_name,
      pdpProduct.brandName,
      pdpProduct.brand,
    );
    const title = pickFirstTrimmed(
      pdpProduct.title,
      pdpProduct.name,
      carry?.name,
      carry?.title,
      carry?.display_name,
      carry?.displayName,
      categoryFallback,
    );
    const category = pickFirstTrimmed(
      carry?.category,
      carry?.category_name,
      pdpProduct.category,
      pdpProduct.category_name,
      pdpProduct.categoryName,
      categoryFallback,
    );
    const directUrl = pickFirstTrimmed(
      carry?.pdp_url,
      carry?.url,
      carry?.product_url,
      pdpProduct.pdp_url,
      pdpProduct.pdpUrl,
      pdpProduct.url,
      pdpProduct.product_url,
      pdpProduct.productUrl,
      pdpProduct.image_url,
    );
    const hasHumanReadableIdentity = Boolean(title || brand || category || directUrl || productId);
    if (!hasHumanReadableIdentity) return null;

    const nextSku = {
      ...(productId ? { product_id: productId } : {}),
      ...(merchantId ? { merchant_id: merchantId } : {}),
      ...(brand ? { brand } : {}),
      ...(title ? { name: title, title, display_name: title } : {}),
      ...(category ? { category } : {}),
      ...(categoryPath.length ? { category_path: categoryPath } : {}),
      ...(directUrl ? { url: directUrl, pdp_url: directUrl } : {}),
    };
    return {
      ...(isPlainObject(carry) ? carry : {}),
      ...(productId ? { product_id: productId } : {}),
      ...(merchantId ? { merchant_id: merchantId } : {}),
      ...(canonicalRef ? { canonical_product_ref: canonicalRef } : {}),
      ...(brand ? { brand } : {}),
      ...(title ? { name: title, title, display_name: title, displayName: title } : {}),
      ...(category ? { category, category_name: category } : {}),
      ...(categoryPath.length ? { category_path: categoryPath } : {}),
      ...(directUrl ? { pdp_url: directUrl, url: directUrl, product_url: directUrl, purchase_path: directUrl } : {}),
      sku: nextSku,
      metadata: {
        ...(isPlainObject(carry?.metadata) ? carry.metadata : {}),
        pdp_contract_repaired: true,
        pdp_contract_source: 'get_pdp_v2',
      },
    };
  };

  let base = isPlainObject(candidate) ? { ...candidate } : null;
  if (!base) return null;
  const recoveredBase = recoverRecoCandidateFromRawPdpResponse(base);
  if (recoveredBase) base = recoveredBase;

  let sku = isPlainObject(base.sku) ? base.sku : isPlainObject(base.product) ? base.product : null;
  const recoveredSku = recoverRecoCandidateFromRawPdpResponse(sku, base);
  if (recoveredSku) {
    base = recoveredSku;
    sku = isPlainObject(base.sku) ? base.sku : isPlainObject(base.product) ? base.product : null;
  }
  if (!sku) return base;
  const next = { ...base };

  const setIfMissing = (key, ...values) => {
    if (typeof next[key] === 'string' && String(next[key]).trim()) return;
    const picked = pickFirstString(...values);
    if (!picked) return;
    next[key] = picked;
  };

  const setArrayIfMissing = (key, values) => {
    if (Array.isArray(next[key]) && next[key].length > 0) return;
    if (!Array.isArray(values)) return;
    const compacted = values
      .map((item) => (typeof item === 'string' ? item.trim() : item == null ? '' : String(item).trim()))
      .filter(Boolean);
    if (!compacted.length) return;
    next[key] = compacted.slice(0, 12);
  };

  setIfMissing('product_id', sku.product_id, sku.productId, sku.sku_id, sku.skuId);
  setIfMissing('merchant_id', sku.merchant_id, sku.merchantId);
  setIfMissing('name', sku.name, sku.title, sku.display_name, sku.displayName);
  setIfMissing('title', sku.title, sku.name, sku.display_name, sku.displayName);
  setIfMissing('display_name', sku.display_name, sku.displayName, sku.name, sku.title);
  setIfMissing('displayName', sku.displayName, sku.display_name, sku.name, sku.title);
  setIfMissing('brand', sku.brand, sku.brand_name, sku.brandName);
  setIfMissing('category', sku.category, sku.category_name, sku.categoryName, sku.product_type, sku.productType, sku.type);
  setIfMissing('category_name', sku.category_name, sku.categoryName, sku.category);
  setIfMissing('category_path', sku.category_path, sku.categoryPath);
  setIfMissing('product_type', sku.product_type, sku.productType);
  setIfMissing('type', sku.type, sku.product_type, sku.productType, sku.category);
  setIfMissing('retrieval_source', sku.retrieval_source, sku.retrievalSource);
  setIfMissing('retrieval_reason', sku.retrieval_reason, sku.retrievalReason);
  const retrievalSourceNow = String(next.retrieval_source || '').trim().toLowerCase();
  if (!retrievalSourceNow) {
    const sourceToken = pickFirstString(next.source, next.source_type, next.sourceType, sku.source, sku.source_type, sku.sourceType);
    const sourceLower = String(sourceToken || '').trim().toLowerCase();
    if (sourceLower.includes('external')) next.retrieval_source = 'external_seed';
    else if (sourceLower.includes('llm')) next.retrieval_source = 'llm_fallback';
    else next.retrieval_source = 'catalog';
  }
  const retrievalReasonNow = String(next.retrieval_reason || '').trim();
  if (!retrievalReasonNow) {
    const sourceNormalized = String(next.retrieval_source || '').trim().toLowerCase();
    if (sourceNormalized === 'external_seed') next.retrieval_reason = 'external_seed_supplement';
    else if (sourceNormalized === 'llm_fallback') next.retrieval_reason = 'catalog_empty_or_filtered';
    else next.retrieval_reason = 'catalog_search_match';
  }
  setArrayIfMissing('tags', Array.isArray(sku.tags) ? sku.tags : []);

  const directUrl = pickFirstString(
    next.pdp_url,
    next.url,
    next.link,
    next.product_url,
    next.purchase_path,
    sku.canonical_pdp_url,
    sku.canonicalPdpUrl,
    sku.pdp_url,
    sku.pdpUrl,
    sku.url,
    sku.product_url,
    sku.productUrl,
    sku.purchase_path,
    sku.purchasePath,
  );
  if (directUrl && !PRODUCT_INTEL_HTTP_URL_RE.test(String(next.pdp_url || '').trim())) next.pdp_url = directUrl;
  if (directUrl && !PRODUCT_INTEL_HTTP_URL_RE.test(String(next.url || '').trim())) next.url = directUrl;
  if (directUrl && !PRODUCT_INTEL_HTTP_URL_RE.test(String(next.product_url || '').trim())) next.product_url = directUrl;
  if (directUrl && !PRODUCT_INTEL_HTTP_URL_RE.test(String(next.purchase_path || '').trim())) next.purchase_path = directUrl;
  if (!isPlainObject(next.pdp_open) && isPlainObject(sku.pdp_open)) next.pdp_open = { ...sku.pdp_open };

  const canonicalRefRaw = isPlainObject(next.canonical_product_ref)
    ? next.canonical_product_ref
    : isPlainObject(sku.canonical_product_ref)
      ? sku.canonical_product_ref
      : isPlainObject(sku.canonicalProductRef)
        ? sku.canonicalProductRef
        : null;
  const canonicalRef = normalizeCanonicalProductRef(
    canonicalRefRaw || {
      product_id: pickFirstString(next.product_id, next.productId, sku.product_id, sku.productId),
      merchant_id: pickFirstString(next.merchant_id, next.merchantId, sku.merchant_id, sku.merchantId),
    },
    { requireMerchant: true, allowOpaqueProductId: false },
  );
  if (canonicalRef && !isPlainObject(next.canonical_product_ref)) {
    next.canonical_product_ref = canonicalRef;
  }

  return next;
}

function isSkincareCategory(candidate) {
  const row = coerceRecoCandidateForGuardrail(candidate);
  if (!row) return false;
  const sku = isPlainObject(row.sku) ? row.sku : isPlainObject(row.product) ? row.product : {};
  const joined = [
    row.step,
    row.slot,
    row.category,
    row.category_name,
    row.category_path,
    row.product_type,
    row.type,
    row.brand,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
    row.why_match,
    row.why,
    row.tags,
    sku.category,
    sku.category_name,
    sku.category_path,
    sku.step,
    sku.slot,
    sku.product_type,
    sku.type,
    sku.brand,
    sku.name,
    sku.title,
    sku.display_name,
    sku.displayName,
    sku.tags,
  ]
    .flatMap((value) => (Array.isArray(value) ? value : [value]))
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return false;
  return PRODUCT_INTEL_SKINCARE_RE.test(joined);
}

function isBlacklistedCategoryOrTitle(candidate) {
  const row = coerceRecoCandidateForGuardrail(candidate);
  if (!row) return false;
  const sku = isPlainObject(row.sku) ? row.sku : isPlainObject(row.product) ? row.product : {};
  const joined = [
    row.category,
    row.category_name,
    row.category_path,
    row.product_type,
    row.type,
    row.brand,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
    sku.category,
    sku.category_name,
    sku.category_path,
    sku.product_type,
    sku.type,
    sku.brand,
    sku.name,
    sku.title,
    sku.display_name,
    sku.displayName,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return false;
  return PRODUCT_INTEL_BLACKLIST_RE.test(joined);
}

const TRAVEL_RECO_ALLOWED_RE = /\b(spf|sunscreen|sun screen|sun stick|uv|cleanser|face wash|moistur|moisturizer|gel cream|gel-cream|cream|lotion|serum|essence|mask|mist|balm|barrier|repair|hydrating|hydration|soothing|after sun|lip balm|防晒|洁面|洗面奶|保湿|补水|面霜|乳液|精华|面膜|喷雾|修护|屏障|舒缓|晒后|润唇)\b/i;
const TRAVEL_RECO_BLOCK_RE = /\b(brush|applicator|blender|tool|makeup|eyeshadow|blush|lipstick|foundation|concealer|palette|mascara|brow|nail|perfume|hair|comb|razor|shaver|accessor|化妆刷|彩妆|眼影|粉底|口红|睫毛膏|眉笔|指甲|香水|梳子|剃须|配件)\b/i;

function isTravelRecoPayload(payload) {
  const meta = isPlainObject(payload?.recommendation_meta) ? payload.recommendation_meta : {};
  const taskMode = String(payload?.task_mode || meta.task_mode || '').trim().toLowerCase();
  const triggerSource = String(meta.trigger_source || meta.triggerSource || '').trim().toLowerCase();
  const handoffSource = String(meta.handoff_source || meta.handoffSource || '').trim().toLowerCase();
  return (
    taskMode === 'travel_readiness_products' ||
    triggerSource === 'travel_handoff' ||
    handoffSource === 'travel_readiness'
  );
}

function isTravelRecoAllowedCandidate(candidate) {
  const row = coerceRecoCandidateForGuardrail(candidate);
  if (!row) return false;
  const sku = isPlainObject(row.sku) ? row.sku : isPlainObject(row.product) ? row.product : {};
  const joined = [
    row.step,
    row.slot,
    row.category,
    row.category_name,
    row.category_path,
    row.product_type,
    row.type,
    row.brand,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
    row.why_match,
    row.why,
    row.reasons,
    row.notes,
    row.tags,
    sku.category,
    sku.category_name,
    sku.category_path,
    sku.product_type,
    sku.type,
    sku.brand,
    sku.name,
    sku.title,
    sku.display_name,
    sku.displayName,
    sku.tags,
  ]
    .flatMap((value) => (Array.isArray(value) ? value : [value]))
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return false;
  if (TRAVEL_RECO_BLOCK_RE.test(joined)) return false;
  return TRAVEL_RECO_ALLOWED_RE.test(joined);
}

function isSearchLikeUrl(url) {
  const value = String(url || '').trim();
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(value)) return false;
  return PRODUCT_INTEL_SEARCH_URL_RE.test(value);
}

function isHttpsUrl(url) {
  return /^https:\/\/\S+/i.test(String(url || '').trim());
}

function buildInternalPdpUrlFromTarget({ productId, merchantId } = {}) {
  const normalizedProductId = String(productId || '').trim();
  if (!normalizedProductId || !AURORA_PIVOTA_SHOP_BASE_URL) return '';
  try {
    const url = new URL(`${AURORA_PIVOTA_SHOP_BASE_URL}/products/${encodeURIComponent(normalizedProductId)}`);
    const normalizedMerchantId = String(merchantId || '').trim();
    if (normalizedMerchantId) url.searchParams.set('merchant_id', normalizedMerchantId);
    url.searchParams.set('entry', 'aurora_chatbox');
    return url.toString();
  } catch {
    return '';
  }
}

function extractCanonicalRefFromProductGroupId(rawGroupId) {
  const groupId = String(rawGroupId || '').trim();
  if (!groupId) return null;
  const tokens = groupId
    .split(':')
    .map((token) => String(token || '').trim())
    .filter(Boolean);
  if (tokens.length < 3) return null;
  if (tokens[0].toLowerCase() !== 'pg') return null;
  const merchantId = tokens[1];
  const productId = tokens.slice(2).join(':');
  return normalizeCanonicalProductRef(
    {
      product_id: productId,
      merchant_id: merchantId,
    },
    { requireMerchant: true, allowOpaqueProductId: false },
  );
}

function deriveInternalPdpUrlFromContract(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const skuCandidate = isPlainObject(row.sku) ? row.sku : isPlainObject(row.product) ? row.product : null;

  const prefetchPayload = extractPdpCorePrefetchPayloadFromItem(row);
  const prefetchRef = normalizeCanonicalProductRef(prefetchPayload?.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (prefetchRef) {
    const fromPrefetchRef = buildInternalPdpUrlFromTarget({
      productId: prefetchRef.product_id,
      merchantId: prefetchRef.merchant_id,
    });
    if (fromPrefetchRef) return fromPrefetchRef;
  }

  const prefetchSubjectGroupId = pickFirstTrimmed(
    prefetchPayload?.subject?.id,
    prefetchPayload?.subject?.product_group_id,
    prefetchPayload?.subject?.productGroupId,
  );
  const prefetchGroupRef = extractCanonicalRefFromProductGroupId(prefetchSubjectGroupId);
  if (prefetchGroupRef) {
    const fromPrefetchGroup = buildInternalPdpUrlFromTarget({
      productId: prefetchGroupRef.product_id,
      merchantId: prefetchGroupRef.merchant_id,
    });
    if (fromPrefetchGroup) return fromPrefetchGroup;
  }

  const { subjectProductGroupId, directProductRef, rawProductId, rawMerchantId } = extractRecoPdpDirectKeys(row, skuCandidate);
  if (directProductRef) {
    const fromDirectRef = buildInternalPdpUrlFromTarget({
      productId: directProductRef.product_id,
      merchantId: directProductRef.merchant_id,
    });
    if (fromDirectRef) return fromDirectRef;
  }

  const subjectGroupRef = extractCanonicalRefFromProductGroupId(subjectProductGroupId);
  if (subjectGroupRef) {
    const fromSubjectGroup = buildInternalPdpUrlFromTarget({
      productId: subjectGroupRef.product_id,
      merchantId: subjectGroupRef.merchant_id,
    });
    if (fromSubjectGroup) return fromSubjectGroup;
  }

  const fallbackRef = normalizeCanonicalProductRef(
    {
      product_id: rawProductId,
      merchant_id: rawMerchantId,
    },
    { requireMerchant: true, allowOpaqueProductId: false },
  );
  if (fallbackRef) {
    const fromFallbackRef = buildInternalPdpUrlFromTarget({
      productId: fallbackRef.product_id,
      merchantId: fallbackRef.merchant_id,
    });
    if (fromFallbackRef) return fromFallbackRef;
  }

  return '';
}

function extractCandidateOpenUrl(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const sku = isPlainObject(row.sku) ? row.sku : {};
  const product = isPlainObject(row.product) ? row.product : {};
  const pdpOpen = isPlainObject(row.pdp_open) ? row.pdp_open : {};
  const pdpOpenExternal = isPlainObject(pdpOpen.external) ? pdpOpen.external : {};
  const url = pickFirstString(
    row.pdp_url,
    row.url,
    row.link,
    row.product_url,
    row.purchase_path,
    row.purchasePath,
    sku.pdp_url,
    sku.url,
    sku.purchase_path,
    product.pdp_url,
    product.url,
    product.purchase_path,
    pdpOpenExternal.url,
  );
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(url)) {
    const derivedInternalUrl = deriveInternalPdpUrlFromContract(row);
    if (!PRODUCT_INTEL_HTTP_URL_RE.test(derivedInternalUrl)) return '';
    return derivedInternalUrl;
  }
  return url;
}

function normalizeCandidateWithDirectUrl(candidate, directUrl) {
  const row = isPlainObject(candidate) ? { ...candidate } : {};
  const url = String(directUrl || '').trim();
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(url)) return row;
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.url || '').trim())) {
    row.url = url;
  }
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.pdp_url || '').trim())) {
    row.pdp_url = url;
  }
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.product_url || '').trim())) {
    row.product_url = url;
  }
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.purchase_path || '').trim())) {
    row.purchase_path = url;
  }
  return row;
}

function hasOpenableUrl(candidate) {
  if (extractCandidateOpenUrl(candidate)) return true;
  const row = isPlainObject(candidate) ? candidate : {};
  const pdpOpen = isPlainObject(row.pdp_open) ? row.pdp_open : {};
  const path = String(pdpOpen.path || '').trim().toLowerCase();
  if (path === 'group') {
    const groupId = pickFirstString(row.subject_product_group_id, pdpOpen.product_group_id, pdpOpen.productGroupId);
    return Boolean(groupId);
  }
  if (path === 'ref' || path === 'resolve' || path === 'internal') {
    const ref = isPlainObject(pdpOpen.product_ref) ? pdpOpen.product_ref : {};
    const productId = pickFirstString(ref.product_id, ref.productId, row.product_id, row.productId);
    return Boolean(productId);
  }
  if (path === 'external') {
    const external = isPlainObject(pdpOpen.external) ? pdpOpen.external : {};
    if (PRODUCT_INTEL_HTTP_URL_RE.test(String(external.url || '').trim())) return true;
    return Boolean(String(external.query || '').trim());
  }
  return false;
}

function isResolverExternalOpenContractRow(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const pdpOpen = isPlainObject(row.pdp_open) ? row.pdp_open : {};
  const metadata = isPlainObject(row.metadata) ? row.metadata : {};
  const mode = normalizePdpOpenMode(
    pickFirstString(
      pdpOpen.path,
      metadata.pdp_open_mode,
      metadata.pdp_open_path,
    ),
    '',
  );
  if (mode !== 'external') return false;

  const reasonCode = normalizeResolveReasonCode(
    pickFirstString(
      metadata.resolve_reason_code,
      metadata.pdp_open_fail_reason,
      metadata.resolve_fail_reason,
      pdpOpen.resolve_reason_code,
    ),
    '',
  );

  const external = isPlainObject(pdpOpen.external) ? pdpOpen.external : {};
  const externalUrl = pickFirstString(external.url);
  const externalQuery = pickFirstString(external.query);
  if (!externalUrl && !externalQuery) return false;

  const directTopLevelUrl = pickFirstString(
    row.pdp_url,
    row.url,
    row.link,
    row.product_url,
    row.purchase_path,
    row.purchasePath,
  );
  const hasDirectTopLevelUrl = PRODUCT_INTEL_HTTP_URL_RE.test(directTopLevelUrl);
  if (reasonCode) return true;

  const metadataMode = String(pickFirstString(metadata.pdp_open_mode, metadata.pdp_open_path)).trim().toLowerCase();
  return !hasDirectTopLevelUrl && (metadataMode === 'external' || metadataMode === 'internal');
}

function buildProductRelevanceDualQaPrompt(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const payload = {
    name: pickFirstString(row.name, row.title, row.display_name, row.displayName),
    brand: pickFirstString(row.brand),
    category: pickFirstString(row.category, row.category_name, row.product_type, row.type),
    why_match: pickFirstString(row.why_match, row.why),
    ingredient_name: pickFirstString(row.ingredient_name),
    url: extractCandidateOpenUrl(row),
  };
  return JSON.stringify(payload);
}

function parseDualQaRelevanceDecision(obj) {
  const row = isPlainObject(obj) ? obj : {};
  const relevant = row.relevant === true;
  const category = String(row.category || '').trim().toLowerCase();
  const reason = pickFirstString(row.reason, row.rationale);
  return {
    relevant,
    category,
    reason,
  };
}

function shouldRunDualQaForCandidate({ skincareHit, blacklistHit, joined }) {
  if (blacklistHit) return false;
  const hasSkincareHints = PRODUCT_INTEL_SKINCARE_RE.test(joined);
  const hasStrongNonSkincareHints = /(fashion|apparel|clothing|jewelry|wallet|watch|bag|gift|brush|tool|lingerie)/i.test(joined);
  if (skincareHit && hasSkincareHints && !hasStrongNonSkincareHints) return false;
  return true;
}

async function evaluateIngredientCandidateWithQaMode(
  candidate,
  {
    qaMode = AURORA_PRODUCT_RELEVANCE_QA_MODE,
    singleProvider = AURORA_LLM_SINGLE_PROVIDER,
    allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
    qaContext = null,
  } = {},
) {
  const row = isPlainObject(candidate) ? candidate : {};
  const joined = [
    row.category,
    row.category_name,
    row.product_type,
    row.type,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
    row.brand,
    row.why_match,
    row.why,
    row.ingredient_name,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  const voteA = isSkincareCategory(row) && !isBlacklistedCategoryOrTitle(row);
  const voteB =
    PRODUCT_INTEL_SKINCARE_RE.test(joined) &&
    !PRODUCT_INTEL_BLACKLIST_RE.test(joined) &&
    !/(fashion|apparel|clothing|jewelry|wallet|watch|bag|gift)/i.test(joined);
  const heuristicPass = voteA && voteB;
  const blacklistHit = isBlacklistedCategoryOrTitle(row);
  const mode = resolveQaMode(qaMode);
  const normalizedSingleProvider = resolveQaSingleProvider(singleProvider);
  const defaultResult = {
    pass: heuristicPass,
    qa_mode: mode,
    reject_reason: heuristicPass ? null : 'heuristic_relevance_reject',
  };

  if (mode === 'off') {
    markQaContextSkip(qaContext, 'relevance', 'qa_mode_off');
    return defaultResult;
  }
  if (!shouldRunDualQaForCandidate({ skincareHit: voteA, blacklistHit, joined })) return defaultResult;
  if (shouldSkipQaByBudget({ qaContext, stage: 'relevance' })) return defaultResult;

  const cacheKey = buildProductDualQaCacheKey(row);
  const scopedCacheKey = cacheKey ? `${mode}:${normalizedSingleProvider}:${cacheKey}` : '';
  const cached = getProductDualQaCache(scopedCacheKey);
  if (typeof cached === 'boolean') {
    return {
      pass: cached,
      qa_mode: mode,
      reject_reason: cached ? null : mode === 'dual' ? 'dual_llm_relevance_reject' : 'single_llm_relevance_reject',
    };
  }

  const providers = pickRuntimeQaProviders({
    mode,
    singleProvider: normalizedSingleProvider,
  });
  if ((mode === 'dual' && providers.length < 2) || !providers.length) {
    const fallbackPass = heuristicPass;
    setProductDualQaCache(scopedCacheKey, fallbackPass);
    markQaContextSkip(qaContext, 'relevance', 'qa_provider_unavailable');
    return {
      pass: fallbackPass,
      qa_mode: mode,
      reject_reason: fallbackPass ? null : mode === 'dual' ? 'dual_llm_relevance_reject' : 'single_llm_relevance_reject',
    };
  }

  const systemPrompt =
    'Return JSON only: {"relevant":boolean,"category":string,"reason":string}. Reject non-skincare items.';
  const userPrompt = buildProductRelevanceDualQaPrompt(row);

  if (mode === 'single') {
    let parsed = null;
    for (const provider of providers) {
      const vote = await callRuntimeQaJson({
        kind: 'product_relevance',
        systemPrompt,
        userPrompt,
        timeoutMs: AURORA_PRODUCT_RELEVANCE_GEMINI_TIMEOUT_MS,
      });
      if (!vote || !vote.ok || !isPlainObject(vote.json)) {
        markQaContextCall(qaContext, 'relevance', provider, 'error', vote && vote.meta ? vote.meta : null);
        continue;
      }
      parsed = parseDualQaRelevanceDecision(vote.json);
      markQaContextCall(
        qaContext,
        'relevance',
        provider,
        parsed && parsed.relevant === true ? 'ok' : 'reject',
        vote && vote.meta ? vote.meta : null,
      );
      if (parsed) break;
    }
    const pass = Boolean(parsed && parsed.relevant === true && parsed.category !== 'non_skincare');
    setProductDualQaCache(scopedCacheKey, pass);
    return {
      pass,
      qa_mode: mode,
      reject_reason: pass ? null : 'single_llm_relevance_reject',
    };
  }

  const [vote1, vote2] = await Promise.all(
    providers
      .slice(0, 2)
      .map((provider) =>
        callRuntimeQaJson({
          kind: 'product_relevance',
          systemPrompt,
          userPrompt,
          timeoutMs: AURORA_PRODUCT_RELEVANCE_GEMINI_TIMEOUT_MS,
        }).then((vote) => ({ provider, vote })),
      ),
  );
  const parsed1 = vote1 && vote1.vote && vote1.vote.ok ? parseDualQaRelevanceDecision(vote1.vote.json) : null;
  const parsed2 = vote2 && vote2.vote && vote2.vote.ok ? parseDualQaRelevanceDecision(vote2.vote.json) : null;
  markQaContextCall(
    qaContext,
    'relevance',
    [vote1 && vote1.provider, vote2 && vote2.provider].filter(Boolean).join(','),
    parsed1 && parsed2 ? 'ok' : 'error',
    ((vote1 && vote1.vote && vote1.vote.meta) || (vote2 && vote2.vote && vote2.vote.meta)) || null,
  );

  // Fail-closed by design: require dual-pass consensus.
  const pass = Boolean(
    parsed1 &&
      parsed2 &&
      parsed1.relevant === true &&
      parsed2.relevant === true &&
      parsed1.category !== 'non_skincare' &&
      parsed2.category !== 'non_skincare',
  );
  setProductDualQaCache(scopedCacheKey, pass);
  return {
    pass,
    qa_mode: mode,
    reject_reason: pass ? null : 'dual_llm_relevance_reject',
  };
}

function buildExternalSearchCta(candidate, reason = 'search_fallback') {
  const row = isPlainObject(candidate) ? candidate : {};
  const title = pickFirstString(row.name, row.title, row.display_name, row.displayName, row.product_id, 'Open search result');
  const directUrl = extractCandidateOpenUrl(row);
  const query = pickFirstString(title, row.ingredient_name, row.category, row.brand);
  const url = PRODUCT_INTEL_HTTP_URL_RE.test(directUrl) ? directUrl : buildExternalGoogleSearchUrl(query);
  const source = pickFirstString(row.source, row.brand).toLowerCase() || 'external';
  return {
    title,
    url,
    source,
    reason,
  };
}

function isTrustedCatalogGroundedRecoCandidate(row, payload) {
  const candidate = isPlainObject(row) ? row : {};
  const payloadObj = isPlainObject(payload) ? payload : {};
  const sourceMode = String(
    pickFirstTrimmed(
      payloadObj.recommendation_meta && payloadObj.recommendation_meta.source_mode,
      payloadObj.source,
      candidate.source,
    ) || '',
  )
    .trim()
    .toLowerCase();
  if (sourceMode !== 'catalog_grounded') return false;
  const hasStableId = Boolean(
    pickFirstTrimmed(candidate.product_id, candidate.productId, candidate.sku_id, candidate.skuId),
  );
  if (!hasStableId) return false;
  if (isResolverExternalOpenContractRow(candidate)) return true;
  if (hasOpenableUrl(candidate)) return true;
  const directUrl = extractCandidateOpenUrl(candidate);
  return PRODUCT_INTEL_HTTP_URL_RE.test(directUrl);
}

function buildStrictFilterFallbackSearchCtas(payload, maxItems = 3) {
  const p = isPlainObject(payload) ? payload : {};
  const science = isPlainObject(p.evidence) && isPlainObject(p.evidence.science) ? p.evidence.science : {};
  const keyIngredients = Array.isArray(science.key_ingredients) ? science.key_ingredients : [];
  const goals = Array.isArray(p.profile && p.profile.goals) ? p.profile.goals : [];
  const seed = [...keyIngredients, ...goals]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ')
    .toLowerCase();

  const queryCandidates = [];
  const pushQuery = (query) => {
    const normalized = String(query || '').trim();
    if (!normalized) return;
    if (queryCandidates.some((row) => String(row || '').toLowerCase() === normalized.toLowerCase())) return;
    queryCandidates.push(normalized);
  };

  if (/(uv|spf|sun|sunscreen|uva|uvb)/i.test(seed)) {
    pushQuery('SPF50+ broad spectrum sunscreen for sensitive skin');
  }
  if (/(barrier|ceramide|b5|panthenol|hyaluronic|dry|dehydrated)/i.test(seed)) {
    pushQuery('Ceramide barrier repair moisturizer fragrance free');
  }
  if (/(acne|texture|pore|oily|salicylic)/i.test(seed)) {
    pushQuery('Gentle salicylic acid serum for texture and pores');
  }
  if (/(tone|dark spot|pigment|niacinamide|tranexamic|ascorbic|vitamin c|uneven)/i.test(seed)) {
    pushQuery('Niacinamide or vitamin C serum for uneven tone');
  }

  if (!queryCandidates.length) {
    pushQuery('SPF50+ broad spectrum sunscreen for sensitive skin');
    pushQuery('Ceramide barrier repair moisturizer fragrance free');
    pushQuery('Gentle non-stripping cleanser sensitive skin');
  }

  return queryCandidates.slice(0, Math.max(1, Math.min(6, Number(maxItems) || 3))).map((query) => ({
    title: query,
    url: buildExternalGoogleSearchUrl(query),
    source: 'fallback',
    reason: 'strict_filter_all_dropped_fallback',
  }));
}

function tryDecodeSearchQueryFromUrl(url) {
  const raw = String(url || '').trim();
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(raw)) return '';
  try {
    const parsed = new URL(raw);
    const query = pickFirstString(
      parsed.searchParams.get('q'),
      parsed.searchParams.get('query'),
      parsed.searchParams.get('k'),
      parsed.searchParams.get('keyword'),
    );
    return String(query || '').trim();
  } catch {
    return '';
  }
}

function dedupeExternalSearchCtas(ctas, maxItems = 12) {
  const list = Array.isArray(ctas) ? ctas : [];
  const out = [];
  const seen = new Set();
  for (const item of list) {
    if (!isPlainObject(item)) continue;
    const title = pickFirstString(item.title, item.name, item.query);
    const url = pickFirstString(item.url);
    if (!title && !url) continue;
    const key = `${String(title || '').trim().toLowerCase()}::${String(url || '').trim().toLowerCase()}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({
      title,
      ...(url ? { url } : {}),
      ...(pickFirstString(item.source) ? { source: pickFirstString(item.source).toLowerCase() } : {}),
      ...(pickFirstString(item.reason) ? { reason: pickFirstString(item.reason) } : {}),
    });
    if (out.length >= Math.max(1, Number(maxItems) || 12)) break;
  }
  return out;
}

function normalizeFallbackQueryText(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  return raw
    .replace(/\s+/g, ' ')
    .replace(/^[`"'“”'‘’()[\]{}<>|\\,.;:!?~]+/g, '')
    .replace(/[`"'“”'‘’()[\]{}<>|\\,.;:!?~]+$/g, '')
    .trim();
}

function isIngredientIdStyleToken(value) {
  const token = String(value || '').trim().toLowerCase();
  if (!token) return false;
  if (/^[a-z0-9]+(?:_[a-z0-9]+)+$/.test(token)) return true;
  if (/^(ingredient|ing)[-_]?[a-z0-9_]+$/.test(token)) return true;
  return false;
}

function isOpaqueFallbackLookupToken(value) {
  const token = String(value || '').trim().toLowerCase();
  if (!token) return false;
  if (/^[a-z0-9]{18,}$/.test(token) && !/[aeiou]/.test(token)) return true;
  return false;
}

function normalizeHumanReadableFallbackQuery(value) {
  const normalized = normalizeFallbackQueryText(value);
  if (!normalized) return '';
  const token = normalized.toLowerCase();
  if (isIngredientIdStyleToken(token)) return '';
  if (isOpaqueFallbackLookupToken(token)) return '';
  return normalized;
}

function collectPurchasableFallbackQueries({
  payload,
  recommendationRows = [],
  externalSearchCtas = [],
  extraSeeds = [],
  maxQueries = AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
} = {}) {
  const queries = [];
  const seen = new Set();
  const pushQuery = (value) => {
    const normalized = normalizeHumanReadableFallbackQuery(value);
    if (!normalized) return;
    const key = normalized.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    queries.push(normalized);
  };

  const p = isPlainObject(payload) ? payload : {};
  const science = isPlainObject(p.evidence) && isPlainObject(p.evidence.science) ? p.evidence.science : {};
  const ingredientSeeds = Array.isArray(science.key_ingredients) ? science.key_ingredients.slice(0, 3) : [];

  for (const row of Array.isArray(recommendationRows) ? recommendationRows : []) {
    if (!isPlainObject(row)) continue;
    pushQuery(pickFirstString(row.name, row.title, row.display_name, row.displayName));
    pushQuery(tryDecodeSearchQueryFromUrl(extractCandidateOpenUrl(row)));
  }

  for (const cta of Array.isArray(externalSearchCtas) ? externalSearchCtas : []) {
    if (!isPlainObject(cta)) continue;
    pushQuery(pickFirstString(cta.title, cta.query));
    pushQuery(tryDecodeSearchQueryFromUrl(cta.url));
  }

  for (const value of Array.isArray(extraSeeds) ? extraSeeds : []) {
    if (isPlainObject(value)) {
      pushQuery(pickFirstString(value.name, value.title, value.ingredient));
      const ingredientId = pickFirstString(value.ingredient_id, value.ingredientId);
      if (ingredientId && !isIngredientIdStyleToken(ingredientId)) {
        pushQuery(ingredientId);
      }
      continue;
    }
    pushQuery(value);
  }

  for (const ingredient of ingredientSeeds) {
    const token = normalizeHumanReadableFallbackQuery(ingredient);
    if (!token) continue;
    const nextSeed = /\bskincare\b|护肤/i.test(token) ? token : `${token} skincare`;
    pushQuery(nextSeed);
  }

  return queries.slice(0, Math.max(1, Number(maxQueries) || 4));
}

async function recoverPurchasableProductsFromQueries({
  queries = [],
  strictFilter = true,
  qaMode = AURORA_PRODUCT_RELEVANCE_QA_MODE,
  singleProvider = AURORA_LLM_SINGLE_PROVIDER,
  allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
  qaContext = null,
  fallbackCandidateBuilder,
  allowExternalSeedSupplement = false,
  externalSeedStrategy = 'supplement_internal_first',
  logger,
  guardrailRuleId = 'reco_guardrail',
  maxProducts = AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
} = {}) {
  const out = {
    products: [],
    rejected: [],
    external_search_ctas: [],
    attempted_queries: [],
    selected_source_counts: {},
    no_result_reason: null,
    alternatives: [],
  };
  if (typeof fallbackCandidateBuilder !== 'function') return out;

  const seenProducts = new Set();
  const targetMax = Math.max(1, Number(maxProducts) || AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS);

  for (const query of Array.isArray(queries) ? queries : []) {
    const q = String(query || '').trim();
    if (!q) continue;
    if (out.products.length >= targetMax) break;
    out.attempted_queries.push(q);

    let fallbackOut = null;
    try {
      fallbackOut = await fallbackCandidateBuilder({
        query: q,
        limit: Math.max(2, targetMax - out.products.length),
        allowExternalSeed: allowExternalSeedSupplement === true,
        externalSeedStrategy,
        logger,
      });
    } catch (err) {
      logger?.warn?.({ err: err?.message || String(err), query: q }, 'aurora bff: purchasable fallback query failed');
      continue;
    }

    const sourceKey = String(fallbackOut?.selected_source || 'none').trim() || 'none';
    out.selected_source_counts[sourceKey] = Number(out.selected_source_counts[sourceKey] || 0) + 1;

    const products = Array.isArray(fallbackOut?.products) ? fallbackOut.products : [];
    for (const raw of products) {
      if (out.products.length >= targetMax) break;
      const normalized = normalizeRecoCatalogProduct(raw);
      if (!isPlainObject(normalized)) continue;

      const dedupeKey = `${String(normalized.product_id || '').trim()}::${String(normalized.merchant_id || '').trim()}::${String(extractCandidateOpenUrl(normalized) || '').trim().toLowerCase()}`;
      if (seenProducts.has(dedupeKey)) continue;

      const blacklistHit = isBlacklistedCategoryOrTitle(normalized);
      const skincareHit = isSkincareCategory(normalized);
      const relevanceDecision = await evaluateIngredientCandidateWithQaMode(normalized, {
        qaMode: 'off',
        singleProvider,
        allowOpenAiFallback,
        qaContext,
      });
      const directUrl = extractCandidateOpenUrl(normalized);
      const openable = hasOpenableUrl(normalized);
      const searchLike = isSearchLikeUrl(directUrl);
      const relevanceRejectReason = blacklistHit
        ? 'blacklisted_category_or_title'
        : strictFilter && !skincareHit
          ? 'non_skincare_category'
          : !(relevanceDecision && relevanceDecision.pass === true)
            ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
            : '';

      if (relevanceRejectReason) {
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: pickFirstString(normalized.source, normalized.brand).toLowerCase() || null,
          reject_reason: relevanceRejectReason,
          rule_id: guardrailRuleId,
        });
        continue;
      }
      if (searchLike) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'search_url_demoted'));
        continue;
      }
      if (!openable) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'missing_openable_url_search_fallback'));
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: pickFirstString(normalized.source, normalized.brand).toLowerCase() || null,
          reject_reason: 'product_url_missing',
          rule_id: guardrailRuleId,
        });
        continue;
      }
      if (!directUrl) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'open_contract_only_no_direct_url'));
        continue;
      }
      if (!isHttpsUrl(directUrl)) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'non_https_pdp_url_demoted'));
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: pickFirstString(normalized.source, normalized.brand).toLowerCase() || null,
          reject_reason: 'non_https_pdp_url',
          rule_id: guardrailRuleId,
        });
        continue;
      }

      seenProducts.add(dedupeKey);
      out.products.push(normalizeCandidateWithDirectUrl(normalized, directUrl));
    }
  }

  out.external_search_ctas = dedupeExternalSearchCtas(out.external_search_ctas, 12);
  if (out.products.length === 0) {
    out.no_result_reason = out.no_result_reason || 'no_candidate_match';
    out.alternatives = out.alternatives.length ? out.alternatives : ['adjust_goal', 'adjust_sensitivity', 'broaden_filters'];
  }
  return out;
}

function buildProductLookupLlmFallbackPrompt({ query, limit = 6, productCandidates = [] } = {}) {
  const promptVersion = 'inline_selector_v2';
  const q = String(query || '').trim();
  const topN = Math.max(1, Math.min(12, Math.trunc(Number(limit) || 6)));
  const candidates = (Array.isArray(productCandidates) ? productCandidates : [])
    .map((row) => {
      const item = isPlainObject(row) ? row : {};
      const name = pickFirstString(item.name, item.title, item.display_name, item.displayName);
      const brand = pickFirstString(item.brand, item.source);
      const category = pickFirstString(item.category, item.product_type, item.type);
      const pdpUrl = extractCandidateOpenUrl(item);
      if (!name || !pdpUrl) return null;
      return {
        name: String(name).slice(0, 120),
        ...(brand ? { brand: String(brand).slice(0, 80) } : {}),
        ...(category ? { category: String(category).slice(0, 48) } : {}),
        pdp_url: String(pdpUrl).slice(0, 400),
        signals: asResearchStringArray(item.signals, 4),
      };
    })
    .filter(Boolean)
    .slice(0, 20);

  return [
    `[PROMPT_VERSION=${promptVersion}]`,
    'Role: strict fallback product selector.',
    'Task: select purchasable skincare products for the query from the allowed candidate pool only.',
    'Output contract: return strict JSON only as { "products": [ { "name": string, "brand": string, "category": string, "pdp_url": string, "why": string } ] }.',
    'Hard constraints:',
    '- Skincare only (cleanser/serum/moisturizer/sunscreen/treatment).',
    '- Include direct PDP HTTPS URLs only.',
    '- Do NOT return search URLs (google/bing/amazon search/etc).',
    '- No makeup tools, apparel, or non-skincare products.',
    '- Return strict JSON only. No extra keys, no prose outside JSON.',
    '- CRITICAL: Use ONLY products from context.product_candidates. Do NOT guess or rewrite outside the candidate pool.',
    '- Copy product identity from the chosen candidate; do not invent brands, URLs, or category facts.',
    '- Keep "why" short and query-grounded, not marketing-heavy.',
    'Missing-data policy:',
    '- If no valid candidate fits, return {"products": []}.',
    '- Prefer an empty result over weak or out-of-pool matches.',
    `Max products: ${topN}`,
    `Query: ${q}`,
    `context=${JSON.stringify({ product_candidates: candidates })}`,
  ].join('\n');
}

function normalizeLlmFallbackCandidate(raw, { query, index } = {}) {
  const row = isPlainObject(raw) ? raw : {};
  const name = pickFirstString(row.name, row.title, row.display_name, row.displayName);
  const url = pickFirstString(row.pdp_url, row.url, row.link, row.product_url, row.purchase_path);
  if (!name || !url) return null;

  const brand = pickFirstString(row.brand);
  const category = pickFirstString(row.category, row.type, row.product_type);
  const why = pickFirstString(row.why, row.reason, row.why_match);
  const productId = pickFirstString(
    row.product_id,
    row.productId,
    `llm_${crypto
      .createHash('sha1')
      .update(`${name}|${brand}|${url}|${String(query || '')}|${Number(index) || 0}`)
      .digest('hex')
      .slice(0, 16)}`,
  );

  return {
    product_id: String(productId || '').trim(),
    merchant_id: 'llm_fallback',
    name: String(name || '').trim(),
    ...(brand ? { brand: String(brand).trim() } : {}),
    ...(category ? { category: String(category).trim() } : {}),
    source: 'llm_fallback',
    retrieval_source: 'llm_fallback',
    retrieval_reason: 'catalog_empty_or_filtered',
    pdp_url: String(url).trim(),
    url: String(url).trim(),
    product_url: String(url).trim(),
    purchase_path: String(url).trim(),
    ...(why ? { why_match: String(why).trim() } : {}),
    reco_reason_codes: Array.isArray(row.reco_reason_codes)
      ? row.reco_reason_codes.map((v) => String(v || '').trim()).filter(Boolean).slice(0, 6)
      : ['matched_query'],
  };
}

function initLlmFallbackStageCounts() {
  return {
    timeout: 0,
    error: 0,
    invalid_json: 0,
    empty: 0,
    recovered: 0,
  };
}

function mergeLlmFallbackStageCounts(base, patch) {
  const left = isPlainObject(base) ? base : initLlmFallbackStageCounts();
  const right = isPlainObject(patch) ? patch : {};
  return {
    timeout: Math.max(0, Math.trunc(Number(left.timeout || 0) + Number(right.timeout || 0))),
    error: Math.max(0, Math.trunc(Number(left.error || 0) + Number(right.error || 0))),
    invalid_json: Math.max(0, Math.trunc(Number(left.invalid_json || 0) + Number(right.invalid_json || 0))),
    empty: Math.max(0, Math.trunc(Number(left.empty || 0) + Number(right.empty || 0))),
    recovered: Math.max(0, Math.trunc(Number(left.recovered || 0) + Number(right.recovered || 0))),
  };
}

function classifyLlmFallbackErrorReason(err) {
  const code = String(err && err.code ? err.code : '').trim().toLowerCase();
  const message = String(err && err.message ? err.message : err || '').trim().toLowerCase();
  if (
    code.includes('timeout') ||
    code === 'etimedout' ||
    code === 'econnaborted' ||
    message.includes('timeout') ||
    message.includes('timed out') ||
    message.includes('abort')
  ) {
    return 'timeout';
  }
  return 'error';
}

async function recoverProductsWithLlmFallbackFromQueries({
  queries = [],
  strictFilter = true,
  singleProvider = AURORA_LLM_SINGLE_PROVIDER,
  allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
  qaContext = null,
  productCandidates = [],
  recoTrigger = '',
  logger,
  guardrailRuleId = 'reco_guardrail',
  maxProducts = AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
} = {}) {
  const out = {
    products: [],
    rejected: [],
    external_search_ctas: [],
    attempted_queries: [],
    selected_source_counts: {},
    llm_used: false,
    stage_counts: initLlmFallbackStageCounts(),
    last_reason: null,
    no_result_reason: null,
    alternatives: [],
  };
  if (!AURORA_PRODUCT_LOOKUP_LLM_FALLBACK_ENABLED) return out;

  const normalizedCandidates = (Array.isArray(productCandidates) ? productCandidates : [])
    .map((row) => normalizeRecoCatalogProduct(row))
    .filter((row) => isPlainObject(row))
    .map((row) => ({
      normalized: row,
      url: String(extractCandidateOpenUrl(row) || '').trim().toLowerCase(),
      name: String(pickFirstString(row.name, row.title, row.display_name, row.displayName) || '')
        .trim()
        .toLowerCase(),
    }))
    .filter((row) => row.url && row.name);
  const allowedUrlSet = new Set(normalizedCandidates.map((row) => row.url));
  const allowedNameSet = new Set(normalizedCandidates.map((row) => row.name));
  const candidateOnlyEnabled = INGREDIENT_RETRIEVER_CANDIDATE_ONLY_ENABLED === true && normalizedCandidates.length > 0;
  if (candidateOnlyEnabled && recoTrigger && String(recoTrigger).trim().toLowerCase() !== 'explicit_user_action') {
    out.no_result_reason = 'non_explicit_trigger';
    out.alternatives = ['wait_for_explicit_action'];
    out.last_reason = 'llm_empty';
    return out;
  }

  const seenProducts = new Set();
  const targetMax = Math.max(1, Number(maxProducts) || AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS);

  for (const query of Array.isArray(queries) ? queries : []) {
    const q = String(query || '').trim();
    if (!q) continue;
    if (out.products.length >= targetMax) break;
    out.attempted_queries.push(q);

    let llmResp = null;
    try {
      llmResp = await callGeminiJsonObjectImpl({
        model: AURORA_DIAG_FORCE_GEMINI_MODEL,
        systemPrompt:
          'You are a strict skincare product selector. Output STRICT JSON only. Never invent URLs. Only use context product candidates.',
        userPrompt: buildProductLookupLlmFallbackPrompt({
          query: q,
          limit: Math.max(2, targetMax - out.products.length),
          productCandidates: normalizedCandidates.map((row) => row.normalized),
        }),
        timeoutMs: AURORA_PRODUCT_LOOKUP_LLM_FALLBACK_TIMEOUT_MS,
        temperature: 0.2,
        maxOutputTokens: 400,
        responseJsonSchema: buildProductRetrieverJsonSchema(Math.max(2, targetMax - out.products.length)),
      });
    } catch (err) {
      logger?.warn?.({ err: err?.message || String(err), query: q }, 'aurora bff: llm fallback query failed');
      const stageReason = classifyLlmFallbackErrorReason(err);
      out.stage_counts = mergeLlmFallbackStageCounts(out.stage_counts, {
        timeout: stageReason === 'timeout' ? 1 : 0,
        error: stageReason === 'error' ? 1 : 0,
      });
      out.last_reason = stageReason === 'timeout' ? 'llm_timeout' : 'llm_error';
      continue;
    }
    if (!llmResp || llmResp.ok !== true || !isPlainObject(llmResp.json)) {
      const respError = pickFirstString(llmResp && llmResp.error, llmResp && llmResp.reason).toLowerCase();
      if (respError.includes('timeout')) {
        out.stage_counts = mergeLlmFallbackStageCounts(out.stage_counts, { timeout: 1 });
        out.last_reason = 'llm_timeout';
      } else {
        out.stage_counts = mergeLlmFallbackStageCounts(out.stage_counts, { invalid_json: 1 });
        out.last_reason = 'llm_invalid_json';
      }
      continue;
    }

    const rowsRaw = Array.isArray(llmResp.json.products)
      ? llmResp.json.products
      : Array.isArray(llmResp.json.items)
        ? llmResp.json.items
        : Array.isArray(llmResp.json.recommendations)
          ? llmResp.json.recommendations
          : [];
    if (!rowsRaw.length) {
      out.stage_counts = mergeLlmFallbackStageCounts(out.stage_counts, { empty: 1 });
      out.last_reason = 'llm_empty';
      continue;
    }

    out.llm_used = true;
    out.selected_source_counts.llm_fallback = Number(out.selected_source_counts.llm_fallback || 0) + 1;
    let recoveredForQuery = false;

    for (let i = 0; i < rowsRaw.length; i += 1) {
      if (out.products.length >= targetMax) break;
      const candidate = normalizeLlmFallbackCandidate(rowsRaw[i], { query: q, index: i });
      const normalized = normalizeRecoCatalogProduct(candidate);
      if (!isPlainObject(normalized)) continue;
      if (candidateOnlyEnabled) {
        const normalizedUrl = String(extractCandidateOpenUrl(normalized) || '').trim().toLowerCase();
        const normalizedName = String(
          pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName) || '',
        )
          .trim()
          .toLowerCase();
        if (!allowedUrlSet.has(normalizedUrl) && !allowedNameSet.has(normalizedName)) continue;
      }

      const dedupeKey = `${String(normalized.product_id || '').trim()}::${String(normalized.merchant_id || '').trim()}::${String(
        extractCandidateOpenUrl(normalized) || '',
      )
        .trim()
        .toLowerCase()}`;
      if (seenProducts.has(dedupeKey)) continue;

      const blacklistHit = isBlacklistedCategoryOrTitle(normalized);
      const skincareHit = isSkincareCategory(normalized);
      const relevanceDecision = await evaluateIngredientCandidateWithQaMode(normalized, {
        qaMode: 'off',
        singleProvider,
        allowOpenAiFallback,
        qaContext,
      });
      const directUrl = extractCandidateOpenUrl(normalized);
      const openable = hasOpenableUrl(normalized);
      const searchLike = isSearchLikeUrl(directUrl);
      const relevanceRejectReason = blacklistHit
        ? 'blacklisted_category_or_title'
        : strictFilter && !skincareHit
          ? 'non_skincare_category'
          : !(relevanceDecision && relevanceDecision.pass === true)
            ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
            : '';

      if (relevanceRejectReason) {
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: 'llm_fallback',
          reject_reason: relevanceRejectReason,
          rule_id: guardrailRuleId,
        });
        continue;
      }
      if (searchLike) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'search_url_demoted'));
        continue;
      }
      if (!openable) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'missing_openable_url_search_fallback'));
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: 'llm_fallback',
          reject_reason: 'product_url_missing',
          rule_id: guardrailRuleId,
        });
        continue;
      }
      if (!directUrl) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'open_contract_only_no_direct_url'));
        continue;
      }
      if (!isHttpsUrl(directUrl)) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'non_https_pdp_url_demoted'));
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: 'llm_fallback',
          reject_reason: 'non_https_pdp_url',
          rule_id: guardrailRuleId,
        });
        continue;
      }

      seenProducts.add(dedupeKey);
      out.products.push(
        normalizeCandidateWithDirectUrl(
          {
            ...normalized,
            retrieval_source: 'llm_fallback',
            retrieval_reason: pickFirstString(normalized.retrieval_reason, 'catalog_empty_or_filtered'),
          },
          directUrl,
        ),
      );
      recoveredForQuery = true;
    }
    if (recoveredForQuery) {
      out.stage_counts = mergeLlmFallbackStageCounts(out.stage_counts, { recovered: 1 });
      out.last_reason = 'llm_recovered';
    } else {
      out.stage_counts = mergeLlmFallbackStageCounts(out.stage_counts, { empty: 1 });
      out.last_reason = 'llm_empty_after_filter';
    }
  }

  out.external_search_ctas = dedupeExternalSearchCtas(out.external_search_ctas, 12);
  return out;
}

function deriveProductsEmptyReason({
  keptCount = 0,
  externalSearchCount = 0,
  strictFallbackCount = 0,
  droppedCount = 0,
  missingUrlCount = 0,
  contractOnlyCount = 0,
  searchDemotedCount = 0,
  nonHttpsCount = 0,
  llmFallbackAttempted = 0,
  llmFallbackRecovered = 0,
  llmFallbackTimeout = 0,
  llmFallbackInvalidJson = 0,
  llmFallbackError = 0,
  llmFallbackEmpty = 0,
} = {}) {
  if (Number(keptCount) > 0) return null;
  if (Number(llmFallbackAttempted) > 0 && Number(llmFallbackRecovered) === 0) {
    if (Number(llmFallbackTimeout) > 0) return 'llm_lookup_timeout';
    if (Number(llmFallbackInvalidJson) > 0) return 'llm_lookup_invalid_json';
    if (Number(llmFallbackError) > 0) return 'llm_lookup_error';
    if (Number(llmFallbackEmpty) > 0) return 'llm_lookup_empty';
    return 'llm_lookup_fallback_empty';
  }
  if (Number(strictFallbackCount) > 0 && Number(externalSearchCount) > 0) return 'strict_filter_fallback_only';
  if (Number(nonHttpsCount) > 0) return 'no_pdp_after_filter';
  if ((Number(missingUrlCount) + Number(contractOnlyCount) + Number(searchDemotedCount)) > 0) {
    return 'no_pdp_after_filter';
  }
  if (Number(droppedCount) > 0) return 'strict_filter_fallback_only';
  return 'no_candidate';
}

function countPurchasableProductsForTargets(targets) {
  let count = 0;
  for (const target of Array.isArray(targets) ? targets : []) {
    if (!isPlainObject(target)) continue;
    const productsNode = target.products;
    if (Array.isArray(productsNode)) {
      count += productsNode.length;
      continue;
    }
    if (isPlainObject(productsNode)) {
      for (const value of Object.values(productsNode)) {
        if (Array.isArray(value)) count += value.length;
      }
    }
    if (Array.isArray(target.candidates)) count += target.candidates.length;
    if (Array.isArray(target.items)) count += target.items.length;
  }
  return count;
}

function collectProductCandidatesFromRecoTargets(targets, max = 24) {
  const out = [];
  for (const target of Array.isArray(targets) ? targets : []) {
    if (!isPlainObject(target)) continue;
    const productsNode = isPlainObject(target.products) ? target.products : {};
    for (const value of Object.values(productsNode)) {
      if (!Array.isArray(value)) continue;
      for (const row of value) {
        out.push(row);
        if (out.length >= max) return out;
      }
    }
    const candidates = Array.isArray(target.candidates) ? target.candidates : [];
    for (const row of candidates) {
      out.push(row);
      if (out.length >= max) return out;
    }
    const items = Array.isArray(target.items) ? target.items : [];
    for (const row of items) {
      out.push(row);
      if (out.length >= max) return out;
    }
  }
  return out;
}

async function sanitizeRecoCandidatesForUi(
  cards,
  {
    strictFilter,
    dualQa,
    qaMode,
    singleProvider,
    allowOpenAiFallback,
    qaContext = null,
    fallbackCandidateBuilder = null,
    allowExternalSeedSupplement = false,
    externalSeedStrategy = 'supplement_internal_first',
    allowResolverExternalRecommendations = false,
    logger = null,
  } = {},
) {
  const list = Array.isArray(cards) ? cards : [];
  if (!list.length) {
    return {
      cards: [],
      rejected: [],
      dropped: 0,
      externalized: 0,
      lookup_meta: {
        llm_fallback_attempted: 0,
        llm_fallback_recovered: 0,
        llm_fallback_used: false,
        llm_fallback_stage_counts: initLlmFallbackStageCounts(),
        llm_fallback_last_reason: null,
      },
    };
  }
  const effectiveQaMode = (() => {
    if (qaMode !== undefined && qaMode !== null && String(qaMode).trim()) return resolveQaMode(qaMode);
    if (dualQa === true) return 'dual';
    if (dualQa === false) return 'off';
    return resolveQaMode(AURORA_PRODUCT_RELEVANCE_QA_MODE);
  })();
  const effectiveSingleProvider = resolveQaSingleProvider(singleProvider);
  const effectiveOpenAiFallback =
    allowOpenAiFallback === undefined || allowOpenAiFallback === null
      ? AURORA_LLM_OPENAI_FALLBACK_ENABLED
      : Boolean(allowOpenAiFallback);

  let dropped = 0;
  let externalized = 0;
  const rejected = [];
  const lookupMeta = {
    llm_fallback_attempted: 0,
    llm_fallback_recovered: 0,
    llm_fallback_used: false,
    llm_fallback_stage_counts: initLlmFallbackStageCounts(),
    llm_fallback_last_reason: null,
  };
  const nextCards = [];
  for (const card of list) {
    if (!isPlainObject(card)) {
      nextCards.push(card);
      continue;
    }
    const type = String(card.type || '').trim().toLowerCase();
    const payload = isPlainObject(card.payload) ? { ...card.payload } : null;
    if (!payload) {
      nextCards.push(card);
      continue;
    }

    if (type === 'recommendations') {
      const recs = Array.isArray(payload.recommendations) ? payload.recommendations : [];
      const travelRecoMode = isTravelRecoPayload(payload);
      const kept = [];
      const externalSearchCtas = Array.isArray(payload.external_search_ctas) ? payload.external_search_ctas.slice(0, 6) : [];
      let droppedForCard = 0;
      let searchDemotedForCard = 0;
      let contractDemotedForCard = 0;
      let missingUrlFallbackForCard = 0;
      let strictFilterFallbackForCard = 0;
      let nonHttpsDemotedForCard = 0;
      let pdpContractRepairedForCard = 0;
      let pdpContractDroppedForCard = 0;
      let recoveryRecoveredForCard = 0;
      let recoveryAttemptedForCard = 0;
      let llmFallbackRecoveredForCard = 0;
      let llmFallbackAttemptedForCard = 0;
      let llmFallbackTimeoutForCard = 0;
      let llmFallbackInvalidJsonForCard = 0;
      let llmFallbackErrorForCard = 0;
      let llmFallbackEmptyForCard = 0;
      for (const rec of recs) {
        const row = coerceRecoCandidateForGuardrail(rec);
        if (!row) continue;
        const pdpContractRepaired = Boolean(isPlainObject(row.metadata) && row.metadata.pdp_contract_repaired === true);
        if (pdpContractRepaired) {
          pdpContractRepairedForCard += 1;
        }
        if (
          String(row.pdp_version || row.pdpVersion || '').trim() ||
          (isPlainObject(row.subject) && (Array.isArray(row.modules) || String(row.status || '').trim()))
        ) {
          dropped += 1;
          droppedForCard += 1;
          pdpContractDroppedForCard += 1;
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: extractCandidateOpenUrl(row) || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: 'reco_contract_invalid_raw_pdp_response',
            rule_id: 'reco_guardrail',
          });
          continue;
        }

        const blacklistHit = isBlacklistedCategoryOrTitle(row);
        const skincareHit = isSkincareCategory(row);
        const travelAllowed = !travelRecoMode || isTravelRecoAllowedCandidate(row);
        const trustedCatalogGrounded = isTrustedCatalogGroundedRecoCandidate(row, payload);
        const relevanceDecision = await evaluateIngredientCandidateWithQaMode(row, {
          qaMode: effectiveQaMode,
          singleProvider: effectiveSingleProvider,
          allowOpenAiFallback: effectiveOpenAiFallback,
          qaContext,
        });
        const directUrl = extractCandidateOpenUrl(row);
        const openable = hasOpenableUrl(row);
        const searchLike = isSearchLikeUrl(directUrl);
        const resolverExternalBypass = allowResolverExternalRecommendations === true && isResolverExternalOpenContractRow(row);
        const relevanceRejectReason = blacklistHit
          ? 'blacklisted_category_or_title'
          : travelRecoMode && !travelAllowed
            ? 'travel_non_skincare_category'
          : strictFilter && !skincareHit && !trustedCatalogGrounded
            ? 'non_skincare_category'
            : !(relevanceDecision && relevanceDecision.pass === true) && !trustedCatalogGrounded
              ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
              : '';

        if (relevanceRejectReason) {
          dropped += 1;
          droppedForCard += 1;
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: directUrl || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: relevanceRejectReason,
            rule_id: 'reco_guardrail',
          });
          continue;
        }

        if (isRecoUngroundedItem(row)) {
          kept.push({
            ...row,
            grounding_status: 'ungrounded',
            metadata: {
              ...(isPlainObject(row.metadata) ? row.metadata : {}),
              reco_render_mode: 'editorial',
            },
          });
          continue;
        }

        if (resolverExternalBypass) {
          kept.push(row);
          continue;
        }
        if (searchLike) {
          externalized += 1;
          searchDemotedForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'search_url_demoted'));
          continue;
        }
        if (!openable) {
          externalized += 1;
          missingUrlFallbackForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'missing_openable_url_search_fallback'));
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: directUrl || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: 'product_url_missing',
            rule_id: 'reco_guardrail',
          });
          continue;
        }
        if (!directUrl) {
          externalized += 1;
          contractDemotedForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'open_contract_only_no_direct_url'));
          continue;
        }
        if (!isHttpsUrl(directUrl)) {
          externalized += 1;
          nonHttpsDemotedForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'non_https_pdp_url_demoted'));
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: directUrl || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: 'non_https_pdp_url',
            rule_id: 'reco_guardrail',
          });
          continue;
        }

        kept.push(normalizeCandidateWithDirectUrl(row, directUrl));
      }

      if (kept.length === 0 && externalSearchCtas.length === 0 && droppedForCard > 0) {
        const strictFallback = buildStrictFilterFallbackSearchCtas(payload, 3);
        if (strictFallback.length) {
          strictFilterFallbackForCard += 1;
          externalized += strictFallback.length;
          externalSearchCtas.push(...strictFallback);
        }
      }

      if (kept.length === 0 && AURORA_PURCHASABLE_FALLBACK_ENABLED && typeof fallbackCandidateBuilder === 'function') {
        const recoveryQueries = collectPurchasableFallbackQueries({
          payload,
          recommendationRows: recs,
          externalSearchCtas,
          maxQueries: AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
        });
        if (recoveryQueries.length) {
          const recovered = await recoverPurchasableProductsFromQueries({
            queries: recoveryQueries,
            strictFilter,
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
            fallbackCandidateBuilder,
            allowExternalSeedSupplement,
            externalSeedStrategy,
            logger,
            guardrailRuleId: 'reco_guardrail',
            maxProducts: AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
          });
          recoveryAttemptedForCard = recovered.attempted_queries.length;
          recoveryRecoveredForCard = recovered.products.length;
          if (recovered.products.length) {
            kept.push(...recovered.products.slice(0, AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS));
          }
          if (recovered.rejected.length) rejected.push(...recovered.rejected);
          if (recovered.external_search_ctas.length) {
            externalSearchCtas.push(...recovered.external_search_ctas);
            externalized += recovered.external_search_ctas.length;
          }
        }
      }

      if (kept.length === 0 && AURORA_PRODUCT_LOOKUP_LLM_FALLBACK_ENABLED) {
        const llmQueries = collectPurchasableFallbackQueries({
          payload,
          recommendationRows: recs,
          externalSearchCtas,
          maxQueries: AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
        });
        if (llmQueries.length) {
          const llmRecovered = await recoverProductsWithLlmFallbackFromQueries({
            queries: llmQueries,
            strictFilter,
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
            productCandidates: recs,
            recoTrigger: 'explicit_user_action',
            logger,
            guardrailRuleId: 'reco_guardrail',
            maxProducts: AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
          });
          llmFallbackAttemptedForCard = llmRecovered.attempted_queries.length;
          llmFallbackRecoveredForCard = llmRecovered.products.length;
          const llmStageCounts = isPlainObject(llmRecovered.stage_counts) ? llmRecovered.stage_counts : {};
          llmFallbackTimeoutForCard = Math.max(0, Math.trunc(Number(llmStageCounts.timeout || 0)));
          llmFallbackInvalidJsonForCard = Math.max(0, Math.trunc(Number(llmStageCounts.invalid_json || 0)));
          llmFallbackErrorForCard = Math.max(0, Math.trunc(Number(llmStageCounts.error || 0)));
          llmFallbackEmptyForCard = Math.max(0, Math.trunc(Number(llmStageCounts.empty || 0)));
          if (llmRecovered.products.length) {
            kept.push(...llmRecovered.products.slice(0, AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS));
          }
          if (llmRecovered.rejected.length) rejected.push(...llmRecovered.rejected);
          if (llmRecovered.external_search_ctas.length) {
            externalSearchCtas.push(...llmRecovered.external_search_ctas);
            externalized += llmRecovered.external_search_ctas.length;
          }
        }
      }

      lookupMeta.llm_fallback_attempted += llmFallbackAttemptedForCard;
      lookupMeta.llm_fallback_recovered += llmFallbackRecoveredForCard;
      if (llmFallbackRecoveredForCard > 0) lookupMeta.llm_fallback_used = true;
      lookupMeta.llm_fallback_stage_counts = mergeLlmFallbackStageCounts(lookupMeta.llm_fallback_stage_counts, {
        timeout: llmFallbackTimeoutForCard,
        invalid_json: llmFallbackInvalidJsonForCard,
        error: llmFallbackErrorForCard,
        empty: llmFallbackEmptyForCard,
        recovered: llmFallbackRecoveredForCard > 0 ? 1 : 0,
      });
      const llmLastReason = pickFirstString(
        llmFallbackRecoveredForCard > 0 ? 'llm_recovered' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackTimeoutForCard > 0 ? 'llm_timeout' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackInvalidJsonForCard > 0 ? 'llm_invalid_json' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackErrorForCard > 0 ? 'llm_error' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackEmptyForCard > 0 ? 'llm_empty' : '',
      );
      if (llmLastReason) lookupMeta.llm_fallback_last_reason = llmLastReason;

      const mergedFieldMissing = mergeFieldMissing(card.field_missing, [
        ...(droppedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'strict_skincare_filter' }] : []),
        ...(pdpContractRepairedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'pdp_contract_repaired' }] : []),
        ...(pdpContractDroppedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'pdp_contract_invalid_dropped' }] : []),
        ...(searchDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'search_url_demoted' }] : []),
        ...(contractDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'open_contract_only_demoted' }] : []),
        ...(missingUrlFallbackForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'product_url_missing_fallback' }] : []),
        ...(strictFilterFallbackForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'strict_filter_fallback_search' }] : []),
        ...(nonHttpsDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'non_https_pdp_url_demoted' }] : []),
        ...(recoveryAttemptedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'purchasable_fallback_attempted' }] : []),
        ...(recoveryRecoveredForCard > 0 ? [{ field: 'payload.recommendations', reason: 'purchasable_fallback_recovered' }] : []),
        ...(llmFallbackAttemptedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'llm_lookup_fallback_attempted' }] : []),
        ...(llmFallbackRecoveredForCard > 0 ? [{ field: 'payload.recommendations', reason: 'llm_lookup_fallback_recovered' }] : []),
        ...(llmFallbackTimeoutForCard > 0 ? [{ field: 'payload.recommendations', reason: 'llm_lookup_timeout' }] : []),
        ...(llmFallbackInvalidJsonForCard > 0 ? [{ field: 'payload.recommendations', reason: 'llm_lookup_invalid_json' }] : []),
        ...(llmFallbackErrorForCard > 0 ? [{ field: 'payload.recommendations', reason: 'llm_lookup_error' }] : []),
        ...(llmFallbackEmptyForCard > 0 ? [{ field: 'payload.recommendations', reason: 'llm_lookup_empty' }] : []),
      ]);
      const finalExternalSearchCtas = AURORA_DISCOVERY_CARD_IN_LIST_ENABLED
        ? dedupeExternalSearchCtas(externalSearchCtas, 8)
        : [];
      const derivedProductsEmptyReason = deriveProductsEmptyReason({
        keptCount: kept.length,
        externalSearchCount: finalExternalSearchCtas.length,
        strictFallbackCount: strictFilterFallbackForCard,
        droppedCount: droppedForCard,
        missingUrlCount: missingUrlFallbackForCard,
        contractOnlyCount: contractDemotedForCard,
        searchDemotedCount: searchDemotedForCard,
        nonHttpsCount: nonHttpsDemotedForCard,
        llmFallbackAttempted: llmFallbackAttemptedForCard,
        llmFallbackRecovered: llmFallbackRecoveredForCard,
        llmFallbackTimeout: llmFallbackTimeoutForCard,
        llmFallbackInvalidJson: llmFallbackInvalidJsonForCard,
        llmFallbackError: llmFallbackErrorForCard,
        llmFallbackEmpty: llmFallbackEmptyForCard,
      });
      const productsEmptyReason =
        derivedProductsEmptyReason ||
        (
          kept.length === 0 &&
          finalExternalSearchCtas.length === 0 &&
          pdpContractDroppedForCard > 0
            ? 'reco_contract_invalid'
            : ''
        );

      nextCards.push({
        ...card,
        payload: {
          ...payload,
          recommendations: kept,
          ...(kept.length === 0 && recs.length > 0 && normalizeRecoProductsEmptyReason(productsEmptyReason) === 'strict_filter_fallback_only'
            ? { plan_only_recommendations: recs }
            : {}),
          ...(finalExternalSearchCtas.length ? { external_search_ctas: finalExternalSearchCtas } : {}),
          ...(productsEmptyReason ? { products_empty_reason: productsEmptyReason } : {}),
        },
        ...(mergedFieldMissing.length ? { field_missing: mergedFieldMissing } : {}),
      });
      continue;
    }

    if (type === 'ingredient_plan_v2' || type === 'ingredient_plan') {
      const planNode = isPlainObject(payload.plan) ? { ...payload.plan } : null;
      const targets = Array.isArray(payload.targets)
        ? payload.targets
        : planNode && Array.isArray(planNode.targets)
          ? planNode.targets
          : [];
      const externalSearchCtas = Array.isArray(payload.external_search_ctas) ? payload.external_search_ctas.slice(0, 12) : [];
      const nextTargets = [];
      let droppedForCard = 0;
      let searchDemotedForCard = 0;
      let contractDemotedForCard = 0;
      let missingUrlFallbackForCard = 0;
      let nonHttpsDemotedForCard = 0;
      let recoveryRecoveredForCard = 0;
      let recoveryAttemptedForCard = 0;
      let llmFallbackRecoveredForCard = 0;
      let llmFallbackAttemptedForCard = 0;
      let llmFallbackTimeoutForCard = 0;
      let llmFallbackInvalidJsonForCard = 0;
      let llmFallbackErrorForCard = 0;
      let llmFallbackEmptyForCard = 0;
      const guardrailRuleId = type === 'ingredient_plan_v2' ? 'ingredient_plan_v2_guardrail' : 'ingredient_plan_guardrail';

      const sanitizeRows = async (sourceRows) => {
        const kept = [];
        for (const product of sourceRows) {
          const row = coerceRecoCandidateForGuardrail(product);
          if (!row) continue;
          const blacklistHit = isBlacklistedCategoryOrTitle(row);
          const skincareHit = isSkincareCategory(row);
          const relevanceDecision = await evaluateIngredientCandidateWithQaMode(row, {
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
          });
          const directUrl = extractCandidateOpenUrl(row);
          const openable = hasOpenableUrl(row);
          const searchLike = isSearchLikeUrl(directUrl);
          const resolverExternalBypass = allowResolverExternalRecommendations === true && isResolverExternalOpenContractRow(row);
          const relevanceRejectReason = blacklistHit
            ? 'blacklisted_category_or_title'
            : strictFilter && !skincareHit
              ? 'non_skincare_category'
              : !(relevanceDecision && relevanceDecision.pass === true)
                ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
                : '';

          if (relevanceRejectReason) {
            dropped += 1;
            droppedForCard += 1;
            rejected.push({
              query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_url: directUrl || null,
              candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
              reject_reason: relevanceRejectReason,
              rule_id: guardrailRuleId,
            });
            continue;
          }
          if (resolverExternalBypass) {
            kept.push(row);
            continue;
          }
          if (searchLike) {
            externalized += 1;
            searchDemotedForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'search_url_demoted'));
            continue;
          }
          if (!openable) {
            externalized += 1;
            missingUrlFallbackForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'missing_openable_url_search_fallback'));
            rejected.push({
              query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_url: directUrl || null,
              candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
              reject_reason: 'product_url_missing',
              rule_id: guardrailRuleId,
            });
            continue;
          }
          if (!directUrl) {
            externalized += 1;
            contractDemotedForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'open_contract_only_no_direct_url'));
            continue;
          }
          if (!isHttpsUrl(directUrl)) {
            externalized += 1;
            nonHttpsDemotedForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'non_https_pdp_url_demoted'));
            rejected.push({
              query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_url: directUrl || null,
              candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
              reject_reason: 'non_https_pdp_url',
              rule_id: guardrailRuleId,
            });
            continue;
          }
          kept.push(normalizeCandidateWithDirectUrl(row, directUrl));
        }
        return kept;
      };

      for (const target of targets) {
        const baseTarget = isPlainObject(target) ? { ...target } : {};
        if (Array.isArray(baseTarget.products)) {
          baseTarget.products = await sanitizeRows(baseTarget.products);
        } else if (isPlainObject(baseTarget.products)) {
          const products = { ...baseTarget.products };
          const bucketNames = Object.keys(products);
          for (const bucketName of bucketNames) {
            const sourceRows = Array.isArray(products[bucketName]) ? products[bucketName] : [];
            products[bucketName] = await sanitizeRows(sourceRows);
          }
          baseTarget.products = products;
        }

        if (Array.isArray(baseTarget.candidates)) {
          baseTarget.candidates = await sanitizeRows(baseTarget.candidates);
        }
        if (Array.isArray(baseTarget.items)) {
          baseTarget.items = await sanitizeRows(baseTarget.items);
        }
        nextTargets.push(baseTarget);
      }

      let keptProductsCount = countPurchasableProductsForTargets(nextTargets);
      if (keptProductsCount === 0 && AURORA_PURCHASABLE_FALLBACK_ENABLED && typeof fallbackCandidateBuilder === 'function') {
        const recoveryQueries = collectPurchasableFallbackQueries({
          payload,
          externalSearchCtas,
          extraSeeds: nextTargets,
          maxQueries: AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
        });
        if (recoveryQueries.length) {
          const recovered = await recoverPurchasableProductsFromQueries({
            queries: recoveryQueries,
            strictFilter,
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
            fallbackCandidateBuilder,
            allowExternalSeedSupplement,
            externalSeedStrategy,
            logger,
            guardrailRuleId,
            maxProducts: AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
          });
          recoveryAttemptedForCard = recovered.attempted_queries.length;
          recoveryRecoveredForCard = recovered.products.length;
          if (recovered.rejected.length) rejected.push(...recovered.rejected);
          if (recovered.external_search_ctas.length) {
            externalSearchCtas.push(...recovered.external_search_ctas);
            externalized += recovered.external_search_ctas.length;
          }
          if (recovered.products.length) {
            if (!nextTargets.length) {
              nextTargets.push({
                ingredient: 'general_skincare',
                products: {
                  competitors: [],
                  dupes: [],
                },
              });
            }
            const firstTarget = isPlainObject(nextTargets[0]) ? { ...nextTargets[0] } : {};
            const productsNode = isPlainObject(firstTarget.products) ? { ...firstTarget.products } : {};
            const competitors = Array.isArray(productsNode.competitors) ? productsNode.competitors.slice() : [];
            productsNode.competitors = [...competitors, ...recovered.products].slice(0, AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS);
            firstTarget.products = productsNode;
            nextTargets[0] = firstTarget;
          }
          keptProductsCount = countPurchasableProductsForTargets(nextTargets);
        }
      }

      if (keptProductsCount === 0 && AURORA_PRODUCT_LOOKUP_LLM_FALLBACK_ENABLED) {
        const llmQueries = collectPurchasableFallbackQueries({
          payload,
          externalSearchCtas,
          extraSeeds: nextTargets,
          maxQueries: AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
        });
        if (llmQueries.length) {
          const llmRecovered = await recoverProductsWithLlmFallbackFromQueries({
            queries: llmQueries,
            strictFilter,
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
            productCandidates: collectProductCandidatesFromRecoTargets(nextTargets, 24),
            recoTrigger: 'explicit_user_action',
            logger,
            guardrailRuleId,
            maxProducts: AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
          });
          llmFallbackAttemptedForCard = llmRecovered.attempted_queries.length;
          llmFallbackRecoveredForCard = llmRecovered.products.length;
          const llmStageCounts = isPlainObject(llmRecovered.stage_counts) ? llmRecovered.stage_counts : {};
          llmFallbackTimeoutForCard = Math.max(0, Math.trunc(Number(llmStageCounts.timeout || 0)));
          llmFallbackInvalidJsonForCard = Math.max(0, Math.trunc(Number(llmStageCounts.invalid_json || 0)));
          llmFallbackErrorForCard = Math.max(0, Math.trunc(Number(llmStageCounts.error || 0)));
          llmFallbackEmptyForCard = Math.max(0, Math.trunc(Number(llmStageCounts.empty || 0)));
          if (llmRecovered.rejected.length) rejected.push(...llmRecovered.rejected);
          if (llmRecovered.external_search_ctas.length) {
            externalSearchCtas.push(...llmRecovered.external_search_ctas);
            externalized += llmRecovered.external_search_ctas.length;
          }
          if (llmRecovered.products.length) {
            if (!nextTargets.length) {
              nextTargets.push({
                ingredient: 'general_skincare',
                products: {
                  competitors: [],
                  dupes: [],
                },
              });
            }
            const firstTarget = isPlainObject(nextTargets[0]) ? { ...nextTargets[0] } : {};
            const productsNode = isPlainObject(firstTarget.products) ? { ...firstTarget.products } : {};
            const competitors = Array.isArray(productsNode.competitors) ? productsNode.competitors.slice() : [];
            productsNode.competitors = [...competitors, ...llmRecovered.products].slice(0, AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS);
            firstTarget.products = productsNode;
            nextTargets[0] = firstTarget;
          }
          keptProductsCount = countPurchasableProductsForTargets(nextTargets);
        }
      }

      lookupMeta.llm_fallback_attempted += llmFallbackAttemptedForCard;
      lookupMeta.llm_fallback_recovered += llmFallbackRecoveredForCard;
      if (llmFallbackRecoveredForCard > 0) lookupMeta.llm_fallback_used = true;
      lookupMeta.llm_fallback_stage_counts = mergeLlmFallbackStageCounts(lookupMeta.llm_fallback_stage_counts, {
        timeout: llmFallbackTimeoutForCard,
        invalid_json: llmFallbackInvalidJsonForCard,
        error: llmFallbackErrorForCard,
        empty: llmFallbackEmptyForCard,
        recovered: llmFallbackRecoveredForCard > 0 ? 1 : 0,
      });
      const llmLastReason = pickFirstString(
        llmFallbackRecoveredForCard > 0 ? 'llm_recovered' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackTimeoutForCard > 0 ? 'llm_timeout' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackInvalidJsonForCard > 0 ? 'llm_invalid_json' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackErrorForCard > 0 ? 'llm_error' : '',
        llmFallbackAttemptedForCard > 0 && llmFallbackEmptyForCard > 0 ? 'llm_empty' : '',
      );
      if (llmLastReason) lookupMeta.llm_fallback_last_reason = llmLastReason;

      const mergedFieldMissing = mergeFieldMissing(card.field_missing, [
        ...(droppedForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'strict_skincare_filter' }] : []),
        ...(searchDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'search_url_demoted' }] : []),
        ...(contractDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'open_contract_only_demoted' }] : []),
        ...(missingUrlFallbackForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'product_url_missing_fallback' }] : []),
        ...(nonHttpsDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'non_https_pdp_url_demoted' }] : []),
        ...(recoveryAttemptedForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'purchasable_fallback_attempted' }] : []),
        ...(recoveryRecoveredForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'purchasable_fallback_recovered' }] : []),
        ...(llmFallbackAttemptedForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'llm_lookup_fallback_attempted' }] : []),
        ...(llmFallbackRecoveredForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'llm_lookup_fallback_recovered' }] : []),
        ...(llmFallbackTimeoutForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'llm_lookup_timeout' }] : []),
        ...(llmFallbackInvalidJsonForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'llm_lookup_invalid_json' }] : []),
        ...(llmFallbackErrorForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'llm_lookup_error' }] : []),
        ...(llmFallbackEmptyForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'llm_lookup_empty' }] : []),
      ]);
      const finalExternalSearchCtas = AURORA_DISCOVERY_CARD_IN_LIST_ENABLED
        ? dedupeExternalSearchCtas(externalSearchCtas, 12)
        : [];
      const productsEmptyReason = deriveProductsEmptyReason({
        keptCount: keptProductsCount,
        externalSearchCount: finalExternalSearchCtas.length,
        strictFallbackCount: 0,
        droppedCount: droppedForCard,
        missingUrlCount: missingUrlFallbackForCard,
        contractOnlyCount: contractDemotedForCard,
        searchDemotedCount: searchDemotedForCard,
        nonHttpsCount: nonHttpsDemotedForCard,
        llmFallbackAttempted: llmFallbackAttemptedForCard,
        llmFallbackRecovered: llmFallbackRecoveredForCard,
        llmFallbackTimeout: llmFallbackTimeoutForCard,
        llmFallbackInvalidJson: llmFallbackInvalidJsonForCard,
        llmFallbackError: llmFallbackErrorForCard,
        llmFallbackEmpty: llmFallbackEmptyForCard,
      });

      nextCards.push({
        ...card,
        payload: {
          ...payload,
          ...(Array.isArray(payload.targets)
            ? { targets: nextTargets }
            : planNode
              ? { plan: { ...planNode, targets: nextTargets } }
              : { targets: nextTargets }),
          ...(finalExternalSearchCtas.length ? { external_search_ctas: finalExternalSearchCtas } : {}),
          ...(productsEmptyReason ? { products_empty_reason: productsEmptyReason } : {}),
        },
        ...(mergedFieldMissing.length ? { field_missing: mergedFieldMissing } : {}),
      });
      continue;
    }

    nextCards.push(card);
  }

  return { cards: nextCards, rejected, dropped, externalized, lookup_meta: lookupMeta };
}

function applyPhotoClaimConsistency(cards) {
  const list = Array.isArray(cards) ? cards : [];
  const hasPhotoModules = list.some((card) => {
    if (!isPlainObject(card)) return false;
    if (String(card.type || '').trim().toLowerCase() !== 'photo_modules_v1') return false;
    const payload = isPlainObject(card.payload) ? card.payload : {};
    const modules = Array.isArray(payload.modules) ? payload.modules : [];
    return modules.length > 0;
  });

  return list.map((card) => {
    if (!isPlainObject(card)) return card;
    const type = String(card.type || '').trim().toLowerCase();
    const payload = isPlainObject(card.payload) ? { ...card.payload } : null;
    if (!payload) return card;

    if (type === 'photo_modules_v1') {
      return {
        ...card,
        payload: {
          ...payload,
          render_capabilities: {
            ...(isPlainObject(payload.render_capabilities) ? payload.render_capabilities : {}),
            mask_overlay_enabled: AURORA_PHOTO_MODULE_MASK_OVERLAY_ENABLED,
          },
        },
      };
    }

    if (type !== 'analysis_summary') return card;

    const qualityReport = isPlainObject(payload.quality_report) ? { ...payload.quality_report } : {};
    const photoQuality = isPlainObject(qualityReport.photo_quality) ? { ...qualityReport.photo_quality } : {};
    const qualityGrade = String(photoQuality.grade || '').trim().toLowerCase();
    const claimedUsedPhotos = payload.used_photos === true;
    if (!claimedUsedPhotos) return card;

    const forceUnavailable = !hasPhotoModules;

    if (!forceUnavailable) return card;

    const nextFieldMissing = mergeFieldMissing(card.field_missing, [
      {
        field: 'analysis.used_photos',
        reason: qualityGrade === 'fail' ? 'photo_quality_fail' : 'photo_modules_missing',
      },
    ]);

    return {
      ...card,
      payload: {
        ...payload,
        used_photos: false,
        photo_analysis_status: 'unavailable',
        photo_analysis_reason: 'photo_modules_missing',
      },
      ...(nextFieldMissing.length ? { field_missing: nextFieldMissing } : {}),
    };
  });
}

function buildAnalysisStoryUiCardV1({ story, evidence, language } = {}) {
  const isCn = String(language || '').toUpperCase() === 'CN';
  const row = isPlainObject(story) ? story : {};
  const confidence = isPlainObject(row.confidence_overall) ? row.confidence_overall : {};
  const confidenceLevel = pickFirstString(confidence.level, isCn ? '中' : 'medium');
  const findingTitles = asStringArray(
    Array.isArray(row.priority_findings)
      ? row.priority_findings.map((item) => pickFirstString(item && item.title, item && item.detail))
      : [],
    3,
  );
  const fallbackEvidence = asStringArray(
    Array.isArray(evidence && evidence.finding_evidence)
      ? evidence.finding_evidence.map((item) => pickFirstString(item && item.observation))
      : [],
    3,
  );
  const keyPoints = findingTitles.length ? findingTitles : fallbackEvidence;
  const amActions = asStringArray(
    Array.isArray(row.am_plan) ? row.am_plan.map((step) => pickFirstString(step && step.step)) : [],
    2,
  );
  const pmActions = asStringArray(
    Array.isArray(row.pm_plan) ? row.pm_plan.map((step) => pickFirstString(step && step.step)) : [],
    2,
  );
  const actionsNow = asStringArray(
    [
      ...amActions.map((step) => (isCn ? `早上：${step}` : `AM: ${step}`)),
      ...pmActions.map((step) => (isCn ? `晚上：${step}` : `PM: ${step}`)),
    ],
    4,
  );
  const avoidNow = asStringArray(Array.isArray(row.safety_notes) ? row.safety_notes : [], 3);
  const lowConfidenceNoFindings =
    String(confidenceLevel).toLowerCase() === 'low' &&
    !findingTitles.length &&
    !fallbackEvidence.length;
  const headline = lowConfidenceNoFindings
    ? (isCn
      ? '照片分析未能完成，请在自然光下重新拍照以获取准确结果。'
      : 'Photo analysis could not be completed. Please retake photos in natural daylight for accurate results.')
    : (pickFirstString(
        Array.isArray(row.target_state) ? row.target_state[0] : '',
        isCn
          ? '先稳定，再循序推进亮肤与纹理改善。'
          : 'Stabilize first, then improve tone and texture step by step.',
      ) || (isCn ? '先稳后进。' : 'Stability first.'));
  const timeline = isPlainObject(row.timeline) ? row.timeline : {};
  const nextCheckin = pickFirstString(
    Array.isArray(timeline.first_4_weeks) ? timeline.first_4_weeks[0] : '',
    Array.isArray(timeline.week_8_12_expectation) ? timeline.week_8_12_expectation[0] : '',
    isCn ? '2 周后复查耐受与稳定度。' : 'Re-check tolerance and stability in 2 weeks.',
  );

  return {
    headline,
    key_points: keyPoints,
    actions_now: actionsNow,
    avoid_now: avoidNow,
    confidence_label: confidenceLevel,
    next_checkin: nextCheckin,
  };
}

