        llmFailureClass: baseContract.failure_class || upstreamReco?.llmFailureClass,
        upstreamFailureCode: upstreamReco?.upstreamFailureCode,
        promptContractOk: guardedRecoCard?.payload?.prompt_contract_ok !== false,
